reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}


resource "aws_route53_zone" "primary" {
  name = "example53.com"
}

resource "aws_cloudwatch_log_group" "aws_route53_example_com" {
  name              = "/aws/route53/${aws_route53_zone.primary.name}"
  retention_in_days = 30
}

# Example CloudWatch log resource policy to allow Route53 to write logs
# to any log group under /aws/route53/*

data "aws_iam_policy_document" "route53-query-logging-policy" {
  statement {
    actions = [
      "logs:CreateLogStream",
      "logs:PutLogEvents",
    ]

    resources = ["arn:aws:logs:*:*:log-group:/aws/route53/*"]

    principals {
      identifiers = ["route53.amazonaws.com"]
      type        = "Service"
    }
  }
}

resource "aws_cloudwatch_log_resource_policy" "route53-query-logging-policy" {
  policy_document = data.aws_iam_policy_document.route53-query-logging-policy.json
  policy_name     = "route53-query-logging-policy"
}

resource "aws_route53_query_log" "example_com" {
  depends_on = [aws_cloudwatch_log_resource_policy.route53-query-logging-policy]

  cloudwatch_log_group_arn = aws_cloudwatch_log_group.aws_route53_example_com.arn
  zone_id                  = aws_route53_zone.primary.zone_id
}

response:
To fulfill the request, let's break it down step by step:

1. **Understand AWS Route 53 Query Logging**:  
   Route 53 supports query logging, which sends DNS queries made to a specified hosted zone to CloudWatch Logs. This requires:
   - A **Route 53 Hosted Zone** (named "primary").
   - A **CloudWatch Log Group** (to store DNS query logs).
   - A **CloudWatch Log Resource Policy** (to grant Route 53 permissions to write logs).
   - A **Query Log** resource that links the hosted zone to the log group.

2. **Resources Needed**:
   - `aws_route53_zone`: Create a Route 53 hosted zone named "primary".
   - `aws_cloudwatch_log_group`: Create a log group named `aws_route53_example_com`.
   - `aws_cloudwatch_log_resource_policy`: Define a policy named `route53-query-logging-policy` allowing Route 53 to put log events.
   - `aws_route53_query_log`: Enable DNS query logging for the zone, directing logs to the specified log group.

3. **Important Notes**:
   - The domain name in `aws_route53_zone` must be a valid domain (e.g., `example.com`). We'll use `example.com` as a placeholder.
   - The resource policy must allow `logs:PutLogEvents` and `logs:CreateLogStream` from `route53.amazonaws.com`.

4. **Final HCL Structure**:
   Combine all required resources with correct names and permissions.

```hcl
resource "aws_route53_zone" "primary" {
  name = "example.com"
  comment = "Primary hosted zone"
}

resource "aws_cloudwatch_log_group" "aws_route53_example_com" {
  name = "aws_route53_example_com"
  retention_in_days = 30
  tags = {
    Name = "Route53QueryLogs"
  }
}

resource "aws_cloudwatch_log_resource_policy" "route53_query_logging_policy" {
  policy_name = "route53-query-logging-policy"

  policy_document = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "route53.amazonaws.com"
        }
        Action = [
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
        Condition = {
          StringEquals = {
            "aws:SourceAccount" = "*"
          },
          ArnLike = {
            "aws:SourceArn" = "arn:aws:route53:::hostedzone/*"
          }
        }
      }
    ]
  })
}

resource "aws_route53_query_log" "example" {
  cloudwatch_log_group_arn = aws_cloudwatch_log_group.aws_route53_example_com.arn
  zone_id                  = aws_route53_zone.primary.id
}
```

