# Configure multiple AWS providers for different regions
provider "aws" {
  alias  = "main"
  region = "us-west-1"
}

provider "aws" {
  alias  = "us-east"
  region = "us-east-1"
}

provider "aws" {
  alias  = "eu-central"
  region = "eu-central-1"
}

provider "aws" {
  alias  = "ap-southeast"
  region = "ap-southeast-1"
}

# Create Route 53 private hosted zone in us-west-1
resource "aws_route53_zone" "main" {
  provider = aws.main
  name     = "main"
  vpc {
    vpc_id     = aws_vpc.main.id
    vpc_region = "us-west-1"
  }
}

# Create VPCs in each region (required for private hosted zones and DB instances)
resource "aws_vpc" "main" {
  provider   = aws.main
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "main-vpc"
  }
}

resource "aws_vpc" "us_east" {
  provider   = aws.us-east
  cidr_block = "10.1.0.0/16"
  tags = {
    Name = "us-east-vpc"
  }
}

resource "aws_vpc" "eu_central" {
  provider   = aws.eu-central
  cidr_block = "10.2.0.0/16"
  tags = {
    Name = "eu-central-vpc"
  }
}

resource "aws_vpc" "ap_southeast" {
  provider   = aws.ap-southeast
  cidr_block = "10.3.0.0/16"
  tags = {
    Name = "ap-southeast-vpc"
  }
}

# Create subnets for DB instances (minimum one per VPC for RDS)
resource "aws_subnet" "main" {
  provider          = aws.main
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-west-1a"
  tags = {
    Name = "main-subnet"
  }
}

resource "aws_subnet" "us_east" {
  provider          = aws.us-east
  vpc_id            = aws_vpc.us_east.id
  cidr_block        = "10.1.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "us-east-subnet"
  }
}

resource "aws_subnet" "eu_central" {
  provider          = aws.eu-central
  vpc_id            = aws_vpc.eu_central.id
  cidr_block        = "10.2.1.0/24"
  availability_zone = "eu-central-1a"
  tags = {
    Name = "eu-central-subnet"
  }
}

resource "aws_subnet" "ap_southeast" {
  provider          = aws.ap-southeast
  vpc_id            = aws_vpc.ap_southeast.id
  cidr_block        = "10.3.1.0/24"
  availability_zone = "ap-southeast-1a"
  tags = {
    Name = "ap-southeast-subnet"
  }
}

# Create DB subnet groups
resource "aws_db_subnet_group" "main" {
  provider      = aws.main
  name          = "primary-subnet-group"
  subnet_ids    = [aws_subnet.main.id]
  description   = "Subnet group for primary DB"
}

resource "aws_db_subnet_group" "us_east" {
  provider      = aws.us-east
  name          = "replica-us-east-subnet-group"
  subnet_ids    = [aws_subnet.us_east.id]
  description   = "Subnet group for US East replica"
}

resource "aws_db_subnet_group" "eu_central" {
  provider      = aws.eu-central
  name          = "replica-eu-central-subnet-group"
  subnet_ids    = [aws_subnet.eu_central.id]
  description   = "Subnet group for EU Central replica"
}

resource "aws_db_subnet_group" "ap_southeast" {
  provider      = aws.ap-southeast
  name          = "replica-ap-southeast-subnet-group"
  subnet_ids    = [aws_subnet.ap_southeast.id]
  description   = "Subnet group for AP Southeast replica"
}

# Create the primary DB instance in us-west-1
resource "aws_db_instance" "primary" {
  provider                          = aws.main
  identifier                        = "primary"
  instance_class                    = "db.t3.micro"
  allocated_storage                 = 20
  engine                            = "mysql"
  engine_version                    = "8.0"
  username                          = "admin"
  password                          = "password123"
  db_subnet_group_name              = aws_db_subnet_group.main.name
  skip_final_snapshot               = true
  publicly_accessible               = false
  vpc_security_group_ids            = [aws_security_group.db_main.id]
}

# Create replica DB instances in different regions
resource "aws_db_instance" "replica_us_east" {
  provider                          = aws.us-east
  identifier                        = "replica-us-east"
  instance_class                    = "db.t3.micro"
  allocated_storage                 = 20
  engine                            = "mysql"
  engine_version                    = "8.0"
  username                          = "admin"
  password                          = "password123"
  db_subnet_group_name              = aws_db_subnet_group.us_east.name
  skip_final_snapshot               = true
  publicly_accessible               = false
  vpc_security_group_ids            = [aws_security_group.db_us_east.id]
  replicate_source_db               = aws_db_instance.primary.arn
}

resource "aws_db_instance" "replica_eu_central" {
  provider                          = aws.eu-central
  identifier                        = "replica-eu-central"
  instance_class                    = "db.t3.micro"
  allocated_storage                 = 20
  engine                            = "mysql"
  engine_version                    = "8.0"
  username                          = "admin"
  password                          = "password123"
  db_subnet_group_name              = aws_db_subnet_group.eu_central.name
  skip_final_snapshot               = true
  publicly_accessible               = false
  vpc_security_group_ids            = [aws_security_group.db_eu_central.id]
  replicate_source_db               = aws_db_instance.primary.arn
}

resource "aws_db_instance" "replica_ap_southeast" {
  provider                          = aws.ap-southeast
  identifier                        = "replica-ap-southeast"
  instance_class                    = "db.t3.micro"
  allocated_storage                 = 20
  engine                            = "mysql"
  engine_version                    = "8.0"
  username                          = "admin"
  password                          = "password123"
