  skip_final_snapshot               = true
  publicly_accessible               = false
  vpc_security_group_ids            = [aws_security_group.db_ap_southeast.id]
  replicate_source_db               = aws_db_instance.primary.arn
}

# Security groups for DB instances
resource "aws_security_group" "db_main" {
  provider = aws.main
  name     = "db-main-sg"
  vpc_id   = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16", "10.1.0.0/16", "10.2.0.0/16", "10.3.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_security_group" "db_us_east" {
  provider = aws.us-east
  name     = "db-us-east-sg"
  vpc_id   = aws_vpc.us_east.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16", "10.1.0.0/16", "10.2.0.0/16", "10.3.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_security_group" "db_eu_central" {
  provider = aws.eu-central
  name     = "db-eu-central-sg"
  vpc_id   = aws_vpc.eu_central.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16", "10.1.0.0/16", "10.2.0.0/16", "10.3.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_security_group" "db_ap_southeast" {
  provider = aws.ap-southeast
  name     = "db-ap-southeast-sg"
  vpc_id   = aws_vpc.ap_southeast.id

  ingress {
    from_port   = 3306
