    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Create a weighted Route 53 record that points to the replica DB instances
resource "aws_route53_record" "replica_weighted" {
  provider = aws.main
  zone_id  = aws_route53_zone.main.zone_id
  name     = "replicas.main"
  type     = "CNAME"
  weighted_routing_policy {
    weight = 100
  }
  set_identifier = "replica-us-east"
  ttl            = 300
  records        = [aws_db_instance.replica_us_east.address]
}

