  vpc_id            = aws_vpc.us_east.id
  cidr_block        = "10.1.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "us-east-subnet"
  }
}

resource "aws_subnet" "eu_central" {
  provider          = aws.eu-central
  vpc_id            = aws_vpc.eu_central.id
  cidr_block        = "10.2.1.0/24"
  availability_zone = "eu-central-1a"
  tags = {
    Name = "eu-central-subnet"
  }
}

resource "aws_subnet" "ap_southeast" {
  provider          = aws.ap-southeast
  vpc_id            = aws_vpc.ap_southeast.id
  cidr_block        = "10.3.1.0/24"
  availability_zone = "ap-southeast-1a"
  tags = {
    Name = "ap-southeast-subnet"
  }
}

# Create DB subnet groups
resource "aws_db_subnet_group" "main" {
  provider      = aws.main
  name          = "primary-subnet-group"
  subnet_ids    = [aws_subnet.main.id]
  description   = "Subnet group for primary DB"
}

resource "aws_db_subnet_group" "us_east" {
  provider      = aws.us-east
  name          = "replica-us-east-subnet-group"
  subnet_ids    = [aws_subnet.us_east.id]
  description   = "Subnet group for US East replica"
