# Create an IAM role for Elastic Beanstalk EC2 instances
resource "aws_iam_role" "eb_ec2_role" {
  name = "eb_ec2_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

# Attach required policies to the IAM role (e.g., AWS managed policy for EB EC2 instances)
resource "aws_iam_role_policy_attachment" "eb_ec2_role_attachment" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

# Create an instance profile for EC2 instances to use the IAM role
resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "eb_ec2_profile"
  role = aws_iam_role.eb_ec2_role.name
}

# Create an Elastic Beanstalk application
resource "aws_elastic_beanstalk_application" "my_api_app" {
  name        = "my_api_app"
  description = "An API application hosted on Elastic Beanstalk with autoscaling"
}

# Create an Elastic Beanstalk application version (minimal setup, you may provide source_bundle in real use)
resource "aws_elastic_beanstalk_application_version" "default" {
  name        = "app-v1"
  application = aws_elastic_beanstalk_application.my_api_app.name
  description = "First version of my_api_app"

  # Placeholder: you would point to a source bundle (S3 bucket and key) in practice
  # bucket = aws_s3_bucket.app_bucket.bucket
  # key    = "app-v1.zip"
}

# Create Elastic Beanstalk environment with autoscaling based on CPU utilization
resource "aws_elastic_beanstalk_environment" "my_api_app_env" {
  name                = "my-api-app-env"
  application         = aws_elastic_beanstalk_application.my_api_app.name
  solution_stack_name = "64bit Amazon Linux 2 v3.4.12 running Python 3.9" # Example stack, adjust as needed

  # Environment variables if needed
  setting {
    namespace = "aws:ec2:instances"
    name      = "InstanceType"
    value     = "t3.small"
  }

  # Associate the instance profile
  setting {
    namespace = "aws:ec2:instances"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }

  # Auto scaling configuration using CPU thresholds
  setting {
    namespace = "aws:autoscaling:asg"
    name      = "MinSize"
    value     = "2"
  }

  setting {
    namespace = "aws:autoscaling:asg"
    name      = "MaxSize"
    value     = "6"
  }

  setting {
    namespace = "aws:autoscaling:trigger"
    name      = "MeasureName"
    value     = "CPUUtilization"
  }

  setting {
    namespace = "aws:autoscaling:trigger"
    name      = "LowerThreshold"
    value     = "30"
  }

  setting {
    namespace = "aws:autoscaling:trigger"
    name      = "UpperThreshold"
    value     = "80"
  }

  setting {
    namespace = "aws:autoscaling:trigger"
    name      = "BreachDuration"
    value     = "5"
  }

  setting {
    namespace = "aws:autoscaling:trigger"
    name      = "LowerBreachScaleIncrement"
    value     = "-1"
  }

  setting {
    namespace = "aws:autoscaling:trigger"
    name      = "UpperBreachScaleIncrement"
    value     = "1"
  }

  setting {
    namespace = "aws:autoscaling:trigger"
    name      = "Period"
    value     = "300"
  }

  # Optional: deploy a specific application version
  version_label = aws_elastic_beanstalk_application_version.default.name
}

