  name = "eb_ec2_profile"
  role = aws_iam_role.eb_ec2_role.name
}

# Create IAM role for Elastic Beanstalk service
resource "aws_iam_role" "eb_service_role" {
  name = "eb-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "elasticbeanstalk.amazonaws.com"
        }
      }
    ]
  })
}

# IAM role policy for Elastic Beanstalk service
resource "aws_iam_role_policy_attachment" "eb-service-role-attachment" {
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSElasticBeanstalkEnhancedHealth"
  role       = aws_iam_role.eb_service_role.name
}

resource "aws_iam_role_policy_attachment" "eb-service-role-elasticbeanstalk-attachment" {
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkService"
  role       = aws_iam_role.eb_service_role.name
}

# EC2 instance policies for Elastic Beanstalk
resource "aws_iam_role_policy_attachment" "eb-ec2-role-s3-attachment" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3ReadOnlyAccess"
  role       = aws_iam_role.eb_ec2_role.name
}

resource "aws_iam_role_policy_attachment" "eb-ec2-role-sqs-attachment" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonSQSFullAccess"
  role       = aws_iam_role.eb_ec2_role.name
}

resource "aws_iam_role_policy_attachment" "eb-ec2-role-ssm-attachment" {
