resource "aws_elastic_beanstalk_application_version" "version" {
  name        = "version"
  application = aws_elastic_beanstalk_application.batch_job_app.name
  description = "First version of the batch processing application"

  bucket = aws_s3_bucket.application_bucket.bucket
  key    = aws_s3_object.application_zip.key

  depends_on = [aws_s3_object.application_zip]
}

# Create Elastic Beanstalk configuration template for worker environment
