# Step-by-step breakdown:
# 1. Create a Route 53 public hosted zone for the domain
# 2. Create an Elastic Beanstalk application
# 3. Create an S3 bucket to store application versions (must be unique)
# 4. Upload an application version object to the S3 bucket
# 5. Create an IAM role for EC2 instances in Elastic Beanstalk
# 6. Create an instance profile to associate with the IAM role
# 7. Create an Elastic Beanstalk environment pointing to the application
# 8. Create a Route 53 record to point to the Elastic Beanstalk environment

resource "aws_route53_zone" "main" {
  name = "example.com"
}

resource "aws_elastic_beanstalk_application" "myapp" {
  name        = "myapp"
  description = "Example Elastic Beanstalk Application"
}

resource "aws_s3_bucket" "bucket" {
  bucket = "examplebucket-${random_id.unique.hex}"
  acl    = "private"
}

resource "random_id" "unique" {
  byte_length = 8
}

resource "aws_s3_object" "examplebucket_object" {
  bucket = aws_s3_bucket.bucket.bucket
  key    = "examplebucket_object"
  source = "/path/to/source" # This should point to your actual application source bundle
  etag   = filemd5("/path/to/source")
}

resource "aws_iam_role" "eb_ec2_role" {
  name = "eb_ec2_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      },
    ]
  })
}

resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "eb_ec2_profile"
  role = aws_iam_role.eb_ec2_role.name
}

resource "aws_elastic_beanstalk_application_version" "version" {
  name        = "version"
  application = aws_elastic_beanstalk_application.myapp.name
  description = "Application version"

  bucket = aws_s3_bucket.bucket.bucket
  key    = aws_s3_object.examplebucket_object.key
}

resource "aws_elastic_beanstalk_environment" "eb_env" {
  name                = "eb-env"
  application         = aws_elastic_beanstalk_application.myapp.name
  solution_stack_name = "64bit Amazon Linux 2 v3.3.6 running Python 3.9" # Example stack - adjust as needed
  version_label       = aws_elastic_beanstalk_application_version.version.name

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }
}

resource "aws_route53_record" "eb_record" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "example.com"
  type    = "A"

  alias {
    name                   = aws_elastic_beanstalk_environment.eb_env.cname
    zone_id                = aws_elastic_beanstalk_environment.eb_env.cname
    evaluate_target_health = true
  }
}
