extracted_code:
# This Terraform configuration sets up two Elastic Beanstalk environments in different regions:
# - us_west: in us-west-2 (Oregon)
# - eu_central: in eu-central-1 (Frankfurt)
# It also configures Route 53 with latency-based routing (or optionally geolocation routing)
# to direct users to the nearest environment based on their location.

# Since Terraform cannot manage multiple regions in a single configuration by default,
# we use provider aliases to target multiple AWS regions.

provider "aws" {
  alias  = "us_west"
  region = "us-west-2"
}

provider "aws" {
  alias  = "eu_central"
  region = "eu-central-1"
}

provider "aws" {
  # Default provider for Route 53 (can be any region, as Route 53 is global)
  region = "us-east-1"
}

# S3 bucket to store Elastic Beanstalk application versions
resource "aws_s3_bucket" "eb_app_bucket" {
  bucket = "eb-application-version-bucket-${random_id.suffix.hex}"
  acl    = "private"

  versioning {
    enabled = true
  }

  lifecycle {
    prevent_destroy = true
  }
}

# Random suffix to ensure unique bucket name
resource "random_id" "suffix" {
  byte_length = 4
}

# Create Elastic Beanstalk application
resource "aws_elastic_beanstalk_application" "eb_app" {
  name        = "geo-distributed-app"
  description = "Elastic Beanstalk app deployed in us-west-2 and eu-central-1"
}

# Application version for Elastic Beanstalk (dummy source bundle required)
resource "aws_s3_object" "eb_app_version" {
  bucket = aws_s3_bucket.eb_app_bucket.id
  key    = "app-v1.zip"
  source = "app.zip" # You must provide this file locally or generate one
  etag   = filemd5("app.zip")
}

resource "aws_elastic_beanstalk_application_version" "us_west_app_version" {
  provider = aws.us_west

  name        = "app-version-us-west"
  application = aws_elastic_beanstalk_application.eb_app.name
  bucket      = aws_s3_bucket.eb_app_bucket.id
  key         = aws_s3_object.eb_app_version.key
}

resource "aws_elastic_beanstalk_application_version" "eu_central_app_version" {
  provider = aws.eu_central

  name        = "app-version-eu-central"
  application = aws_elastic_beanstalk_application.eb_app.name
  bucket      = aws_s3_bucket.eb_app_bucket.id
  key         = aws_s3_object.eb_app_version.key
}

# Elastic Beanstalk environment in us-west-2
resource "aws_elastic_beanstalk_environment" "us_west" {
  provider = aws.us_west

  name                = "us-west-environment"
  application         = aws_elastic_beanstalk_application.eb_app.name
  solution_stack_name = "64bit Amazon Linux 2 v5.9.2 running Python 3.9" # Example stack
  version_label       = aws_elastic_beanstalk_application_version.us_west_app_version.name

  setting {
    namespace = "aws:ec2:instances"
    name      = "InstanceType"
    value     = "t3.small"
  }
}

# Elastic Beanstalk environment in eu-central-1
resource "aws_elastic_beanstalk_environment" "eu_central" {
  provider = aws.eu_central

  name                = "eu-central-environment"
  application         = aws_elastic_beanstalk_application.eb_app.name
  solution_stack_name = "64bit Amazon Linux 2 v5.9.2 running Python 3.9" # Same stack
  version_label       = aws_elastic_beanstalk_application_version.eu_central_app_version.name

  setting {
    namespace = "aws:ec2:instances"
    name      = "InstanceType"
    value     = "t3.small"
  }
}

# Route 53 Hosted Zone
resource "aws_route53_zone" "main" {
  name = "example.com" # Replace with your domain
}

# Route 53 record for latency-based (or geolocation) routing
# Using geolocation routing for regions

resource "aws_route53_record" "eb_us_west" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "app.example.com"
  type    = "CNAME"
  ttl     = 300
  records = [aws_elastic_beanstalk_environment.us_west.cname]

  # Geolocation routing: route North America to us-west
  geolocation_routing_policy {
    continent = "NA"
  }

  # Set a unique identifier for this resource
  set_identifier = "us-west-environment"
}

resource "aws_route53_record" "eb_eu_central" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "app.example.com"
  type    = "CNAME"
  ttl     = 300
  records = [aws_elastic_beanstalk_environment.eu_central.cname]

  # Geolocation routing: route Europe to eu-central
  geolocation_routing_policy {
    continent = "EU"
  }

  # Set a unique identifier for this resource
  set_identifier = "eu-central-environment"
}

# Optional default record if no geolocation match
resource "aws_route53_record" "eb_default" {
  count = 1

  zone_id = aws_route53_zone.main.zone_id
  name    = "app.example.com"
  type    = "CNAME"
  ttl     = 300
  records = [aws_elastic_beanstalk_environment.us_west.cname]

  routing_policy {
    _weighted {
      set_identifier = "default"
      weight         = 1
    }
  }

  set_identifier = "default-environment"
}

# Outputs
output "us_west_environment_cname" {
  value = aws_elastic_beanstalk_environment.us_west.cname
}

output "eu_central_environment_cname" {
  value = aws_elastic_beanstalk_environment.eu_central.cname
}

output "route53_zone_name_servers" {
  value = aws_route53_zone.main.name_servers
}

output "application_url" {
  value = "app.example.com"
  description = "Visit this URL to access the application via geolocation-based routing"
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"

      configuration_aliases = [ aws.default, aws.west, aws.europe ]
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1" # Default region
  alias  = "default"

  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

provider "aws" {
  region = "us-west-1"
  alias  = "west"

  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

provider "aws" {
  region = "eu-central-1"
  alias  = "europe"

  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_iam_role" "eb_ec2_role" {
  provider = aws.default
  name = "elastic_beanstalk_ec2_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Effect = "Allow",
        Principal = {
          Service = "ec2.amazonaws.com"
        },
      },
    ]
  })
}

# Attach the AWS managed policy for Elastic Beanstalk to the role
resource "aws_iam_role_policy_attachment" "eb_managed_policy" {
  provider = aws.default
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

# Create an instance profile tied to the role
resource "aws_iam_instance_profile" "eb_ec2_profile" {
  provider = aws.default
  name = "elastic_beanstalk_ec2_profile"
  role = aws_iam_role.eb_ec2_role.name
}

resource "aws_s3_bucket" "us_west_sample_bucket" {
  provider = aws.west
  bucket_prefix = "sample-"
}

resource "aws_s3_object" "us_west_examplebucket_object" {
  provider = aws.west
  key    = "app"
  bucket = aws_s3_bucket.us_west_sample_bucket.id
  source = "./supplement/app.zip"
}

# Elastic Beanstalk application
resource "aws_elastic_beanstalk_application" "us_west" {
  provider = aws.west
  name        = "my-global-app"
  description = "A global application deployed in US-West."
}

resource "aws_elastic_beanstalk_application_version" "us_west_version" {
  provider = aws.west
  name        = "v1"
  application = aws_elastic_beanstalk_application.us_west.name
  bucket = aws_s3_object.us_west_examplebucket_object.bucket
  key    = aws_s3_object.us_west_examplebucket_object.key
}

# US-West Elastic Beanstalk Environment
resource "aws_elastic_beanstalk_environment" "us_west" {
  provider            = aws.west
  name                = "my-global-app-us-west"
  application         = aws_elastic_beanstalk_application.us_west.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.3.0 running Python 3.9"

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }
}

resource "aws_s3_bucket" "eu_sample_bucket" {
  provider = aws.europe
  bucket_prefix = "sample-"
}

resource "aws_s3_object" "eu_examplebucket_object" {
  provider = aws.europe
  key    = "app"
  bucket = aws_s3_bucket.eu_sample_bucket.id
  source = "./supplement/app.zip"
}

# Elastic Beanstalk Application (EU-Central Region)
resource "aws_elastic_beanstalk_application" "eu_central" {
  provider = aws.europe
  name        = "my-global-app"
  description = "A global application deployed in EU-Central."
}

resource "aws_elastic_beanstalk_application_version" "europe_version" {
  provider = aws.europe
  name        = "v1"
  application = aws_elastic_beanstalk_application.eu_central.name
  bucket = aws_s3_object.eu_examplebucket_object.bucket
  key    = aws_s3_object.eu_examplebucket_object.key
}

# EU-Central Elastic Beanstalk Environment
resource "aws_elastic_beanstalk_environment" "eu_central" {
  provider            = aws.europe
  name                = "my-global-app-eu-central"
  application         = aws_elastic_beanstalk_application.eu_central.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.3.0 running Python 3.9"

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }
}

# Route53 Hosted Zone for the domain
resource "aws_route53_zone" "main" {
  provider = aws.default
  name     = "myglobalapp.com"
}

# Geolocation Routing Policy Records for Route 53 to direct traffic based on location
resource "aws_route53_record" "us_west" {
  provider    = aws.default
  zone_id     = aws_route53_zone.main.zone_id
  name        = "west.myglobalapp.com"
  type        = "CNAME"
  ttl         = "60"
  set_identifier = "us-west"
  geolocation_routing_policy {
    continent = "NA"
  }
  records = [
    aws_elastic_beanstalk_environment.us_west.name
  ]
}

resource "aws_route53_record" "eu_central" {
  provider    = aws.default
  zone_id     = aws_route53_zone.main.zone_id
  name        = "central.myglobalapp.com"
  type        = "CNAME"
  ttl         = "60"
  set_identifier = "eu-central"
  geolocation_routing_policy {
    continent = "EU"
  }
  records = [
    aws_elastic_beanstalk_environment.eu_central.name
  ]
}

