# Step 3: Create an IAM instance profile for EC2 instances in Elastic Beanstalk
# First, define the role that EC2 instances will assume
resource "aws_iam_role" "eb_ec2_role" {
  name = "eb-ec2-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
