extracted_code:
# Configure Blue/Green deployment with Elastic Beanstalk and RDS database snapshot
# Step-by-step:
# 1. Create an RDS instance named "my_db"
# 2. Create an instance profile named "ec2_eb_profile1" for EC2 instances in Elastic Beanstalk
# 3. Set up two Elastic Beanstalk environments (blue and green) for swapping
# 4. Use null_resource with local-exec to snapshot the RDS instance before deployment

provider "aws" {
  region = "us-east-1"
}

# Create RDS instance with name "my_db"
resource "aws_db_instance" "my_db" {
  identifier           = "my-db-instance"
  engine               = "mysql"
  engine_version       = "8.0"
  instance_class       = "db.t3.micro"
  name                 = "my_db" # Database name inside the RDS instance
  username             = "admin"
  password             = "securepassword123"
  allocated_storage    = 20
  skip_final_snapshot  = true
  apply_immediately    = true
  backup_retention_period = 7
  publicly_accessible   = false
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  db_subnet_group_name = aws_db_subnet_group.db_subnet_group.name
}

# DB subnet group for RDS
resource "aws_db_subnet_group" "db_subnet_group" {
  name       = "main-db-subnet-group"
  subnet_ids = aws_subnet.private_subnets[*].id
  tags = {
    Name = "Main DB Subnet Group"
  }
}

# Security group for RDS
resource "aws_security_group" "rds_sg" {
  name        = "rds-sg"
  description = "Allow incoming from EB instances"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# VPC for the infrastructure
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "main-vpc"
  }
}

# Subnets for the VPC
resource "aws_subnet" "private_subnets" {
  count                   = 2
  vpc_id                  = aws_vpc.main.id
  cidr_block              = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index + 1)
  availability_zone       = element(data.aws_availability_zones.available.names, count.index)
  map_public_ip_on_launch = false

  tags = {
    Name = "private-subnet-${count.index}"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

# Create IAM instance profile for EC2 instances in Elastic Beanstalk
# IAM Role
resource "aws_iam_role" "ec2_eb_role" {
  name = "ec2_eb_role1"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Instance Profile
resource "aws_iam_instance_profile" "ec2_eb_profile1" {
  name = "ec2_eb_profile1"
  role = aws_iam_role.ec2_eb_role.name
}

# IAM Role for Elastic Beanstalk service
resource "aws_iam_role" "eb_service_role" {
  name = "elastic-beanstalk-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "elasticbeanstalk.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Role Policy for EB service
resource "aws_iam_role_policy" "eb_service_policy" {
  name = "elastic-beanstalk-service"
  role = aws_iam_role.eb_service_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "ec2:Describe*",
          "ec2:RequestSpotInstances",
          "ecr:GetAuthorizationToken",
          "ecr:BatchCheckLayerAvailability",
          "ecr:GetDownloadUrlForLayer",
          "ecr:DescribeRepositories",
          "ecr:DescribeImages",
          "s3:Get*",
          "s3:List*",
          "sns:ListSubscriptionsByTopic",
          "sns:GetTopicAttributes",
          "cloudwatch:Describe*",
          "elasticloadbalancing:Describe*",
          "elasticloadbalancing:DescribeLoadBalancers",
          "autoscaling:Describe*",
          "logs:DescribeLogStreams",
          "logs:GetLogEvents"
        ]
        Resource = "*"
      }
    ]
  })
}

# Elastic Beanstalk application
resource "aws_elastic_beanstalk_application" "eb_app" {
  name        = "my-eb-app"
  description = "My Elastic Beanstalk Application"
}

# Blue environment
resource "aws_elastic_beanstalk_environment" "blue_env" {
  name                = "blue-env"
  application         = aws_elastic_beanstalk_application.eb_app.name
  solution_stack_name = "64bit Amazon Linux 2 v3.3.15 running Docker"

  # Environment variables
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_HOST"
    value     = aws_db_instance.my_db.address
  }
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_NAME"
    value     = aws_db_instance.my_db.name
  }

  # Use the instance profile
  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.ec2_eb_profile1.name
  }

  # Ensure only one environment is active at a time
  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "EnvironmentType"
    value     = "LoadBalanced"
  }
}

# Green environment
resource "aws_elastic_beanstalk_environment" "green_env" {
  name                = "green-env"
  application         = aws_elastic_beanstalk_application.eb_app.name
  solution_stack_name = "64bit Amazon Linux 2 v3.3.15 running Docker"

  # Environment variables
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_HOST"
    value     = aws_db_instance.my_db.address
  }
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_NAME"
    value     = aws_db_instance.my_db.name
  }

  # Use the instance profile
  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.ec2_eb_profile1.name
  }

  # Ensure only one environment is active at a time
  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "EnvironmentType"
    value     = "LoadBalanced"
  }
}

# Take snapshot of RDS before any deployment (simulate pre-deployment hook)
resource "null_resource" "rds_snapshot" {
  triggers = {
    # Change this value to trigger new snapshot
    deployment_timestamp = timestamp()
    db_identifier        = aws_db_instance.my_db.identifier
  }

  provisioner "local-exec" {
    command = <<EOT
      echo "Creating RDS snapshot for ${self.triggers.db_identifier}..."
      aws rds create-db-snapshot \n        --db-snapshot-identifier my-db-snapshot-${replace(timestamp(), ":", "-")}-$${RANDOM} \n        --db-instance-identifier ${self.triggers.db_identifier}
      echo "Snapshot initiated."
    EOT

    interpreter = ["bash", "-c"]
  }
}

# Output environment URLs
output "blue_environment_url" {
  value = "http://${aws_elastic_beanstalk_environment.blue_env.endpoint_url}"
}

output "green_environment_url" {
  value = "http://${aws_elastic_beanstalk_environment.green_env.endpoint_url}"
}

output "db_instance_endpoint" {
  value = aws_db_instance.my_db.address
}

