# We are configuring Route 53 to manage a domain and route traffic to an Elastic Beanstalk environment.
# Steps:
# 1. Create a Route 53 hosted zone for the domain.
# 2. Create an Elastic Beanstalk application and environment named "myenv".
# 3. Associate an EC2 instance profile "eb_ec2_profile1" with the environment.
# 4. Create an RDS database instance named "myapp_db" and associate it with the EB environment.
# 5. Set up a DNS record in Route 53 that points to the Elastic Beanstalk environment (via CNAME or alias).
#
# Note: Since Elastic Beanstalk environments have a dedicated domain (e.g., myenv.region.elasticbeanstalk.com),
# we create a Route 53 record pointing to it (preferably an alias record for better performance and no extra cost).
#
# Assumptions:
# - The domain name is provided (e.g., example.com). We'll use a variable for flexibility.
# - The Elastic Beanstalk environment is in the same region.
# - We are using AWS provider.

provider "aws" {
  region = "us-east-1"
}

# Variable for domain name
variable "domain_name" {
  description = "The domain name to manage in Route 53"
  type        = string
  default     = "example.com"
}

# Route 53 Hosted Zone
resource "aws_route53_zone" "primary" {
  name = var.domain_name
}

# IAM instance profile for EB EC2 instances
# Note: aws_iam_instance_profile cannot be created directly without referencing an existing role.
# We need to create a role first for EC2 access.

resource "aws_iam_role" "eb_ec2_role" {
  name = "eb_ec2_role1"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "eb_ec2_role_policy" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "eb_ec2_profile1"
  role = aws_iam_role.eb_ec2_role.name
}

# Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "eb_app" {
  name        = "myapp"
  description = "My Elastic Beanstalk Application"
}

# RDS Database Instance (to be associated with EB)
resource "aws_db_instance" "myapp_db" {
  identifier           = "myapp-db"
  instance_class       = "db.t3.micro"
  engine               = "mysql"
  allocated_storage    = 20
  engine_version       = "8.0"
  name                 = "myapp_db"
  username             = "admin"
  password             = "securepassword123"
  skip_final_snapshot  = true
  publicly_accessible  = false
  db_subnet_group_name = aws_db_subnet_group.eb_subnet_group.name
}

# DB Subnet group (required for RDS in VPC)
resource "aws_vpc" "eb_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "eb-vpc"
  }
}

resource "aws_subnet" "eb_subnet" {
  count                   = 2
  vpc_id                  = aws_vpc.eb_vpc.id
  cidr_block              = cidrsubnet(aws_vpc.eb_vpc.cidr_block, 8, count.index)
  availability_zone       = element(data.aws_availability_zones.available.names, count.index)
  map_public_ip_on_launch = true

  tags = {
    Name = "eb-subnet-${count.index}"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_db_subnet_group" "eb_subnet_group" {
  name       = "eb-db-subnet-group"
  subnet_ids = aws_subnet.eb_subnet[*].id

  tags = {
    Name = "eb-db-subnet-group"
  }
}

# Elastic Beanstalk Environment
resource "aws_elastic_beanstalk_environment" "myenv" {
  name                = "myenv"
  application         = aws_elastic_beanstalk_application.eb_app.name
  solution_stack_name = "64bit Amazon Linux 2 v5.6.4 running Python 3.9" # Example stack

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }

  # Link to RDS via environment variables
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_HOST"
    value     = aws_db_instance.myapp_db.endpoint
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_NAME"
    value     = aws_db_instance.myapp_db.name
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_USER"
    value     = aws_db_instance.myapp_db.username
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_PASSWORD"
    value     = aws_db_instance.myapp_db.password
  }

  # Other settings as needed
}

# Route 53 record pointing to EB environment
resource "aws_route53_record" "www" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "www.${var.domain_name}"
  type    = "A"

  alias {
    name                   = aws_elastic_beanstalk_environment.myenv.cname
    zone_id                = aws_elastic_beanstalk_environment.myenv.cname_zone_id
    evaluate_target_health = true
  }
}

# Optionally, add a root domain A record (if applicable)
resource "aws_route53_record" "root" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = var.domain_name
  type    = "A"

  alias {
    name                   = aws_elastic_beanstalk_environment.myenv.cname
    zone_id                = aws_elastic_beanstalk_environment.myenv.cname_zone_id
    evaluate_target_health = true
  }
}

