extracted_code:
# Multi-region Terraform configuration for Elastic Beanstalk with RDS and Route 53
# We'll define provider configurations for both regions, then create corresponding resources
# in each region, including Elastic Beanstalk applications/environments, RDS databases,
# IAM instance profile, and Route 53 routing to manage traffic between regions.

# Required providers
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Providers for two regions
provider "aws" {
  alias  = "us-east-1"
  region = "us-east-1"
}

provider "aws" {
  alias  = "eu-west-1"
  region = "eu-west-1"
}

# Route 53 provider (can use any region, as Route 53 is global)
provider "aws" {
  alias  = "route53"
  region = "us-east-1"
}

# IAM instance profile for Elastic Beanstalk EC2 instances
resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "eb_ec2_profile3"
  role = aws_iam_role.eb_ec2_role.name
}

resource "aws_iam_role" "eb_ec2_role" {
  name = "eb_ec2_role3"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "eb_ec2_policy" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

# Route 53: Create a hosted zone and configure multi-region routing
resource "aws_route53_zone" "main" {
  name = "example.com" # This should be replaced with your actual domain
}

# Multi-region setup using for_each to reduce duplication
locals {
  regions = {
    "us-east-1" = {
      provider    = "aws.us-east-1"
      env_name    = "myenv_us_east"
      app_name    = "myapp_us_east"
      db_name     = "main_db_us_east"
      weight      = 100
      region_name = "us-east-1"
    },
    "eu-west-1" = {
      provider    = "aws.eu-west-1"
      env_name    = "myenv_eu_west"
      app_name    = "myapp_eu_west"
      db_name     = "main_db_eu_west"
      weight      = 100
      region_name = "eu-west-1"
    }
  }
}

# Regional resources using for_each
resource "aws_elastic_beanstalk_application" "eb_app" {
  for_each = local.regions

  provider = each.value.provider

  name        = each.value.app_name
  description = "Multi-region application in ${each.key}"
}

resource "aws_elastic_beanstalk_environment" "eb_env" {
  for_each = local.regions

  provider = each.value.provider

  name                = each.value.env_name
  application         = aws_elastic_beanstalk_application.eb_app[each.key].name
  solution_stack_name = "64bit Amazon Linux 2 v3.3.15 running Python 3.9"

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }

  # Pass environment variables to connect to RDS
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_HOST"
    value     = aws_db_instance.rds_instance[each.key].address
  }
}

resource "aws_db_instance" "rds_instance" {
  for_each = local.regions

  provider = each.value.provider

  identifier           = each.value.db_name
  engine               = "mysql"
  instance_class       = "db.t3.micro"
  allocated_storage    = 20
  storage_type         = "gp2"
  engine_version       = "8.0"
  name                 = "maindb"
  username             = "admin"
  password             = "password12345"
  backup_retention_period = 7
  multi_az             = false
  skip_final_snapshot  = true
  publicly_accessible  = false

  tags = {
    Name = each.value.db_name
  }
}

# Route 53 weighted routing to balance traffic between regions
resource "aws_route53_record" "app_weighted_us" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "app.example.com"
  type    = "CNAME"
  ttl     = "60"

  weighted_routing_policy {
    weight = 100
  }

  set_identifier = "us-east-1"

  # Get CNAME from Elastic Beanstalk environment in us-east-1
  records = [aws_elastic_beanstalk_environment.eb_env["us-east-1"].cname]
}

resource "aws_route53_record" "app_weighted_eu" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "app.example.com"
  type    = "CNAME"
  ttl     = "60"

  weighted_routing_policy {
    weight = 100
  }

  set_identifier = "eu-west-1"

  # Get CNAME from Elastic Beanstalk environment in eu-west-1
  records = [aws_elastic_beanstalk_environment.eb_env["eu-west-1"].cname]
}

# Health checks for each region (optional but recommended for failover)
resource "aws_route53_health_check" "eb_us" {
  fqdn              = aws_elastic_beanstalk_environment.eb_env["us-east-1"].cname
  port              = 80
  type              = "HTTP"
  resource_path     = "/"
  failure_threshold = "3"
  request_interval  = "30"
}

resource "aws_route53_health_check" "eb_eu" {
  fqdn              = aws_elastic_beanstalk_environment.eb_env["eu-west-1"].cname
  port              = 80
  type              = "HTTP"
  resource_path     = "/"
  failure_threshold = "3"
  request_interval  = "30"
}

# Add health check to records if desired (commented out for simplicity)
# You can enable this by adding 'health_check_id' to aws_route53_record resources

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"

      configuration_aliases = [ aws.us_east_1, aws.eu_west_1 ]
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  alias  = "us_east_1"
  region = "us-east-1"

  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

provider "aws" {
  alias  = "eu_west_1"
  region = "eu-west-1"

  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}


resource "aws_iam_role" "eb_ec2_role" {
  provider = aws.us_east_1
  name = "elastic_beanstalk_ec2_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Effect = "Allow",
        Principal = {
          Service = "ec2.amazonaws.com"
        },
      },
    ]
  })
}

# Attach the AWS managed policy for Elastic Beanstalk to the role
resource "aws_iam_role_policy_attachment" "eb_managed_policy" {
  provider = aws.us_east_1
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}


# Create an instance profile tied to the role
resource "aws_iam_instance_profile" "eb_ec2_profile" {
  provider = aws.us_east_1
  name = "elastic_beanstalk_ec2_profile"
  role = aws_iam_role.eb_ec2_role.name
}

# RDS in US East (N. Virginia)
resource "aws_db_instance" "main_db_us_east" {
  provider             = aws.us_east_1
  allocated_storage    = 20
  storage_type         = "gp2"
  engine               = "mysql"
  engine_version       = "5.7"
  instance_class       = "db.t3.micro"
  username             = "dbadmin"
  password             = "mysecurepassword"
  parameter_group_name = "default.mysql5.7"
  skip_final_snapshot  = true
  multi_az             = true
}

# Elastic Beanstalk Application in US East
resource "aws_elastic_beanstalk_application" "myapp_us_east" {
  provider = aws.us_east_1
  name     = "my-application-us-east"
}

# Elastic Beanstalk Environment in US East
resource "aws_elastic_beanstalk_environment" "myenv_us_east" {
  provider            = aws.us_east_1
  name                = "my-application-env-us-east"
  application         = aws_elastic_beanstalk_application.myapp_us_east.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.3.0 running Python 3.9"

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_HOST"
    value     = aws_db_instance.main_db_us_east.address
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_USERNAME"
    value     = aws_db_instance.main_db_us_east.address
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_PASSWORD"
    value     = aws_db_instance.main_db_us_east.address
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }
}

# RDS in EU West (Ireland)
resource "aws_db_instance" "main_db_eu_west" {
  provider             = aws.eu_west_1
  allocated_storage    = 20
  storage_type         = "gp2"
  engine               = "mysql"
  engine_version       = "5.7"
  instance_class       = "db.t3.micro"
  multi_az             = true
  username             = "dbadmin"
  password             = "mysecurepassword"
  parameter_group_name = "default.mysql5.7"
  skip_final_snapshot  = true
}

# Elastic Beanstalk Application in EU West
resource "aws_elastic_beanstalk_application" "myapp_eu_west" {
  provider = aws.eu_west_1
  name     = "my-application-eu-west"
}

# Elastic Beanstalk Environment in EU West
resource "aws_elastic_beanstalk_environment" "myenv_eu_west" {
  provider            = aws.eu_west_1
  name                = "my-application-env-eu-west"
  application         = aws_elastic_beanstalk_application.myapp_eu_west.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.3.0 running Python 3.9"

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_HOST"
    value     = aws_db_instance.main_db_eu_west.address
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_USERNAME"
    value     = aws_db_instance.main_db_eu_west.address
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_PASSWORD"
    value     = aws_db_instance.main_db_eu_west.address
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }
}

# Main Route 53 Hosted Zone
resource "aws_route53_zone" "main" {
  provider = aws.us_east_1
  name = "myapp.com"
}

# Latency Based Routing in Route 53 for US East Elastic Beanstalk Environment
resource "aws_route53_record" "eb_env_us_east" {
  provider = aws.us_east_1
  zone_id = aws_route53_zone.main.zone_id
  name    = "us-east.myapp.com"
  type    = "CNAME"
  ttl     = "60"
  records = [aws_elastic_beanstalk_environment.myenv_us_east.cname]
  set_identifier = "EastEnv"
  latency_routing_policy {
    region = "us-east-1"
  }
}

resource "aws_route53_record" "eb_env_eu_west" {
  provider = aws.eu_west_1
  zone_id = aws_route53_zone.main.zone_id
  name    = "eu-west.myapp.com"
  type    = "CNAME"
  ttl     = "60"
  records = [aws_elastic_beanstalk_environment.myenv_eu_west.cname]
  set_identifier = "WestEnv"
  latency_routing_policy {
    region = "eu-west-1"
  }
}

