  instance_type        = "t3.micro"
  subnet_id            = aws_subnet.private[1].id
  security_groups      = [aws_security_group.ec2_security_group.id]
  iam_instance_profile = aws_iam_instance_profile.eb_ec2_profile.name

  tags = {
