  }
}

# Elastic Load Balancer for Blue environment
resource "aws_lb" "blue" {
  name               = "blue-lb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.ec2_security_group.id]
  subnets            = aws_subnet.public[*].id
}

