  }
}

resource "aws_lb_listener" "green" {
  load_balancer_arn = aws_lb.green.arn
  port              = 80
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.green.arn
  }
}

# Route 53 Health Checks for Blue and Green
resource "aws_route53_health_check" "blue" {
  fqdn              = aws_lb.blue.dns_name
  port              = 80
  type              = "HTTP"
  resource_path     = "/"
  failure_threshold = "3"
  request_interval  = "30"

  tags = {
    Environment = "blue"
  }
}

resource "aws_route53_health_check" "green" {
  fqdn              = aws_lb.green.dns_name
  port              = 80
  type              = "HTTP"
  resource_path     = "/"
  failure_threshold = "3"
  request_interval  = "30"

  tags = {
    Environment = "green"
  }
}

# Route 53 Failover Routing for Blue/Green
resource "aws_route53_record" "app_failover" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "app.example.com" # Replace with actual domain name
  type    = "A"

  alias {
    name                   = aws_lb.blue.dns_name
    zone_id                = aws_lb.blue.zone_id
    evaluate_target_health = true
  }

  # Primary (Blue) record
  weighted_routing_policy {
    weight = 100
  }

  set_identifier = "blue"
  health_check_id = aws_route53_health_check.blue.id
}

resource "aws_route53_record" "app_failover_standby" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "app.example.com"
  type    = "A"

  alias {
    name                   = aws_lb.green.dns_name
    zone_id                = aws_lb.green.zone_id
    evaluate_target_health = true
  }

  # Secondary (Green) record - standby
  weighted_routing_policy {
    weight = 0
  }

  set_identifier = "green"
  health_check_id = aws_route53_health_check.green.id
  failover_routing_policy {
    type = "SECONDARY"
  }
}

# Data sources
data "aws_availability_zones" "available" {
  state = "available"
}

data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-2.0.????????-x86_64-gp2"]
  }

  filter {
    name   = "architecture"
    values = ["x86_64"]
  }

  filter {
    name   = "root-device-type"
    values = ["ebs"]
  }
}

