# This Terraform configuration provisions infrastructure to deploy and scale a web application
# using AWS Elastic Beanstalk, which supports multiple programming languages including
# Python, Node.js, Java, Ruby, PHP, Go, and .NET.

resource "aws_elastic_beanstalk_application" "web_app" {
  name        = "web-application"
  description = "Elastic Beanstalk application to deploy and scale a web application"
}

resource "aws_elastic_beanstalk_environment" "web_app_env" {
  name                = "web-application-environment"
  application         = aws_elastic_beanstalk_application.web_app.name
  solution_stack_name = "64bit Amazon Linux 2 v5.6.10 running Docker" # Example for containerized apps

  setting {
    namespace = "aws:autoscaling:asg"
    name      = "MinSize"
    value     = "2"
  }

  setting {
    namespace = "aws:autoscaling:asg"
    name      = "MaxSize"
    value     = "6"
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "EnvironmentType"
    value     = "LoadBalanced"
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "InstanceType"
    value     = "t3.medium"
  }

  # Enable detailed CloudWatch monitoring
  setting {
    namespace = "aws:elasticbeanstalk:cloudwatch:logs"
    name      = "StreamLogs"
    value     = "true"
  }

  setting {
    namespace = "aws:elasticbeanstalk:cloudwatch:logs"
    name      = "DeleteOnTerminate"
    value     = "false"
  }
}

# Provision an S3 bucket to store application versions
resource "aws_s3_bucket" "version_bucket" {
  bucket_prefix = "webapp-version-bucket-"
}

resource "aws_s3_bucket_versioning" "versioning" {
  bucket = aws_s3_bucket.version_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

# Output the URL of the deployed application
output "application_url" {
  value = "https://${aws_elastic_beanstalk_environment.web_app_env.cname}"
}

output "application_name" {
  value = aws_elastic_beanstalk_application.web_app.name
}

