# Create an Elastic Beanstalk application with application version lifecycle configuration
# Step-by-step:
# 1. Define the Elastic Beanstalk application
# 2. Configure the application version lifecycle settings
#   - Set maximum count of application versions to keep
#   - Set deletion behavior when max count is reached
#   - Enable version lifecycle management

resource "aws_elastic_beanstalk_application" "example" {
  name        = "tf-elastic-beanstalk-app"
  description = "Application with version lifecycle management"

  # Configure application version lifecycle
  appversion_lifecycle {
    service_role                  = aws_iam_role.beanstalk_service_role.arn
    max_count                     = 10
    delete_source_from_s3       = true
    max_age_in_days               = 90
    delete_source_from_s3_enabled = true
  }
}

# IAM role required for Elastic Beanstalk to manage application versions in S3
resource "aws_iam_role" "beanstalk_service_role" {
  name = "beanstalk-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "elasticbeanstalk.amazonaws.com"
        }
      }
    ]
  })
}

# Required permissions for the service role to manage application versions
resource "aws_iam_role_policy" "beanstalk_service_policy" {
  name = "beanstalk-service-policy"
  role = aws_iam_role.beanstalk_service_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:Get*",
          "s3:Delete*",
          "s3:List*",
          "s3:Put*"
        ]
        Resource = [
          "arn:aws:s3:::elasticbeanstalk-*",
          "arn:aws:s3:::elasticbeanstalk-*/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "s3:CreateBucket"
        ]
        Resource = [
          "arn:aws:s3:::elasticbeanstalk-*"
        ]
      }
    ]
  })
}

