# Create an AWS CodeBuild project with an example IAM role and GitHub source

resource "aws_iam_role" "codebuild_role" {
  name = "example-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "codebuild_policy" {
  name = "example-codebuild-policy"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Resource = "*"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
      },
      {
        Effect = "Allow"
        Resource = "*"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:GetBucketAcl",
          "s3:GetBucketLocation"
        ]
      }
    ]
  })
}

resource "aws_codebuild_project" "example" {
  name          = "example-codebuild-project"
  description   = "An example CodeBuild project with GitHub source"
  build_timeout = 60
  service_role  = aws_iam_role.codebuild_role.arn

  source {
    type      = "GITHUB"
    location  = "https://github.com/example-user/example-repo.git"
    git_clone_depth = 1

    git_submodules_config {
      fetch_submodules = false
    }
  }

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    type                = "LINUX_CONTAINER"
    image               = "aws/codebuild/amazonlinux2-x86_64-standard:5.0"
    compute_type        = "BUILD_GENERAL1_SMALL"
    privileged_mode     = false

    environment_variable {
      name  = "EXAMPLE_VAR"
      value = "example-value"
    }
  }

  cache {
    type = "NO_CACHE"
  }

  logs_config {
    cloudwatch_logs {
      group_name = "/aws/codebuild/${aws_codebuild_project.example.name}"
      stream_name = "main"
    }
    s3_logs {
      status = "DISABLED"
    }
  }
}

