extracted_code:
# Create an AWS CodeBuild project with required components

# IAM role for CodeBuild to assume
resource "aws_iam_role" "codebuild_role" {
  name = "codebuild-example-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy attachment for required CodeBuild permissions
resource "aws_iam_role_policy_attachment" "codebuild_service_role" {
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSCodeBuildServiceRole"
  role       = aws_iam_role.codebuild_role.name
}

# Optional: Add S3 permissions for cache (if using custom bucket)
resource "aws_iam_role_policy_attachment" "s3_read_write" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3ReadOnlyAccess"
  role       = aws_iam_role.codebuild_role.name
}

# Source configuration using GitHub
# Note: For GitHub, you need to connect via AWS CodeStar Connections for GitHub
resource "aws_codebuild_project" "example" {
  name          = "example-codebuild-project"
  description   = "An example CodeBuild project with GitHub source and cache"
  service_role  = aws_iam_role.codebuild_role.arn

  # Source using GitHub via CodeStar Connections
  # You need to create a connection in AWS CodeStar first
  source {
    type      = "GITHUB"
    location  = "https://github.com/example-user/example-repo.git"
    git_clone_depth = 1

    # Report build status to GitHub
    git_submodules_config {
      fetch_submodules = false
    }
  }

  # Build environment configuration
  environment {
    type                = "LINUX_CONTAINER"
    image               = "aws/codebuild/standard:5.0"
    compute_type        = "BUILD_GENERAL1_SMALL"

    # Environment variables (non-sensitive)
    environment_variable {
      name  = "ENVIRONMENT"
      value = "production"
    }

    environment_variable {
      name  = "APP_NAME"
      value = "example-app"
    }

    # Sensitive environment variables (will be encrypted via KMS)
    environment_variable {
      name  = "API_KEY"
      value = "secret-key-value"
      type  = "PLAINTEXT" # Use "PARAMETER_STORE" or "SECRETS_MANAGER" for better security
    }
  }

  # Cache configuration using S3 bucket
  # You can either use local cache or S3
  cache {
    type = "S3"
    location = "codebuild-cache-${aws_iam_role.codebuild_role.id}/project-cache"
  }

  # Artifacts (optional)
  artifacts {
    type = "NO_ARTIFACTS"
  }

  # Build timeout (in minutes)
  timeout_in_mins = 60

  # Enable encryption using default KMS key
  encrypted = true

  # Tags
  tags = {
    Name        = "example-codebuild"
    Environment = "production"
  }
}

# Create S3 bucket for CodeBuild cache
resource "aws_s3_bucket" "codebuild_cache" {
  bucket = "codebuild-cache-${substr(aws_iam_role.codebuild_role.id, 0, 10)}"
  acl    = "private"

  versioning {
    enabled = false
  }

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }
}

# Allow CodeBuild role to access the cache bucket
resource "aws_s3_bucket_policy" "codebuild_cache_policy" {
  bucket = aws_s3_bucket.codebuild_cache.bucket

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          AWS = aws_iam_role.codebuild_role.arn
        }
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:DeleteObject",
          "s3:DeleteObjectVersion"
        ]
        Resource = "${aws_s3_bucket.codebuild_cache.arn}/*"
      }
    ]
  })

  depends_on = [aws_iam_role_policy_attachment.codebuild_service_role]
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}


resource "aws_iam_role" "example" {
  name = "example"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Sid    = ""
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      },
    ]
  })
}

resource "aws_codebuild_project" "example" {
  name          = "Row2CodeBuild"
  description   = "Row2CodeBuild"
  build_timeout = 5
  service_role  = aws_iam_role.example.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  cache {
    type  = "LOCAL"
    modes = ["LOCAL_DOCKER_LAYER_CACHE", "LOCAL_SOURCE_CACHE"]
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:7.0-24.10.29"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "SOME_KEY1"
      value = "SOME_VALUE1"
    }

    environment_variable {
      name  = "SOME_KEY2"
      value = "SOME_VALUE2"
      type  = "PARAMETER_STORE"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/mitchellh/packer.git"
    git_clone_depth = 1

    git_submodules_config {
      fetch_submodules = true
    }
  }

  source_version = "master"
}

