  policy_arn = "arn:aws:iam::aws:policy/AWSCodeBuildBasicAccess"
  role       = aws_iam_role.codebuild_role.name
}

resource "aws_iam_role_policy_attachment" "codebuild_cloudwatch_logs" {
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSCodeBuildCloudWatchLogsAccess"
  role       = aws_iam_role.codebuild_role.name
}

resource "aws_codebuild_project" "example" {
  name          = "example-codebuild-project"
  description   = "CodeBuild project without source"
  build_timeout = 60
  queued_timeout = 120

  # No source configuration
  source {
    type      = "NO_SOURCE"
    buildspec = <<EOF
version: 0.2
phases:
  build:
    commands:
      - echo 'Hello from CodeBuild'
EOF
  }

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    type                = "LINUX_CONTAINER"
