# Step 1: Define required AWS provider
provider "aws" {
  region = "us-east-1"
}

# Step 2: Create an IAM role for CodeBuild with necessary permissions
resource "aws_iam_role" "codebuild_role" {
  name = "example-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# Step 3: Attach a policy to the IAM role to allow CodeBuild to perform required actions
resource "aws_iam_role_policy" "codebuild_policy" {
  name = "example-codebuild-policy"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Resource = "*"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
      },
      {
        Effect = "Allow"
        Resource = "*"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:GetBucketLocation"
        ]
      }
    ]
  })
}

# Step 4: Define a GitHub source for the CodeBuild project
# Note: For GitHub, you need to create a webhook separately and store OAuth in AWS SSM or Secrets Manager
resource "aws_codebuild_project" "example" {
  name          = "example-codebuild-project"
  description   = "An example CodeBuild project with GitHub source"
  build_timeout = 60
  queue_timeout = 480

  # Source configuration using GitHub
  source {
    type      = "GITHUB"
    location  = "https://github.com/example-user/example-repo.git"
    git_clone_depth = 1

    # Version can be a branch, tag, or commit
    git_checkout_submodules = false

    # Authenticated access requires a GitHub token stored in AWS Secrets Manager
    auth {
      type = "OAUTH"
    }

    # BuildSpec file in the repo root
    buildspec = "buildspec.yml"
  }

  # Artifacts configuration - output artifacts to S3
  artifacts {
    type = "S3"
    location = aws_s3_bucket.artifact_bucket.bucket
    name = "output-artifact.zip"
    packaging = "ZIP"
  }

  # Cache configuration using S3
  cache {
    type = "S3"
    location = aws_s3_bucket.cache_bucket.bucket
  }

  # Environment configuration for the build
  environment {
    type                = "LINUX_CONTAINER"
    image               = "aws/codebuild/standard:5.0"
    compute_type        = "BUILD_GENERAL1_SMALL"
    privileged_mode     = false

    environment_variable {
      name  = "EXAMPLE_VAR"
      value = "example-value"
    }
  }

  # IAM role for the project
  service_role = aws_iam_role.codebuild_role.arn

  # Enable logs to CloudWatch
  logs_config {
    cloudwatch_logs {
      group_name = "/aws/codebuild/${aws_codebuild_project.example.name}"
      stream_name = "${aws_codebuild_project.example.name}"
    }
    s3_logs {
      enabled = false
    }
  }

  # Tags for the project
  tags = {
    Name = "example-codebuild"
    Environment = "dev"
  }
}

# Step 5: Create S3 buckets for artifacts and cache
resource "aws_s3_bucket" "artifact_bucket" {
  bucket = "example-codebuild-artifacts-${random_string.suffix.result}"
  acl    = "private"

  force_destroy = true
}

resource "aws_s3_bucket" "cache_bucket" {
  bucket = "example-codebuild-cache-${random_string.suffix.result}"
  acl    = "private"

  force_destroy = true
}

# Random suffix to ensure unique S3 bucket names
resource "random_string" "suffix" {
  length  = 8
  special = false
  upper   = false
}

