}

# Step 2: Create an IAM role for CodeBuild to assume
resource "aws_iam_role" "codebuild_role" {
  name = "codebuild-example-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# Step 3: Attach necessary IAM policies to the role
resource "aws_iam_role_policy_attachment" "codebuild_service_role" {
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSCodeBuildServiceRole"
  role       = aws_iam_role.codebuild_role.name
}

# Optional: Add S3 permissions if the project uses artifacts
resource "aws_iam_role_policy_attachment" "s3_read_only" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3ReadOnlyAccess"
  role       = aws_iam_role.codebuild_role.name
}

# Step 4: Create the CodeBuild project with primary and secondary sources
resource "aws_codebuild_project" "example" {
  name         = "example-codebuild-project"
  description  = "An example CodeBuild project with secondary sources"
  service_role = aws_iam_role.codebuild_role.arn

  # Artifacts (output)
  artifacts {
    type = "NO_ARTIFACTS"
  }

  # Primary source from CodeCommit
  source {
    type      = "CODECOMMIT"
    location  = "https://git-codecommit.us-east-1.amazonaws.com/v1/repos/MyDemoRepo"
    git_clone_depth = 1
  }

  # Secondary sources (up to 12 allowed)
  secondary_sources {
    type              = "GITHUB"
    location          = "https://github.com/example/my-second-repo.git"
    git_clone_depth   = 1
    source_identifier = "secondary-github-source"
  }

  secondary_sources {
    type              = "S3"
    location          = "my-example-bucket/build-sources.zip"
    source_identifier = "secondary-s3-source"
  }

  # Environment configuration
  environment {
    type                = "LINUX_CONTAINER"
    image               = "aws/codebuild/standard:5.0"
    compute_type        = "BUILD_GENERAL1_SMALL"
    privileged_mode     = false

    environment_variable {
      name  = "SOME_VARIABLE"
      value = "some-value"
    }
  }

  # Build timeout (in minutes)
  timeout_in_mins = 60

  # Tags
  tags = {
    Environment = "Dev"
    Project     = "Example"
  }
}

# Output the CodeBuild project ARN
output "codebuild_project_arn" {
  value = aws_codebuild_project.example.arn
}

# Output the IAM role ARN
output "codebuild_role_arn" {
  value = aws_iam_role.codebuild_role.arn
}

