resource "aws_codebuild_project" "example" {
  name          = "example-codebuild-project"
  description   = "An example CodeBuild project with secondary artifacts"
  build_timeout = 60
  queued_timeout = 480
  service_role  = aws_iam_role.codebuild_role.arn

  # Source configuration
  source {
    type      = "GITHUB"
    location  = "https://github.com/example-user/example-repo.git"
    git_clone_depth = 1

    git_submodules_config {
      fetch_submodules = false
    }
  }

  # Primary artifacts
  artifacts {
    type = "NO_ARTIFACTS"
  }

  # Secondary artifacts
  secondary_artifacts {
    artifact_identifier = "secondary artifact 1"
    type                = "S3"
    location            = "example-secondary-bucket"
    path                = "output"
    packaging           = "ZIP"
    name                = "secondary-output.zip"
