      name  = "ENVIRONMENT"
      value = "example"
    }

    environment_variable {
      name  = "ANOTHER_VAR"
      value = "example-value"
    }
  }

  # Cache configuration (optional)
  cache {
    type = "LOCAL"
    modes = [
      "LOCAL_DOCKER_LAYER_CACHE",
      "LOCAL_SOURCE_CACHE"
    ]
  }

  # Tags
  tags = {
    Name        = "ExampleCodeBuildProject"
    Environment = "example"
  }
}

