# This configuration creates:
# 1. An IAM role for CodeBuild with basic permissions
# 2. A CodeBuild project with batch configuration enabled

resource "aws_iam_role" "codebuild_role" {
  name = "codebuild-example-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "codebuild_policy" {
  name = "codebuild-example-policy"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Resource = "*"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
      },
      {
        Effect = "Allow"
        Resource = "*"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:GetBucketLocation"
        ]
      }
    ]
  })
}

resource "aws_codebuild_project" "example" {
  name          = "example-codebuild-project"
  description   = "Example CodeBuild project with batch configuration"
  build_timeout = 60
  queued_timeout = 480
  service_role  = aws_iam_role.codebuild_role.arn

  # Source configuration
  source {
    type      = "GITHUB"
    location  = "https://github.com/example/repo.git"
    git_clone_depth = 1

    git_submodules_config {
      fetch_submodules = false
    }
  }

  # Source version can be branch, tag, or commit
  source_version = "main"

  # Artifacts configuration
  artifacts {
    type = "NO_ARTIFACTS"
  }

  # Cache configuration (optional)
  cache {
    type = "LOCAL"
    modes = ["LOCAL_DOCKER_LAYER_CACHE", "LOCAL_SOURCE_CACHE"]
  }

  # Environment configuration
  environment {
    type                = "LINUX_CONTAINER"
    image               = "aws/codebuild/standard:5.0"
    image_pull_credentials_type = "CODEBUILD"
    compute_type        = "BUILD_GENERAL1_SMALL"

    environment_variable {
      name  = "ENVIRONMENT"
      value = "example"
    }

    environment_variable {
      name  = "BUILD_MODE"
      value = "batch"
      type  = "PLAINTEXT"
    }
  }

  # Batch configuration
  batch_service_role = aws_iam_role.codebuild_role.arn

  batch {
    # Maximum number of builds allowed in a batch
    resolve_conflicts = "OVERWRITE"

    # Batch build configuration
    batch_build {
      # Restrictions on batch builds
      timeout_in_mins    = 480
      max_parallel_builds = 10
    }
  }

  # VPC configuration (optional - commented out)
  # vpc_config {
  #   vpc_id            = "vpc-12345678"
  #   subnets           = ["subnet-12345678", "subnet-87654321"]
  #   security_group_ids = ["sg-12345678"]
  # }

  # Tags
  tags = {
    Name        = "example-codebuild"
    Environment = "example"
    Project     = "terraform"
  }

  # Enable logs to CloudWatch
  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/${aws_codebuild_project.example.name}"
      stream_name = "main"
      status      = "ENABLED"
    }

    s3_logs {
      status = "DISABLED"
    }
  }
}

