terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_lex_intent" "order_flowers" {
  name = "OrderFlowers"
  description = "Intent to order a bouquet of flowers for pick up"

  sample_utterances = [
    "I would like to pick up flowers",
    "I would like to order some flowers",
  ]

  slot {
    name                     = "FlowerType"
    description              = "Type of flower to order"
    slot_constraint          = "Required" 
    slot_type                = "AMAZON.AlphaNumeric"
    priority                 = 1

    sample_utterances = ["I would like to get {FlowerType} flower."]

    value_elicitation_prompt {
      message {
        content             = "What type of flower would you like?"
        content_type        = "PlainText"
      }
      max_attempts         = 2
    }
  }

  slot {
    name                     = "PickupDate"
    description              = "Date of flower pickup"
    slot_constraint          = "Required" 
    slot_type                = "AMAZON.DATE"
    priority                 = 2

    value_elicitation_prompt {
      message {
        content             = "When would you like to pickup your flower?"
        content_type        = "PlainText"
      }
      max_attempts         = 2
    }
  }

  confirmation_prompt {
    max_attempts = 2

    message {
      content      = "Okay, your {FlowerType} will be ready for pickup on {PickupDate}.  Does this sound okay?"
      content_type = "PlainText"
    }
  }

  fulfillment_activity {
    type = "ReturnIntent"
  }

  rejection_statement {
    message {
      content      = "Okay, I will not place your order."
      content_type = "PlainText"
    }
  }
}

resource "aws_lex_bot" "order_flowers" {
  name     = "OrderFlowers"
  description = "Bot to order flowers on the behalf of a user"
  locale   = "en-US"
  process_behavior = "BUILD"
  voice_id = "Salli"
  child_directed = false
  create_version = false
  detect_sentiment            = false
  idle_session_ttl_in_seconds = 600

  abort_statement {
    message {
      content_type = "PlainText"
      content      = "Sorry, I am not able to assist at this time"
    }
  }

  clarification_prompt {
    max_attempts = 2

    message {
      content_type = "PlainText"
      content      = "I didn't understand you, what would you like to do?"
    }
  }

  intent {
    intent_name    = aws_lex_intent.order_flowers.name
    intent_version = aws_lex_intent.order_flowers.version
  }
}

extracted_code:
# Creating an AWS Lex bot with multiple slots requires defining:
# 1. The bot intent with multiple slots
# 2. Individual slot types (if custom) or use built-in ones
# 3. The bot itself referencing the intent
# 4. Optional: Permissions and aliases

# Step 1: Define an intent with multiple slots
resource "aws_lex_intent" "order_flower_intent" {
  name = "OrderFlowers"

  # First slot: Flower type
  slot {
    name                     = "FlowerType"
    slot_type                = "AMAZON.Flower"  # Built-in slot type
    slot_type_version        = 1
    description              = "Type of flower to order"
    sample_utterances        = ["^I would like to order {FlowerType}", "^I want to buy {FlowerType}"]
    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What type of flowers would you like to order?"
        content_type = "PlainText"
      }
    }
  }

  # Second slot: Pickup date
  slot {
    name                     = "PickupDate"
    slot_type                = "AMAZON.DATE"
    slot_type_version        = 1
    description              = "Date to pick up the flowers"
    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "When would you like to pick up your flowers?"
        content_type = "PlainText"
      }
    }
  }

  # Third slot: Pickup time
  slot {
    name                     = "PickupTime"
    slot_type                = "AMAZON.TIME"
    slot_type_version        = 1
    description              = "Time to pick up the flowers"
    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What time would you like to pick up your flowers?"
        content_type = "PlainText"
      }
    }
  }

  # Confirmation prompt for the intent
  confirmation_prompt {
    max_attempts = 2
    message {
      content      = "Okay, I'll order {FlowerType} to be picked up on {PickupDate} at {PickupTime}. Should I proceed?"
      content_type = "PlainText"
    }
  }

  # Rejection statement
  rejection_statement {
    message {
      content      = "Okay, I canceled your flower order."
      content_type = "PlainText"
    }
  }

  # Sample utterances for the intent
  sample_utterances = [
    "I want to order flowers",
    "I would like to buy some flowers",
    "I want to purchase flowers"
  ]
}

# Step 2: Define the Lex bot that uses the intent
resource "aws_lex_bot" "flower_ordering_bot" {
  name                 = "FlowerOrderingBot"
  description          = "Bot to order flowers with multiple slots"
  abort_statement {
    message {
      content      = "Sorry, I couldn't understand. Your order has been cancelled."
      content_type = "PlainText"
    }
  }

  # Clear the default intents and add our custom intent
  intent {
    intent_name    = aws_lex_intent.order_flower_intent.name
    intent_version = "$$LATEST"
  }

  # Settings for idle session timeout and speech recognition
  idle_session_ttl_in_seconds = 600
  voice_id                    = "Joanna"
  process_behavior            = "BUILD"

  # Clarification prompt when input is not understood
  clarification_prompt {
    max_attempts = 2
    message {
      content      = "I didn't understand. Can you please repeat?"
      content_type = "PlainText"
    }
  }
}

# Optional: Create an alias for the bot
resource "aws_lex_bot_alias" "bot_alias" {
  name           = "Prod"
  description    = "Production alias for Flower Ordering Bot"
  bot_name       = aws_lex_bot.flower_ordering_bot.name
  bot_version    = "$$LATEST"

  # You can add sentiment analysis here if needed
}

