# Creating an AWS Lex Bot for ordering pizzas with a conclusion statement
# Step 1: Define the Lex Bot with required settings
# - Intents: We'll define at least one intent for ordering pizza
# - Conclusion statement: This is the message the bot delivers when the conversation is complete
# - Child-directed: Set to false since it's a pizza ordering bot
# - Process_behavior: Should respond immediately after fulfilling the intent

resource "aws_lex_bot" "pizza_order_bot" {
  name                = "PizzaOrderBot"
  description         = "Bot for ordering pizzas"
  abort_statement {
    message {
      content      = "Sorry, I couldn't process your order. Goodbye."
      content_type = "PlainText"
    }
  }

  clarification_prompt {
    max_attempts = 2
    message {
      content      = "I didn't understand. Can you please repeat your order?"
      content_type = "PlainText"
    }
  }

  intent {
    intent_name = aws_lex_intent.pizza_ordering_intent.name
    intent_version = "$$LATEST"
  }

  # Conclusion statement shown when the order is successfully completed
  conclusion_statement {
    message {
      content      = "Your pizza order has been placed successfully. It will arrive in 30 minutes!"
      content_type = "PlainText"
    }
  }

  # Idle session timeout in seconds
  idle_session_ttl_in_seconds = 600

  # Voice ID for voice-enabled interactions (optional)
  # voice_id = "Matthew"

  process_behavior = "BUILD"

  # Not child-directed
  child_directed = false

  # Locale
  locale = "en_US"

  # Create a checksum for detecting changes in dependent resources
  create_version = false
}

# Step 2: Define the intent for ordering pizza
resource "aws_lex_intent" "pizza_ordering_intent" {
  name = "OrderPizza"

  # Sample utterances for triggering the intent
  sample_utterances = [
    "I want to order a pizza",
    "Order a pizza",
    "Can I get a pizza",
    "I'd like to place a pizza order"
  ]

  # Conclusion statement for this intent
  conclusion_statement {
    message {
      content      = "Got it! I'm preparing your order."
      content_type = "PlainText"
    }
  }

  # Define slots for capturing pizza details
  slot {
    name = "PizzaSize"
    slot_constraint = "Required"
    priority = 1
    description = "Size of the pizza"
    slot_type_name = "AMAZON.US_SIZE"
    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What size pizza would you like?"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name = "PizzaType"
    slot_constraint = "Required"
    priority = 2
    description = "Type of pizza"
    slot_type_name = "PizzaTypeCustom"
    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What type of pizza would you like? For example, pepperoni or vegetarian."
        content_type = "PlainText"
      }
    }
  }

  # Fulfillment activity: returns a message directly
  fulfillment_activity {
    type = "ReturnIntent"
  }
}

# Step 3: Define a custom slot type for pizza types
resource "aws_lex_slot_type" "pizza_type_custom" {
  name = "PizzaTypeCustom"
  description = "Custom slot type for different pizza types"

  enumeration_value {
    value = "pepperoni"
  }
  enumeration_value {
    value = "vegetarian"
  }
  enumeration_value {
    value = "margherita"
  }
  enumeration_value {
    value = "hawaiian"
  }
  enumeration_value {
    value = "meat lovers"
  }

  create_version = false
}

