# AWS Lex Bot for Booking a Trip
# We need to create a Lex bot with intents, utterances, prompts, and other configurations
# to handle trip booking. This includes defining the bot's behavior, intents, slot types,
# and fulfillment.

resource "aws_lex_bot" "trip_booking_bot" {
  name                          = "TripBookingBot"
  description                   = "Bot for booking trips"
  role_arn                      = aws_iam_role.lex_role.arn
  idle_session_ttl_in_seconds   = 300
  process_behavior              = "BUILD"
  locale                        = "en-US"
  child_directed                = false
  enable_model_improvements     = true
  clarification_prompt {
    message {
      content          = "I didn't understand. Please rephrase or say help."
      content_type     = "PlainText"
      group_number     = 1
    }
    max_attempts = 2
  }

  abort_statement {
    message {
      content      = "Okay, I'm canceling your trip booking."
      content_type = "PlainText"
      group_number = 1
    }
  }

  intent {
    intent_name    = "BookTrip"
    intent_version = "$LATEST"
  }

  # Create the BookTrip intent separately
  depends_on = [aws_lex_intent.book_trip_intent]
}

# Define the IAM role for Lex to assume
resource "aws_iam_role" "lex_role" {
  name = "lex-trip-bot-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

# Add necessary permissions for Lex
resource "aws_iam_role_policy" "lex_policy" {
  name = "lex-trip-bot-policy"
  role = aws_iam_role.lex_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "cloudwatch:PutMetricData",
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents",
          "logs:DescribeLogGroups",
          "logs:DescribeLogStreams"
        ]
        Effect   = "Allow"
        Resource = "*"
      }
    ]
  })
}

# Define the BookTrip intent
resource "aws_lex_intent" "book_trip_intent" {
  name = "BookTrip"

  # Sample utterances for booking a trip
  sample_utterances = [
    "I want to book a trip",
    "Book a trip for me",
    "Plan a trip",
    "I need to travel",
    "Make a reservation for a trip"
  ]

  # Fulfillment configuration
  fulfillment_activity {
    type = "ReturnIntent"
  }

  # Create required slots for the trip booking
  slot {
    slot_name           = "Destination"
    description         = "The destination for the trip"
    slot_type           = "AMAZON.US_CITY"
    slot_type_version   = "$$LATEST"
    value_elicitation_prompt {
      message {
        content      = "Where would you like to go?"
        content_type = "PlainText"
        group_number = 1
      }
      max_attempts = 2
    }
    priority         = 1
    mandatory        = true
  }

  slot {
    slot_name           = "TravelDate"
    description         = "The date of travel"
    slot_type           = "AMAZON.DATE"
    slot_type_version   = "$$LATEST"
    value_elicitation_prompt {
      message {
        content      = "What date would you like to travel?"
        content_type = "PlainText"
        group_number = 1
      }
      max_attempts = 2
    }
    priority         = 2
    mandatory        = true
  }

  slot {
    slot_name           = "ReturnDate"
    description         = "The return date for the trip"
    slot_type           = "AMAZON.DATE"
    slot_type_version   = "$$LATEST"
    value_elicitation_prompt {
      message {
        content      = "What date would you like to return?"
