extracted_code:
# Creating an AWS Lex Bot for ordering pizzas with 5 different intents
# Step 1: Define the Lex Bot with basic configuration
# Step 2: Define 5 intents:
#   - OrderPizza: To place a new pizza order
#   - CancelOrder: To cancel an existing order
#   - CheckOrderStatus: To check the status of an order
#   - SelectToppings: To choose custom toppings
#   - AskMenu: To get information about menu options
# Step 3: Each intent will include sample utterances and confirmation prompts where needed
# Step 4: Use the aws_lex_bot and aws_lex_intent resources

resource "aws_lex_bot" "pizza_ordering_bot" {
  name                 = "PizzaOrderingBot"
  description          = "Bot for ordering pizzas with multiple intents"
  abort_statement      = {
    message = {
      content      = "Sorry, I couldn't understand. Goodbye."
      content_type = "PlainText"
    }
  }
  clarification_prompt = {
    max_attempts = 2
    message = {
      content      = "I didn't understand. Can you please repeat?"
      content_type = "PlainText"
    }
  }
  idle_session_ttl_in_seconds = 600
  voice_id                    = "Joanna"
  process_behavior            = "BUILD"

  # Intent references
  intent {
    intent_name    = aws_lex_intent.order_pizza.name
    intent_version = aws_lex_intent.order_pizza.version
  }
  intent {
    intent_name    = aws_lex_intent.cancel_order.name
    intent_version = aws_lex_intent.cancel_order.version
  }
  intent {
    intent_name    = aws_lex_intent.check_order_status.name
    intent_versions = aws_lex_intent.check_order_status.version
  }
  intent {
    intent_name    = aws_lex_intent.select_toppings.name
    intent_version = aws_lex_intent.select_toppings.version
  }
  intent {
    intent_name    = aws_lex_intent.ask_menu.name
    intent_version = aws_lex_intent.ask_menu.version
  }

  create_version = false
  locale         = "en-US"
}

# Intent 1: OrderPizza
resource "aws_lex_intent" "order_pizza" {
  name = "OrderPizza"

  slot {
    name                 = "PizzaSize"
    slot_type_name       = "AMAZON.Number"
    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What size pizza would you like? For example, 10, 12, or 14 inches."
        content_type = "PlainText"
      }
    }
    priority           = 1
    sample_utterances  = ["size {PizzaSize}", "I want a {PizzaSize} inch pizza"]
    slot_constraint    = "Required"
  }

  slot {
    name                 = "CrustType"
    slot_type_name       = "CrustType"
    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What type of crust? Choose from thin, thick, or stuffed."
        content_type = "PlainText"
      }
    }
    priority          = 2
    sample_utterances = ["crust {CrustType}", "with {CrustType} crust"]
    slot_constraint   = "Required"
  }

  confirmation_prompt {
    max_attempts = 2
    message {
      content      = "You want a {PizzaSize}-inch pizza with {CrustType} crust. Should I proceed with your order?"
      content_type = "PlainText"
    }
  }

  rejection_statement {
    message {
      content      = "Your order has been cancelled."
      content_type = "PlainText"
    }
  }

  sample_utterances = [
    "I want to order a pizza",
    "Can I order a pizza?",
    "Place a pizza order",
    "Order a pizza with {CrustType} crust"
  ]

  fulfillment_activity {
    type = "ReturnIntent"
  }
}

# Custom slot type for crust
resource "aws_lex_slot_type" "crust_type" {
  name        = "CrustType"
  description = "Type of pizza crust"

  enumeration_value {
    value = "thin"
  }
  enumeration_value {
    value = "thick"
  }
  enumeration_value {
    value = "stuffed"
  }

  create_version = true
}

# Intent 2: CancelOrder
resource "aws_lex_intent" "cancel_order" {
  name = "CancelOrder"

  slot {
    name               = "OrderId"
    slot_type_name     = "AMAZON.Number"
    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "Please provide your order ID."
        content_type = "PlainText"
      }
    }
    sample_utterances = ["order {OrderId}"]
    slot_constraint   = "Required"
  }

  sample_utterances = [
    "Cancel my order {OrderId}",
    "I want to cancel order {OrderId}",
    "Please cancel order {OrderId}"
  ]

  fulfillment_activity {
    type = "ReturnIntent"
  }

  confirmation_prompt {
    max_attempts = 2
    message {
      content      = "Are you sure you want to cancel order {OrderId}?"
      content_type = "PlainText"
    }
  }
}

# Intent 3: CheckOrderStatus
resource "aws_lex_intent" "check_order_status" {
  name = "CheckOrderStatus"

  slot {
    name               = "OrderId"
    slot_type_name     = "AMAZON.Number"
    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "Please provide your order ID to check status."
        content_type = "PlainText"
      }
    }
    sample_utterances = ["order {OrderId}"]
    slot_constraint   = "Required"
  }

  sample_utterances = [
    "What is the status of order {OrderId}",
    "Check status for order {OrderId}",
    "Where is my order {OrderId}"
  ]

  fulfillment_activity {
    type = "ReturnIntent"
  }
}

# Intent 4: SelectToppings
resource "aws_lex_intent" "select_toppings" {
  name = "SelectToppings"

  slot {
    name               = "Toppings"
    slot_type_name     = "Toppings"
    value_elicitation_prompt {
      max_attempts = 3
      message {
        content      = "Which toppings would you like? You can say pepperoni, mushrooms, olives, etc."
        content_type = "PlainText"
      }
    }
    sample_utterances = ["toppings {Toppings}"]
    slot_constraint   = "Required"
    priority          = 1
  }

  sample_utterances = [
    "Add {Toppings} to my pizza",
    "I want {Toppings} on my pizza",
    "Include {Toppings}"
  ]

  fulfillment_activity {
    type = "ReturnIntent"
  }
}

# Custom slot type for toppings
resource "aws_lex_slot_type" "toppings" {
  name        = "Toppings"
  description = "Pizza toppings"

  enumeration_value {
    value = "pepperoni"
  }
  enumeration_value {
    value = "mushrooms"
  }
  enumeration_value {
    value = "olives"
  }
  enumeration_value {
    value = "onions"
  }
  enumeration_value {
    value = "sausage"
  }
  enumeration_value {
    value = "bacon"
  }
  enumeration_value {
    value = "pineapple"
  }

  create_version = true
}

# Intent 5: AskMenu
resource "aws_lex_intent" "ask_menu" {
  name = "AskMenu"

  sample_utterances = [
    "What's on the menu?",
    "Show me the menu",
    "What pizzas do you have?",
    "Tell me about your pizza options"
  ]

  conclusion_statement {
    message {
      content      = "We offer Margherita, Pepperoni, Veggie, Hawaiian, and Supreme pizzas. Sizes from 10 to 16 inches. Crust options: thin, thick, stuffed."
      content_type = "PlainText"
    }
  }

  fulfillment_activity {
    type = "ReturnIntent"
  }
}

