    slot_constraint   = "Required"
    priority          = 1
  }

  sample_utterances = [
    "Add {Toppings} to my pizza",
    "I want {Toppings} on my pizza",
    "Include {Toppings}"
  ]

  fulfillment_activity {
    type = "ReturnIntent"
  }
}

# Custom slot type for toppings
resource "aws_lex_slot_type" "toppings" {
  name        = "Toppings"
  description = "Pizza toppings"

  enumeration_value {
    value = "pepperoni"
  }
  enumeration_value {
    value = "mushrooms"
  }
  enumeration_value {
    value = "olives"
  }
  enumeration_value {
    value = "onions"
  }
  enumeration_value {
    value = "sausage"
  }
  enumeration_value {
    value = "bacon"
  }
  enumeration_value {
    value = "pineapple"
  }

  create_version = true
}

# Intent 5: AskMenu
resource "aws_lex_intent" "ask_menu" {
  name = "AskMenu"

  sample_utterances = [
    "What's on the menu?",
    "Show me the menu",
    "What pizzas do you have?",
    "Tell me about your pizza options"
  ]

  conclusion_statement {
    message {
      content      = "We offer Margherita, Pepperoni, Veggie, Hawaiian, and Supreme pizzas. Sizes from 10 to 16 inches. Crust options: thin, thick, stuffed."
      content_type = "PlainText"
    }
  }

  fulfillment_activity {
    type = "ReturnIntent"
  }
}
