# Creating an AWS Lex Bot for ordering pizzas targeted towards kids
# Step 1: Define the bot with appropriate intents, such as ordering pizza, selecting toppings, and confirming order
# Step 2: Use a child-friendly voice and session timeout settings
# Step 3: Enable logging and set appropriate tags for resource management
# Step 4: Define the bot alias for production deployment with a description

resource "aws_lex_bot" "pizza_bot_for_kids" {
  name                = "PizzaPal"
  description         = "A fun and friendly pizza ordering bot designed for kids!"
  role_arn            = aws_iam_role.lex_bot_role.arn

  # Child-friendly voice
  voice_id            = "Joanna"  # Clear, friendly voice; can also use "Matthew" or other neutral voices

  # Child-oriented settings
  idle_session_ttl_in_seconds = 600  # 10 minutes for a child to respond
  clarification_prompt {
    message {
      content_type = "PlainText"
      content      = "I didn't catch that. Want to try again? Say something like 'I want a cheese pizza'!"
      group_number = 1
    }
    max_attempts = 2
  }

  # Intent to order pizza
  intent {
    intent_name    = "OrderPizza"
    intent_version = "$LATEST"
  }

  # Intent to handle help/quit
  intent {
    intent_name    = "AMAZON.HelpIntent"
    intent_version = "$LATEST"
  }

  intent {
    intent_name    = "AMAZON.CancelIntent"
    intent_version = "$LATEST"
  }

  intent {
    intent_name    = "AMAZON.StopIntent"
    intent_version = "$LATEST"
  }

  # Child-safe active listening
  active_directory_pairing_requirement = "NONE"

  # Enable audio for voice interaction (friendly for kids)
  process_behavior = "SAVE"

  # Tags for cost allocation and tracking
  tags = {
    Environment = "Production"
    Project     = "KidsPizzaBot"
    Owner       = "ParentingTech"
  }
}

# IAM role required for Lex to interact with other AWS services
resource "aws_iam_role" "lex_bot_role" {
  name = "lex-pizza-bot-role-for-kids"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

# Allow CloudWatch logging for monitoring bot interactions
resource "aws_iam_role_policy" "lex_bot_logging" {
  name = "lex_bot_cloudwatch_policy"
  role = aws_iam_role.lex_bot_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "cloudwatch:PutMetricData"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      }
    ]
  })
}

# Optional: Bot Alias for versioning (e.g., prod)
resource "aws_lex_bot_alias" "pizza_bot_prod" {
  name                    = "PROD"
  description             = "Production alias for PizzaPal bot"
  bot_name                = aws_lex_bot.pizza_bot_for_kids.name
  bot_version             = aws_lex_bot.pizza_bot_for_kids.version
  conversation_logs {
    iam_role_arn = aws_iam_role.lex_bot_role.arn
    log_settings {
      resource_type           = "AUDIO"
      resource_arn            = "arn:aws:s3:::pizza-bot-audio-logs-${random_string.suffix.result}"
      destination              = "S3"
      kms_key_arn             = aws_kms_key.pizza_bot_kms.arn
    }
  }
}

# Random suffix to create a unique S3 bucket name
resource "random_string" "suffix" {
  length  = 8
  special = false
  upper   = false
}

# KMS key for encrypting audio logs
resource "aws_kms_key" "pizza_bot_kms" {
  description             = "KMS key for encrypting PizzaPal bot audio logs"
  deletion_window_in_days = 10
  enable_key_rotation     = true
}

# S3 bucket for storing audio logs (child privacy compliant)
resource "aws_s3_bucket" "pizza_bot_audio_logs" {
  bucket = "pizza-bot-audio-logs-${random_string.suffix.result}"
  tags   = {
    Project = "KidsPizzaBot"
    Usage   = "LexAudioLogs"
  }
}

# Block public access for child data protection
resource "aws_s3_bucket_public_access_block" "pizza_bot_logs_block" {
  bucket                  = aws_s3_bucket.pizza_bot_audio_logs.id
  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Optional: Add bucket policy to require encryption
resource "aws_s3_bucket_policy" "require_encryption" {
  bucket = aws_s3_bucket.pizza_bot_audio_logs.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Deny"
        Principal = "*"
        Action = "s3:PutObject"
        Resource = "${aws_s3_bucket.pizza_bot_audio_logs.arn}/*"
        Condition = {
          StringNotEquals = {
            "s3:x-amz-server-side-encryption": "aws:kms"
          }
        }
        Sid = "DenyUnEncryptedObjectUploads"
      }
    ]
  })
}

