terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_lambda_permission" "allow_lex_to_start_execution" {
  statement_id  = "AllowExecutionFromLex"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.hello_pizza.function_name
  principal     = "lex.amazonaws.com"
  # source_arn    = "${aws_lex_bot.order_pizza.arn}:$LATEST"
}

data "archive_file" "hello_pizza" {
  type        = "zip"
  source_file = "./supplement/hello_pizza.py"
  output_path = "./supplement/hello_pizza.zip"
}

resource "aws_lambda_function" "hello_pizza" {
  function_name = "hello_pizza"
  role          = aws_iam_role.iam_exec_role.arn
  filename      = data.archive_file.hello_pizza.output_path
  source_code_hash = data.archive_file.hello_pizza.output_base64sha256
  handler       = "hello_pizza.handler"
  runtime       = "python3.12"
}

resource "aws_iam_role" "iam_exec_role" {
  name = "iam-exec-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Sid    = ""
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      },
    ]
  })
}

resource "aws_lex_intent" "OrderPizza" {
  name = "OrderPizza"

  sample_utterances = [
    "I would like to pick up a pizza",
    "I would like to order some pizzas",
  ]

  slot {
    name                     = "PizzaType"
    description              = "Type of pizza to order"
    slot_constraint          = "Required" 
    slot_type                = "AMAZON.AlphaNumeric"
    priority                 = 1
    value_elicitation_prompt {
      message {
        content             = "What type of pizza would you like?"
        content_type        = "PlainText"
      }
      max_attempts         = 2
    }
  }

  fulfillment_activity {
    type = "CodeHook"
    code_hook {
      uri            = aws_lambda_function.hello_pizza.arn
      message_version = "1.0"
    }
  }
}

resource "aws_lex_bot" "order_pizza" {
  name     = "OrderPizza"
  description  = "Orders a pizza from a local pizzeria"

  idle_session_ttl_in_seconds = 600
  locale = "en-US"

  child_directed = false

  voice_id = "Salli"
  process_behavior = "BUILD"

  clarification_prompt {
    max_attempts = 2
    message {
      content      = "I didn't understand that, can you please repeat?"
      content_type = "PlainText"
    }
  }

  abort_statement {
    message {
      content      = "Sorry, I could not understand. Goodbye."
      content_type = "PlainText"
    }
  }

  intent {
    intent_name    = aws_lex_intent.OrderPizza.name
    intent_version = aws_lex_intent.OrderPizza.version
  }

  # depends_on = [aws_lambda_permission.allow_lex_to_start_execution]
}

response:
```hcl
# Step 1: Define the AWS provider
provider "aws" {
  region = "us-east-1"  # You can change this to your preferred region
}

# Step 2: Create a Lambda function that will handle the fulfillment logic for the Lex bot
resource "aws_lambda_function" "pizza_order_function" {
  filename      = "lambda_function_payload.zip" # This should point to your deployment package
  function_name = "PizzaOrderFulfillment"
  role          = aws_iam_role.lambda_exec.arn
  handler       = "index.handler"
  runtime       = "python3.9"

  # Set environment variables if needed
  environment {
    variables = {
      TABLE_NAME = aws_dynamodb_table.pizza_orders.name
    }
  }

  # Source code for the lambda can be from a local file, S3, etc.
  source_code_hash = filebase64sha256("lambda_function_payload.zip")
}

# Step 3: Create an IAM role for the Lambda function to interact with AWS services
resource "aws_iam_role" "lambda_exec" {
  name = "pizza-order-lambda-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# Step 4: Attach basic execution policy and DynamoDB access (optional, for storing orders)
resource "aws_iam_role_policy_attachment" "lambda_basic_exec" {
  role       = aws_iam_role.lambda_exec.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

resource "aws_iam_role_policy" "lambda_dynamo_policy" {
  name = "lambda_dynamo_db_policy"
  role = aws_iam_role.lambda_exec.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "dynamodb:PutItem",
          "dynamodb:GetItem",
          "dynamodb:UpdateItem"
        ]
        Resource = aws_dynamodb_table.pizza_orders.arn
      }
    ]
  })
}

# Step 5: Create DynamoDB table to store pizza orders (optional)
resource "aws_dynamodb_table" "pizza_orders" {
  name           = "PizzaOrders"
  hash_key       = "OrderId"
  billing_mode   = "PAY_PER_REQUEST"

  attribute {
    name = "OrderId"
    type = "S"
  }
}

# Step 6: Create AWS Lex Bot for ordering pizzas
resource "aws_lex_bot" "pizza_bot" {
  name = "PizzaOrderBot"

  # Define intents
  intent {
    intent_name    = "OrderPizza"
    intent_version = "$LATEST"
  }

  # Create the associated intent separately
  process_behavior      = "BUILD"  # Build and process changes
  child_directed        = false
  voice_id              = "Joanna"
  enable_model_improvements = true
  locale                = "en-US"
  clarification_prompt {
    max_attempts = 2
    message {
      content          = "I didn't understand. Can you please repeat?"
      content_type     = "PlainText"
    }
  }
  abort_statement {
    message {
      content      = "Sorry, I couldn't process your request. Goodbye."
      content_type = "PlainText"
    }
  }
  timeout_in_seconds = 300
}

# Step 7: Create the intent for ordering pizza
resource "aws_lex_intent" "order_pizza_intent" {
  name = "OrderPizza"

  # Fulfillment activity: use Lambda function
  fulfillment_activity {
    type = "CodeHook"
    code_hook {
      uri                 = aws_lambda_function.pizza_order_function.arn
      message_version     = "1.0"
    }
  }

  # Sample utterances
  sample_utterances = [
    "I want to order a pizza",
    "Can I get a pizza",
    "Order a large pepperoni pizza",
    "I would like to buy a pizza"
  ]

  # Create slots for pizza order
  slot {
    name                 = "PizzaSize"
    slot_type            = "AMAZON.Number"
    slot_constraint      = "Required"
    value_elicitation_prompt {
      message {
        content      = "What size pizza would you like?"
        content_type = "PlainText"
      }
      max_attempts = 2
    }
    priority = 1
  }

  slot {
    name                 = "PizzaType"
    slot_type            = "AMAZON.SearchQuery"
    slot_constraint      = "Required"
    value_elicitation_prompt {
      message {
        content      = "What type of pizza would you like?"
        content_type = "PlainText"
      }
      max_attempts = 2
    }
    priority = 2
  }

  confirmation_prompt {
    message {
      content      = "Ready to order your {PizzaSize}-inch {PizzaType} pizza?"
      content_type = "PlainText"
    }
    max_attempts = 2
  }

  rejection_statement {
    message {
      content      = "Okay, I'll cancel your pizza order."
      content_type = "PlainText"
    }
  }
}

# Final note: You must publish a new bot version and alias if you want to use it in production
resource "aws_lex_bot_alias" "pizza_bot_alias" {
  name            = "prod"
  bot_name        = aws_lex_bot.pizza_bot.name
  bot_version     = aws_lex_bot.pizza_bot.version
}
```

