# Creating an AWS Lex V2 bot designed for children requires careful consideration of the bot properties,
# including child-friendly settings, data privacy, and appropriate voice and locale settings.

# Step-by-step considerations:
# 1. We are using the AWS Lex Model Building V2 bot resource (aws_lexv2models_bot).
# 2. The bot should be configured for a child-oriented use case, so we'll enable child-directed voice features.
# 3. We'll set data privacy to restrict targeted advertising and ensure data retention is appropriately governed.
# 4. Choose a default locale (e.g., en_US) and set idle session timeout.
# 5. Define the bot name (e.g., "ChildrenStoryBot") and role ARN for permissions.

resource "aws_lexv2models_bot" "children_bot" {
  name                        = "ChildrenStoryBot"
  role_arn                    = aws_iam_role.lex_bot_role.arn
  data_privacy = {
    child_directed = true  # Required for bots directed at children under 13 under COPPA
  }
  idle_session_ttl_in_seconds = 600 # 10 minutes of inactivity
  description                 = "A conversational bot designed to tell stories and play games with children"

  # Define bot locale settings
  bot_locale_specifications = {
    en_US = {
      custom_vocabulary = {}
      voice_settings = {
        voice_id = "Joanna"  # Friendly and clear voice; can be changed to "Matthew" or child-appropriate voices
      }
      description = "English (US) locale for children interactions"
    }
  }

  tags = {
    Environment = "Development"
    Purpose     = "ChildEngagement"
    Owner       = "ParentalControlTeam"
  }
}

# IAM role required by Lex bot to operate (e.g., logging, integration)
resource "aws_iam_role" "lex_bot_role" {
  name = "LexChildrenBotRole"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lexv2.amazonaws.com"
        }
        Condition = {}
      }
    ]
  })
}

# Attach AWS managed policy for Lex runtime operations (minimal required access)
resource "aws_iam_role_policy_attachment" "lex_bot_policy" {
  role       = aws_iam_role.lex_bot_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonLexRunBots"
}

