# Create a Kinesis Firehose Delivery Stream with a Redshift destination
# Steps:
# 1. Define the Firehose delivery stream with Redshift as the destination
# 2. Specify required Redshift connection details (cluster, database, table, user, password)
# 3. Include S3 configuration as an intermediate source (required for Redshift copy)
# 4. Set up proper IAM roles for Firehose to access S3 and Redshift
# 5. Configure copy command, buffering hints, and other Redshift-specific settings

resource "aws_kinesis_firehose_delivery_stream" "firehose_redshift_stream" {
  name        = "firehose-to-redshift"
  destination = "redshift"

  # S3 Configuration - intermediate bucket for Firehose before loading into Redshift
  s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.s3_bucket.arn

    # Optional: specify buffer size and interval
    buffer_size     = 10
    buffer_interval = 60
    compression_format = "UNCOMPRESSED"
  }

  redshift_configuration {
    # Role for Firehose to assume for Redshift access
    role_arn           = aws_iam_role.firehose_role.arn
    cluster_jdbcurl    = "jdbc:redshift://${aws_redshift_cluster.redshift_cluster.endpoint}/${var.redshift_db_name}"
    username           = var.redshift_username
    password           = var.redshift_password
    data_table_name    = var.redshift_table_name
    data_table_columns = var.redshift_table_columns

    # S3 configuration again here (Firehose copies from S3 to Redshift)
    s3_configuration {
      role_arn           = aws_iam_role.firehose_role.arn
