# Create an S3 bucket as a backup location for the Firehose stream
resource "aws_s3_bucket" "firehose_backup" {
  bucket = "firehose-backup-bucket-example"
  force_destroy = true

  # Enable versioning for data durability
  versioning {
    enabled = true
  }

  # Enable server-side encryption
  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }
}

# Create an IAM role for Kinesis Firehose to assume
resource "aws_iam_role" "firehose_role" {
  name = "firehose_delivery_role"

  # Trust policy allowing Firehose to assume this role
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
        Condition = {
          StringEquals = {
            "sts:ExternalId": "your-external-id"  # Replace or remove if not needed
          }
        }
      }
    ]
  })
}

# IAM policy for Firehose permissions
resource "aws_iam_policy" "firehose_policy" {
  name = "firehose_delivery_policy"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      # Allow Firehose to write to the backup S3 bucket
      {
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Effect   = "Allow"
        Resource = [
          aws_s3_bucket.firehose_backup.arn,
          "${aws_s3_bucket.firehose_backup.arn}/*"
        ]
      },
      # Allow Firehose to send data to Elasticsearch
      {
        Action = [
          "es:DescribeElasticsearchDomain",
          "es:DescribeElasticsearchDomains",
          "es:DescribeElasticsearchDomainConfig",
          "es:ESHttpDelete",
          "es:ESHttpPatch",
          "es:ESHttpPost",
          "es:ESHttpPut"
        ]
        Effect   = "Allow"
        Resource = "arn:aws:es:*:*:domain/*"
      },
      # Allow Firehose to use KMS if needed (optional, if using encrypted streams)
      {
        Action = [
          "kms:Decrypt"
        ]
        Effect   = "Allow"
        Resource = "*"
        # Best practice is to scope to specific KMS key ARN
      },
      # CloudWatch Logs permissions (recommended for monitoring)
      {
        Action = [
          "logs:PutLogEvents"
        ]
        Effect   = "Allow"
        Resource = "arn:aws:logs:*:*:log-group:/aws/kinesisfirehose/*"
      }
    ]
  })
}

# Attach the policy to the Firehose IAM role
resource "aws_iam_role_policy_attachment" "firehose_policy_attach" {
  role       = aws_iam_role.firehose_role.name
  policy_arn = aws_iam_policy.firehose_policy.arn
}

# Create the Kinesis Firehose Delivery Stream with Elasticsearch destination
resource "aws_kinesis_firehose_delivery_stream" "es_stream" {
  name        = "terraform-firehose-es-stream"
  destination = "elasticsearch"

  # S3 backup configuration (required for Firehose)
  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.firehose_backup.arn

    # Optional: Define buffer sizes and compression
    buffer_size            = 10
    buffer_interval        = 60
    compression_format     = "GZIP"
    error_output_prefix    = "firehose/errors/"
    prefix                 = "firehose/data/"

    # CloudWatch Logging
    cloud_watch_logging_options {
      enabled         = true
      log_group_name  = "/aws/kinesisfirehose/${var.stream_name}"
      log_stream_name = "DirectToElasticsearch"
    }
  }

  # Elasticsearch destination configuration
  elasticsearch_configuration {
    domain_arn = "arn:aws:es:us-west-2:123456789012:domain/example-domain" # Replace with your domain ARN
    role_arn   = aws_iam_role.firehose_role.arn
    index_name = "firehose-logs"
    type_name  = "log" # Removed in newer Elasticsearch versions, can be omitted
    index_rotation_period = "OneDay"

    # Buffering configurations
    buffering_interval = 300
    buffering_size     = 10

    # Retry duration in case of indexing failure (in seconds)
    retry_duration = 300

    # S3 backup for failed documents
    s3_backup_mode = "FailedDocumentsOnly"
    s3_configuration {
      role_arn   = aws_iam_role.firehose_role.arn
      bucket_arn = aws_s3_bucket.firehose_backup.arn
      buffer_size = 10
      buffer_interval = 300
    }

    # Optional: CloudWatch logging for Elasticsearch destination
    cloud_watch_logging_options {
      enabled         = true
      log_group_name  = "/aws/kinesisfirehose/${var.stream_name}"
      log_stream_name = "ElasticsearchDestination"
    }
  }
}

