# Create a Kinesis Firehose Delivery Stream with an OpenSearch destination
# Steps:
# 1. Define the delivery stream with `kinesis_firehose_delivery_stream`
# 2. Specify the source (Kinesis stream or direct PUT)
# 3. Set up the destination to Amazon OpenSearch (successor to Elasticsearch)
# 4. Include necessary IAM roles and permissions
# 5. Configure S3 backup, buffering, and retry options
# 6. Define OpenSearch index and type, and enable error logging

resource "aws_kinesis_firehose_delivery_stream" "opensearch_stream" {
  name        = "firehose-opensearch-demo"
  destination = "opensearch"

  # Source configuration: can be 'direct_put' or from a Kinesis stream
  # Here we use direct_put (default)
  kinesis_stream_config {
    kinesis_stream_arn = aws_kinesis_stream.source_stream.arn
  }

  # S3 backup configuration (required for OpenSearch destination)
  s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.backup_bucket.arn

    # Optional: specify buffer size, interval, compression, and encryption
    buffer_size = 5
    buffer_interval = 300
    compression_format = "UNCOMPRESSED"
  }

  # OpenSearch destination configuration
  opensearch_configuration {
    role_arn           = aws_iam_role.firehose_role.arn
    domain_arn         = aws_opensearch_domain.example.arn
    index_name         = "firehose-logs"
    type_name          = "_doc" # For older OpenSearch versions; optional
    index_rotation     = "OneDay" # Options: NoRotation, OneHour, OneDay, OneWeek, OneMonth

    # Buffering hints
    buffering_interval = 300
    buffering_size     = 5

    retry_duration     = 300

    # Error logging
    s3_backup_mode = "FailedDocumentsOnly"

    processing_configuration {
      enabled = true

      processors {
        type = "Lambda"

        parameters {
          parameter_name  = "LambdaArn"
          parameter_value = aws_lambda_function.processor.arn
        }
      }
    }

    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = aws_cloudwatch_log_group.firehose.name
      log_stream_name = aws_cloudwatch_log_stream.firehose_stream.name
    }
  }
}

# IAM role for Firehose to access S3, OpenSearch, and CloudWatch
resource "aws_iam_role" "firehose_role" {
  name = "firehose-opensearch-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# Replace the following resources with existing ones as needed
resource "aws_kinesis_stream" "source_stream" {
  name        = "source-stream"
  shard_count = 2
}

resource "aws_s3_bucket" "backup_bucket" {
  bucket = "firehose-backup-bucket-example"
  force_destroy = true
}

resource "aws_opensearch_domain" "example" {
  domain_name = "firehose-opensearch-demo"
  cluster_config {
    instance_type = "t3.small.search"
  }

  ebs_options {
    ebs_enabled = true
    volume_size = 10
  }

  cluster_config {
    instance_type = "m5.large.search"
    instance_count = 1
  }

  advanced_security_options {
    enabled                        = true
    internal_user_database_enabled = true

    master_user_options {
      master_user_name     = "admin"
      master_user_password = "Password123!"
    }
  }

  domain_endpoint_options {
    enforce_https               = true
    tls_security_policy           = "Policy-Minimum-TLS-1-2-2019-07"
    enforce_tls_auth             = true
  }

  ebs_options {
    ebs_enabled = true
    volume_type = "gp2"
    volume_size = 10
  }

  encrypt_at_rest {
    enabled    = true
    kms_key_id = "alias/aws/opensearch"
  }

  node_to_node_encryption {
    enabled = true
  }

  snapshot_options {
    automated_snapshot_start_hour = 23
  }

  tags = {
    Environment = "production"
  }
}

# Example Lambda function for preprocessing (optional)
resource "aws_lambda_function" "processor" {
  filename         = "lambda_function_payload.zip"
  function_name    = "firehose-processor"
  role             = aws_iam_role.lambda_role.arn
  handler          = "index.handler"
  runtime          = "nodejs18.x"
  source_code_hash = filebase64sha256("lambda_function_payload.zip")
}

# CloudWatch log group and stream
resource "aws_cloudwatch_log_group" "firehose" {
  name = "/aws/firehose/opensearch-demo"
}

resource "aws_cloudwatch_log_stream" "firehose_stream" {
  name           = "delivery-stream"
  log_group_name = aws_cloudwatch_log_group.firehose.name
}

# IAM role policy for Firehose
resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose_opensearch_policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.backup_bucket.arn,
          "${aws_s3_bucket.backup_bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "es:DescribeElasticsearchDomain",
          "es:DescribeElasticsearchDomains",
          "es:DescribeElasticsearchDomainConfig",
          "es:ESHttpPut",
          "es:ESHttpPost"
        ]
        Resource = aws_opensearch_domain.example.arn
      },
      {
        Effect = "Allow"
        Action = [
          "logs:PutLogEvents"
        ]
        Resource = aws_cloudwatch_log_group.firehose.arn
      },
      {
        Effect = "Allow"
        Action = [
          "kinesis:DescribeStream",
          "kinesis:GetShardIterator",
          "kinesis:GetRecords"
        ]
        Resource = aws_kinesis_stream.source_stream.arn
      }
    ]
  })
}

# Optional: IAM role for Lambda
resource "aws_iam_role" "lambda_role" {
  name = "lambda-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

