# Create a Kinesis Firehose Delivery Stream with Splunk destination

# Step 1: Define the Kinesis Firehose Delivery Stream resource
# - Specify the name of the delivery stream
# - Set the destination to "splunk"
# - Configure the Splunk destination with required settings:
#   - HECEndpoint: The Splunk HTTP Event Collector (HEC) URL
#   - HECAcknowledgmentTimeout: How long Firehose waits for acknowledgment from Splunk
#   - HECToken: Authentication token for Splunk HEC
#   - S3 configuration for buffer and backup
#   - Buffer hints (size and interval)
#   - Enable S3 backup of undelivered or failed data

resource "aws_kinesis_firehose_delivery_stream" "splunk_stream" {
  name        = "firehose-splunk-delivery-stream"
  destination = "splunk"

  # S3 configuration for intermediate storage and backup
  splunk_configuration {
    hec_endpoint        = "https://input-prd-p-l5x1234.splunkcloud.com:8088/services/collector"
    hec_token           = "your-splunk-hec-token"
    hec_acknowledgment_timeout = 600
    s3_backup_mode      = "FailedEventsOnly"  # or "AllEvents" if needed

    s3_configuration {
      role_arn   = aws_iam_role.firehose_role.arn
      bucket_arn = aws_s3_bucket.splunk_bucket.arn
      buffer_size = 5
      buffer_interval = 300
      compression_format = "UNCOMPRESSED"
    }

    # Optional: Enable data transformation via Lambda
    # processing_configuration {
    #   enabled = true
    #   processors {
    #     type = "Lambda"
    #     parameters {
    #       parameter_name  = "LambdaArn"
    #       parameter_value = "arn:aws:lambda:us-west-2:123456789012:function:kinesis-firehose-lambda:latest"
    #     }
    #   }
    # }
  }

  # Optional: Tags for the delivery stream
  tags = {
    Environment = "production"
    App         = "splunk-ingestion"
  }
}

# Step 2: Create S3 bucket for Firehose buffering and backup
resource "aws_s3_bucket" "splunk_bucket" {
  bucket = "firehose-splunk-buffer-bucket"
  # Note: S3 bucket names must be globally unique; consider using a prefix or random suffix
}

# Step 3: Create IAM role for Firehose to access S3 and write logs
resource "aws_iam_role" "firehose_role" {
  name = "firehose-splunk-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Sid    = ""
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# Step 4: Attach IAM policies to the role for S3 and Splunk access
resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose-s3-splunk-policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.splunk_bucket.arn,
          "${aws_s3_bucket.splunk_bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow",
        Action = [
          "logs:PutLogEvents"
        ],
        Resource = "arn:aws:logs:*:*:log-group:/aws/kinesisfirehose/*"
      }
      # Note: Splunk HEC access is managed via token, not IAM
    ]
  })
}

