# Kinesis Firehose Delivery Stream with Elasticsearch Destination in a VPC

# Steps:
# 1. Create a VPC for the Elasticsearch cluster
# 2. Create subnets (at least 2 for high availability) in different AZs
# 3. Create a security group to allow access to Elasticsearch
# 4. Create an Elasticsearch domain (AWS OpenSearch Service) within the VPC
# 5. Create an S3 bucket as the backup bucket for Firehose
# 6. Create an IAM role for Firehose to access Elasticsearch, S3, and other services
# 7. Create the Kinesis Firehose delivery stream with Elasticsearch destination in VPC

resource "aws_vpc" "es_vpc" {
  cidr_block = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support = true

  tags = {
    Name = "es-vpc"
  }
}

resource "aws_subnet" "es_subnet_1" {
  vpc_id            = aws_vpc.es_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-west-2a"

  tags = {
    Name = "es-subnet-1"
  }
}

resource "aws_subnet" "es_subnet_2" {
  vpc_id            = aws_vpc.es_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-west-2b"

  tags = {
    Name = "es-subnet-2"
  }
}

resource "aws_security_group" "es_sg" {
  vpc_id = aws_vpc.es_vpc.id

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "es-security-group"
  }
}

resource "aws_opensearch_domain" "es_domain" {
  domain_name = "firehose-es-domain"

  cluster_config {
    instance_type = "t3.small.search"
    instance_count = 2
    zone_awareness_enabled = true
    zone_awareness_config {
      availability_zone_count = 2
    }
  }

  vpc_options {
    subnet_ids         = [aws_subnet.es_subnet_1.id, aws_subnet.es_subnet_2.id]
    security_group_ids = [aws_security_group.es_sg.id]
  }

  encrypt_at_rest {
    enabled = true
    kms_key_id = "alias/aws/opensearchservice"
  }

  domain_endpoint_options {
    enforce_https = true
    tls_security_policy = "Policy-Min-TLS-1-2-2019-07"
  }

  node_to_node_encryption {
    enabled = true
  }

  ebs_options {
    ebs_enabled = true
    volume_size = 10
  }
}

resource "aws_s3_bucket" "firehose_s3_backup" {
  bucket = "firehose-es-backup-bucket"
  force_destroy = true
}

resource "aws_iam_role" "firehose_role" {
  name = "firehose_delivery_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose_es_policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.firehose_s3_backup.arn,
          "${aws_s3_bucket.firehose_s3_backup.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "es:DescribeElasticsearchDomain",
          "es:DescribeElasticsearchDomains",
          "es:DescribeElasticsearchDomainConfig",
          "es:ESHttpDelete",
          "es:ESHttpPatch",
          "es:ESHttpPost",
          "es:ESHttpPut"
        ]
        Resource = aws_opensearch_domain.es_domain.arn
      },
      {
        Effect = "Allow"
        Action = "sts:AssumeRole"
        Resource = aws_iam_role.firehose_role.arn
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:DescribeVpcs",
          "ec2:DescribeSubnets",
          "ec2:DescribeSecurityGroups",
          "ec2:DescribeNetworkInterfaces",
          "ec2:CreateNetworkInterface",
          "ec2:CreateNetworkInterfacePermission",
          "ec2:DeleteNetworkInterface"
        ]
        Resource = "*"
      }
    ]
  })
}

resource "aws_kinesis_firehose_delivery_stream" "es_delivery_stream" {
  name        = "terraform-firehose-es-stream"
  destination = "elasticsearch"

  elasticsearch_configuration {
    domain_arn = aws_opensearch_domain.es_domain.arn
    role_arn   = aws_iam_role.firehose_role.arn
    index_name = "firehose-logs"
    type_name  = "log" # Note: Type is deprecated in ES 7.x+, can be omitted or set to "_doc"
    index_rotation = "OneDay"

    s3_configuration {
      role_arn   = aws_iam_role.firehose_role.arn
      bucket_arn = aws_s3_bucket.firehose_s3_backup.arn
    }

    vpc_config {
      subnet_ids         = [aws_subnet.es_subnet_1.id, aws_subnet.es_subnet_2.id]
      security_group_ids = [aws_security_group.es_sg.id]
      role_arn           = aws_iam_role.firehose_role.arn
    }

    document_id_options {
      default_document_id_format = "FirehoseManaged"
    }

    processing_configuration {
      enabled = false
    }
  }
}

