        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose_http_policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.firehose_bucket.arn,
          "${aws_s3_bucket.firehose_bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "firehose:PutRecord",
          "firehose:PutRecordBatch",
          "firehose:UpdateDestination"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = "logs:PutLogEvents"
        Resource = aws_cloudwatch_log_group.firehose_log_group.arn
      }
    ]
  })
}

resource "aws_s3_bucket" "firehose_bucket" {
  bucket = "my-firehose-stream-bucket"
  force_destroy = true
}

resource "aws_cloudwatch_log_group" "firehose_log_group" {
  name = "/aws/firehose/http-endpoint-delivery"
}

resource "aws_kinesis_firehose_delivery_stream" "to_http_endpoint" {
  name        = "firehose-to-new-relic"
  destination = "http_endpoint"

  http_endpoint_configuration {
    url = "https://aws-api.newrelic.com/firehose/v1/accounts/12345678/events"
    name = "NewRelicEndpoint"
    access_key = "your-new-relic-insert-key"  # For authentication; value should be managed via variables or secrets

    content_encoding = "GZIP"  # Optional: improves efficiency
    role_arn         = aws_iam_role.firehose_role.arn

    s3_configuration {
      role_arn   = aws_iam_role.firehose_role.arn
      bucket_arn = aws_s3_bucket.firehose_bucket.arn

      buffer_size  = 5
      buffer_interval = 300
      compression_format = "GZIP"

      cloudwatch_logging_options {
        enabled         = true
        log_group_name  = aws_cloudwatch_log_group.firehose_log_group.name
        log_stream_name = "s3-delivery"
      }
    }

    # Optional: Custom headers for authentication or metadata
    request_configuration {
      content_encoding = "GZIP"

      common_attributes {
        name  = "X-Insert-Key"
        value = "your-new-relic-insert-key"  # This should match your auth method
      }
    }
  }

  # Optional: CloudWatch logging for Firehose itself
  tags = {
    Environment = "staging"
  }
}
