# Create a Kinesis Firehose Delivery Stream with OpenSearch Destination within a VPC
# Steps:
# 1. Set up required providers (AWS)
# 2. Create a VPC for the OpenSearch cluster (if not already existing)
# 3. Create subnets (at least two) and a security group for OpenSearch
# 4. Create an OpenSearch domain with VPC options
# 5. Create required IAM roles and policies for Firehose to access OpenSearch and write data
# 6. Create the Kinesis Firehose Delivery Stream with an OpenSearch destination inside the VPC

resource "aws_vpc" "opensearch_vpc" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "opensearch-vpc"
  }
}

resource "aws_subnet" "opensearch_subnet_a" {
  vpc_id            = aws_vpc.opensearch_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-west-2a"

  tags = {
    Name = "opensearch-subnet-a"
  }
}

resource "aws_subnet" "opensearch_subnet_b" {
  vpc_id            = aws_vpc.opensearch_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-west-2b"

  tags = {
    Name = "opensearch-subnet-b"
  }
}

resource "aws_security_group" "opensearch_sg" {
  vpc_id = aws_vpc.opensearch_vpc.id

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "opensearch-security-group"
  }
}

resource "aws_opensearch_domain" "example" {
  domain_name = "firehose-opensearch-domain"

  cluster_config {
    instance_type = "t3.small.search"
    instance_count = 2
    zone_awareness_enabled = true
    zone_awareness_config {
      availability_zone_count = 2
    }
  }

  vpc_options {
    security_group_ids = [aws_security_group.opensearch_sg.id]
    subnet_ids           = [aws_subnet.opensearch_subnet_a.id, aws_subnet.opensearch_subnet_b.id]
  }

  encrypt_at_rest {
    enabled = true
  }

  node_to_node_encryption {
    enabled = true
  }

  domain_endpoint_options {
    enforce_https = true
    tls_security_policy = "Policy-Min-TLS-1-2-2019-07"
  }

  ebs_options {
    ebs_enabled = true
    volume_size = 10
  }

  # Required access policy to allow access from Firehose within VPC
  access_policies = jsonencode({
    Version: "2012-10-17",
    Statement: [
      {
        Effect: "Allow",
        Principal: {
          AWS: "*"
        },
        Action: "es:*",
        Resource: "${aws_opensearch_domain.example.arn}/*"
      }
    ]
  })
}

# IAM role for Kinesis Firehose to assume
resource "aws_iam_role" "firehose_role" {
  name = "firehose-opensearch-role"

  assume_role_policy = jsonencode({
    Version: "2012-10-17",
    Statement: [
      {
        Effect: "Allow",
        Principal: {
          Service: "firehose.amazonaws.com"
        },
        Action: "sts:AssumeRole"
      }
    ]
  })
}

# IAM policy for Kinesis Firehose to access OpenSearch, S3 (for backup), and write logs
resource "aws_iam_policy" "firehose_policy" {
  name = "firehose-opensearch-policy"

  policy = jsonencode({
    Version: "2012-10-17",
    Statement: [
      {
        Effect: "Allow",
        Action: [
          "es:DescribeElasticsearchDomain",
          "es:DescribeElasticsearchDomains",
          "es:DescribeElasticsearchDomainConfig",
          "es:ESHttpPost",
          "es:ESHttpPut"
        ],
        Resource: aws_opensearch_domain.example.arn
      },
      {
        Effect: "Allow",
        Action: [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ],
        Resource: [
          aws_s3_bucket.firehose_bucket.arn,
          "${aws_s3_bucket.firehose_bucket.arn}/*"
        ]
      },
      {
        Effect: "Allow",
        Action: [
          "logs:PutLogEvents"
        ],
        Resource: "arn:aws:logs:*:*:log-group:/aws/kinesisfirehose/*"
      },
      {
        Effect: "Allow",
        Action: [
          "ec2:DescribeVpcs",
          "ec2:DescribeSubnets",
          "ec2:DescribeSecurityGroups",
          "ec2:DescribeNetworkInterfaces",
          "ec2:CreateNetworkInterface",
          "ec2:CreateNetworkInterfacePermission",
          "ec2:DeleteNetworkInterface"
        ],
        Resource: "*"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "firehose_policy_attach" {
  role       = aws_iam_role.firehose_role.name
  policy_arn = aws_iam_policy.firehose_policy.arn
}

# S3 bucket for Firehose to use as backup for failed delivery
resource "aws_s3_bucket" "firehose_bucket" {
  bucket = "firehose-backup-bucket-example"
  acl    = "private"

  versioning {
    enabled = false
  }

  lifecycle {
    prevent_destroy = false
  }
}

# Kinesis Firehose Delivery Stream with OpenSearch destination inside VPC
resource "aws_kinesis_firehose_delivery_stream" "opensearch_stream" {
  name        = "firehose-to-opensearch-stream"
  destination = "opensearch"

  # S3 backup configuration
  s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.firehose_bucket.arn
  }

  opensearch_configuration {
    role_arn          = aws_iam_role.firehose_role.arn
    domain_arn        = aws_opensearch_domain.example.arn
    index_name        = "firehose-index"
    type_name         = "firehose-type"  # Optional in newer versions, can be removed if using OpenSearch 1.0+
    index_rotation    = "OneHour"
    s3_backup_mode    = "FailedDocumentsOnly"

    s3_configuration {
      role_arn   = aws_iam_role.firehose_role.arn
      bucket_arn = aws_s3_bucket.firehose_bucket.arn
    }

    vpc_config {
      subnet_ids         = [aws_subnet.opensearch_subnet_a.id, aws_subnet.opensearch_subnet_b.id]
      security_group_ids = [aws_security_group.opensearch_sg.id]
      role_arn           = aws_iam_role.firehose_role.arn
    }
  }

  tags = {
    Environment = "dev"
  }
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_s3_bucket" "bucket" {
  bucket_prefix = "my-bucket-"
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

data "aws_availability_zones" "available" {
  state = "available"
}

# Subnets
resource "aws_subnet" "first" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.1.0/24"

  map_public_ip_on_launch = true
  availability_zone       = data.aws_availability_zones.available.names[0]
}

resource "aws_subnet" "second" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.2.0/24"

  map_public_ip_on_launch = true
