resource "aws_kendra_index" "example" {
  name     = "example-kendra-index"
  role_arn = aws_iam_role.kendra.arn

  # Specify capacity units for the index
  capacity_units {
    query_capacity_units   = 1
    storage_capacity_units = 1
  }

  # Enable user context filtering with user and group resolution
  user_token_configurations {
    json_token_type_configuration {
      user_name_attribute_field = "username"
      group_attribute_field     = "groups"
    }
  }

  # Configure user and group resolution
  user_context_policy = "ATTRIBUTE_FILTER"

  # Optional: Add description
  description = "Kendra index with user group resolution for access control"

  # Tags for the index
  tags = {
    Name        = "example-kendra-index"
    Environment = "production"
  }
}

