response:
# Terraform Configuration for AWS Kendra Index with User Group Resolution

Let's think through the requirements:

1. We need to create an AWS Kendra index, which is a managed search service
2. The index should include user group resolution configuration for access control
3. We'll need to specify required parameters like name, role ARN, and capacity units
4. For user group resolution, we'll configure it to use AWS SSO or another identity source

```hcl
resource "aws_kendra_index" "example" {
  name     = "example-kendra-index"
  role_arn = aws_iam_role.kendra.arn

  # Specify capacity units for the index
  capacity_units {
    query_capacity_units   = 1
    storage_capacity_units = 1
  }

  # Enable user context filtering with user and group resolution
  user_token_configurations {
    json_token_type_configuration {
      user_name_attribute_field = "username"
      group_attribute_field     = "groups"
    }
  }

  # Configure user and group resolution
  user_context_policy = "ATTRIBUTE_FILTER"

  # Optional: Add description
  description = "Kendra index with user group resolution for access control"

  # Tags for the index
  tags = {
    Name        = "example-kendra-index"
    Environment = "production"
  }
}

# IAM role required for Kendra service
resource "aws_iam_role" "kendra" {
  name = "kendra-index-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kendra.amazonaws.com"
        }
      }
    ]
  })
}

# IAM role policy for Kendra
resource "aws_iam_role_policy" "kendra" {
  name = "kendra-index-policy"
  role = aws_iam_role.kendra.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "cloudwatch:PutMetricData"
        ]
        Resource = "*"
        Condition = {
          StringEquals = {
            "cloudwatch:namespace": "AWS/Kendra"
          }
        }
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      }
    ]
  })
}
```

