response:
To fulfill the request, let's break it down step by step:

1. We need a VPC resource named "main" — this represents the AWS VPC that will be associated with the private hosted zone.
2. We need a `aws_route53_zone` resource named `private_zone` with the domain name `internal.example53.com`. Since it's intended to be a private zone (linked to a VPC), it must have the `vpc` block specifying the VPC it's associated with.
3. We need a `aws_route53_record` resource that is not an alias (i.e., it uses `records` instead of `alias`). This record will be part of the private zone and can be, for example, a DNS A record pointing to some IP.

Assumptions:
- The record will be an A record for `test.internal.example53.com` pointing to a placeholder IP (e.g., `10.0.0.1`).
- The zone is private (because it's linked to a VPC).

Now, writing the Terraform configuration accordingly:

```hcl
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "main-vpc"
  }
}

resource "aws_route53_zone" "private_zone" {
  name = "internal.example53.com"

  vpc {
    vpc_id = aws_vpc.main.id
  }

  tags = {
    Name = "internal-example53-com-private-zone"
  }
}

resource "aws_route53_record" "example" {
  zone_id = aws_route53_zone.private_zone.zone_id
  name    = "test.internal.example53.com"
  type    = "A"
  ttl     = 300
  records = ["10.0.0.1"]
}
```

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_route53_zone" "primary" {
  name = "example53.com"
}

# Health check for the primary resource
resource "aws_route53_health_check" "primary_health_check" {
  fqdn              = "example.com"
  port              = 80
  type              = "HTTP"
  resource_path     = "/"
  failure_threshold = 3
}

# Primary A record with a health check (active endpoint)
resource "aws_route53_record" "primary_record" {
  zone_id           = aws_route53_zone.primary.zone_id
  name              = "example.com"
  type              = "A"
  ttl               = "60"
  records           = ["192.0.2.10"]
  set_identifier    = "primary"
  health_check_id   = aws_route53_health_check.primary_health_check.id

  failover_routing_policy {
    type = "PRIMARY"
  }
}

# Secondary A record without a health check (passive endpoint)
resource "aws_route53_record" "secondary_record" {
  zone_id           = aws_route53_zone.primary.zone_id
  name              = "example.com"
  type              = "A"
  ttl               = "60"
  records           = ["192.0.2.20"]
  set_identifier    = "secondary"

  failover_routing_policy {
    type = "SECONDARY"
  }
}

extracted_code:
# Step-by-step approach:
# 1. We need a Route 53 public hosted zone named "main"
# 2. We need two health checks - primary and secondary - each monitoring an FQDN
# 3. For active-active failover, we'll use a multivalue answer routing policy
#    where both records are returned, but only healthy ones are used
# 4. Each record will have a health check associated with it

resource "aws_route53_zone" "main" {
  name = "main"
}

resource "aws_route53_health_check" "primary_health_check" {
  fqdn              = "primary.example.com"
  port              = 80
  type              = "HTTP"
  resource_path     = "/"
  failure_threshold = "3"
  request_interval  = "30"

  tags = {
    Name = "primary_health_check"
  }
}

resource "aws_route53_health_check" "secondary_health_check" {
  fqdn              = "secondary.example.com"
  port              = 80
  type              = "HTTP"
  resource_path     = "/"
  failure_threshold = "3"
  request_interval  = "30"

  tags = {
    Name = "secondary_health_check"
  }
}

resource "aws_route53_record" "active_active_record" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "www.main"
  type    = "A"
  # Using multivalue answer routing for active-active with failover
  multivalue_answer_routing_policy = true

  alias {
    zone_id                = aws_route53_zone.main.zone_id
    name                   = aws_route53_health_check.primary_health_check.fqdn
    evaluate_target_health = true
  }

  health_check_id = aws_route53_health_check.primary_health_check.id
}

resource "aws_route53_record" "secondary_record" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "www.main"
  type    = "A"
  multivalue_answer_routing_policy = true

  alias {
    zone_id                = aws_route53_zone.main.zone_id
    name                   = aws_route53_health_check.secondary_health_check.fqdn
    evaluate_target_health = true
  }

  health_check_id = aws_route53_health_check.secondary_health_check.id
}

