# We are creating a Route 53 configuration with a routing policy that directs users 
# to the least congested endpoint using latency-based routing across two regions:
# us-east-1 and eu-central-1. We will:
# 1. Create a Route 53 public hosted zone called "primary"
# 2. Create two records (one for each region) with health checks
# 3. Use Latency routing policy to route users to the region with lowest latency
#    which correlates with less congestion in many cases

resource "aws_route53_zone" "primary" {
  name = "primary"
}

# Health check for us-east-1 endpoint
resource "aws_route53_health_check" "us_east_1_health_check" {
  fqdn              = "us-east-1.primary"
  port              = 80
  type              = "HTTP"
  resource_path     = "/"
  failure_threshold = "3"
  request_interval  = "30"
}

# Health check for eu-central-1 endpoint
resource "aws_route53_health_check" "eu_central_1_health_check" {
  fqdn              = "eu-central-1.primary"
  port              = 80
  type              = "HTTP"
  resource_path     = "/"
  failure_threshold = "3"
  request_interval  = "30"
}

# Latency-based routing record pointing to two endpoints in different regions
resource "aws_route53_record" "latency_based_routing" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "www"
  type    = "A"
  # Using latency routing to direct to the region with the best latency
  alias {
    name                   = "us-east-1-endpoint.example.com" # placeholder for actual endpoint
    zone_id                = "Z3AQBSTGFYJSTF" # placeholder zone ID (e.g., of a load balancer)
    evaluate_target_health = true
  }
}

# Define latency records for each region
resource "aws_route53_record" "us_east_1_latency_record" {
  for_each = {
    us-east-1 = "us-east-1-endpoint.example.com"
    eu-central-1 = "eu-central-1-endpoint.example.com"
  }

  zone_id = aws_route53_zone.primary.zone_id
  name    = "www"
  type    = "A"
  routing_policy {
    latency {
      region = each.key
    }
  }
  set_identifier = each.key

  alias {
    name   = each.value
    zone_id                = "Z3AQBSTGFYJSTF" # Example: AWS ELB Zone ID, should be replaced
    evaluate_target_health = true
  }
}

# Note: In real-world usage, you'd point to actual Load Balancers or Resources in those regions.
# The health checks and latency routing work together to route to the least congested (lowest latency) region.

