}

resource "aws_iam_role_policy_attachment" "attach_eks_fargate_policy" {
  role       = aws_iam_role.eks_fargate_pod_execution_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSFargatePodExecutionRolePolicy"
}

resource "aws_eks_cluster" "example" {
  name     = "example-eks-cluster"
  role_arn = aws_iam_role.eks_fargate_pod_execution_role.arn

  vpc_config {
    subnet_ids = aws_subnet.example[*].id
  }

  # Ensure the cluster is created before attempting kube config setup
  depends_on = [
    aws_iam_role_policy_attachment.attach_eks_fargate_policy
  ]
}

resource "aws_subnet" "example" {
  count = 2

  vpc_id            = aws_vpc.example.id
  cidr_block        = cidrsubnet(aws_vpc.example.cidr_block, 8, count.index)
  availability_zone = data.aws_availability_zones.available.names[count.index]

  tags = {
    Name                    = "example-subnet-${count.index}"
    "kubernetes.io/cluster/${aws_eks_cluster.example.name}" = "shared"
  }
}

resource "aws_vpc" "example" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "example-vpc"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_eks_fargate_profile" "kube_system_profile" {
  cluster_name           = aws_eks_cluster.example.name
  fargate_profile_name   = "kube-system-profile"
  pod_execution_role_arn = aws_iam_role.eks_fargate_pod_execution_role.arn

  selector {
    namespace = "kube-system"
  }

  subnet_ids = aws_subnet.example[*].id

  # Wait for cluster and role to be ready
  depends_on = [
    aws_iam_role_policy_attachment.attach_eks_fargate_policy,
    aws_eks_cluster.example
  ]
}

# Retrieve authentication token for EKS cluster access
data "aws_eks_cluster_auth" "cluster_auth" {
  name = aws_eks_cluster.example.name
}

# Patch coredns deployment using the EKS cluster endpoint and auth
resource "null_resource" "patch_coredns" {
  triggers = {
    deployment_name = "coredns"
    namespace       = "kube-system"
  }

  provisioner "local-exec" {
    command = <<EOT
      cat << EOF | kubectl apply -f -
      apiVersion: apps/v1
      kind: Deployment
      metadata:
        name: ${self.triggers.deployment_name}
        namespace: ${self.triggers.namespace}
      spec:
        template:
          metadata:
            annotations:
              cluster-autoscaler.kubernetes.io/safe-to-evict: 'false'
      EOF
    EOT
  }

  # Use kubectl with EKS configuration
  environment = {
    KUBECONFIG = "/tmp/eks-kubeconfig.yaml"
  }

  depends_on = [
    aws_eks_fargate_profile.kube_system_profile
  ]

  # Construct kubeconfig for kubectl use
  triggers = {
    kubeconfig = <<EOT
      apiVersion: v1
      clusters:
      - cluster:
          server: ${aws_eks_cluster.example.endpoint}
          certificate-authority-data: ${aws_eks_cluster.example.certificate_authority[0].data}
        name: kubernetes
      contexts:
      - context:
          cluster: kubernetes
          user: aws
        name: aws
      current-context: aws
      kind: Config
      preferences: {}
      users:
      - name: aws
        user:
          exec:
            apiVersion: client.authentication.k8s.io/v1beta1
            command: aws
            args:
              - "eks"
              - "get-token"
              - "--cluster-name"
              - "${aws_eks_cluster.example.name}"
    EOT
  }
}
```

