# Create an AWS EKS Node Group with required configurations and IAM dependencies
# Step 1: Define the EKS node group resource with required attributes
# Step 2: Set scaling configuration including desired, min, max sizes and max unavailable
# Step 3: Configure update configuration for node management during updates
# Step 4: Ensure dependencies on IAM role policies for proper permissions

resource "aws_eks_node_group" "example" {
  cluster_name    = "example"
  node_group_name = "example"
  node_role_arn   = aws_iam_role.eks_node_role.arn
  subnet_ids      = var.subnet_ids

  # Scaling configuration
  scaling_config {
    desired_size = 1
    max_size     = 2
    min_size     = 1
  }

  # Update configuration for node management
  update_config {
    max_unavailable = 1
  }

  # Ensuring the node group creation only happens after required IAM policies are attached
  depends_on = [
    aws_iam_role_policy_attachment.eks_worker_attach,
    aws_iam_role_policy_attachment.eks_cni_attach,
    aws_iam_role_policy_attachment.ecr_read_only_attach
  ]
}

# IAM Role for EKS Node Group
resource "aws_iam_role" "eks_node_role" {
  name = "eks-node-role-example"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

# Attach required policies for EKS worker nodes
resource "aws_iam_role_policy_attachment" "eks_worker_attach" {
  role       = aws_iam_role.eks_node_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSWorkerNodePolicy"
}

resource "aws_iam_role_policy_attachment" "eks_cni_attach" {
  role       = aws_iam_role.eks_node_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKS_CNI_Policy"
}

resource "aws_iam_role_policy_attachment" "ecr_read_only_attach" {
  role       = aws_iam_role.eks_node_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonEC2ContainerRegistryReadOnly"
}

# Variables to accept subnet IDs
variable "subnet_ids" {
  description = "List of subnet IDs to attach the EKS node group"
  type        = list(string)
}

