# Step 1: Define the IAM trust policy document that allows EKS pods to assume the role
data "aws_iam_policy_document" "example_assume_role" {
  statement {
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["pods.eks.amazonaws.com"]
    }

    actions = ["sts:AssumeRoleWithWebIdentity"]

    condition {
      test     = "StringEquals"
      variable = "pods.eks.amazonaws.com/aud"
      values   = ["sts.amazonaws.com"]
    }
  }
}

# Step 2: Create the IAM role that EKS pods can assume, using the above trust policy
resource "aws_iam_role" "example" {
  name               = "example-eks-pod-role"
  assume_role_policy = data.aws_iam_policy_document.example_assume_role.json

  # Required tags for EKS pod identity
  tags = {
    "eks.amazonaws.com/role-arn" = aws_iam_role.example.arn
  }
}

# Step 3: Attach the AWS managed S3 read-only policy to the IAM role
resource "aws_iam_role_policy_attachment" "s3_read_only" {
  role       = aws_iam_role.example.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3ReadOnlyAccess"
}

# Step 4: Define the EKS pod identity association to link the IAM role to a specific cluster, namespace, and service account
resource "aws_eks_pod_identity_association" "example" {
  cluster_name = "example"                 # Name of the EKS cluster
  namespace    = "example-namespace"       # Kubernetes namespace
  service_account = "example-serviceaccount" # Kubernetes service account
  role_arn     = aws_iam_role.example.arn  # ARN of the IAM role to associate
}

