  # Specify VPC configuration for the EKS cluster
  vpc_config {
    subnet_ids = [
      # Example subnet IDs — these should be replaced with actual subnet IDs from your VPC
      # "subnet-12345678",
      # "subnet-87654321"
    ]

    # Optional: Enable public access to the cluster API server
    endpoint_public_access  = true
    endpoint_private_access = true

    # Optional: Specify security group IDs if needed
    # security_group_ids = [aws_security_group.eks_cluster_sg.id]
  }

  # Ensure IAM role is created and policies are attached before creating the cluster
  depends_on = [
    aws_iam_role_policy_attachment.eks_cluster_policy,
    aws_iam_role_policy_attachment.eks_vpc_resource_controller,
  ]

  # Enable cluster logging
  enabled_cluster_log_types = [
    "api",
    "audit",
    "scheduler",
    "controllerManager",
    "authenticator"
  ]

