      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "eks.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the AmazonEKSClusterPolicy to the IAM role
resource "aws_iam_role_policy_attachment" "eks_cluster_policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSClusterPolicy"
  role       = aws_iam_role.eks_cluster_role.name

  # Ensures the role is created before attaching the policy
  depends_on = [aws_iam_role.eks_cluster_role]
}

# Retrieve existing VPC and subnets in us-east-1
data "aws_vpc" "main" {
  filter {
    name   = "tag:Name"
    values = ["*eks*"] # Adjust filter as needed to match your VPC
  }

  filter {
    name   = "availability-zone"
    values = ["us-east-1a", "us-east-1b"] # Ensures VPC has presence in at least these AZs
  }
}

data "aws_subnets" "eks_subnets" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.main.id]
  }

  filter {
    name   = "tag:kubernetes.io/role/elb"
    values = ["1"]
  }
}

# Create the EKS cluster
resource "aws_eks_cluster" "eks_cluster" {
  name     = "my-eks-cluster"
  role_arn = aws_iam_role.eks_cluster_role.arn
  version  = "1.29"

  vpc_config {
    subnet_ids = data.aws_subnets.eks_subnets.ids

    # Public access enabled, private access disabled per requirement
    endpoint_private_access = false
    endpoint_public_access  = true
  }

  # Ensure the IAM role policy is attached before creating the cluster
  depends_on = [
    aws_iam_role_policy_attachment.eks_cluster_policy
  ]

  # Required for EKS cluster to initialize properly
  enabled_cluster_log_types = []
}

# Output the EKS cluster endpoint and ARN for reference
output "eks_cluster_endpoint" {
  value = aws_eks_cluster.eks_cluster.endpoint
}

output "eks_cluster_arn" {
  value = aws_eks_cluster.eks_cluster.arn
}

output "iam_role_arn" {
  value = aws_iam_role.eks_cluster_role.arn
}

