# Step 1: Create an S3 bucket with forced destruction enabled
# - We need to set `force_destroy` to true so that the bucket can be destroyed even if it contains objects
# - The bucket name is specified as 'my_bucket'

# Step 2: Create an S3 bucket metric to monitor the entire bucket
# - We'll use aws_s3_bucket_metric to create a metric filter for the bucket
# - The metric will monitor all objects in the bucket using a filter rule

# Step 3: Create an S3 object (file) in the bucket
# - We need to define an object with a specific key (filename) and content
# - We'll use the aws_s3_object resource for this

resource "aws_s3_bucket" "my_bucket" {
  bucket = "my_bucket"
  force_destroy = true
}

resource "aws_s3_bucket_metric" "my_bucket_metric" {
  bucket = aws_s3_bucket.my_bucket.id
  name   = "my_bucket_metric"

  filter {
    prefix = ""
  }
}

resource "aws_s3_object" "my_object" {
  bucket = aws_s3_bucket.my_bucket.id
  key    = "my_object"
  content = "This is the content of my object stored in S3"
}

