extracted_code:
# This configuration sets up an S3 bucket and DynamoDB table for secure Terraform state management.
# Step-by-step considerations:
# 1. S3 bucket for state storage: Enable versioning for state history, server-side encryption for data protection,
#    block public access to prevent exposure, and enforce lifecycle policies.
# 2. Enable S3 bucket versioning to allow state rollback and prevent accidental overwrites.
# 3. Use AES256 server-side encryption for data at rest.
# 4. Block all public access to the S3 bucket to ensure security.
# 5. Protect against accidental deletion using a bucket-level lock (object lock) and enforce with a lifecycle rule.
# 6. DynamoDB table for state locking: Create with 'LockID' as the hash key (partition key), required by Terraform.
# 7. Use 'PAY_PER_REQUEST' (on-demand) billing mode for cost-effective scalability.
# 8. Enable point-in-time recovery on DynamoDB as an additional safety measure.

resource "aws_s3_bucket" "terraform_state" {
  bucket = "my-terraform-state-bucket-${random_id.suffix.hex}"

  versioning {
    enabled = true
  }

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true

  # Prevent deletion by enabling bucket-level locking with object lock (optional but recommended)
  object_lock_enabled = true

  object_lock_configuration {
    object_lock_enabled = "Enabled"
    rule {
      default_retention {
        mode = "GOVERNANCE"
        days = 1
      }
    }
  }
}

resource "aws_s3_bucket_public_access_block" "terraform_state" {
  bucket = aws_s3_bucket.terraform_state.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

resource "aws_dynamodb_table" "terraform_locks" {
  name         = "terraform-locks"
  billing_mode = "PAY_PER_REQUEST"
  hash_key     = "LockID"

  attribute {
    name = "LockID"
    type = "S"
  }

  # Enable point-in-time recovery for accidental write protection
  point_in_time_recovery {
    enabled = true
  }

  # Ensure TTL is not set, as Terraform state locks should persist manually
}

# Generate a unique suffix for the bucket name to avoid naming conflicts
resource "random_id" "suffix" {
  byte_length = 4
}

