resource "aws_s3_bucket" "wellcomecollection_platform_infra" {
  bucket = "wellcomecollection-platform-infra"

  # Prevent accidental destruction of the bucket
  lifecycle {
    prevent_destroy = true
  }

  # Set the ACL to private
  acl = "private"

  # Enable versioning
  versioning {
    enabled = true
  }

  # Configure lifecycle rules
  lifecycle_rule {
    # Rule for objects with prefix 'tmp/'
    id      = "temp-objects-expiry"
    prefix  = "tmp/"
    enabled = true

    expiration {
      days = 30
    }
  }

  lifecycle_rule {
    # Rule for versioning: transition non-current versions to STANDARD_IA after 30 days
    id      = "noncurrent-version-transition"
    enabled = true

    noncurrent_version_transition {
      days          = 30
      storage_class = "STANDARD_IA"
    }

    # Delete non-current versions after 90 days
    noncurrent_version_expiration {
      days = 90
    }
  }

  # Server-side encryption by default
  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }

  # Enforce HTTPS access
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Deny"
        Principal = "*"
        Action = "s3:*"
        Resource = [
          "${aws_s3_bucket.wellcomecollection_platform_infra.arn}",
          "${aws_s3_bucket.wellcomecollection_platform_infra.arn}/*"
        ]
        Condition = {
          Bool = {
            "aws:SecureTransport" = "false"
          }
        }
        Sid = "ForceSSLOnly"
      }
    ]
  })
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_s3_bucket" "platform_infra" {
  bucket_prefix = "wellcomecollection-platform-infra-"
}

resource "aws_s3_bucket_ownership_controls" "example" {
    bucket = aws_s3_bucket.platform_infra.id
    rule {
        object_ownership = "BucketOwnerPreferred"
    }
}

resource "aws_s3_bucket_acl" "platform_infra" {
  depends_on = [ aws_s3_bucket_ownership_controls.example ]

  bucket = aws_s3_bucket.platform_infra.id
  acl    = "private"
}

resource "aws_s3_bucket_lifecycle_configuration" "platform_infra" {
  bucket = aws_s3_bucket.platform_infra.id

  rule {
    id = "tmp"

    filter {
      prefix = "tmp/"
    }

    expiration {
      days = 30
    }

    status = "Enabled"
  }

  rule {
    id = "expire_old_versions"

    transition {
      days          = 30
      storage_class = "STANDARD_IA"
    }

    noncurrent_version_expiration {
      noncurrent_days = 90
    }

    status = "Enabled"
  }
}

resource "aws_s3_bucket_versioning" "platform_infra" {
  bucket = aws_s3_bucket.platform_infra.id

  versioning_configuration {
    status = "Enabled"
  }
}

