# Variables
variable "bucket_suffix" {
  description = "Suffix to append to bucket names"
  type        = string
  default     = "test"
}

# Provider
provider "aws" {
  region = "us-east-1"
}

# CloudGoat data storage bucket
resource "aws_s3_bucket" "cloudgoat_data" {
  bucket = "cloudgoat-data-${var.bucket_suffix}"

  acl    = "private"

  object_ownership = "ObjectWriter"

  versioning {
    enabled = false
  }

  tags = {
    Name        = "CloudGoat Data Bucket"
    Environment = "Production"
  }
}

# Web data storage bucket
resource "aws_s3_bucket" "web_data" {
  bucket = "web-data-${var.bucket_suffix}"

  acl    = "private"

  object_ownership = "ObjectWriter"

  versioning {
    enabled = false
  }

  tags = {
    Name        = "Web Data Bucket"
    Environment = "Production"
  }
}

# Public access block for web data bucket
resource "aws_s3_bucket_public_access_block" "web_data" {
  bucket = aws_s3_bucket.web_data.id

  ignore_public_acls   = true
  block_public_acls    = true
  restrict_public_buckets = true
  block_public_policy  = false
}

# Upload order_data2.csv to web data bucket
resource "aws_s3_object" "order_data" {
  bucket = aws_s3_bucket.web_data.id
  key    = "order_data2.csv"
  source = "path/to/order_data2.csv"
  etag   = filemd5("path/to/order_data2.csv")
}

# Bucket policy for web data bucket allowing s3:PutObject for all principals
resource "aws_s3_bucket_policy" "web_data_put_object" {
  bucket = aws_s3_bucket.web_data.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "AllowPutObject"
        Effect    = "Allow"
        Principal = "*"
        Action    = "s3:PutObject"
        Resource  = "${aws_s3_bucket.web_data.arn}/*"
      }
    ]
  })
}
