# Step 4: Create a bucket policy that allows s3:GetObject with a Referer condition
# This policy grants GetObject access to all principals only if the Referer header matches a specified value
resource "aws_s3_bucket_policy" "example_bucket_policy" {
  bucket = aws_s3_bucket.example_bucket.id

  policy = jsonencode({
    Version = "2012-10-17"
