  bucket = "your-bucket-name"

  # Enable S3 event notifications to the SNS topic
  notification {
    topic {
      topic_arn     = aws_sns_topic.s3_event_notification.arn
      events        = ["s3:ObjectCreated:*"]
      filter_suffix = ".log"
    }
  }
}

