}

# Step 2: Create the IAM policy document allowing S3 to publish to SNS
data "aws_iam_policy_document" "s3_to_sns" {
  statement {
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["s3.amazonaws.com"]
    }

    actions = [
      "SNS:Publish"
    ]

