# Step-by-step reasoning:
# 1. We need to create an S3 bucket with a specific name: "mybucket"
# 2. Versioning must be enabled on the bucket - this is a prerequisite for object lock
# 3. Object lock must be enabled at bucket creation time and cannot be disabled later
# 4. Object lock configuration includes:
#    - Object lock enabled at bucket level
#    - Default retention in COMPLIANCE mode with 5 days retention period
# 5. We'll use the same bucket resource for both versioning and object lock configuration
# 6. The bucket ID and ARN can be referenced using the resource attributes

resource "aws_s3_bucket" "mybucket" {
  bucket = "mybucket"

  # Enable object lock at bucket creation - required for retention configuration
  object_lock_enabled = true

  # Versioning configuration
  versioning {
    enabled = true
  }

  # Object lock configuration for default retention
  object_lock_configuration {
    object_lock_enabled = "Enabled"
    rule {
      default_retention {
        mode = "COMPLIANCE"
        days = 5
      }
    }
  }

  # Add a lifecycle rule to prevent accidental deletion
  lifecycle {
    prevent_destroy = true
  }
}

# Output the bucket details for reference
output "bucket_id" {
  value = aws_s3_bucket.mybucket.id
}

output "bucket_arn" {
  value = aws_s3_bucket.mybucket.arn
}

output "bucket_name" {
  value = aws_s3_bucket.mybucket.bucket
}

