# - One bucket will be set to private access (private_bucket)
# - The other will allow log delivery (logging_bucket) and receive logs

# Step 2: Set ACLs:
# - private_bucket: 'private' ACL to restrict access
# - logging_bucket: 'log-delivery-write' ACL to allow AWS to deliver logs

# Step 3: Enable logging on the private_bucket, directing logs to the logging_bucket
# - Use the target_bucket parameter to point to the logging_bucket
# - Specify a log_file_prefix for organized log storage

resource "aws_s3_bucket" "private_bucket" {
  bucket = "my-private-bucket-unique-name-12345"
  acl    = "private"

  tags = {
    Name        = "Private-Bucket"
    Environment = "production"
  }
}

resource "aws_s3_bucket" "logging_bucket" {
  bucket = "my-logging-bucket-unique-name-67890"
  acl    = "log-delivery-write"

  tags = {
    Name        = "Logging-Bucket"
    Environment = "production"
  }
}

# Step 4: Enable server access logging on the private bucket
# Logs will be delivered to the logging bucket with the specified prefix
resource "aws_s3_bucket_logging" "private_bucket_logging" {
  bucket = aws_s3_bucket.private_bucket.id
  target_bucket = aws_s3_bucket.logging_bucket.id
  target_prefix = "logs/"
}

