    enabled = true
  }

  # Block public access as a security best practice
  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Step 3: Upload an object to the S3 bucket with given key and source file
resource "aws_s3_object" "example_object" {
  bucket = aws_s3_bucket.example_bucket.bucket
  key    = "new_object_key"
  source = "path/to/file"

  # Enable server-side encryption by default
  server_side_encryption = "AES256"
}

# Output the bucket name and object key for reference
output "bucket_name" {
  value = aws_s3_bucket.example_bucket.bucket
}

output "object_key" {
  value = aws_s3_object.example_object.key
}

