```hcl
# Step-by-step breakdown:
# 1. Create a VPC with a CIDR block
# 2. Create a public and private subnet in the same AZ (or different if needed)
# 3. Set up Internet Gateway and route for public subnet
# 4. Set up NAT Gateway (required for private subnet outbound access)
# 5. Create route tables for public and private subnets
# 6. Create a key pair (or use existing) for EC2 access
# 7. Create a security group for web access (e.g., SSH and HTTP)
# 8. Create a Launch Template for consistent EC2 configuration
# 9. Create an EC2 Fleet with 5 On-Demand and 4 Spot instances using the launch template

provider "aws" {
  region = "us-west-2"
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "main-vpc"
  }
}

resource "aws_subnet" "public" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  map_public_ip_on_launch = true
  availability_zone       = "us-west-2a"

  tags = {
    Name = "public-subnet"
  }
}

resource "aws_subnet" "private" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-west-2a"

  tags = {
    Name = "private-subnet"
  }
}

resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "main-igw"
  }
}

resource "aws_eip" "nat_eip" {
  domain = "vpc"
}

resource "aws_nat_gateway" "nat_gw" {
  allocation_id = aws_eip.nat_eip.id
  subnet_id     = aws_subnet.public.id

  tags = {
    Name = "nat-gateway"
  }

  depends_on = [aws_internet_gateway.igw]
}

resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "public-route-table"
  }
}

resource "aws_route_table" "private_rt" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    nat_gateway_id = aws_nat_gateway.nat_gw.id
  }

  tags = {
    Name = "private-route-table"
  }
}

resource "aws_route_table_association" "public_assoc" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public_rt.id
}

resource "aws_route_table_association" "private_assoc" {
  subnet_id      = aws_subnet.private.id
  route_table_id = aws_route_table.private_rt.id
}

resource "aws_key_pair" "ec2_keypair" {
  key_name   = "ec2-keypair"
  public_key = "ssh-rsa AAAAB3NzaC1yc2EAAAADAQABAAABAQC6O0qWJzO9ZbV3XwF0t7a5X2u6bHg8Zq6vRl9WY8cPp8q5x1u6f3aX7v8n7qVW2k4q7s3c8d6f7g8h9j0k1m2n3o4p5q6r7s8t9u0v1w2x3y4z5 MyKey" # Replace with your public key
}

resource "aws_security_group" "web_sg" {
  name        = "web-security-group"
  description = "Allow SSH and HTTP inbound traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "web-sg"
  }
}

resource "aws_launch_template" "ec2_template" {
  name_prefix   = "ec2-launch-template-"
  image_id      = data.aws_ami.amzn2.id
  instance_type = "t3.micro"
  key_name      = aws_key_pair.ec2_keypair.key_name
  vpc_security_group_ids = [aws_security_group.web_sg.id]

  user_data = base64encode(<<-EOF
              #!/bin/bash
              yum update -y
              yum install -y httpd
              systemctl start httpd
              systemctl enable httpd
              echo "<h1>Deployed via Terraform</h1>" > /var/www/html/index.html
              EOF
  )

  tag_specifications {
    resource_type = "instance"
    tags = {
      Name = "Fleet-Instance"
    }
  }
}

data "aws_ami" "amzn2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }

  filter {
    name   = "virtualization-type"
    values = ["hvm"]
  }
}

resource "aws_ec2_fleet" "example_fleet" {
  target_capacity_specification {
    default_target_capacity_type = "spot"
    total_target_capacity        = 9
    on_demand_target_capacity    = 5
    spot_target_capacity         = 4
  }

  launch_template_config {
    launch_template_specification {
      name    = aws_launch_template.ec2_template.name
      version = "$$Latest"
    }

    overrides {
      subnet_id = aws_subnet.public.id
    }
  }

  fleet_type = "maintain"
}
```

