  }
}

resource "aws_db_instance" "database" {
  identifier           = "main-database"
  engine               = "mysql"
  engine_version       = "8.0"
  instance_class       = "db.t3.micro"
  allocated_storage    = 20
  storage_type         = "gp2"
  username             = "dbadmin"
  password             = "securepassword123"
  db_name              = "myapp"
