# Create a VPC with private subnets and launch two latest Amazon Linux 2 EC2 instances with EFS shared storage

provider "aws" {
  region = "us-east-1"
}

# Define VPC
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "private-ec2-efs-vpc"
  }
}

# Create two private subnets in different AZs
resource "aws_subnet" "private_subnet_1" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = data.aws_availability_zones.available.names[0]
  map_public_ip_on_launch = false

  tags = {
    Name = "private-subnet-1"
  }
}

resource "aws_subnet" "private_subnet_2" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = data.aws_availability_zones.available.names[1]
  map_public_ip_on_launch = false

  tags = {
    Name = "private-subnet-2"
  }
}

# Data source to get AZs
data "aws_availability_zones" "available" {
  state = "available"
}

# Internet Gateway for NAT (to allow private instances to reach internet)
resource "aws_internet_gateway" "gw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "main-igw"
  }
}

# EIP for NAT Gateway
resource "aws_eip" "nat_eip" {
  domain = "vpc"
}

# NAT Gateway to allow outbound internet access from private subnets
resource "aws_nat_gateway" "nat_gw" {
  allocation_id = aws_eip.nat_eip.id
  subnet_id     = aws_subnet.private_subnet_1.id

  tags = {
    Name = "nat-gateway"
  }

  # Ensure proper dependency
  depends_on = [aws_internet_gateway.gw]
}

# Route table for private subnets
resource "aws_route_table" "private_rt" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_nat_gateway.nat_gw.id
  }

  tags = {
    Name = "private-route-table"
  }
}

# Associate private subnets with route table
resource "aws_route_table_association" "private_subnet_1_assoc" {
  subnet_id      = aws_subnet.private_subnet_1.id
  route_table_id = aws_route_table.private_rt.id
}

resource "aws_route_table_association" "private_subnet_2_assoc" {
  subnet_id      = aws_subnet.private_subnet_2.id
  route_table_id = aws_route_table.private_rt.id
}

# Security Group for EC2 instances (allow SSH from bastion and EFS access)
resource "aws_security_group" "ec2_sg" {
  name        = "ec2-security-group"
  description = "Allow SSH and NFS access for EC2 instances"
  vpc_id      = aws_vpc.main.id

  # Allow SSH from trusted IPs (or bastion host)
  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]  # Allow SSH from within VPC (assuming bastion)
  }

  # Allow NFS traffic from VPC CIDR for EFS access
  ingress {
    from_port   = 2049
    to_port     = 2049
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "ec2-security-group"
  }
}

# EFS file system
resource "aws_efs_file_system" "efs" {
  creation_token = "efs-shared-storage"

  tags = {
    Name = "shared-efs"
  }
}

# EFS mount target in each private subnet
resource "aws_efs_mount_target" "mount_target_1" {
  file_system_id = aws_efs_file_system.efs.id
  subnet_id      = aws_subnet.private_subnet_1.id
  security_groups = [aws_security_group.ec2_sg.id]
}

resource "aws_efs_mount_target" "mount_target_2" {
  file_system_id = aws_efs_file_system.efs.id
  subnet_id      = aws_subnet.private_subnet_2.id
  security_groups = [aws_security_group.ec2_sg.id]
}

# Key pair for SSH access (you should provide your public key)
# resource "aws_key_pair" "deployer" {
#   key_name   = "deployer-key"
#   public_key = "ssh-rsa AAAAB3NzaC1yc2E... your-public-key-here"
# }

# User data script to mount EFS on instance launch
resource "aws_instance" "ec2_instance_1" {
  ami           = data.aws_ami.amzn2_ami.id
  instance_type = "t3.micro"
  subnet_id     = aws_subnet.private_subnet_1.id
  security_groups = [aws_security_group.ec2_sg.name]

  # key_name        = aws_key_pair.deployer.key_name
  associate_public_ip_address = false
  iam_instance_profile        = aws_iam_instance_profile.ec2_efs_profile.name

  user_data = <<-EOF
              #!/bin/bash
              yum update -y
              yum install -y amazon-efs-utils nfs-utils
              mkdir -p /efs
              echo "${aws_efs_file_system.efs.dns_name}:/ /efs efs defaults,_netdev 0 0" >> /etc/fstab
              mount -a
              EOF

  tags = {
    Name = "ec2-instance-1"
  }
}

resource "aws_instance" "ec2_instance_2" {
  ami           = data.aws_ami.amzn2_ami.id
  instance_type = "t3.micro"
  subnet_id     = aws_subnet.private_subnet_2.id
  security_groups = [aws_security_group.ec2_sg.name]

  # key_name        = aws_key_pair.deployer.key_name
  associate_public_ip_address = false
  iam_instance_profile        = aws_iam_instance_profile.ec2_efs_profile.name

  user_data = <<-EOF
              #!/bin/bash
              yum update -y
              yum install -y amazon-efs-utils nfs-utils
              mkdir -p /efs
              echo "${aws_efs_file_system.efs.dns_name}:/ /efs efs defaults,_netdev 0 0" >> /etc/fstab
              mount -a
              EOF

  tags = {
    Name = "ec2-instance-2"
  }
}

# Get latest Amazon Linux 2 AMI
data "aws_ami" "amzn2_ami" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-kernel-*"]
  }

  filter {
    name   = "architecture"
    values = ["x86_64"]
  }

  filter {
    name   = "root-device-type"
    values = ["ebs"]
  }
}

# IAM role to allow EC2 instances access to EFS (if needed)
resource "aws_iam_role" "ec2_efs_role" {
  name = "ec2-efs-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_instance_profile" "ec2_efs_profile" {
  name = "ec2-efs-profile"
  role = aws_iam_role.ec2_efs_role.name
}

# Optional: attach basic EBS and EFS access policies
resource "aws_iam_role_policy_attachment" "ec2_efs_policy" {
  role       = aws_iam_role.ec2_efs_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonElasticFileSystemReadOnlyAccess"
}

