# Step-by-step breakdown:
# 1. We need to create a RedShift cluster with exactly 2 nodes.
# 2. We need to define a resource policy and attach it to the cluster.
# 3. AWS RedShift uses IAM policies for managing access, so we'll use aws_redshift_cluster and aws_iam_policy + attach via aws_iam_policy_attachment or directly apply via resource policies if applicable.
# 4. However, note: RedShift does not directly accept an IAM resource-based policy like some other AWS services. Instead, access control is typically managed via IAM roles and cluster parameter groups.
# 5. But for use cases such as managing who can perform actions on the cluster (e.g., using RedShift Resource Policies for cross-account access or API-level permissions), AWS supports attaching a resource policy using aws_redshift_resource_policy.

# So:
# - Create a RedShift cluster with node_type and cluster_type set accordingly for a 2-node setup.
# - Use aws_redshift_resource_policy to attach a policy document to the cluster.

resource "aws_redshift_cluster" "example" {
  cluster_identifier = "example-redshift-cluster"
  database_name      = "exampledb"
  master_username    = "adminuser"
  master_password    = "SecurePassword123!" # In practice, use AWS Secrets Manager or tfvars with sensitive flag
  node_type          = "dc2.large"          # Example node type
  cluster_type       = "multi-node"
  number_of_nodes    = 2

  # Required parameters
  cluster_subnet_group_name = aws_redshift_subnet_group.example.name
  publicly_accessible        = false
  skip_final_snapshot        = true  # Not recommended for production
}

resource "aws_redshift_subnet_group" "example" {
  name       = "example-redshift-subnet-group"
  subnet_ids = [aws_subnet.subnet1.id, aws_subnet.subnet2.id]

  tags = {
    Name = "ExampleRedshiftSubnetGroup"
  }
}

# Mock subnets and VPC for completeness
resource "aws_vpc" "example" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "ExampleVPC"
  }
}

resource "aws_subnet" "subnet1" {
  vpc_id            = aws_vpc.example.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-west-2a"

  tags = {
    Name = "ExampleSubnet1"
  }
}

resource "aws_subnet" "subnet2" {
  vpc_id            = aws_vpc.example.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-west-2b"

  tags = {
    Name = "ExampleSubnet2"
  }
}

# Resource policy that allows certain actions on the cluster
# Example: Allow a specific IAM role to manage the cluster (e.g., from another account)
resource "aws_redshift_resource_policy" "example" {
  cluster_identifier = aws_redshift_cluster.example.cluster_identifier

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          AWS = "arn:aws:iam::123456789012:root"  # Example: allow root of another account
        }
        Action = [
          "redshift:GetClusterCredentials",
          "redshift:DescribeClusters"
        ]
        Resource = aws_redshift_cluster.example.arn
      }
    ]
  })
}

