```hcl
# Let's think through the requirements step by step:

# 1. We need an AWS Lambda function - this requires:
#    - A Lambda function resource
#    - A role/permission for Lambda to execute
#    - A simple function code (we'll use a basic example)

# 2. We need to invoke it every 15 minutes - this requires:
#    - An EventBridge (CloudWatch Events) rule with a rate of 15 minutes
#    - A target to connect the rule to the Lambda function
#    - Permissions for EventBridge to invoke the Lambda

# 3. We'll use a simple inline Python function for demonstration

resource "aws_iam_role" "lambda_role" {
  name = "lambda-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

resource "aws_lambda_function" "scheduled_function" {
  filename      = "lambda_function.zip"
  function_name = "scheduled-lambda-function"
  role          = aws_iam_role.lambda_role.arn
  handler       = "index.handler"
  runtime       = "python3.9"

  # Create a simple inline Lambda function
  source_code_hash = filebase64sha256("lambda_function.zip") # This would be your actual deployment package

  # Environment variables (optional)
  environment {
    variables = {
      FUNCTION_NAME = "scheduled-lambda-function"
    }
  }

  # Using placeholder for actual code
  lifecycle {
    ignore_changes = [source_code_hash] # This allows changes to the code without forcing recreation during testing
  }
}

# Create the EventBridge rule to trigger every 15 minutes
resource "aws_cloudwatch_event_rule" "lambda_schedule" {
  name                = "run-every-15-minutes"
  description         = "Run Lambda function every 15 minutes"
  schedule_expression = "rate(15 minutes)"
}

# Add permission for EventBridge to invoke the Lambda
resource "aws_lambda_permission" "allow_cloudwatch" {
  statement_id  = "AllowExecutionFromCloudWatch"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.scheduled_function.function_name
  principal     = "events.amazonaws.com"
  source_arn    = aws_cloudwatch_event_rule.lambda_schedule.arn
}

# Set the Lambda function as the target of the EventBridge rule
resource "aws_cloudwatch_event_target" "lambda_target" {
  rule      = aws_cloudwatch_event_rule.lambda_schedule.name
  target_id = "lambda-scheduled-target"
  arn       = aws_lambda_function.scheduled_function.arn
}
```

