# Create DynamoDB tables in three regions: us-east-1, us-west-1, and us-west-2
# Since Terraform manages resources per provider configuration, and each region requires a separate provider instance,
# we'll configure multiple AWS providers and associate each table with the appropriate provider.

provider "aws" {
  region = "us-east-1"
  alias  = "us-east-1"
}

provider "aws" {
  region = "us-west-1"
  alias  = "us-west-1"
}

provider "aws" {
  region = "us-west-2"
  alias  = "us-west-2"
}

# Define a DynamoDB table in us-east-1
resource "aws_dynamodb_table" "table_us_east_1" {
  provider = aws.us-east-1

  name           = "example-table-us-east-1"
  billing_mode   = "PROVISIONED"
  read_capacity  = 5
  write_capacity = 5
  hash_key       = "id"

  attribute {
    name = "id"
    type = "S"
  }

  # Enable server-side encryption
  server_side_encryption {
    enabled = true
  }

  # Enable point-in-time recovery
  point_in_time_recovery {
    enabled = true
  }
}

# Define a DynamoDB table in us-west-1
