# Creating a DynamoDB Global Table with replicas requires:
# 1. A DynamoDB table in the primary region with stream enabled (required for global tables)
# 2. Enabling global tables which will allow replication to other regions
# 3. Specifying replica regions where the table should be replicated

# We'll use AWS provider (assumes provider is configured separately)
# The stream_view_type must be set (e.g., NEW_AND_OLD_IMAGES) for global tables

resource "aws_dynamodb_table" "global_table" {
  name             = "example-global-table"
  billing_mode     = "PAY_PER_REQUEST" # Required for global tables (on-demand)
  hash_key         = "id"
  stream_enabled   = true
  stream_view_type = "NEW_AND_OLD_IMAGES" # Required for global tables

  attribute {
    name = "id"
    type = "S"
  }

  # Global table configuration - list of regions where replicas will be created
  # Note: AWS manages the replication, we just specify the regions
  global_secondary_index {
    # Example GSI - optional, but included to show structure
    name               = "gsi-example"
    hash_key           = "category"
    range_key          = "created_date"
    projection_type    = "ALL"
    read_capacity      = 1
    write_capacity     = 1
  }

  replica {
    region_name = "us-west-2"
  }

  replica {
    region_name = "eu-west-1"
  }

  # Point-in-time recovery can be enabled for disaster recovery
  point_in_time_recovery {
    enabled = true
  }

  tags = {
    Environment = "production"
    ManagedBy   = "Terraform"
  }
}

# Note: The provider must be configured with multiple regions to manage replicas
# Example provider configuration would include:
# provider "aws" {
#   region = "us-east-1"
# }
#
# provider "aws" {
#   alias  = "uswest2"
#   region = "us-west-2"
# }
#
# provider "aws" {
#   alias  = "euwest1"
#   region = "eu-west-1"
# }
#
# However, with modern Terraform and AWS provider >= 3.0, cross-region resources
# can be managed without explicitly defining aliased providers when using replicas
# in the dynamodb_table resource.

