# The stream_view_type must be set (e.g., NEW_AND_OLD_IMAGES) for global tables

resource "aws_dynamodb_table" "global_table" {
  name             = "example-global-table"
  billing_mode     = "PAY_PER_REQUEST" # Required for global tables (on-demand)
  hash_key         = "id"
  stream_enabled   = true
  stream_view_type = "NEW_AND_OLD_IMAGES" # Required for global tables

  attribute {
    name = "id"
    type = "S"
  }

  # Global table configuration - list of regions where replicas will be created
  # Note: AWS manages the replication, we just specify the regions
  global_secondary_index {
    # Example GSI - optional, but included to show structure
