```hcl
# Create two subnets in different availability zones and launch Amazon Linux 2 instances with EBS volumes

# Configure provider
provider "aws" {
  region = "us-east-1"
}

# Data source to get the latest Amazon Linux 2 AMI
data "aws_ami" "amazon_linux2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }

  filter {
    name   = "virtualization-type"
    values = ["hvm"]
  }
}

# Create a VPC (required for subnets)
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "subnet-example-vpc"
  }
}

# Create Internet Gateway for the VPC
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "subnet-example-igw"
  }
}

# Create public route table
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "subnet-example-public-rt"
  }
}

# Create subnet in us-east-1a
resource "aws_subnet" "subnet_a" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = true

  tags = {
    Name = "subnet-us-east-1a"
  }
}

# Create subnet in us-east-1b
resource "aws_subnet" "subnet_b" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-east-1b"
  map_public_ip_on_launch = true

  tags = {
    Name = "subnet-us-east-1b"
  }
}

# Associate subnets with the public route table
resource "aws_route_table_association" "subnet_a_association" {
  subnet_id      = aws_subnet.subnet_a.id
  route_table_id = aws_route_table.public.id
}

resource "aws_route_table_association" "subnet_b_association" {
  subnet_id      = aws_subnet.subnet_b.id
  route_table_id = aws_route_table.public.id
}

# Create a security group to allow SSH access
resource "aws_security_group" "allow_ssh" {
  name        = "allow_ssh"
  description = "Allow SSH inbound traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "allow_ssh"
  }
}

# Create 50 GB EBS volume for first instance
resource "aws_ebs_volume" "ebs_volume_a" {
  availability_zone = "us-east-1a"
  size              = 50
  type              = "gp2"

  tags = {
    Name = "ebs-volume-instance-a"
  }
}

# Create 50 GB EBS volume for second instance
resource "aws_ebs_volume" "ebs_volume_b" {
  availability_zone = "us-east-1b"
  size              = 50
  type              = "gp2"

  tags = {
    Name = "ebs-volume-instance-b"
  }
}

# Create EC2 instance in us-east-1a with the latest Amazon Linux 2 AMI and t2.micro
resource "aws_instance" "instance_a" {
  ami           = data.aws_ami.amazon_linux2.id
  instance_type = "t2.micro"
  subnet_id     = aws_subnet.subnet_a.id
  security_groups = [aws_security_group.allow_ssh.name]
  associate_public_ip_address = true

  tags = {
    Name = "instance-us-east-1a"
  }
}

# Create EC2 instance in us-east-1b with the latest Amazon Linux 2 AMI and t2.micro
resource "aws_instance" "instance_b" {
  ami           = data.aws_ami.amazon_linux2.id
  instance_type = "t2.micro"
  subnet_id     = aws_subnet.subnet_b.id
  security_groups = [aws_security_group.allow_ssh.name]
  associate_public_ip_address = true

  tags = {
    Name = "instance-us-east-1b"
  }
}

# Attach EBS volumes to instances
resource "aws_volume_attachment" "ebs_att_a" {
  device_name = "/dev/sdh"
  volume_id   = aws_ebs_volume.ebs_volume_a.id
  instance_id = aws_instance.instance_a.id
}

resource "aws_volume_attachment" "ebs_att_b" {
  device_name = "/dev/sdh"
  volume_id   = aws_ebs_volume.ebs_volume_b.id
  instance_id = aws_instance.instance_b.id
}
```

