# We'll create a full configuration for an EC2 Fleet with launch templates inside public and private subnets.
# Steps:
# 1. Define necessary providers (AWS) and optionally set a region.
# 2. Create a VPC.
# 3. Create public and private subnets in the VPC.
# 4. Create an internet gateway for public access.
# 5. Set up route tables for public (with IGW) and private (no direct IGW).
# 6. Create a launch template for AWS Linux 2 AMI (latest) and t3.micro or similar instance.
# 7. Define an EC2 Fleet with 5 On-Demand and 4 Spot instances using the launch template.
# 8. Output relevant info.

# Note: We'll use dynamic latest Amazon Linux 2 AMI and assume us-west-2 region.

provider "aws" {
  region = "us-west-2"
}

data "aws_availability_zones" "available" {
  state = "available"
}

data "aws_ami" "amzn2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }

  filter {
    name   = "virtualization-type"
    values = ["hvm"]
  }
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "ec2-fleet-vpc"
  }
}

resource "aws_subnet" "public" {
  count                   = 1
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = true

  tags = {
    Name = "public-subnet"
  }
}

resource "aws_subnet" "private" {
  count             = 1
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = data.aws_availability_zones.available.names[count.index]

  tags = {
    Name = "private-subnet"
  }
}

resource "aws_internet_gateway" "gw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "main-igw"
  }
}

resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.gw.id
  }

  tags = {
    Name = "public-route-table"
  }
}

resource "aws_route_table_association" "public" {
  count          = length(aws_subnet.public)
  subnet_id      = aws_subnet.public[count.index].id
  route_table_id = aws_route_table.public.id
}

resource "aws_route_table" "private" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "private-route-table"
  }
}

resource "aws_route_table_association" "private" {
  count          = length(aws_subnet.private)
  subnet_id      = aws_subnet.private[count.index].id
  route_table_id = aws_route_table.private.id
}

resource "aws_launch_template" "fleet_template" {
  name   = "ec2-fleet-launch-template"
  image_id = data.aws_ami.amzn2.id
  instance_type = "t3.micro"
  key_name = "your-key-pair" # Replace or use actual key pair
  user_data = base64encode("#!/bin/bash
echo 'Hello from EC2 Fleet' > /home/ec2-user/message.txt")

  network_interfaces {
    associate_public_ip_address = true
    subnet_id                     = aws_subnet.public[0].id
    security_groups               = [aws_security_group.allow_ssh.id]
  }

  tags = {
    Name = "EC2-Fleet-Instance"
  }
}

resource "aws_security_group" "allow_ssh" {
  name        = "allow_ssh"
  description = "Allow SSH inbound"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "SSH"
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_ec2_fleet" "example" {
  launch_template_config {
    launch_template_specification {
      name    = aws_launch_template.fleet_template.name
      version = "$$Latest"
    }
  }

  target_capacity_specification {
    default_target_capacity_type = "maintain"
    total_target_capacity        = 9
    on_demand_target_capacity    = 5
    spot_target_capacity         = 4
  }

  fleet_type = "maintain" # Ensures fleet maintains capacity even after instance termination

  tags = {
    Name = "example-fleet"
  }
}

output "vpc_id" {
  value = aws_vpc.main.id
}

output "public_subnet_id" {
  value = aws_subnet.public[0].id
}

output "private_subnet_id" {
  value = aws_subnet.private[0].id
}

output "fleet_instance_ids" {
  value = aws_ec2_fleet.example.instance_set[*].instance_ids
}

