    to_port     = 2049
    protocol    = "tcp"
    source_security_group_id = aws_security_group.ec2.id
  }

  egress {
    from_port        = 0
    to_port          = 0
    protocol         = -1
    cidr_blocks      = ["0.0.0.0/0"]
    ipv6_cidr_blocks = ["::/0"]
  }

  tags = {
