  }
}

resource "aws_subnet" "public" {
  count = 2

  vpc_id               = aws_vpc.main.id
  cidr_block           = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index + 1)
  availability_zone    = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = true

  tags = {
    Name = "public-subnet-${count.index}"
  }
}

resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "public-route-table"
  }
}

resource "aws_route_table" "private" {
  count = 2

  vpc_id = aws_vpc.main.id

  route {
    cidr_block     = "0.0.0.0/0"
    nat_gateway_id = aws_nat_gateway.nat[count.index].id
  }

  tags = {
    Name = "private-route-table-${count.index}"
  }
}

resource "aws_route_table_association" "public" {
  count = 2

  subnet_id      = aws_subnet.public[count.index].id
  route_table_id = aws_route_table.public.id
}

resource "aws_route_table_association" "private" {
  count = 2

  subnet_id      = aws_subnet.private[count.index].id
  route_table_id = aws_route_table.private[count.index].id
}

resource "aws_security_group" "ec2" {
  name   = "instance-allow-ssh-nfs"
  vpc_id = aws_vpc.main.id

  # Allow SSH from your IP (optional; remove if not needed)
  # egress
  egress {
    from_port        = 0
    to_port          = 0
    protocol         = -1
    cidr_blocks      = ["0.0.0.0/0"]
    ipv6_cidr_blocks = ["::/0"]
  }

  # Self-referencing rule for EFS NFS access
  ingress {
    from_port = 2049
    to_port   = 2049
    protocol  = "tcp"
    self      = true
  }

  tags = {
    Name = "ec2-security-group"
  }
}

resource "aws_security_group" "efs" {
  name   = "efs-access"
  vpc_id = aws_vpc.main.id

  ingress {
    from_port   = 2049
    to_port     = 2049
    protocol    = "tcp"
    source_security_group_id = aws_security_group.ec2.id
  }

  egress {
    from_port        = 0
    to_port          = 0
    protocol         = -1
    cidr_blocks      = ["0.0.0.0/0"]
    ipv6_cidr_blocks = ["::/0"]
  }

  tags = {
    Name = "efs-security-group"
  }
}

resource "aws_efs_file_system" "shared" {
  encrypted = true

  tags = {
    Name = "shared-efs"
  }
}

resource "aws_efs_mount_target" "mount_target" {
  count = 2

  file_system_id  = aws_efs_file_system.shared.id
  subnet_id       = aws_subnet.private[count.index].id
  security_groups = [aws_security_group.efs.id]
}

resource "aws_iam_role" "ec2_role" {
  name = "ec2-efs-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "ec2_policy" {
  role       = aws_iam_role.ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSSMManagedInstanceCore"
}

resource "aws_iam_instance_profile" "ec2_profile" {
  name = "ec2-efs-profile"
  role = aws_iam_role.ec2_role.name
}

resource "aws_instance" "web" {
  count = 2

  ami                    = data.aws_ami.amazon_linux_latest.id
  instance_type          = "t3.micro"
  subnet_id              = aws_subnet.private[count.index].id
  private_ip             = cidrhost(aws_subnet.private[count.index].cidr_block, 10)
  security_groups        = [aws_security_group.ec2.name]
  iam_instance_profile   = aws_iam_instance_profile.ec2_profile.name
  source_dest_check      = false
  user_data_replace_on_change = true

  user_data = <<-EOF
              #!/bin/bash
              yum update -y
              yum install -y amazon-efs-utils nfs-utils
              mkdir -p /mnt/efs
              echo "${aws_efs_file_system.shared.dns_name}:/ /mnt/efs efs defaults,_netdev,nofail 0 0" >> /etc/fstab
              mount -a
              EOF

  tags = {
    Name = "web-instance-${count.index}"
  }
}
