# Let's break down the requirements step by step:
# 1. We need to create an MSK (Managed Streaming for Kafka) cluster on AWS
# 2. The cluster should have 3 broker nodes
# 3. We need to consider required supporting resources:
#    - VPC with subnets (at least 2 subnets in different AZs, but 3 preferred for 3 brokers)
#    - Security group for the MSK cluster
#    - IAM roles for MSK
#    - Configuration for the Kafka cluster

resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-vpc"
  }
}

resource "aws_subnet" "msk_subnets" {
  count             = 3
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = cidrsubnet(aws_vpc.msk_vpc.cidr_block, 8, count.index)
  availability_zone = element(data.aws_availability_zones.available.names, count.index)

  tags = {
    Name = "msk-subnet-${count.index + 1}"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_security_group" "msk_security_group" {
  name   = "msk-security-group"
  vpc_id = aws_vpc.msk_vpc.id

  # Kafka clients
  ingress {
    from_port   = 9092
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Kafka encrypted
  ingress {
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # SSH access (optional, for debugging)
  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-security-group"
  }
}

resource "aws_iam_role" "msk_role" {
  name = "msk-instance-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kafka.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "msk_policy_attachment" {
  role       = aws_iam_role.msk_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonMSKClusterPolicy"
}

resource "aws_msk_configuration" "example" {
  name    = "example"
  kafka_versions = ["2.8.1", "2.8.2"]

  server_properties = <<EOF
auto.create.topics.enable = true
log.retention.hours = 168
log.segment.bytes = 1073741824
log.retention.check.interval.ms = 300000
num.network.threads = 3
num.io.threads = 8
socket.send.buffer.bytes = 102400
socket.receive.buffer.bytes = 102400
socket.request.max.bytes = 104857600
num.partitions = 1
num.recovery.threads.per.data.dir = 1
offsets.topic.replication.factor = 3
transaction.state.log.replication.factor = 3
transaction.state.log.min.isr = 2
log.cleanup.policy = delete
