```hcl
# Let's break down the requirements step by step:
# 1. We need to create an MSK (Managed Streaming for Kafka) cluster on AWS
# 2. The cluster should have 3 broker nodes
# 3. We need to consider required supporting resources:
#    - VPC with subnets (at least 2 subnets in different AZs, but 3 preferred for 3 brokers)
#    - Security group for the MSK cluster
#    - IAM roles for MSK
#    - Configuration for the Kafka cluster

resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-vpc"
  }
}

resource "aws_subnet" "msk_subnets" {
  count             = 3
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = cidrsubnet(aws_vpc.msk_vpc.cidr_block, 8, count.index)
  availability_zone = element(data.aws_availability_zones.available.names, count.index)

  tags = {
    Name = "msk-subnet-${count.index + 1}"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_security_group" "msk_security_group" {
  name   = "msk-security-group"
  vpc_id = aws_vpc.msk_vpc.id

  # Kafka clients
  ingress {
    from_port   = 9092
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Kafka encrypted
  ingress {
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # SSH access (optional, for debugging)
  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-security-group"
  }
}

resource "aws_iam_role" "msk_role" {
  name = "msk-instance-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kafka.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "msk_policy_attachment" {
  role       = aws_iam_role.msk_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonMSKClusterPolicy"
}

resource "aws_msk_configuration" "example" {
  name    = "example"
  kafka_versions = ["2.8.1", "2.8.2"]

  server_properties = <<EOF
auto.create.topics.enable = true
log.retention.hours = 168
log.segment.bytes = 1073741824
log.retention.check.interval.ms = 300000
num.network.threads = 3
num.io.threads = 8
socket.send.buffer.bytes = 102400
socket.receive.buffer.bytes = 102400
socket.request.max.bytes = 104857600
num.partitions = 1
num.recovery.threads.per.data.dir = 1
offsets.topic.replication.factor = 3
transaction.state.log.replication.factor = 3
transaction.state.log.min.isr = 2
log.cleanup.policy = delete
zookeeper.session.timeout.ms = 18000
group.min.session.timeout.ms = 6000
group.max.session.timeout.ms = 300000
group.initial.rebalance.delay.ms = 3000
default.replication.factor = 3
min.insync.replicas = 2
replica.lag.time.max.ms = 30000
replica.socket.timeout.ms = 30000
replica.fetch.wait.max.ms = 500
replica.fetch.min.bytes = 1
replica.fetch.response.max.bytes = 10485760
num.replica.fetchers = 1
delete.topic.enable = true
EOF
}

resource "aws_msk_cluster" "example" {
  cluster_name           = "example-cluster"
  kafka_version          = "2.8.2"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type  = "kafka.m5.large"
    client_subnets = aws_subnet.msk_subnets[*].id
    security_groups = [aws_security_group.msk_security_group.id]

    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  configuration_info {
    arn      = aws_msk_configuration.example.arn
    revision = aws_msk_configuration.example.latest_revision
  }

  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.msk.arn
  }

  # Enable encryption in transit
  client_authentication {
    tls {
      certificate_authority_arns = [aws_acm_certificate.certificate.arn]
    }
  }

  tags = {
    Environment = "production"
  }
}

resource "aws_kms_key" "msk" {
  description             = "KMS key for MSK cluster"
  enable_key_rotation     = true
}

resource "aws_acm_certificate" "certificate" {
  private_key      = file("${path.module}/private-key.pem")
  certificate_body = file("${path.module}/certificate.pem")
}
