# Amazon MSK (Managed Streaming for Kafka) cluster configuration
# We are creating a managed MSK cluster with 3 broker nodes in the us-east-1 region.
# Steps:
# 1. Define AWS provider with us-east-1 region.
# 2. Create a VPC and subnets (at least two) for MSK (highly available across AZs).
# 3. Create a security group for the MSK cluster.
# 4. Define the MSK cluster configuration with 3 broker nodes (3 AZs), using kafka.m5.large instance type (example).
# 5. Use a client subnets list (2 or 3 subnets in different AZs in us-east-1).
# 6. Enable encryption, logging, and other best practices as needed.

provider "aws" {
  region = "us-east-1"
}

# Create a VPC for the MSK cluster
resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-vpc"
  }
}

# Create three public subnets in different AZs for high availability
resource "aws_subnet" "msk_subnets" {
  count             = 3
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = cidrsubnet(aws_vpc.msk_vpc.cidr_block, 8, count.index)
  availability_zone = "us-east-1${element(["a", "b", "c"], count.index)}"

  tags = {
    Name = "msk-subnet-${element(["a", "b", "c"], count.index)}"
  }
}

# Create a security group for the MSK cluster
resource "aws_security_group" "msk_cluster_sg" {
  name        = "msk-cluster-security-group"
  description = "Security group for MSK cluster"
  vpc_id      = aws_vpc.msk_vpc.id

  # Allow inbound traffic on Kafka ports (9094 for TLS internal, 9096 for TLS internet, 9092 for plaintext - only internal)
  # Best practice: restrict source IPs as needed; here broad for example
  ingress {
    description = "Kafka Client"
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-cluster-sg"
  }
}

# Create the MSK cluster
resource "aws_msk_cluster" "msk_cluster" {
  cluster_name           = "managed-msk-cluster"
  kafka_version          = "3.5.1"  # Use latest stable version
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type = "kafka.m5.large"  # Example instance type

    client_subnets = [
      aws_subnet.msk_subnets[0].id,
      aws_subnet.msk_subnets[1].id,
      aws_subnet.msk_subnets[2].id,
    ]

    security_groups = [aws_security_group.msk_cluster_sg.id]

    storage_info {
      ebs_storage_info {
        volume_size = 1000  # GB
      }
    }
  }

  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.msk_kms.key_id
    encryption_in_transit {
      client_broker = "TLS"
      in_cluster    = true
    }
  }

  # Enable logging to CloudWatch (optional but recommended)
  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = "/aws/msk/managed-msk-cluster"
      }
    }
  }

  # Enhanced monitoring (optional)
  enhanced_monitoring = "PER_BROKER"

  # Cleanup on destroy
  tags = {
    Environment = "dev"
  }

  # Set cluster termination protection to prevent accidental deletion
  cluster_operation = "None"
}

# Create a KMS key for encryption at rest
resource "aws_kms_key" "msk_kms" {
  description             = "KMS key for MSK cluster encryption"
  enable_key_rotation     = true

  tags = {
    Name = "msk-kms-key"
  }
}

# Optionally, create a log group for CloudWatch logs
resource "aws_cloudwatch_log_group" "msk_log_group" {
  name              = "/aws/msk/managed-msk-cluster"
  retention_in_days = 7
}

