# 3. We need a VPC with subnets (at least 2 subnets in different AZs, but for 3 brokers, 3 subnets ideal).
# 4. Create a security group for the MSK cluster allowing broker communication.
# 5. Define the MSK cluster with 3 broker nodes using a multi-AZ configuration.
# 6. Use an Apache Kafka version and specify broker instance type.
# 7. Enable zookeeper and set up client authentication and encryption as needed (basic config).

provider "aws" {
  region = "us-east-2"
}

resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-vpc"
  }
}

resource "aws_subnet" "msk_subnets" {
  count             = 3
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.${count.index + 1}.0/24"
  availability_zone = "us-east-2${element(["a", "b", "c"], count.index)}"

  tags = {
    Name = "msk-subnet-${count.index + 1}"
  }
}

resource "aws_security_group" "msk_cluster_sg" {
  name        = "msk-cluster-security-group"
  description = "Security group for MSK cluster"
  vpc_id      = aws_vpc.msk_vpc.id

  # Allow all outbound
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow inbound on common MSK ports (2181, 9092, 9094 etc.)
  ingress {
    from_port   = 2181
    to_port     = 2181
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  ingress {
    from_port   = 9092
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  ingress {
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  tags = {
    Name = "msk-cluster-sg"
  }
}

resource "aws_kms_key" "msk_kms" {
  description             = "KMS key for encrypting MSK cluster"
  enable_key_rotation     = true
  deletion_window_in_days = 10
}

resource "aws_msk_cluster" "example" {
  cluster_name           = "example-msk-cluster"
  kafka_version          = "3.5.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type   = "kafka.m5.large"
    client_subnets  = aws_subnet.msk_subnets[*].id
    security_groups = [aws_security_group.msk_cluster_sg.id]

    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.msk_kms.arn
    encryption_in_transit {
      client_broker = "TLS"
      in_cluster    = true
    }
  }

  client_authentication {
    tls {
      certificate_authority_arns = []
    }
  }

  configuration_info {
    # Optional: if using custom configuration
    # arn      = aws_msk_configuration.example.arn
    # revision = aws_msk_configuration.example.latest_revision
  }

  tags = {
    Environment = "dev"
  }

  # Ensure cluster is inside the VPC and subnets
  depends_on = [
    aws_internet_gateway.msk_igw
  ]
}

# Internet gateway for public internet access (for updates, DNS, etc., though brokers may be private)
resource "aws_internet_gateway" "msk_igw" {
  vpc_id = aws_vpc.msk_vpc.id

  tags = {
    Name = "msk-igw"
  }
}

