# Note: The request mentions "us-east1" which is a Google Cloud region, but MSK (Managed Streaming for Kafka) is an AWS service (Amazon Managed Streaming for Kafka).
# Therefore, there's a conflict in the request. Since MSK is AWS-specific, I'll proceed with AWS resources.
# However, if the intent was Google Cloud, note that GCP does not have an "MSK" service — it has "Pub/Sub" or other solutions.
# Assuming the user meant AWS MSK in region us-east-1 (note: AWS uses "us-east-1", not "us-east1"), we proceed accordingly.
# We will create:
# 1. An AWS MSK cluster (Kafka) with default settings.
# 2. A CloudWatch log group for storing broker logs.
# 3. Required IAM roles and policies for MSK to write logs to CloudWatch.

resource "aws_cloudwatch_log_group" "msk_logs" {
  name = "/aws/msk/terraform-msk-cluster"
  retention_in_days = 7
}

resource "aws_kms_key" "msk_kms" {
  description = "KMS key for encrypting MSK cluster"
  enable_key_rotation = true
}

resource "aws_vpc" "msk_vpc" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "msk-vpc"
  }
}

resource "aws_subnet" "msk_subnet_az1" {
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "msk-subnet-az1"
  }
}

resource "aws_subnet" "msk_subnet_az2" {
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "msk-subnet-az2"
  }
}

resource "aws_security_group" "msk_sg" {
  name   = "msk-cluster-sg"
  vpc_id = aws_vpc.msk_vpc.id

  # Allow TLS from clients (if needed)
  ingress {
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow SSH for monitoring/debugging (in real use, restrict this)
  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-security-group"
  }
}

resource "aws_msk_cluster" "example" {
  cluster_name           = "terraform-msk-cluster"
  kafka_version          = "3.5.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type = "kafka.m5.large"
    client_subnets = [
      aws_subnet.msk_subnet_az1.id,
      aws_subnet.msk_subnet_az2.id,
    ]
    security_groups = [aws_security_group.msk_sg.id]
    storage_info {
      ebs_storage_info {
        volume_size = 1000
      }
    }
  }

  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.msk_kms.arn
  }

  # Enable logging to CloudWatch
  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_logs.name
      }
      # If you have S3 or Firehose, they can be added; otherwise, disable
      firehose {
        enabled = false
      }
      s3 {
        enabled = false
      }
    }
  }

  tags = {
    Environment = "test"
  }

  # Ensure VPC flow logs or ENI policies don't interfere
  depends_on = [
    aws_cloudwatch_log_group.msk_logs,
    aws_kms_key.msk_kms
  ]
}

# IAM role for MSK to use CloudWatch
resource "aws_iam_role" "msk_cloudwatch_logs" {
  name = "msk-cloudwatch-logs-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kafka.amazonaws.com"
        }
      },
    ]
  })
}

resource "aws_iam_role_policy_attachment" "msk_cloudwatch_logs" {
  role       = aws_iam_role.msk_cloudwatch_logs.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonMSKCloudWatchLogsRole"
}

# Associate IAM role with MSK cluster via resource policy
# Note: MSK automatically uses the role if referenced, but we need to attach it to the cluster
# However, the MSK cluster resource does not directly support IAM role attachment.
# Instead, we ensure the MSK cluster can use the role via the AWS managed policy and trust relationship.

