```hcl
# Note: As of current AWS capabilities (2024), Amazon MSK (Managed Streaming for Kafka) 
# does not support "serverless" mode with configurable broker nodes like provisioned clusters.
# Serverless MSK does not allow specifying the number of broker nodes — it's fully auto-scaling.
# However, if you want a provisioned MSK cluster with 3 broker nodes, here's the configuration.
# If you specifically need Serverless, broker count is not applicable.

# Required providers
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Create an MSK cluster (provisioned with 3 broker nodes)
resource "aws_msk_cluster" "example" {
  cluster_name           = "example-msk-cluster"
  kafka_version          = "3.6.1" # Use the latest available version
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type = "kafka.m7g.large" # Serverless doesn't use instance types, but provisioned does

    client_subnets = [
      aws_subnet.example_subnet_1.id,
      aws_subnet.example_subnet_2.id,
      aws_subnet.example_subnet_3.id
    ]

    security_groups = [aws_security_group.msk_security_group.id]
  }

  # Enable encryption and other settings as needed
  encryption_info {
    encryption_in_transit {
      client_broker = "TLS"
      in_cluster    = true
    }
  }

  client_authentication {
    tls {
      certificate_authority_arns = [aws_acm_certificate.certificate.arn]
    }
  }

  # Enable logging to Cloud Watch (optional)
  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = false
      }
      firehose {
        enabled = false
      }
      s3 {
        enabled = false
      }
    }
  }

  # Zookeeper connectivity is being deprecated; use IAM if possible
  # Enhanced monitoring can be set
  configuration_info {
    arn      = aws_msk_configuration.example.arn
    revision = aws_msk_configuration.example.latest_revision
  }

  tags = {
    Environment = "test"
  }
}

# Example VPC and subnets (required for MSK)
resource "aws_vpc" "example" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "example-vpc"
  }
}

resource "aws_subnet" "example_subnet_1" {
  vpc_id            = aws_vpc.example.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-west-2a"

  tags = {
    Name = "example-subnet-1"
  }
}

resource "aws_subnet" "example_subnet_2" {
  vpc_id            = aws_vpc.example.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-west-2b"

  tags = {
    Name = "example-subnet-2"
  }
}

resource "aws_subnet" "example_subnet_3" {
  vpc_id            = aws_vpc.example.id
  cidr_block        = "10.0.3.0/24"
  availability_zone = "us-west-2c"

  tags = {
    Name = "example-subnet-3"
  }
}

# Security group for MSK
resource "aws_security_group" "msk_security_group" {
  vpc_id = aws_vpc.example.id

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/8"]
  }

  tags = {
    Name = "msk-security-group"
  }
}

# MSK Configuration (optional)
resource "aws_msk_configuration" "example" {
  name    = "example-msk-config"
  kafka_versions = ["3.6.1"]
  server_properties = <<PROPERTIES
auto.create.topics.enable = true
kafka.metrics.reporters = aws.ms.cloudwatch.metrics.reporter
PROPERTIES
}

# Certificate for TLS authentication (simplified; in practice use ACM PCA)
resource "aws_acm_certificate" "certificate" {
  private_key      = file("path/to/private.key")
  certificate_body = file("path/to/certificate.pem")
}
```

