```hcl
# We are creating an Amazon MSK (Managed Streaming for Apache Kafka) cluster with 3 broker nodes.
# Requirements:
# - 3 broker nodes
# - CloudWatch Logs for monitoring (open monitoring) - logs sent to CloudWatch
# - S3 bucket for backup or data export
# - Kinesis Firehose delivery stream (to deliver data from MSK to S3, for example)
# - Encryption at rest enabled
# - Open monitoring enabled (sends metrics to CloudWatch)

# Steps:
# 1. Create a VPC and subnets (MSK needs isolated or private subnets)
# 2. Create a security group for MSK brokers
# 3. Create an S3 bucket for Firehose and MSK backups
# 4. Create a CloudWatch log group for MSK logs
# 5. Create a KMS key for encryption at rest
# 6. Create MSK cluster with encryption, logging, and open monitoring
# 7. Create IAM roles and policies for MSK, Firehose, and KMS
# 8. Create Kinesis Firehose delivery stream that sources from MSK (or can write to S3; note: Firehose doesn't directly consume from MSK unless using custom app or via MSK Connect; but we can set it to deliver data to S3, as per typical usage)
#    Since Firehose cannot natively pull from MSK without a consumer, we assume it's intended to deliver data (from elsewhere) to S3, and MSK may produce to it via lambda or direct put.
#    For this configuration, we'll set up Firehose to deliver to S3, which can be used to persist data produced by MSK via a consumer.

# Note: In real-world, you'd typically use Lambda or Kinesis Data Analytics to consume from MSK and send to Firehose.
# But per request, we'll create the Firehose delivery stream to S3.

# We proceed:

provider "aws" {
  region = "us-west-2"
}

# 1. VPC and Subnets
resource "aws_vpc" "msk_vpc" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "msk-vpc"
  }
}

resource "aws_subnet" "msk_subnets" {
  count             = 3
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.${count.index + 1}.0/24"
  availability_zone = element(data.aws_availability_zones.available.names, count.index)

  tags = {
    Name = "msk-subnet-${count.index}"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

# 2. Security Group for MSK
resource "aws_security_group" "msk_sg" {
  name   = "msk-security-group"
  vpc_id = aws_vpc.msk_vpc.id

  ingress {
    from_port   = 2181
    to_port     = 2181
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-security-group"
  }
}

# 3. S3 Bucket for Firehose and logs
resource "aws_s3_bucket" "firehose_bucket" {
  bucket = "msk-firehose-output-bucket-${random_id.bucket_suffix.hex}"
  acl    = "private"

  versioning {
    enabled = true
  }

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }
}

resource "random_id" "bucket_suffix" {
  byte_length = 4
}

# 4. CloudWatch Log Group
resource "aws_cloudwatch_log_group" "msk_log_group" {
  name = "/aws/msk/terraform-msk-cluster"
  retention_in_days = 7
}

# 5. KMS Key for encryption at rest
resource "aws_kms_key" "msk_kms" {
  description             = "KMS key for MSK cluster encryption at rest"
  enable_key_rotation     = true

  tags = {
    Name = "msk-kms-key"
  }
}

# 6. MSK Cluster
resource "aws_msk_cluster" "msk_cluster" {
  cluster_name           = "terraform-msk-cluster"
  kafka_version          = "2.8.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type = "kafka.m5.large"
    client_subnets = aws_subnet.msk_subnets[*].id
    security_groups = [aws_security_group.msk_sg.id]

    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.msk_kms.arn
  }

  open_monitoring {
    prometheus {
      jmx_exporter {
        enabled_in_broker = true
      }
      node_exporter {
        enabled_in_broker = true
      }
    }
  }

  logging_info {
    broker_logs {
      cloud_watch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_log_group.name
      }
      # Sending broker logs to S3 is optional; if needed, we enable it
      s3 {
        enabled = true
        bucket  = aws_s3_bucket.firehose_bucket.id
        prefix  = "msk-logs"
      }
    }
  }

  tags = {
    Name = "terraform-msk-cluster"
  }

  # Ensures the cluster is fully provisioned before proceeding
  depends_on = [
    aws_kms_key.msk_kms,
    aws_cloudwatch_log_group.msk_log_group,
    aws_s3_bucket.firehose_bucket
  ]
}

# 7. IAM Roles for Firehose and MSK (if needed for integration)

# IAM Role for Firehose to write to S3
resource "aws_iam_role" "firehose_role" {
  name = "firehose_delivery_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
