resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose_s3_policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.firehose_bucket.arn,
          "${aws_s3_bucket.firehose_bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "kms:Decrypt",
          "kms:GenerateDataKey"
        ]
        Resource = aws_kms_key.msk_kms.arn
        Condition = {
          StringEquals = {
            "kms:ViaService": "s3.${var.region}.amazonaws.com"
          }
        }
      }
    ]
  })
}

# 8. Kinesis Firehose Delivery Stream
resource "aws_kinesis_firehose_delivery_stream" "msk_to_s3" {
  name        = "msk-firehose-stream"
  destination = "s3"

  s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.firehose_bucket.arn
    prefix     = "firehose-data/year=!{timestamp:yyyy}/month=!{timestamp:MM}/day=!{timestamp:dd}/hour=!{timestamp:HH}/"
    buffer_size = 5
    buffer_interval = 300
    compression_format = "UNCOMPRESSED"
  }

  # We assume data will be sent to this Firehose manually or via lambda; not directly from MSK
  # No MSK source is directly supported in Firehose without consumer

  tags = {
    Environment = "production"
  }
}

# Variables used
variable "region" {
  default = "us-west-2"
}

# Output MSK Cluster ARN and Zookeeper Connect String
output "msk_cluster_arn" {
  value = aws_msk_cluster.msk_cluster.arn
}

output "msk_zookeeper_connect_string" {
  value = aws_msk_cluster.msk_cluster.zookeeper_connect_string
}

output "msk_broker_node_group_info" {
  value = aws_msk_cluster.msk_cluster.broker_node_group_info[0].client_subnets
}

output "firehose_delivery_stream" {
