resource "aws_subnet" "msk_subnets" {
  count             = 3
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.${count.index + 1}.0/24"
  availability_zone = "us-east-1${["a", "b", "c"][count.index]}"
  tags = {
    Name = "msk-subnet-${count.index + 1}"
  }
}

resource "aws_security_group" "msk_sg" {
  name   = "msk-cluster-sg"
  vpc_id = aws_vpc.msk_vpc.id

  ingress {
    from_port   = 2181
    to_port     = 2181
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-security-group"
  }
}

resource "aws_msk_cluster" "msk_cluster" {
  cluster_name           = "managed-msk-cluster"
  kafka_version          = "3.5.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type = "kafka.m5.large"
    client_subnets = [
      aws_subnet.msk_subnets[0].id,
      aws_subnet.msk_subnets[1].id,
      aws_subnet.msk_subnets[2].id
    ]
    security_groups = [aws_security_group.msk_sg.id]
    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  encryption_info {
    encryption_in_transit {
      client_broker = "TLS"
      in_cluster    = true
    }
  }

  client_authentication {
    sasl {
      iam = true
    }
  }

  logging_info {
    broker_logs {
      s3 {
        enabled    = false
        bucket     = ""
        prefix     = ""
      }
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_log_group.name
      }
      firehose {
        enabled       = false
        delivery_stream = ""
      }
    }
  }

  tags = {
    Environment = "dev"
  }
}

resource "aws_cloudwatch_log_group" "msk_log_group" {
  name = "msk-log-group"
  retention_in_days = 7
}

# Step 3: Create MSK Connect custom plugin using debezium.zip
# Assume debezium.zip is locally available; in real-world, it should be in S3

resource "aws_s3_bucket" "plugin_bucket" {
  bucket = "msk-connect-plugin-bucket-${random_string.bucket_suffix.result}"
  force_destroy = true
}

resource "random_string" "bucket_suffix" {
  length  = 8
  special = false
  upper   = false
}

resource "aws_s3_object" "debezium_plugin" {
  bucket = aws_s3_bucket.plugin_bucket.bucket
  key    = "debezium.zip"
  source = "debezium.zip" # This assumes the file exists locally. Adjust path as needed.
  etag   = filemd5("debezium.zip")
}

resource "aws_mskconnect_custom_plugin" "debezium" {
  name = "debezium-custom-plugin"
  content_type = "ZIP"

  location {
    s3 {
      bucket_arn = aws_s3_bucket.plugin_bucket.arn
      file_key   = aws_s3_object.debezium_plugin.key
      # version_id is optional; use latest or pin to specific version
    }
  }

  description = "Debezium connector plugin for CDC"
}

# Step 4: Create MSK Connect worker configuration
resource "aws_mskconnect_worker_configuration" "worker_config" {
  name = "worker-config-debezium"
  description = "Worker config for Debezium"

  properties_file_content = <<EOF
  # Debezium and Kafka Connect configurations
  key.converter=org.apache.kafka.connect.storage.StringConverter
  value.converter=org.apache.kafka.connect.storage.StringConverter
  key.converter.schemas.enable=false
  value.converter.schemas.enable=false
  offset.storage.topic=connect-offsets
  offset.storage.replication.factor=3
  config.storage.topic=connect-configs
  config.storage.replication.factor=3
  status.storage.topic=connect-status
  status.storage.replication.factor=3
  plugin.path=/usr/share/java,/usr/share/confluent-hub-components,/opt/kafka/plugins
  EOF
}

# Step 5: Create MSK Connect Apache Kafka cluster connection (Apache Kafka cluster)
# It represents the connection from the connector to the MSK cluster

resource "aws_mskconnect_apache_kafka_cluster" "kafka_cluster" {
  apache_kafka_cluster {
    bootstrap_servers = aws_msk_cluster.msk_cluster.bootstrap_brokers_tls
    vpc {
      subnet_ids = aws_subnet.msk_subnets[*].id
    }
  }
}

# Step 6: Create MSK Connect connector using the custom plugin
# We assume role permissions exist for MSK Connect

resource "aws_iam_role" "msk_connect_role" {
  name = "msk-connect-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kafkaconnect.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "msk_connect_policy" {
  role       = aws_iam_role.msk_connect_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonKafkaConnectFullAccess"
}

resource "aws_mskconnect_connector" "debezium_connector" {
  name = "debezium-msk-connector"
  connector_configuration = {
    "connector.class"                    = "io.debezium.connector.mysql.MySqlConnector"
    "database.hostname"                  = "mysql.example.com"
    "database.port"                      = "3306"
    "database.user"                      = "user"
    "database.password"                  = "password"
    "database.server.id"                 = "184054"
    "database.server.name"               = "dbserver1"
    "database.include.list"              = "inventory"
    "database.history.kafka.bootstrap.servers" = aws_msk_cluster.msk_cluster.bootstrap_brokers_tls
    "database.history.kafka.topic"              = "schema-changes.inventory"
    "transforms"                                = "route"
    "transforms.route.type"                      = "org.apache.kafka.connect.transforms.RegexRouter"
    "transforms.route.regex"                     = "([^.]+)\.([^.]+)\.([^.]+)"
    "transforms.route.replacement"               = "debezium-$3"
  }
  kafka_cluster {
    apache_kafka_cluster {
      bootstrap_servers = aws_msk_cluster.msk_cluster.bootstrap_brokers_tls
      vpc {
        security_groups = [aws_security_group.msk_sg.id]
        subnet_ids = [
          aws_subnet.msk_subnets[0].id,
          aws_subnet.msk_subnets[1].id,
          aws_subnet.msk_subnets[2].id
        ]
      }
    }
  }
  kafka_cluster_client_authentication {
    authentication_type = "IAM"
  }
  kafka_cluster_encryption_in_transit {
    encryption_type = "TLS"
  }
  kafka_connect_version = "3.5.1"
  plugins {
    custom_plugin {
      name = aws_mskconnect_custom_plugin.debezium.name
      arn  = aws_mskconnect_custom_plugin.debezium.arn
      revision = aws_mskconnect_custom_plugin.debezium.latest_revision
    }
  }
  service_execution_role_arn = aws_iam_role.msk_connect_role.arn
  worker_configuration {
    revision = aws_mskconnect_worker_configuration.worker_config.latest_revision
    name     = aws_mskconnect_worker_configuration.worker_config.name
  }
}

