resource "aws_s3_object" "debezium_plugin" {
  bucket = aws_s3_bucket.debezium_plugin_bucket.bucket
  key    = "plugins/debezium.zip"
  source = "debezium.zip" # Assumes the file is in the local directory
  etag   = filemd5("debezium.zip")
}

# KMS key for encryption at rest
resource "aws_kms_key" "msk_kms" {
  description             = "KMS key for MSK cluster encryption"
  enable_key_rotation     = true
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid = "Enable IAM User Permissions"
        Effect = "Allow"
        Principal = {
          AWS = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"
        }
        Action = [
          "kms:*"
        ]
        Resource = "*"
      }
    ]
  })
}

data "aws_caller_identity" "current" {}

# VPC and networking for MSK
resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-vpc"
  }
}

resource "aws_subnet" "msk_subnets" {
  count                   = 3
  vpc_id                  = aws_vpc.msk_vpc.id
  cidr_block              = cidrsubnet(aws_vpc.msk_vpc.cidr_block, 8, count.index)
  availability_zone       = element(data.aws_availability_zones.available.names, count.index)
  map_public_ip_on_launch = false

  tags = {
    Name = "msk-subnet-${count.index + 1}"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

# Security group for MSK cluster
resource "aws_security_group" "msk_sg" {
  name   = "msk-cluster-sg"
  vpc_id = aws_vpc.msk_vpc.id

  ingress {
    from_port   = 2181
    to_port     = 2181
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  ingress {
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-security-group"
  }
}

# MSK Cluster with encryption at rest, open monitoring, and CloudWatch+S3 logging
resource "aws_msk_cluster" "msk_cluster" {
  cluster_name           = "msk-cluster"
  kafka_version          = "3.5.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type = "kafka.m5.large"
    client_subnets = aws_subnet.msk_subnets[*].id
    security_groups = [aws_security_group.msk_sg.id]
    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.msk_kms.arn
  }

  open_monitoring {
    prometheus {
      jmx_exporter {}
      node_exporter {}
    }
  }

  logging_info {
    broker_logs {
      cloud_watch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_log_group.name
      }
      firehose {
        enabled         = true
        delivery_stream = aws_kinesis_firehose_delivery_stream.firehose_stream.name
      }
      s3 {
        enabled = true
        bucket  = aws_s3_bucket.msk_logs_bucket.id
        prefix  = "logs/msk"
      }
    }
  }

  tags = {
    Environment = "dev"
  }
}

# CloudWatch Log Group for MSK
resource "aws_cloudwatch_log_group" "msk_log_group" {
  name = "/aws/msk/cluster"
  retention_in_days = 7
}

# S3 bucket for MSK logs
resource "aws_s3_bucket" "msk_logs_bucket" {
  bucket = "msk-logs-bucket-${random_string.suffix.result}"
  force_destroy = true
}

# Kinesis Firehose delivery stream to S3
resource "aws_kinesis_firehose_delivery_stream" "firehose_stream" {
  name        = "msk-firehose-stream"
  destination = "s3"

  s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.firehose_dest_bucket.arn
    buffer_size = 1
    buffer_interval = 60
    compression_format = "UNCOMPRESSED"
  }
}

resource "aws_s3_bucket" "firehose_dest_bucket" {
  bucket = "firehose-destination-${random_string.suffix.result}"
  force_destroy = true
}

# IAM role for Firehose
resource "aws_iam_role" "firehose_role" {
  name = "firehose_delivery_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose_delivery_policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Effect = "Allow"
        Resource = [
          aws_s3_bucket.firehose_dest_bucket.arn,
          "${aws_s3_bucket.firehose_dest_bucket.arn}/*"
        ]
      }
    ]
  })
}

# MSK Connect custom plugin from S3
resource "aws_mskconnect_custom_plugin" "debezium_plugin" {
  name        = "debezium-connector-plugin"
  content_type = "ZIP"

  location {
    s3 {
      bucket_arn = aws_s3_bucket.debezium_plugin_bucket.arn
      file_key   = aws_s3_object.debezium_plugin.key
    }
  }

  description = "Debezium custom connector plugin"
}

# MSK Connect worker configuration
resource "aws_mskconnect_worker_configuration" "worker_config" {
  name        = "worker-config"
  description = "Worker configuration for Debezium connector"

  properties_file_content = <<EOF
  key.converter=org.apache.kafka.connect.json.JsonConverter
  value.converter=org.apache.kafka.connect.json.JsonConverter
  key.converter.schemas.enable=true
  value.converter.schemas.enable=true
  config.storage.topic=connect-configs
  offset.storage.topic=connect-offsets
  status.storage.topic=connect-status
  config.storage.replication.factor=3
  offset.storage.replication.factor=3
  status.storage.replication.factor=3
  EOF
}

# MSK Connect to deploy the connector
resource "aws_mskconnect_connector" "debezium_connector" {
  name           = "debezium-msk-connector"
  connector_configuration = {
    "connector.class" = "io.debezium.connector.mysql.MySqlConnector"
    "database.hostname" = "your-database-host"
    "database.port" = "3306"
    "database.user" = "debezium"
    "database.password" = "password"
    "database.server.id" = "184054"
    "database.server.name" = "dbserver1"
    "database.include.list" = "inventory"
    "database.history.kafka.bootstrap.servers" = "${aws_msk_cluster.msk_cluster.bootstrap_brokers_tls}"
    "database.history.kafka.topic" = "schema-changes.inventory"
  }

  # Depends on the availability of MSK cluster
  depends_on = [aws_msk_cluster.msk_cluster]

  kafka_cluster {
    apache_kafka_cluster {
      bootstrap_servers = aws_msk_cluster.msk_cluster.bootstrap_brokers_tls
      vpc {
        security_groups = [aws_security_group.msk_sg.id]
        subnets = aws_subnet.msk_subnets[*].id
      }
    }
  }

  kafka_cluster_client_authentication {
    authentication_type = "NONE"
  }

  kafka_cluster_encryption_in_transit {
    encryption_type = "TLS"
  }

  kafka_connect_version = "2.7.1"

 Plugins {
    custom_plugin {
      custom_plugin_arn = aws_mskconnect_custom_plugin.debezium_plugin.arn
      revision          = aws_mskconnect_custom_plugin.debezium_plugin.latest_revision
    }
  }

  service_execution_role_arn = aws_iam_role.mskconnect_role.arn

  worker_configuration {
    revision = aws_mskconnect_worker_configuration.worker_config.latest_revision
    worker_configuration_arn = aws_mskconnect_worker_configuration.worker_config.arn
  }
}

# IAM role for MSK Connect
resource "aws_iam_role" "mskconnect_role" {
  name = "mskconnect-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kafkaconnect.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "mskconnect_policy" {
  role       = aws_iam_role.mskconnect_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonKafkaConnectFullAccess"
}

