# Let's think through the requirements step by step:
# 1. We need to create a PostgreSQL instance, which is a managed database service.
# 2. This could be on AWS (RDS), GCP (Cloud SQL), or Azure (Database for PostgreSQL).
# 3. Since the cloud provider isn't specified, I'll use GCP as an example since it has strong PostgreSQL support.
# 4. We'll need:
#    - A Google Cloud SQL instance for PostgreSQL
#    - Configuration for database version, tier, storage, etc.
#    - A root user with password
#    - A database within the instance
# 5. We'll use standard settings with reasonable defaults.

provider "google" {
  # You'll need to configure your GCP credentials and project
  # project = "your-project-id"
  # region  = "us-central1"
}

resource "google_sql_database_instance" "postgres_instance" {
  name             = "my-postgres-instance"
  database_version = "POSTGRES_15"
  region           = "us-central1"

  settings {
    tier = "db-g1-small"

    # Storage settings
    storage_auto_resize = true
    storage_auto_resize_limit = 100

    # Backup configuration
    backup_configuration {
      start_time = "02:00"
      enabled    = true
    }

    # IP Configuration to allow connections
    ip_configuration {
      ipv4_enabled = true
      # You can add authorized networks if needed
      # authorized_networks {
      #   name  = "trusted"
      #   value = "10.0.0.0/8"
      # }
    }

    # Maintenance window
    maintenance_window {
      day          = 7     # Sunday
      hour         = 3
      update_track = "stable"
    }
  }
}

resource "google_sql_user" "postgres_user" {
  name     = "postgres-user"
  instance = google_sql_database_instance.postgres_instance.name
  host     = "%"
  password = "your-secure-password-here" # In practice, use terraform's sensitive variables or secret management
}

resource "google_sql_database" "app_database" {
  name     = "app-db"
  instance = google_sql_database_instance.postgres_instance.name
}

