# Create a DynamoDB table with encryption at rest enabled
# Step 1: Define the DynamoDB table resource
# Step 2: Specify the required attributes (hash key and optionally range key)
# Step 3: Enable encryption at rest using the server-side encryption (SSE) with AWS-managed KMS key (default)
# Step 4: Set billing mode and other optional configurations

resource "aws_dynamodb_table" "encrypted_table" {
  name         = "example-encrypted-table"
  billing_mode = "PAY_PER_REQUEST"  # On-demand billing; can also use "PROVISIONED"
  hash_key     = "id"               # Partition key

  # Define attributes used in the schema
  attribute {
    name = "id"
    type = "S"  # String type
  }

  # Enable server-side encryption at rest
  server_side_encryption {
    enabled = true
    # kms_key_arn can be specified for custom KMS key; using default AWS-managed KMS key if omitted
  }

  # Enable point-in-time recovery (optional, but recommended for data protection)
  point_in_time_recovery {
    enabled = true
  }

  # Tags for resource identification
  tags = {
    Name        = "example-encrypted-dynamodb"
    Environment = "production"
  }
}

