# Let's break down the requirements step by step:
# 1. Create a VPC with a CIDR block
# 2. Create a subnet within the VPC
# 3. Create a Network ACL (NACL) and associate it with the subnet
# 4. Define ingress (inbound) rules for the NACL
# 5. Define egress (outbound) rules for the NACL

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "main-vpc"
  }
}

resource "aws_subnet" "main" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-west-2a"

  tags = {
    Name = "main-subnet"
  }
}

resource "aws_network_acl" "main" {
  vpc_id = aws_vpc.main.id

  # Ingress rules (inbound traffic)
  ingress {
    rule_no    = 100
    protocol   = "tcp"
    rule_action = "allow"
    cidr_block = "0.0.0.0/0"
    from_port  = 80
    to_port    = 80
  }

  ingress {
    rule_no    = 110
    protocol   = "tcp"
    rule_action = "allow"
    cidr_block = "0.0.0.0/0"
    from_port  = 443
    to_port    = 443
  }

  # Egress rules (outbound traffic)
  egress {
    rule_no    = 100
    protocol   = "tcp"
    rule_action = "allow"
    cidr_block = "0.0.0.0/0"
    from_port  = 80
    to_port    = 80
