# Create two AWS VPCs and establish a peering connection between them

# Step 1: Create the first VPC
resource "aws_vpc" "vpc_a" {
  cidr_block           = "10.0.0.0/16"
  instance_tenancy     = "default"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "VPC-A"
  }
}

# Step 2: Create the second VPC
resource "aws_vpc" "vpc_b" {
  cidr_block           = "10.1.0.0/16"
  instance_tenancy     = "default"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "VPC-B"
  }
}

# Step 3: Create a VPC peering connection between VPC-A and VPC-B
resource "aws_vpc_peering_connection" "peering" {
  vpc_id      = aws_vpc.vpc_a.id
  peer_vpc_id = aws_vpc.vpc_b.id
  auto_accept = false  # Requires manual acceptance or use another account; set to true if same account and want auto-accept
}

# Step 4: Accept the peering connection (when both VPCs are in the same account)
resource "aws_vpc_peering_connection_accepter" "peering_accepter" {
  vpc_peering_connection_id = aws_vpc_peering_connection.peering.id
  auto_accept               = true

  tags = {
    Name = "Peering-Accepter"
  }
}

# Step 5: Update route tables to enable traffic flow between the VPCs

# Route in VPC-A's main route table to route traffic to VPC-B
resource "aws_route" "route_to_vpc_b" {
  route_table_id         = aws_vpc.vpc_a.main_route_table_id
  destination_cidr_block = aws_vpc.vpc_b.cidr_block
  vpc_peering_connection_id = aws_vpc_peering_connection_accepter.peering_accepter.accepter.id
}

# Route in VPC-B's main route table to route traffic to VPC-A
resource "aws_route" "route_to_vpc_a" {
  route_table_id         = aws_vpc.vpc_b.main_route_table_id
  destination_cidr_block = aws_vpc.vpc_a.cidr_block
  vpc_peering_connection_id = aws_vpc_peering_connection_accepter.peering_accepter.accepter.id
}

