# Set up a basic AWS Neptune cluster with custom parameter groups and subnet restrictions

# Define the AWS provider
provider "aws" {
  region = "us-west-2" # Specify the desired region
}

# Create a custom Neptune parameter group for the cluster
resource "aws_neptune_cluster_parameter_group" "cluster_param_group" {
  name        = "custom-cluster-param-group"
  family      = "neptune1"
  description = "Custom parameter group for Neptune cluster"

  parameter {
    name  = "neptune_enable_audit_log"
    value = "1"
  }

  parameter {
    name  = "neptune_query_timeout"
    value = "30000"
  }
}

# Create a custom Neptune parameter group for the instance
resource "aws_neptune_parameter_group" "instance_param_group" {
  name        = "custom-instance-param-group"
  family      = "neptune1"
  description = "Custom parameter group for Neptune instance"

  parameter {
    name  = "neptune_enable_performance_cloudwatch_logs"
    value = "1"
  }
}

# Create a VPC for the Neptune instance
resource "aws_vpc" "neptune_vpc" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "neptune-vpc"
  }
}

# Create a subnet for the Neptune instance
resource "aws_subnet" "neptune_subnet" {
  vpc_id            = aws_vpc.neptune_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-west-2a"

  tags = {
    Name = "neptune-subnet"
  }
}

# Create a subnet group for Neptune
resource "aws_neptune_subnet_group" "neptune_subnet_group" {
  name       = "neptune-subnet-group"
  subnet_ids = [aws_subnet.neptune_subnet.id]

  tags = {
    Name = "neptune-subnet-group"
  }
}

# Create a security group to allow inbound connections only from the example subnet
resource "aws_security_group" "neptune_sg" {
  name        = "neptune-security-group"
  description = "Allow inbound connections to Neptune from example subnet"
  vpc_id      = aws_vpc.neptune_vpc.id

  # Allow inbound connections on Neptune default port (8182) from the example subnet
  ingress {
    from_port   = 8182
    to_port     = 8182
    protocol    = "tcp"
    cidr_blocks = ["10.0.1.0/24"]
  }

  # Allow all outbound connections
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "neptune-security-group"
  }
}

# Create the Neptune cluster with the custom cluster parameter group and subnet group
resource "aws_neptune_cluster" "neptune_cluster" {
  cluster_identifier                   = "neptune-cluster"
  engine                               = "neptune"
  engine_version                       = "1.2.1.1"
  neptune_cluster_parameter_group_name = aws_neptune_cluster_parameter_group.cluster_param_group.name
  subnet_group_name                    = aws_neptune_subnet_group.neptune_subnet_group.name
  vpc_security_group_ids               = [aws_security_group.neptune_sg.id]
  skip_final_snapshot                  = true
}

# Create a Neptune instance within the cluster with a custom instance parameter group
resource "aws_neptune_cluster_instance" "neptune_instance" {
  cluster_identifier             = aws_neptune_cluster.neptune_cluster.id
  instance_class                 = "db.r5.large"
  engine_version                 = "1.2.1.1"
  neptune_parameter_group_name   = aws_neptune_parameter_group.instance_param_group.name
  identifier                     = "neptune-cluster-instance-1"
  apply_immediately              = true
}

