extracted_code:
# Step-by-step breakdown:
# 1. We need to create an AWS Chime Voice Connector.
# 2. Enable encryption using an AWS KMS key.
# 3. Enable media metrics logging, which requires setting up a CloudWatch log group.
# 4. Attach necessary permissions for Chime to write logs to CloudWatch.

resource "aws_chime_voice_connector" "voice_connector" {
  name               = "example-voice-connector"
  require_encryption = true

  # Enable media/comms metrics logging
  media_streaming {
    data_retention    = 7 # retention in days
    disabled          = false
    streaming_format  = "raw"

    # Specify the destination ARN for media streaming
    fragment_translator {
      role_arn           = aws_iam_role.chime_media_streaming.arn
      destination_arn    = aws_kinesis_stream.media_streaming_stream.arn
    }
  }
}

# KMS key for encrypting calls
resource "aws_kms_key" "voice_connector_kms" {
  description             = "KMS key for Chime Voice Connector encryption"
  deletion_window_in_days = 7
  enable_key_rotation     = true
}

# IAM Role to allow Chime to write logs to CloudWatch
resource "aws_cloudwatch_log_group" "chime_log_group" {
  name              = "/aws/chime/voice-connector-logs"
  retention_in_days = 7
}

resource "aws_iam_role" "chime_media_streaming" {
  name = "chime-media-streaming-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "chime.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "chime_media_streaming_policy" {
  name = "chime-media-streaming-policy"
  role = aws_iam_role.chime_media_streaming.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogStream",
          "logs:PutLogEvents",
          "logs:CreateLogGroup"
        ]
        Resource = aws_cloudwatch_log_group.chime_log_group.arn
      },
      {
        Effect = "Allow"
        Action = [
          "kinesis:PutRecord",
          "kinesis:PutRecords"
        ]
        Resource = aws_kinesis_stream.media_streaming_stream.arn
      }
    ]
  })
}

# Kinesis stream as destination for media streaming
resource "aws_kinesis_stream" "media_streaming_stream" {
  name        = "chime-media-stream"
  shard_count = 1

  retention_period = 24 # hours
}

