extracted_code:
# We are creating an AWS Chime Voice Connector and configuring media streaming to Amazon Kinesis.
# Steps:
# 1. Create a Chime Voice Connector - this acts as a virtual phone number endpoint for SIP traffic.
# 2. Create a Kinesis stream to which media (audio) will be streamed.
# 3. Create an IAM role that allows Chime to write to the Kinesis stream.
# 4. Optionally, set up the streaming configuration on the Voice Connector to point to the Kinesis stream.

resource "aws_chime_voice_connector" "voice_connector" {
  name               = "media-streaming-vc"
  require_encryption = false  # Can be set to true if encryption is required
}

resource "aws_kinesis_stream" "media_stream" {
  name        = "chime-media-stream"
  shard_count = 2
  retention_period = 24  # Minimum 24 hours for Chime media streaming
}

# IAM role for Chime to assume to allow putting records into Kinesis
resource "aws_iam_role" "chime_kinesis_role" {
  name = "chime-kinesis-streaming-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "chime.amazonaws.com"
        }
        Condition = {}
      }
    ]
  })
}

# Attach policy to allow Chime to put records into Kinesis
resource "aws_iam_role_policy" "chime_kinesis_policy" {
  name = "chime_kinesis_access"
  role = aws_iam_role.chime_kinesis_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "kinesis:PutRecord",
          "kinesis:PutRecords"
        ]
        Resource = aws_kinesis_stream.media_stream.arn
      }
    ]
  })
}

# Update the Voice Connector to enable media streaming to Kinesis
resource "aws_chime_voice_connector_streaming" "streaming_config" {
  voice_connector_id = aws_chime_voice_connector.voice_connector.id

  media_insights_configuration {
    configuration_arn = aws_chime_media_insights_pipeline_configuration.media_insights_config.arn
    disabled         = false
  }

  # Enable media streaming to Kinesis
  data_retention_in_hours = 24
  streaming_notifications {
    notification_topic_arn = aws_sns_topic.streaming_notifications.arn  # Optional SNS notification
  }

  # For media streaming, we need to define a media insights pipeline configuration
}

# Media insights pipeline configuration (required for media streaming)
resource "aws_chime_media_insights_pipeline_configuration" "media_insights_config" {
  name = "kinesis-media-stream-pipeline"

  elements {
    type = "KinesisVideoStreamRecorder"

    kinesis_video_stream_recorder_configuration {
      stream_arn                   = aws_kinesis_stream.media_stream.arn
      retention_period_hours = 24
    }
  }

  # Use the IAM role for media insights
  resource_access_role_arn = aws_iam_role.chime_kinesis_role.arn
}

# Optional: SNS topic for streaming notifications (can be omitted if not needed)
resource "aws_sns_topic" "streaming_notifications" {
  name = "chime-streaming-notifications"
}

