# Create a VPC for the Redshift cluster
resource "aws_vpc" "redshift_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "redshift-vpc"
  }
}

# Create two subnets in different AZs for high availability
resource "aws_subnet" "redshift_subnet_1" {
  vpc_id                  = aws_vpc.redshift_vpc.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-west-2a"
  map_public_ip_on_launch = false

  tags = {
    Name = "redshift-subnet-1"
  }
}

resource "aws_subnet" "redshift_subnet_2" {
  vpc_id                  = aws_vpc.redshift_vpc.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-west-2b"
  map_public_ip_on_launch = false

  tags = {
    Name = "redshift-subnet-2"
  }
}

# Create a Redshift subnet group using the two subnets
resource "aws_redshift_subnet_group" "example" {
  name       = "redshift-subnet-group"
  subnet_ids = [aws_subnet.redshift_subnet_1.id, aws_subnet.redshift_subnet_2.id]

  tags = {
    Name = "redshift-subnet-group"
  }
}

# Create a basic Redshift cluster
resource "aws_redshift_cluster" "example" {
  cluster_identifier        = "example-redshift-cluster"
  cluster_type              = "single-node"
  node_type                 = "dc2.large"
  database_name             = "exampledb"
  master_username           = "adminuser"
  master_password           = "SecurePass123!"
  cluster_subnet_group_name = aws_redshift_subnet_group.example.name
  publicly_accessible       = false
  skip_final_snapshot       = true

  # Allow version upgrades
  allow_version_upgrade = true

  # Enable automated snapshots (retained for 1 day)
  automated_snapshot_retention_period = 1
}

# Create Redshift endpoint access for VPC endpoint access (for serverless or provisioned access)
resource "aws_redshift_endpoint_access" "example" {
  cluster_identifier = aws_redshift_cluster.example.cluster_identifier
  endpoint_name      = "example-redshift-endpoint"
  subnet_group_name  = aws_redshift_subnet_group.example.name
  vpc_security_group_ids = [
    aws_security_group.redshift_sg.id
  ]
}

# Create a security group for Redshift access
resource "aws_security_group" "redshift_sg" {
  name        = "redshift-security-group"
  description = "Security group for Redshift cluster"
  vpc_id      = aws_vpc.redshift_vpc.id

  # Allow Redshift default port (5439) from a specific CIDR or modify as needed
  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Change to a more restrictive range in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "redshift-sg"
  }
}

