extracted_code:
# Step 1: Create an AWS SNS topic to receive Redshift event notifications
resource "aws_sns_topic" "redshift_events_topic" {
  name = "redshift-cluster-events"
}

# Step 2: Create a Redshift parameter group with custom parameters
# This defines database configuration settings for the Redshift cluster
resource "aws_redshift_parameter_group" "example" {
  name   = "example-param-group"
  family = "redshift-1.0"

  parameter {
    name  = "enable_user_activity_logging"
    value = "true"
  }

  parameter {
    name  = "require_ssl"
    value = "false"
  }
}

# Step 3: Create a Redshift cluster and associate it with the parameter group
resource "aws_redshift_cluster" "example" {
  cluster_identifier        = "example-redshift-cluster"
  database_name             = "exampledb"
  master_username           = "adminuser"
  master_password           = "exampleSecurePassword123"
  node_type                 = "dc2.large"
  cluster_type              = "single-node"
  publicly_accessible       = false
  availability_zone         = data.aws_availability_zones.available.names[0]
  allow_version_upgrade     = true
  automated_snapshot_retention_period = 7

  # Associate the Redshift parameter group
  cluster_parameter_group_name = aws_redshift_parameter_group.example.name

  # Define VPC security groups and subnet group (required networking setup)
  vpc_security_group_ids = [aws_security_group.redshift_sg.id]
  cluster_subnet_group_name = aws_redshift_subnet_group.example.name

  # Skip final snapshot for example purposes (not recommended in production)
  skip_final_snapshot = true
}

# Step 4: Create a Redshift subnet group for placing the cluster in specific subnets
resource "aws_redshift_subnet_group" "example" {
  name       = "example-redshift-subnet-group"
  subnet_ids = aws_subnet.example_subnets[*].id

  tags = {
    Name = "Example Redshift Subnet Group"
  }
}

# Step 5: Create security group for Redshift cluster
resource "aws_security_group" "redshift_sg" {
  name        = "redshift-security-group"
  description = "Security group for Redshift cluster"
  vpc_id      = aws_vpc.main.id

  # Allow Redshift default port (5439) from trusted sources (restricted to example CIDR)
  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "Redshift SG"
  }
}

# Step 6: Setup VPC and subnets (required for Redshift cluster in VPC)
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "example-vpc"
  }
}

resource "aws_subnet" "example_subnets" {
  count = 2

  vpc_id            = aws_vpc.main.id
  cidr_block        = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone = data.aws_availability_zones.available.names[count.index]

  tags = {
    Name = "example-subnet-${count.index}"
  }
}

# Step 7: Create Redshift event subscription
# This subscribes to Redshift events and sends them to the SNS topic
resource "aws_redshift_event_subscription" "example" {
  name          = "example-redshift-event-sub"
  sns_topic_arn = aws_sns_topic.redshift_events_topic.arn
  source_type   = "cluster"
  event_categories = [
    "configuration",
    "management",
    "monitoring",
    "security"
  ]
  severity = "ERROR"

  # Apply subscription to clusters using the specified parameter group
  # Note: We can't directly tie event subscription to a parameter group,
  # but we can associate it with clusters that use the group.
  source_ids = [aws_redshift_cluster.example.cluster_identifier]

  enabled = true

  # Notify on specific event IDs if needed (optional)
  # event_categories = ["configuration"] 
  # This will notify on parameter group changes, cluster creation, etc.
}

# Data sources to get availability zones
data "aws_availability_zones" "available" {
  state = "available"
}

