# We are creating an S3 bucket to store images for a website.
# Amazon S3 is a scalable object storage service ideal for storing and serving images.
# Steps:
# 1. Create an S3 bucket with a unique name.
# 2. Enable public read access for the images (if the website is static and images are served publicly).
# 3. Configure the bucket for static website hosting (optional, if using S3 to host the site).
# 4. Set appropriate bucket policies to allow public read access to objects.
# 5. Enable versioning for image durability.
# 6. Block public access unless explicitly intended (we'll allow public reads for images only via policy).

resource "aws_s3_bucket" "image_bucket" {
  bucket = "my-website-images-${random_id.suffix.hex}"

  # Enable S3 Block Public Acls, but we'll allow public read via bucket policy
  block_public_acls       = false
  block_public_policy     = false
  ignore_public_acls      = false
  restrict_public_buckets = false

  # Enable versioning for image recovery and backup
  versioning {
    enabled = true
  }

  # Enable static website hosting (optional, if this bucket will host the site)
  website {
    index_document = "index.html"
    error_document = "error.html"
  }

  # Tags for cost allocation and organization
  tags = {
    Name        = "My Website Images"
    Environment = "production"
    Usage       = "store-images-for-website"
  }
}

# Generate a random suffix to ensure bucket name uniqueness
resource "random_id" "suffix" {
  byte_length = 4
}

# Bucket policy to allow public read access to all objects in the bucket
# This allows images to be served publicly via URL
resource "aws_s3_bucket_policy" "public_read_policy" {
  bucket = aws_s3_bucket.image_bucket.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = "*"
        Action = [
          "s3:GetObject"
        ]
        Resource = "${aws_s3_bucket.image_bucket.arn}/*"
      }
    ]
  })
}

# Optionally, enable logging or CORS if needed (for dynamic web apps)
# This example assumes simple public image hosting.

