# Create two S3 buckets:
# 1. The primary bucket to store objects
# 2. A destination bucket for inventory reports

# Step 1: Create the primary S3 bucket where objects will be stored
resource "aws_s3_bucket" "primary_bucket" {
  bucket = "primary-bucket-for-objects-${random_string.suffix.result}"
  # Enable versioning as we need to inventory all current object versions
  versioning {
    enabled = true
  }

  tags = {
    Name        = "Primary S3 Bucket"
    Environment = "production"
  }
}

# Step 2: Create the destination S3 bucket for inventory reports
resource "aws_s3_bucket" "inventory_bucket" {
  bucket = "inventory-reports-bucket-${random_string.suffix.result}"

  tags = {
    Name        = "Inventory Reports S3 Bucket"
    Environment = "production"
  }
}

# Step 3: Enable inventory configuration on the primary bucket
# This will generate CSV reports weekly of all current object versions
resource "aws_s3_bucket_inventory" "weekly_inventory" {
  bucket = aws_s3_bucket.primary_bucket.id
  name   = "weekly-inventory-report"
  included_object_versions = "All" # Include all object versions

  # Schedule set to weekly
  schedule {
    frequency = "Weekly"
  }

  # Destination for the inventory report
  destination {
    bucket {
      bucket_arn = aws_s3_bucket.inventory_bucket.arn
      format     = "CSV"
    }
  }

  # Optional: Filter to limit inventory (none specified here, so all objects)
  # Uncomment below to add a prefix filter if needed
  # filter {
  #   prefix = "data/"
  # }

  # Optional fields in the report
  optional_fields = [
    "Size",
    "LastModifiedDate",
    "StorageClass",
    "ETag",
    "IsMultipartUploaded",
    "ReplicationStatus",
    "EncryptionStatus"
  ]
}

# Step 4: Ensure the inventory bucket can receive inventory reports
# Add bucket policy to allow s3:PutObject from the same account
resource "aws_s3_bucket_policy" "inventory_bucket_policy" {
  bucket = aws_s3_bucket.inventory_bucket.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "s3.amazonaws.com"
        }
        Action   = "s3:PutObject"
        Resource = "${aws_s3_bucket.inventory_bucket.arn}/*"
        Condition = {
          ArnLike = {
            "aws:SourceArn": aws_s3_bucket.primary_bucket.arn
          }
          StringEquals = {
            "aws:SourceAccount": var.account_id
          }
        }
      }
    ]
  })
}

# Step 5: Generate a random suffix to ensure unique bucket names
resource "random_string" "suffix" {
  length  = 8
  special = false
  upper   = false
}

# Variables used
variable "account_id" {
  description = "AWS Account ID to use in policies"
  type        = string
}

