# Step-by-step reasoning:
# 1. We need to store a PDF file in AWS - the best service for storing files is Amazon S3.
# 2. We need to create an S3 bucket to store the file.
# 3. We need to upload the local file "assets/test.pdf" to the S3 bucket.
# 4. We'll use the aws_s3_object resource to upload the file to the bucket.
# 5. We'll create a bucket with a unique name (using a random suffix if needed) and enable encryption and versioning for security.
# 6. We'll use the file() function to read the local file and upload it.

resource "aws_s3_bucket" "pdf_storage" {
  bucket = "pdf-storage-${random_id.bucket_suffix.hex}"

  versioning {
    enabled = true
  }

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }

  tags = {
    Name        = "PDF Storage Bucket"
    Environment = "production"
  }
}

resource "aws_s3_object" "test_pdf" {
  bucket = aws_s3_bucket.pdf_storage.bucket
  key    = "test.pdf"
  source = "assets/test.pdf"
  etag   = filemd5("assets/test.pdf")

  # Set content type for PDF
