# Step 1: Define the S3 bucket resource
# We need to create an S3 bucket with a unique name. Since bucket names must be globally unique,
# it's often best practice to use a prefix or a random name. For demonstration, we'll use a variable
# or allow dynamic naming via prefix.

# Step 2: Enable website hosting on the S3 bucket
# To serve the bucket as a static website, we use the website attribute in the S3 bucket configuration.
# We specify the index document (e.g., index.html) and optionally an error document.

# Step 3: Configure public access
# Static websites on S3 need to be publicly accessible. We'll disable block public access settings,
# but in production, access should be controlled via bucket policies. For now, we'll allow public access
# for the website use case.

# Step 4: Final configuration
# Combine all the above in a single resource block with appropriate arguments.

resource "aws_s3_bucket" "example_website" {
  bucket = "example-website-bucket-${random_id.suffix.hex}"

  # Enable S3 bucket-level Public Access Block settings (disable them for website access)
  override_provider {
    default_tags {
      tags = {
        Purpose = "Static Website Hosting"
        Project = "Example"
      }
    }
  }
}

resource "aws_s3_bucket_website_configuration" "example_website_config" {
  bucket = aws_s3_bucket.example_website.bucket

  index_document {
    suffix = "index.html"
  }

  error_document {
    key = "error.html"
  }
}

resource "aws_s3_bucket_ownership_controls" "example_ownership" {
  bucket = aws_s3_bucket.example_website.bucket
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

