# We need two S3 buckets:
# 1. The main S3 bucket (source bucket) that will have server access logging enabled.
# 2. The log destination bucket where server access logs will be stored.

# Step 1: Create the main S3 bucket (source bucket)
# Step 2: Create the log destination bucket (separate bucket for storing logs)
# Step 3: Enable server access logging on the main bucket, pointing to the log bucket
# Step 4: Apply principles of least privilege and security:
#         - Block public access for both buckets
#         - Enable versioning (optional, but recommended)
#         - Use meaningful bucket names (we'll use prefixes or names based on resource)

resource "aws_s3_bucket" "source_bucket" {
  bucket = "my-source-bucket-12345"  # Change to a globally unique name as needed

  # Block all public access to the source bucket
  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true

  # Enable versioning for data protection (optional but recommended)
  versioning {
    enabled = true
  }

  # Enable server access logging by referencing the log bucket
  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }

  # Set the log bucket and prefix
  # The logging configuration will be completed by referencing the destination bucket
}

resource "aws_s3_bucket" "log_bucket" {
  bucket = "my-log-bucket-12345"  # Change to a globally unique name as needed

  # Block all public access to the log bucket (critical for security)
  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true

  # Enable versioning for the log bucket to preserve log integrity
  versioning {
    enabled = true
  }

  # Encrypt logs at rest
  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }

  # Optional: Add a lifecycle policy to expire old logs (e.g., after 365 days)
  lifecycle_rule {
    id      = "expire-old-logs"
    enabled = true
    prefix  = "logs/"

    noncurrent_version_expiration {
      days = 30
    }

    expiration {
      days = 365
    }
  }
}

# Step 5: Enable server access logging on the source bucket, pointing to the log bucket
# This is done via an aws_s3_bucket_logging resource
resource "aws_s3_bucket_logging" "source_bucket_logging" {
  bucket = aws_s3_bucket.source_bucket.id
  target_bucket = aws_s3_bucket.log_bucket.id
  target_prefix = "logs/"  # Optional: prefix for organizing logs within the log bucket
}

# Optional: Add bucket policy on the log bucket to ensure only logs can be written by AWS S3 log delivery
# This ensures that only AWS S3 can write logs to the bucket, but the bucket owner can read
resource "aws_s3_bucket_policy" "log_delivery_policy" {
  bucket = aws_s3_bucket.log_bucket.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "logging.s3.amazonaws.com"
        }
        Action = "s3:PutObject"
        Resource = "${aws_s3_bucket.log_bucket.arn}/logs/*"
        Condition = {
          StringEquals = {
            "s3:x-amz-acl" = "bucket-owner-full-control"
          }
        }
      }
    ]
  })
}

