extracted_code:
# Autograder Infrastructure using AWS CodeBuild

# We need to set up an automated system that:
# 1. Triggers on GitHub commits for student submissions
# 2. Uses AWS CodeBuild to run code in a controlled environment
# 3. Stores build/test results
# 4. Requires secure access to GitHub repositories

# Components needed:
# - AWS CodeBuild project configured for building/testing student code
# - S3 bucket to store build artifacts and logs
# - IAM roles for CodeBuild to access required resources
# - Optional: CloudWatch for logging and monitoring

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 4.0"
    }
  }
}

# S3 bucket to store build artifacts and logs
resource "aws_s3_bucket" "autograder_artifacts" {
  bucket = "cs-class-autograder-artifacts-${random_string.suffix.result}"
  tags = {
    Name        = "CS Class Autograder Artifacts"
    Environment = "production"
  }
}

resource "aws_s3_bucket_versioning" "autograder_artifacts" {
  bucket = aws_s3_bucket.autograder_artifacts.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "autograder_artifacts" {
  bucket = aws_s3_bucket.autograder_artifacts.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

# IAM role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "cs-autograder-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for CodeBuild role
resource "aws_iam_policy" "codebuild_policy" {
  name = "cs-autograder-codebuild-policy"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:GetBucketAcl",
          "s3:PutObjectAcl"
        ]
        Resource = [
          aws_s3_bucket.autograder_artifacts.arn,
          "${aws_s3_bucket.autograder_artifacts.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "codebuild:BatchPutCodeCoverages",
          "codebuild:BatchPutTestCases",
          "codebuild:CreateReport",
          "codebuild:CreateReportGroup",
          "codebuild:UpdateReport"
        ]
        Resource = "arn:aws:codebuild:*:*:report-group/cs-autograder-*"
      }
    ]
  })
}

# Attach policy to role
resource "aws_iam_role_policy_attachment" "codebuild_policy_attachment" {
  policy_arn = aws_iam_policy.codebuild_policy.arn
  role       = aws_iam_role.codebuild_role.name
}

# Random suffix for unique resource names
resource "random_string" "suffix" {
  length  = 8
  special = false
  upper   = false
}

# CodeBuild project for autograding
resource "aws_codebuild_project" "autograder" {
  name          = "cs-class-autograder"
  description   = "Automated grader for CS class assignments"
  build_timeout = 60 # minutes
  service_role  = aws_iam_role.codebuild_role.arn

  # Source configuration - GitHub
  source {
    type      = "GITHUB"
    location  = "https://github.com/your-org/cs-class-assignments.git"
    git_clone_depth = 1

    # Set to true if using a buildspec.yml file in the repo
    # Set to false if specifying buildspec directly
    buildspec = "buildspec.yml"

    auth {
      type = "OAUTH"
      resource = aws_codestarconnections_connection.github.id
    }
  }

  # Environment configuration
  environment {
    type                = "LINUX_CONTAINER"
    compute_type        = "BUILD_GENERAL1_SMALL"
    image               = "aws/codebuild/standard:5.0"  # Can customize based on course needs (Python, Java, etc.)
    image_pull_credentials_type = "CODEBUILD"

    # Environment variables (can include any needed for grading)
    environment_variable {
      name  = "CLASS_NAME"
      value = "CS101"
    }

    environment_variable {
      name  = "ASSIGNMENT_DEADLINE"
      value = "2023-12-15T23:59:59Z"
      type  = "PLAINTEXT"
    }
  }

  # Output artifacts
  artifacts {
    type = "S3"
    location = aws_s3_bucket.autograder_artifacts.id
    path = "build-output"
    packaging = "ZIP"
  }

  # Secondary artifacts for test results
  secondary_artifacts {
    type = "S3"
    location = aws_s3_bucket.autograder_artifacts.id
    path = "test-results"
    name = "test-results"
    packaging = "ZIP"
  }

  # Cache build artifacts to S3 to speed up subsequent builds
  cache {
    type = "S3"
    location = "${aws_s3_bucket.autograder_artifacts.id}/codebuild-cache"
  }

  # Logs configuration
  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/cs-class-autograder"
      stream_name = "build"
    }

    s3_logs {
      status   = "ENABLED"
      location = "${aws_s3_bucket.autograder_artifacts.id}/logs"
    }
  }

  # Allow reporting build status back to GitHub
  badge_enabled = true

  # Tags
  tags = [
    {
      key   = "Project"
      value = "CS-Class-Autograder"
    },
    {
      key   = "Environment"
      value = "production"
    }
  ]
}

# CodeStar Connection to securely connect to GitHub
resource "aws_codestarconnections_connection" "github" {
  name          = "github-connection"
  provider_type = "GitHub"
}

# Optional: CloudWatch log group for CodeBuild
resource "aws_cloudwatch_log_group" "autograder_logs" {
  name              = "/aws/codebuild/cs-class-autograder"
  retention_in_days = 90
  tags = {
    Project = "CS-Class-Autograder"
  }
}

# Instructions:
# 1. Create a GitHub OAuth token with repo access and configure it in AWS CodeStar Connection
# 2. Set up webhooks in GitHub repository to trigger CodeBuild
# 3. Create a buildspec.yml file in the student repositories with test commands
# 4. Customize the CodeBuild image based on the programming languages used in the course
# 5. Consider creating multiple CodeBuild projects for different assignments if needed

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_s3_bucket" "artifact_bucket" {
  bucket_prefix = "artifact-bucket-"
}

resource "aws_codebuild_project" "autograder_build" {
  name         = "autograder_build"
  service_role = aws_iam_role.autograder_build_role.arn

  artifacts {
    type     = "S3"
    location = aws_s3_bucket.artifact_bucket.arn
    name     = "results.zip" # include this
  }

  environment { # arguments required, exact value not specified
    compute_type = "BUILD_GENERAL1_SMALL"
    image        = "aws/codebuild/standard:7.0-24.10.29"
    type         = "LINUX_CONTAINER"
  }

  source {
    type            = "GITHUB"
    git_clone_depth = 1 # good to have, not required
    location        = "github.com/source-location"
  }
}

resource "aws_iam_role" "autograder_build_role" {
  assume_role_policy = data.aws_iam_policy_document.autograder_build_policy_assume.json
}

data "aws_iam_policy_document" "autograder_build_policy_assume" {
  statement {
    actions = ["sts:AssumeRole"]

    principals {
      type        = "Service"
      identifiers = ["codebuild.amazonaws.com"]
    }
  }

}

data "aws_iam_policy_document" "autograder_build_policy" {
  statement {
    effect = "Allow"
    actions = [
      "ec2:DescribeSubnets",
      "ec2:DescribeSecurityGroups",
      "ec2:DescribeVpcs"
    ]
    resources = [
      "*"
    ]
  }
}

resource "aws_iam_policy" "autograder_build_policy" {
  name        = "lambda_policy"
  description = "Grants permissions to Lambda to describe vpc, subnet, security group"

  policy = data.aws_iam_policy_document.autograder_build_policy.json
}

resource "aws_iam_role_policy_attachment" "lambda_policy_attach" {
  role       = aws_iam_role.autograder_build_role.name
  policy_arn = aws_iam_policy.autograder_build_policy.arn
}

