    compute_type        = "BUILD_GENERAL1_SMALL"
    privileged_mode     = false

    environment_variable {
      name  = "SUBMISSION_BUCKET"
      value = aws_s3_bucket.autograder_submissions.bucket
    }
    environment_variable {
      name  = "RESULT_BUCKET"
      value = aws_s3_bucket.autograder_artifacts.bucket
    }
  }

  # Buildspec defines how to run student code and store results
  build_spec = <<EOF
version: 0.2
phases:
  install:
    runtime-versions:
      python: 3.9
    commands:
      - echo "Installing dependencies..."
      - pip install pytest

  pre_build:
    commands:
      - echo "Copying student code to workspace"
      - aws s3 cp s3://$SUBMISSION_BUCKET/$CODEBUILD_BUILD_ID/student_code.zip ./ --no-progress
      - unzip student_code.zip -d ./student_submission
      - cd ./student_submission

  build:
    commands:
      - echo "Running autograder..."
      - pytest --junitxml=results.xml test_*.py

  post_build:
    commands:
      - echo "Uploading results..."
      - aws s3 cp results.xml s3://$RESULT_BUCKET/grades/$CODEBUILD_BUILD_ID/results.xml --no-progress
      - echo "Autograding complete for $CODEBUILD_BUILD_ID"
EOF

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/cs-class-autograder"
      stream_name = "build"
    }
    s3_logs {
      status   = "ENABLED"
      location = "${aws_s3_bucket.autograder_artifacts.bucket}/logs"
    }
  }

  tags = {
    Project = "CS-Autograder"
    Owner   = "CS-Department"
  }
}

# Optional: Use AWS CodeStar Connection for secure GitHub access (if using GitHub)
# This requires Console setup or additional AWS CLI setup
