extracted_code:
# Step-by-step breakdown:

# 1. We need an S3 bucket to store build artifacts and potentially logs from the autograder runs.
# 2. We need an AWS CodeBuild project that will:
#    - Be triggered by GitHub commits (students pushing code)
#    - Run in a specified environment (custom buildspec)
#    - Store results (e.g., test results, logs) back into S3
# 3. CodeBuild requires:
#    - A service role with permissions to access S3 and other AWS services
#    - A buildspec file (can be in the repo or defined inline)
#    - Environment configuration (e.g., Ubuntu, Docker image if needed)
# 4. We'll create an IAM role and policy for CodeBuild
# 5. Optionally, logging via CloudWatch (default behavior), but artifact storage in S3 is explicit

resource "aws_s3_bucket" "autograder_artifacts" {
  bucket = "cs-class-autograder-artifacts-${random_id.bucket_suffix.hex}"
  # Enable versioning for safety
  versioning {
    enabled = true
  }

  # Enable server-side encryption
  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }

  tags = {
    Name        = "CS Class Autograder Artifacts"
    Environment = "production"
    Project     = "autograder"
  }
}

resource "random_id" "bucket_suffix" {
  byte_length = 4
}

# IAM Role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "cs-autograder-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for CodeBuild
resource "aws_iam_policy" "codebuild_policy" {
  name = "cs-autograder-codebuild-policy"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:GetBucketVersioning",
          "s3:PutBucketVersioning"
        ]
        Resource = [
          aws_s3_bucket.autograder_artifacts.arn,
          "${aws_s3_bucket.autograder_artifacts.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "codebuild:BatchPutCodeCoverages",
          "codebuild:BatchPutTestCases",
          "codebuild:InvokeReportCreate",
          "codebuild:UpdateReport"
        ]
        Resource = "*"
      }
    ]
  })
}

# Attach policy to role
resource "aws_iam_role_policy_attachment" "codebuild_policy_attach" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = aws_iam_policy.codebuild_policy.arn
}

# CodeBuild Project
resource "aws_codebuild_project" "autograder" {
  name         = "cs-class-autograder"
  description  = "Automatically grades student submissions from GitHub"
  service_role = aws_iam_role.codebuild_role.arn

  # Source: GitHub repository (students' code)
  source {
    type      = "GITHUB"
    location  = "https://github.com/your-org/student-repo.git"
    git_clone_depth = 1

    # Optional: webhook to auto-trigger on push
    build_trigger {
      type = "WEBHOOK"
      filter_group {
        pattern = "PUSH, PULL_REQUEST_CREATED, PULL_REQUEST_UPDATED"
        type    = "EVENT"
      }
    }
  }

  # Environment: specify image, type, and environment variables
  environment {
    type                = "LINUX_CONTAINER"
    image               = "aws/codebuild/amazonlinux2-x86_64-standard:5.0" # Can customize with your runtime (Python, Java, etc.)
    compute_type        = "BUILD_GENERAL1_SMALL"
    privileged_mode     = false

    # Example environment variables (can be used to pass configuration)
    environment_variable {
      name  = "CLASS_NUMBER"
      value = "CS101"
    }
  }

  # Artifacts stored in S3
  artifacts {
    type = "S3"
    location = aws_s3_bucket.autograder_artifacts.bucket
    path = "build-output"
    packaging = "ZIP"
    name = "grading-results-$(date +%Y-%m-%d-%H-%M).zip"
  }

  # Secondary artifacts for logs or reports (optional)
  secondary_artifacts {
    type = "S3"
    location = aws_s3_bucket.autograder_artifacts.bucket
    path = "test-reports"
    name = "test-report-$(date +%Y-%m-%d).xml"
    packaging = "ZIP"
  }

  # Cache build artifacts in S3 to speed up future builds
  cache {
    type = "S3"
    location = "${aws_s3_bucket.autograder_artifacts.bucket}/codebuild-cache"
  }

  # Build timeout (in minutes)
  timeout = 30

