extracted_code:
# Terraform configuration for a secure AWS CodeBuild autograder with internet isolation
# This setup includes:
# - A VPC with private subnets (no internet access)
# - CodeBuild project that runs in the VPC and pulls from GitHub
# - IAM roles for CodeBuild with least privilege
# - Logging via CloudWatch and S3
# - Security controls to block internet access for student code

resource "aws_vpc" "autograder" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "autograder-vpc"
  }
}

resource "aws_internet_gateway" "autograder" {
  vpc_id = aws_vpc.autograder.id

  tags = {
    Name = "autograder-igw"
  }
}

# Public subnet for any potential future NAT or bastion (not used by CodeBuild)
resource "aws_subnet" "public" {
  vpc_id                  = aws_vpc.autograder.id
  cidr_block              = "10.0.1.0/24"
  map_public_ip_on_launch = true
  availability_zone       = data.aws_availability_zones.available.names[0]

  tags = {
    Name = "autograder-public-subnet"
  }
}

# Private subnets where CodeBuild will run (no route to internet)
resource "aws_subnet" "private" {
  count                 = 2
  vpc_id                = aws_vpc.autograder.id
  cidr_block            = "10.0.${count.index + 2}.0/24"
  availability_zone     = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = false

  tags = {
    Name = "autograder-private-subnet-${count.index}"
  }
}

# Route table for private subnets (intentionally no internet route)
resource "aws_route_table" "private" {
  vpc_id = aws_vpc.autograder.id

  tags = {
    Name = "autograder-private-route-table"
  }
}

resource "aws_route_table_association" "private" {
  count          = 2
  subnet_id      = aws_subnet.private[count.index].id
  route_table_id = aws_route_table.private.id
}

# Security group for CodeBuild (minimal egress, only necessary ingress)
resource "aws_security_group" "codebuild" {
  name        = "autograder-codebuild-sg"
  description = "Security group for autograder CodeBuild"
  vpc_id      = aws_vpc.autograder.id

  # No ingress - CodeBuild doesn't need to accept connections
  # Egress restricted to only what's needed (VPC only)
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["10.0.0.0/16"]  # Only allow traffic within VPC
  }

  # Explicit deny of internet egress is achieved by not allowing 0.0.0.0/0
  tags = {
    Name = "autograder-codebuild-sg"
  }
}

# S3 bucket to store build artifacts and logs
resource "aws_s3_bucket" "autograder_artifacts" {
  bucket = "autograder-artifacts-${random_string.suffix.result}"
  # Block public access
  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true

  versioning {
    enabled = true
  }

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }

  tags = {
    Name = "autograder-artifacts"
  }
}

# S3 bucket for CodeBuild logs
resource "aws_s3_bucket" "autograder_logs" {
  bucket = "autograder-logs-${random_string.suffix.result}"
  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true

  versioning {
    enabled = true
  }

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }

  tags = {
    Name = "autograder-logs"
  }
}

# IAM role for CodeBuild
resource "aws_iam_role" "codebuild" {
  name = "autograder-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for CodeBuild
resource "aws_iam_policy" "codebuild" {
  name = "autograder-codebuild-policy"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:GetBucketAcl",
          "s3:PutObjectAcl"
        ]
        Resource = [
          aws_s3_bucket.autograder_artifacts.arn,
          "${aws_s3_bucket.autograder_artifacts.arn}/*",
          aws_s3_bucket.autograder_logs.arn,
          "${aws_s3_bucket.autograder_logs.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:CreateNetworkInterface",
          "ec2:DescribeDhcpOptions",
          "ec2:DescribeNetworkInterfaces",
          "ec2:DeleteNetworkInterface",
          "ec2:DescribeSubnets",
          "ec2:DescribeSecurityGroups",
          "ec2:DescribeVpcs"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:CreateTags"
        ]
        Resource = "arn:aws:ec2:*:*:network-interface/*"
      }
    ]
  })
}

# Attach policy to role
resource "aws_iam_role_policy_attachment" "codebuild" {
  policy_arn = aws_iam_policy.codebuild.arn
  role       = aws_iam_role.codebuild.name
}

# CodeBuild project for autograding
resource "aws_codebuild_project" "autograder" {
  name         = "cs-class-autograder"
  description  = "Autograder for CS class assignments"
  service_role = aws_iam_role.codebuild.arn

  # Source from GitHub
  source {
    type      = "GITHUB"
    location  = "https://github.com/example/cs-class-repo.git"
    git_clone_depth = 1

    auth {
      type = "OAUTH"
      resource = aws_codebuild_source_credential.github.token
    }
  }

  # Use a secure, minimal build environment
  environment {
    type                = "LINUX_CONTAINER"
    image               = "aws/codebuild/standard:5.0"
    compute_type        = "BUILD_GENERAL1_SMALL"
    privileged_mode     = false  # Critical: disable privileged mode to prevent container escape

    environment_variable {
      name  = "GRADE_SUBMISSION"
      value = "true"
    }
  }

  # Run in private VPC with no internet access
  vpc_config {
    vpc_id            = aws_vpc.autograder.id
    subnets           = aws_subnet.private[*].id
    security_group_ids = [aws_security_group.codebuild.id]
  }

  # Artifacts stored in S3
  artifacts {
    type = "S3"
    location = aws_s3_bucket.autograder_artifacts.bucket
    path     = "artifacts"
    name     = "grading-result-$(date +%Y-%m-%d-%H-%M-%S)"
  }

  # Secondary artifacts for logs
  secondary_artifacts {
    type = "S3"
    location = aws_s3_bucket.autograder_logs.bucket
    path     = "logs"
    name     = "build-logs"
  }

  # Logs to CloudWatch and S3
  logs_config {
    cloudwatch_logs {
      group_name = "/aws/codebuild/cs-class-autograder"
      stream_name = "autograder-builds"
    }
    s3_logs {
      location = "${aws_s3_bucket.autograder_logs.bucket}/build-logs"
      status   = "ENABLED"
    }
  }

  # Build timeout (graceful handling)
  timeout_in_minutes = 15

  # Cache to speed up repeated builds (stored in S3)
  cache {
    type = "S3"
    location = aws_s3_bucket.autograder_artifacts.bucket
  }

  tags = {
    Project = "CS-Class-Autograder"
    Environment = "Production"
  }
}

# Source credentials for GitHub (store token securely)
resource "aws_codebuild_source_credential" "github" {
  auth_type = "PERSONAL_ACCESS_TOKEN"
  server_type = "GITHUB"
  token = var.github_personal_access_token
}

# Random suffix for S3 buckets
resource "random_string" "suffix" {
  length  = 8
  special = false
  upper   = false
}

# Data source for availability zones
data "aws_availability_zones" "available" {
  state = "available"
}

# Outputs
output "vpc_id" {
  value = aws_vpc.autograder.id
}

output "codebuild_project_name" {
  value = aws_codebuild_project.autograder.name
}

output "artifacts_bucket" {
  value = aws_s3_bucket.autograder_artifacts.bucket
}

output "logs_bucket" {
  value = aws_s3_bucket.autograder_logs.bucket
}

# Variable for GitHub token (should be provided securely)
variable "github_personal_access_token" {
  description = "GitHub personal access token for accessing student repositories"
  type        = string
  sensitive   = true
}

