  name        = "codebuild-security-group"
  description = "Security group for CodeBuild with no outbound internet access"
  vpc_id      = aws_vpc.autograder_vpc.id

  # No egress rule = deny all outbound traffic (default egress allows all)
  egress = []

  # Allow necessary ingress from within the VPC (if needed for logging or internal services)
  ingress {
    from_port   = 0
    to_port     = 65535
    protocol    = "-1"
