```hcl
# Configure the AWS provider
provider "aws" {
  region = "us-east-1"
}

# Create a VPC for the autograder to run in isolation
resource "aws_vpc" "autograder_vpc" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "autograder-vpc"
  }
}

# Create a private subnet within the VPC where CodeBuild will run (no internet access)
resource "aws_subnet" "private_subnet" {
  vpc_id                  = aws_vpc.autograder_vpc.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = false

  tags = {
    Name = "autograder-private-subnet"
  }
}

# Create a security group for CodeBuild that blocks all outbound internet access
resource "aws_security_group" "codebuild_sg" {
  name        = "codebuild-security-group"
  description = "Security group for CodeBuild with no outbound internet access"
  vpc_id      = aws_vpc.autograder_vpc.id

  # No egress rule = deny all outbound traffic (default egress allows all)
  egress = []

  # Allow necessary ingress from within the VPC (if needed for logging or internal services)
  ingress {
    from_port   = 0
    to_port     = 65535
    protocol    = "-1"
    self        = true
  }

  tags = {
    Name = "codebuild-sg-no-internet"
  }
}

# Create an S3 bucket to store student code, build artifacts, and results
resource "aws_s3_bucket" "autograder_bucket" {
  bucket = "cs-class-autograder-${random_id.bucket_suffix.hex}"

  # Enable encryption
  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }

  versioning {
    enabled = true
  }

  tags = {
    Name = "autograder-code-storage"
  }
}

# Generate random suffix for unique bucket name
resource "random_id" "bucket_suffix" {
  byte_length = 4
}

# IAM role for CodeBuild to access S3 and CloudWatch, and run within VPC
resource "aws_iam_role" "codebuild_role" {
  name = "codebuild-autograder-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for CodeBuild permissions
resource "aws_iam_policy" "codebuild_policy" {
  name = "codebuild-autograder-policy"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.autograder_bucket.arn,
          "${aws_s3_bucket.autograder_bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:CreateNetworkInterface",
          "ec2:DescribeDhcpOptions",
          "ec2:DescribeNetworkInterfaces",
          "ec2:DeleteNetworkInterface",
          "ec2:DescribeSubnets",
          "ec2:DescribeSecurityGroups",
          "ec2:DescribeVpcs"
        ]
        Resource = "*"
      }
    ]
  })
}

# Attach the policy to the role
resource "aws_iam_role_policy_attachment" "codebuild_policy_attachment" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = aws_iam_policy.codebuild_policy.arn
}

# AWS CodeBuild project for autograding
resource "aws_codebuild_project" "autograder_project" {
  name          = "cs-class-autograder"
  description   = "Autograder for CS class submissions"
  build_timeout = 60
  queued_timeout = 300

  source {
    type      = "GITHUB"
    location  = "https://github.com/example/cs101-homework.git"
    git_clone_depth = 1

    auth {
      type = "OAUTH"
    }
  }

  artifacts {
    type = "S3"
    location = aws_s3_bucket.autograder_bucket.bucket
    path = "results"
    package_zip = false
  }

  cache {
    type = "S3"
    location = aws_s3_bucket.autograder_bucket.bucket
  }

  environment {
    type            = "LINUX_CONTAINER"
    image           = "aws/codebuild/standard:5.0"
    compute_type    = "BUILD_GENERAL1_SMALL"
    privileged      = false  # Important: disable privileged mode for isolation

    environment_variable {
      name  = "S3_BUCKET"
      value = aws_s3_bucket.autograder_bucket.bucket
    }
  }

  service_role = aws_iam_role.codebuild_role.arn

  vpc_config {
    vpc_id            = aws_vpc.autograder_vpc.id
    subnets           = [aws_subnet.private_subnet.id]
    security_group_ids = [aws_security_group.codebuild_sg.id]
  }

  logs_config {
    cloudwatch_logs {
      group_name = "/aws/codebuild/cs-class-autograder"
      stream_name = "main"
    }
  }

  tags = {
    Project = "CS101-Autograder"
  }
}

# Optional: CloudWatch Log Group for CodeBuild
resource "aws_cloudwatch_log_group" "codebuild_log_group" {
  name              = "/aws/codebuild/cs-class-autograder"
  retention_in_days = 7
  tags = {
    Name = "codebuild-logs"
  }
}

# Output important information
output "autograder_bucket_name" {
  description = "Name of the S3 bucket used for storing student code and results"
  value       = aws_s3_bucket.autograder_bucket.bucket
}

output "vpc_id" {
  description = "ID of the VPC where CodeBuild runs"
  value       = aws_vpc.autograder_vpc.id
}

output "codebuild_project_name" {
  description = "Name of the CodeBuild project"
  value       = aws_codebuild_project.autograder_project.name
}
```

