# Autograder Infrastructure for CS Class using AWS

# Provider configuration
provider "aws" {
  region = "us-west-2" # Can be changed as needed
}

# VPC to isolate the autograding environment
resource "aws_vpc" "autograder_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "autograder-vpc"
  }
}

# Public subnet for CodeBuild (required, but we'll block outbound internet)
resource "aws_subnet" "autograder_subnet" {
  vpc_id                  = aws_vpc.autograder_vpc.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = data.aws_availability_zones.available.names[0]
  map_public_ip_on_launch = false # No public IP

  tags = {
    Name = "autograder-subnet"
  }
}

# Data source to get availability zones
data "aws_availability_zones" "available" {
  state = "available"
}

# Security group for CodeBuild project: allows no outbound traffic to block internet access
resource "aws_security_group" "autograder_sg" {
  vpc_id = aws_vpc.autograder_vpc.id

  # No ingress rules needed — CodeBuild doesn't need inbound connections
  # Egress is blocked explicitly
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
    self        = true
  }

  # Explicit deny: no outbound internet access
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow local traffic within the VPC if needed (e.g., to access S3 via endpoint)
  egress {
    from_port   = 0
    to_port     = 65535
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  tags = {
    Name = "autograder-security-group"
  }
}

# S3 bucket to store student code and results
resource "aws_s3_bucket" "autograder_bucket" {
  bucket = "cs-class-autograder-${random_id.bucket_suffix.hex}"

  tags = {
    Name        = "autograder-code-storage"
    Environment = "production"
  }
}

# Random suffix for unique S3 bucket name
resource "random_id" "bucket_suffix" {
  byte_length = 8
}

# S3 bucket policy to allow CodeBuild to access the bucket
resource "aws_s3_bucket_policy" "autograder_bucket_policy" {
  bucket = aws_s3_bucket.autograder_bucket.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:DeleteObject"
        ]
        Resource = "${aws_s3_bucket.autograder_bucket.arn}/*"
      }
    ]
  })
}

# Ensure S3 bucket is private
resource "aws_s3_bucket_ownership_controls" "autograder_ownership" {
  bucket = aws_s3_bucket.autograder_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "autograder_acl" {
  depends_on = [aws_s3_bucket_ownership_controls.autograder_ownership]
  bucket     = aws_s3_bucket.autograder_bucket.id
  acl        = "private"
}

# IAM role for CodeBuild to assume
resource "aws_iam_role" "codebuild_role" {
  name = "autograder-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
