        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for the CodeBuild role
resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_role.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:DeleteObject"
        ]
        Resource = aws_s3_bucket.autograder_bucket.arn
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetBucketLocation",
          "s3:ListAllMyBuckets"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:CreateNetworkInterface",
          "ec2:DescribeNetworkInterfaces",
          "ec2:DeleteNetworkInterface"
        ]
        Resource = "*"
      }
    ]
  })
}

# CodeBuild project to run student code
resource "aws_codebuild_project" "autograder_project" {
  name         = "cs-autograder"
  description  = "Autograder for CS class submissions"
  service_role = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    type            = "LINUX_CONTAINER"
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/standard:5.0"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "S3_BUCKET"
      value = aws_s3_bucket.autograder_bucket.bucket
    }

    # Restrict networking
    privileged_mode = false
  }

  source {
    type      = "GITHUB"
    location  = "https://github.com/example/cs101-homework.git" # To be replaced per student repo
    git_clone_depth = 1
  }

  # VPC configuration to place CodeBuild in private subnet without internet
  vpc_config {
    vpc_id             = aws_vpc.autograder_vpc.id
    subnets            = [aws_subnet.autograder_subnet.id]
    security_group_ids = [aws_security_group.autograder_sg.id]
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/cs-autograder"
      stream_name = "main"
    }
    s3_logs {
      status   = "ENABLED"
      location = "${aws_s3_bucket.autograder_bucket.id}/logs"
    }
  }

  # Ensure build never has internet access
  source_version = "main"
  timeout_in_minutes = 10
  queued_timeout_in_minutes = 480

  tags = {
    Project = "CS-Autograder"
  }
}

# Optional: VPC endpoint for S3 to allow CodeBuild to access S3 without internet
resource "aws_vpc_endpoint" "s3_endpoint" {
  vpc_id              = aws_vpc.autograder_vpc.id
  service_name        = "com.amazonaws.${var.region}.s3"
  vpc_endpoint_type   = "Gateway"
  route_table_ids     = [] # Gateway endpoints don't use route tables in same way
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = "*"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:DeleteObject"
        ]
        Resource = "${aws_s3_bucket.autograder_bucket.arn}/*"
      }
    ]
  })

  # Required for gateway endpoints
  route_table_ids = aws_route_table.private.ids
}

# Route table for private subnet (required for VPC endpoint)
resource "aws_route_table" "private" {
  vpc_id = aws_vpc.autograder_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "private-route-table"
  }
}

# Associate subnet with route table
resource "aws_route_table_association" "private_assoc" {
  subnet_id      = aws_subnet.autograder_subnet.id
  route_table_id = aws_route_table.private.id
}

# Internet gateway (required to have routes, but we control access via security group)
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.autograder_vpc.id

  tags = {
    Name = "autograder-igw"
  }
}

# Variables
variable "region" {
  description = "AWS region"
  default     = "us-west-2"
}

