# Step-by-step breakdown:
# 1. Create an S3 bucket to store CodeBuild output artifacts.
# 2. Create a VPC with the specified CIDR block (10.0.0.0/16).
# 3. Create a subnet within the VPC using CIDR block 10.0.0.0/24.
# 4. Create a security group associated with the VPC that denies all ingress and egress (default behavior with no rules).
# 5. Set up an AWS CodeBuild project with:
#    - Artifacts type S3 pointing to the created S3 bucket.
#    - Environment with BUILD_GENERAL1_SMALL, alpine image, and LINUX_CONTAINER type.
#    - Source from GitHub with git_clone_depth 1 and the provided location.
#    - vpc_config linking to the created VPC, subnet, and security group.

resource "aws_s3_bucket" "codebuild_artifacts" {
  bucket = "codebuild-output-artifacts-${random_string.suffix.result}"
  versioning {
    enabled = true
  }
}

resource "random_string" "suffix" {
  length  = 8
  special = false
  upper   = false
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "codebuild-vpc"
  }
}

resource "aws_subnet" "main" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.0.0/24"

  tags = {
    Name = "codebuild-subnet"
  }
}

resource "aws_security_group" "codebuild_sg" {
  name        = "codebuild-no-internet-sg"
  description = "Security group with no ingress or egress rules"
  vpc_id      = aws_vpc.main.id

  # No ingress or egress rules means all traffic is denied (default behavior)
  # So we omit any ingress/egress blocks to block all traffic
}

resource "aws_codebuild_project" "student_codebuild" {
