```hcl
# Step-by-step breakdown:

# 1. We need an S3 bucket to store cat pictures uploaded by users.
# 2. We need an API Gateway to expose HTTP endpoints:
#    - POST /upload: to upload cat pictures
#    - GET /random: to get a random cat picture
# 3. We need a Lambda function to handle the logic for uploading and retrieving random images.
# 4. The Lambda function requires an execution role with permissions to read/write S3 and write logs.
# 5. API Gateway will trigger the Lambda function.

resource "aws_s3_bucket" "cat_pictures_bucket" {
  bucket = "cat-pictures-${random_id.bucket_suffix.hex}"
  force_destroy = true # For easy cleanup; remove in production

  # Enable static website hosting if we want to serve images directly
  # But for API Gateway + Lambda control, we'll keep it private and access via Lambda
  acl = "private"

  versioning {
    enabled = true
  }

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

# IAM role for Lambda execution
resource "aws_iam_role" "lambda_execution_role" {
  name = "cat-picture-lambda-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for S3 and CloudWatch access
resource "aws_iam_role_policy" "lambda_policy" {
  name = "cat-picture-lambda-policy"
  role = aws_iam_role.lambda_execution_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.cat_pictures_bucket.arn,
          "${aws_s3_bucket.cat_pictures_bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      }
    ]
  })
}

# Lambda function to handle API requests
resource "aws_lambda_function" "cat_picture_handler" {
  filename         = "lambda_function_payload.zip" # This should be a deployment package
  function_name    = "cat-picture-handler"
  role             = aws_iam_role.lambda_execution_role.arn
  handler          = "index.handler"
  runtime          = "python3.9"

  environment {
    variables = {
      BUCKET_NAME = aws_s3_bucket.cat_pictures_bucket.bucket
    }
  }

  # Optional: If you have a local ZIP file
  # source_code_hash = filebase64sha256("lambda_function_payload.zip")
}

# API Gateway REST API
resource "aws_api_gateway_rest_api" "cat_api" {
  name        = "CatPictureAPI"
  description = "API for uploading and retrieving random cat pictures"
}

# Resource for /upload
resource "aws_api_gateway_resource" "upload_resource" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  parent_id   = aws_api_gateway_rest_api.cat_api.root_resource_id
  path_part   = "upload"
}

# Resource for /random
resource "aws_api_gateway_resource" "random_resource" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  parent_id   = aws_api_gateway_rest_api.cat_api.root_resource_id
  path_part   = "random"
}

# POST method for /upload
resource "aws_api_gateway_method" "upload_post" {
  rest_api_id   = aws_api_gateway_rest_api.cat_api.id
  resource_id   = aws_api_gateway_resource.upload_resource.id
  http_method   = "POST"
  authorization = "NONE"

  request_parameters = {
    "method.request.header.Content-Type" = true
  }

  request_models = {
    "application/json" = "Empty"
  }
}

# Integration of POST /upload with Lambda
resource "aws_api_gateway_integration" "upload_integration" {
  rest_api_id             = aws_api_gateway_rest_api.cat_api.id
  resource_id             = aws_api_gateway_resource.upload_resource.id
  http_method             = aws_api_gateway_method.upload_post.http_method
  integration_http_method = "POST"
  type                    = "AWS_PROXY"
  uri                     = aws_lambda_function.cat_picture_handler.invoke_arn
}

# GET method for /random
resource "aws_api_gateway_method" "random_get" {
  rest_api_id   = aws_api_gateway_rest_api.cat_api.id
  resource_id   = aws_api_gateway_resource.random_resource.id
  http_method   = "GET"
  authorization = "NONE"
}

# Integration of GET /random with Lambda
resource "aws_api_gateway_integration" "random_integration" {
  rest_api_id             = aws_api_gateway_rest_api.cat_api.id
  resource_id             = aws_api_gateway_resource.random_resource.id
  http_method             = aws_api_gateway_method.random_get.http_method
  integration_http_method = "POST"
  type                    = "AWS_PROXY"
  uri                     = aws_lambda_function.cat_picture_handler.invoke_arn
}

# Deploy the API
resource "aws_api_gateway_deployment" "api_deployment" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  stage_name  = "prod"

  triggers = {
    redeployment = sha1(jsonencode([
      aws_api_gateway_method.upload_post.http_method,
      aws_api_gateway_integration.upload_integration.uri,
      aws_api_gateway_method.random_get.http_method,
      aws_api_gateway_integration.random_integration.uri
    ]))
  }

  lifecycle {
    replace_triggered_by = [
      aws_api_gateway_method.upload_post,
      aws_api_gateway_integration.upload_integration,
      aws_api_gateway_method.random_get,
      aws_api_gateway_integration.random_integration
    ]
    ignore_changes = [execution_date]
  }
}

# Grant API Gateway permission to invoke the Lambda
resource "aws_lambda_permission" "api_gateway_invoke" {
  statement_id  = "AllowAPIGatewayInvoke"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.cat_picture_handler.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_api_gateway_rest_api.cat_api.execution_arn}/*/*"
}

# Output the API endpoint URL
output "api_url" {
  description = "The URL of the API Gateway endpoint"
  value       = "${aws_api_gateway_deployment.api_deployment.invoke_url}prod/"
}

# Output bucket name
output "bucket_name" {
  description = "S3 bucket name for cat pictures"
  value       = aws_s3_bucket.cat_pictures_bucket.bucket
}
