extracted_code:
# We are building a serverless web application for uploading and retrieving random cat pictures.
# Components:
# 1. S3 Bucket - to store cat pictures
# 2. Lambda Function - to handle upload and retrieval logic
# 3. API Gateway - to expose REST endpoints for upload and get random image
# 4. IAM Role - for Lambda to access S3 and write logs
# 5. (Optional) CloudWatch Logs for debugging

# We will create:
# - POST /cats - upload a cat image (via base64 encoded body or form data)
# - GET /cats/random - retrieve a signed URL to a random cat image

# Assumptions:
# - Images are uploaded via JSON with base64-encoded data and a filename
# - Lambda processes the upload and stores in S3
# - GET /random returns a presigned URL valid for a short time

provider "aws" {
  region = "us-east-1"
}

# S3 bucket to store cat images
resource "aws_s3_bucket" "cat_pictures" {
  bucket = "cat-pictures-${random_string.suffix.result}"
  force_destroy = true
}

resource "aws_s3_bucket_versioning" "cat_pictures" {
  bucket = aws_s3_bucket.cat_pictures.id
  versioning_configuration {
    status = "Enabled"
  }
}

# Enable S3 block public access
resource "aws_s3_bucket_public_access_block" "cat_pictures" {
  bucket = aws_s3_bucket.cat_pictures.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Lambda execution role
resource "aws_iam_role" "lambda_role" {
  name = "cat-lambda-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for Lambda to access S3 and CloudWatch
resource "aws_iam_role_policy_attachment" "lambda_s3_logs" {
  role       = aws_iam_role.lambda_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

resource "aws_iam_policy" "s3_access" {
  name = "cat-lambda-s3-access"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:ListBucket"
        ]
        Effect = "Allow"
        Resource = [
          aws_s3_bucket.cat_pictures.arn,
          "${aws_s3_bucket.cat_pictures.arn}/*"
        ]
      }
    ]
  })
}

resource "aws_iam_policy_attachment" "s3_access_attachment" {
  name       = "cat-lambda-s3-access-attachment"
  roles      = [aws_iam_role.lambda_role.name]
  policy_arn = aws_iam_policy.s3_access.arn
}

# Generate a unique suffix for bucket name
resource "random_string" "suffix" {
  length  = 8
  special = false
  upper   = false
}

# Lambda function code (simple placeholder)
data "archive_file" "lambda_zip" {
  type        = "zip"
  source_file = "${path.module}/lambda_function.py"
  output_path = "${path.module}/lambda_function.zip"
}

# Check if local lambda file exists; if not, we'll generate a simple one
# But we'll assume it exists or will be created via templating.

# In practice, you'd write a Python Lambda function that:
# - Parses event
# - On POST: decodes base64, saves to S3 with UUID filename
# - On GET: lists objects, picks random, generates presigned URL

# Since we can't include files directly, we use templatefile or base64 inline.
# Here we use a local file, but for completeness, we'll generate a simple script via file provisioner in real use.

# Lambda function
resource "aws_lambda_function" "cat_handler" {
  filename         = data.archive_file.lambda_zip.output_path
  function_name    = "cat-picture-handler"
  role             = aws_iam_role.lambda_role.arn
  handler          = "lambda_function.lambda_handler"
  runtime          = "python3.9"
  source_code_hash = data.archive_file.lambda_zip.output_base64sha256

  environment {
    variables = {
      BUCKET_NAME = aws_s3_bucket.cat_pictures.id
    }
  }

  timeout = 30
}

# API Gateway v2 (HTTP API) for simplicity
resource "aws_apigatewayv2_api" "cats_api" {
  name          = "Cat Picture API"
  protocol_type = "HTTP"
}

# Random cat image integration
resource "aws_apigatewayv2_integration" "get_random_cat" {
  api_id           = aws_apigatewayv2_api.cats_api.id
  integration_type = "AWS_PROXY"
  integration_uri  = aws_lambda_function.cat_handler.invoke_arn
  passthrough_behavior = "WHEN_NO_MATCH"
}

# Upload cat image integration
resource "aws_apigatewayv2_integration" "upload_cat" {
  api_id           = aws_apigatewayv2_api.cats_api.id
  integration_type = "AWS_PROXY"
  integration_uri  = aws_lambda_function.cat_handler.invoke_arn
  passthrough_behavior = "WHEN_NO_MATCH"
}

# POST /cats route
resource "aws_apigatewayv2_route" "upload_route" {
  api_id    = aws_apigatewayv2_api.cats_api.id
  route_key = "POST /cats"
  target    = "integrations/${aws_apigatewayv2_integration.upload_cat.id}"
}

# GET /cats/random route
resource "aws_apigatewayv2_route" "get_random_route" {
  api_id    = aws_apigatewayv2_api.cats_api.id
  route_key = "GET /cats/random"
  target    = "integrations/${aws_apigatewayv2_integration.get_random_cat.id}"
}

# Deploy the API
resource "aws_apigatewayv2_stage" "default_stage" {
  api_id = aws_apigatewayv2_api.cats_api.id
  name   = "prod"
  auto_deploy = true
}

# Grant API Gateway permission to invoke Lambda
resource "aws_lambda_permission" "api_invoke" {
  statement_id  = "AllowExecutionFromAPIGateway"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.cat_handler.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_apigatewayv2_api.cats_api.execution_arn}/*/*"
}

# Output the API endpoint
output "api_endpoint" {
  value = "${aws_apigatewayv2_api.cats_api.api_endpoint}/${aws_apigatewayv2_stage.default_stage.name}"
}

output "s3_bucket_name" {
  value = aws_s3_bucket.cat_pictures.bucket
}

