  role       = aws_iam_role.lambda_execution_role.name
  policy_arn = aws_iam_policy.lambda_policy.arn
}

# Lambda function to handle uploads and serve random cat pictures
resource "aws_lambda_function" "cat_service_lambda" {
  filename         = "lambda/cat_service.zip" # Placeholder for deployment package
  function_name    = "cat-service-function"
  role             = aws_iam_role.lambda_execution_role.arn
  handler          = "main.handler"
  runtime          = "python3.9"
  source_code_hash = filebase64sha256("lambda/cat_service.zip")

  environment {
    variables = {
      S3_BUCKET_NAME = aws_s3_bucket.cat_pictures_bucket.bucket
      DYNAMODB_TABLE = aws_dynamodb_table.cat_pictures_metadata.name
    }
  }

  timeout = 30
  memory_size = 256
}

# API Gateway Rest API
resource "aws_api_gateway_rest_api" "cat_api" {
  name        = "CatPictureAPI"
  description = "API to upload and retrieve cat pictures"
}

# API Gateway Resource for /upload
resource "aws_api_gateway_resource" "upload_resource" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  parent_id   = aws_api_gateway_rest_api.cat_api.root_resource_id
  path_part   = "upload"
}

# API Gateway Resource for /random
resource "aws_api_gateway_resource" "random_resource" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  parent_id   = aws_api_gateway_rest_api.cat_api.root_resource_id
  path_part   = "random"
}

# Method for POST /upload
resource "aws_api_gateway_method" "upload_method" {
  rest_api_id   = aws_api_gateway_rest_api.cat_api.id
  resource_id   = aws_api_gateway_resource.upload_resource.id
  http_method   = "POST"
  authorization = "NONE"

  request_parameters = {
    "method.request.header.Content-Type" = true
  }

  request_models = {
    "application/json" = "Empty"
  }
}

# Method for GET /random
resource "aws_api_gateway_method" "random_method" {
  rest_api_id   = aws_api_gateway_rest_api.cat_api.id
  resource_id   = aws_api_gateway_resource.random_resource.id
  http_method   = "GET"
  authorization = "NONE"
}

# Integration for POST /upload to Lambda
resource "aws_api_gateway_integration" "upload_integration" {
  rest_api_id             = aws_api_gateway_rest_api.cat_api.id
  resource_id             = aws_api_gateway_resource.upload_resource.id
  http_method             = aws_api_gateway_method.upload_method.http_method
  type                    = "AWS_PROXY"
  integration_http_method = "POST"
  uri                     = aws_lambda_function.cat_service_lambda.invoke_arn
}

# Integration for GET /random to Lambda
resource "aws_api_gateway_integration" "random_integration" {
  rest_api_id             = aws_api_gateway_rest_api.cat_api.id
  resource_id             = aws_api_gateway_resource.random_resource.id
  http_method             = aws_api_gateway_method.random_method.http_method
  type                    = "AWS_PROXY"
  integration_http_method = "POST"
  uri                     = aws_lambda_function.cat_service_lambda.invoke_arn
}

# Deploy the API
resource "aws_api_gateway_deployment" "api_deployment" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  stage_name  = "prod"

  triggers = {
    redeployment = sha1(jsonencode([
      aws_api_gateway_method.upload_method.http_method,
      aws_api_gateway_method.random_method.http_method,
      aws_api_gateway_integration.upload_integration.uri,
      aws_api_gateway_integration.random_integration.uri
    ]))
  }

  lifecycle {
    replace_triggered_by = [
      aws_api_gateway_method.upload_method,
      aws_api_gateway_method.random_method,
      aws_api_gateway_integration.upload_integration,
      aws_api_gateway_integration.random_integration
    ]
    ignore_changes = []
  }
}

# Grant API Gateway permission to invoke Lambda
resource "aws_lambda_permission" "apigateway_invoke_permission_upload" {
  statement_id  = "AllowAPIGatewayInvokeUpload"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.cat_service_lambda.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_api_gateway_rest_api.cat_api.execution_arn}/*/POST/upload"
}

resource "aws_lambda_permission" "apigateway_invoke_permission_random" {
  statement_id  = "AllowAPIGatewayInvokeRandom"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.cat_service_lambda.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_api_gateway_rest_api.cat_api.execution_arn}/*/GET/random"
}

# Output the API endpoint URL
output "api_endpoint" {
  description = "API Gateway endpoint URL"
  value       = "${aws_api_gateway_deployment.api_deployment.invoke_url}prod"
}

output "s3_bucket_name" {
  description = "S3 bucket name for cat pictures"
  value       = aws_s3_bucket.cat_pictures_bucket.bucket
}

output "dynamodb_table_name" {
  description = "DynamoDB table name for metadata"
  value       = aws_dynamodb_table.cat_pictures_metadata.name
}
```

