# We need to provision an EC2 instance and set up daily backups at midnight using AWS Backup.
# Steps:
# 1. Create an EC2 instance with necessary resources (VPC, subnet, security group, IAM role if needed).
# 2. Set up AWS Backup by creating:
#    a. A backup vault (required to store backups).
#    b. A backup plan with a rule to backup daily at midnight.
#    c. A backup selection to associate the EC2 instance with the backup plan.
# 3. Ensure the EC2 instance is tagged so it can be selected by the backup plan (via condition or directly).

# We'll use a default VPC and subnet for simplicity, but in production, you might define your own.

resource "aws_instance" "example" {
  ami           = "ami-0c02fb55956c7d316"  # Example Amazon Linux 2 AMI (us-west-2), change as needed
  instance_type = "t2.micro"

  # Optional: Add a tag so we can use it in backup selection
  tags = {
    Name = "example-instance"
    Backup = "daily"  # This tag will be used in backup selection
  }
}

# AWS Backup Vault
resource "aws_backup_vault" "vault" {
  name = "daily-backup-vault"
}

# AWS Backup Plan: Daily at midnight UTC
resource "aws_backup_plan" "daily_plan" {
  name = "daily-midnight-backup"

  rule {
    rule_name         = "daily-midnight-rule"
    target_vault_name = aws_backup_vault.vault.name
    schedule          = "cron(0 0 * * ? *)"  # Daily at midnight UTC

    # Optional: Enable continuous backup and set recovery point TTL
    # lifecycle {
    #   delete_after = 35 # days
    # }
  }
}

# AWS Backup Selection: Select EC2 instances with tag Backup= daily
resource "aws_backup_selection" "selection" {
  iam_role_arn = aws_iam_role.backup_role.arn
  name         = "selected-instances"
  plan_id      = aws_backup_plan.daily_plan.id

  selection_tag {
    type  = "STRINGEQUALS"
    key   = "Backup"
    value = "daily"
  }
}

# IAM Role for AWS Backup to perform actions on EC2
resource "aws_iam_role" "backup_role" {
  name = "AWSBackupRole"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "backup.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Role Policy for AWS Backup
resource "aws_iam_role_policy" "backup_policy" {
  name = "AWSBackupPolicy"
  role = aws_iam_role.backup_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "ec2:DescribeVolumes",
          "ec3:DescribeInstanceAttribute",
          "ec2:DescribeInstances",
          "ec2:DescribeTags",
          "ec2:GetVolumeAttribute",
          "ec2:CreateSnapshots",
          "ec2:CreateTags",
          "ec2:DeleteSnapshot",
          "ec2:DeleteTags",
          "ec2:ResetSnapshotAttribute",
          "ec2:ModifySnapshotAttribute"
        ]
        Resource = "*"
      }
    ]
  })
}

