# 2. We must use AWS Backup to create daily backups (snapshots) of the EC2 instance.
# 3. AWS Backup requires a backup vault, backup plan, and backup selection (via IAM role).
# 4. The backup should trigger daily at midnight UTC.
# 5. We may need an IAM role to allow AWS Backup to manage backups on EC2.

resource "aws_backup_vault" "daily_backup_vault" {
  name        = "daily-backup-vault"
  description = "Vault for daily EC2 backups"
}

resource "aws_backup_plan" "daily_backup_plan" {
  name = "daily-backup-plan"

  rule {
    rule_name         = "daily-backup-rule"
    target_vault_name = aws_backup_vault.daily_backup_vault.name
    schedule          = "cron(0 0 * * ? *)"  # Midnight UTC every day
    start_window_minutes = 60
    completion_window_minutes = 180

    lifecycle {
      delete_after = 35 # Keep backups for 35 days
    }
  }
}

