# We need to provision an EC2 instance with a key pair and set up daily backups at midnight using AWS Backup.
# Steps:
# 1. Create an EC2 key pair (we'll use an existing public key or generate one; for AWS, we typically import a public key).
# 2. Provision an EC2 instance using that key pair.
# 3. Create a Backup Vault to store backups.
# 4. Create a Backup Plan with a rule to back up daily at midnight (Cron expression: cron(0 0 * * ? *)).
# 5. Assign the EC2 instance to the Backup Plan using a Backup Selection (via IAM role, as required by AWS Backup).
# 6. Ensure an IAM role is created for AWS Backup to access EC2 and perform backups.

provider "aws" {
  region = "us-west-2" # You can change this to your preferred region
}

# Step 1: Create an EC2 key pair
# Note: You should have a public key. For demonstration, assuming you have one.
# Replace the public_key with your actual public key or use tls_private_key resource to generate one.
resource "aws_key_pair" "backup_key" {
  key_name   = "terraform-backup-key"
  public_key = "ssh-rsa AAAAB3NzaC1yc2EAAAADAQABAAABAQD3F6tyPEFEzV0LX3X8BsXdMsQz1x2cEikSjedkHOEhf/QOnYw/pj8ZtxaYqHCXZz0j/gnpNprDdAg84aiWT5+Ftfo1lsRsOabQS4/rIActGGMSoX1/hkTEpNp46YLTC3ZlWGnMrSwB2Va4SSHvziWrBN0EMykHdw4BOKW3OfSQvcjhMWZUZWpl5UgKHASzDeERmzu2taUHg==" # Replace with your public key
}

# Step 2: Provision EC2 instance
resource "aws_instance" "backup_instance" {
  ami           = "ami-0c02fb55956c7d316" # Amazon Linux 2 in us-west-2, change as needed
  instance_type = "t3.micro"
  key_name      = aws_key_pair.backup_key.key_name

  tags = {
    Name = "backup-enabled-instance"
  }
}

# Step 3: Create a Backup Vault
resource "aws_backup_vault" "backup_vault" {
  name = "daily-backup-vault"
}

# Step 4: Create a Backup Plan with daily backup at midnight UTC
resource "aws_backup_plan" "daily_backup_plan" {
  name = "daily-midnight-backup-plan"

  rule {
    rule_name         = "daily-midnight-backup"
    target_vault_name = aws_backup_vault.backup_vault.name
    schedule          = "cron(0 0 * * ? *)" # Every day at midnight UTC
    start_window_minutes = 60
    completion_window_minutes = 120

    lifecycle {
      delete_after = 35 # Retain backups for 35 days
    }
  }
}

# Step 5 & 6: Create IAM role for AWS Backup service
resource "aws_iam_role" "backup_role" {
  name = "aws-backup-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "backup.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "backup_policy" {
  role       = aws_iam_role.backup_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForBackup"
}

resource "aws_iam_role_policy_attachment" "backup_s3_policy" {
  role       = aws_iam_role.backup_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3FullAccess" # Required if backing up to S3, though Backup vault handles this
}

# Associate the EC2 instance with the Backup Plan using a selection
resource "aws_backup_selection" "instance_selection" {
  iam_role_arn = aws_iam_role.backup_role.arn
  name         = "backup-instance-selection"
  plan_id      = aws_backup_plan.daily_backup_plan.id

  selection_tag {
    type  = "STRINGEQUALS"
    key   = "Backup"
    value = "true"
  }

  # Alternatively, specify resources directly (but tags are more scalable)
  # resources = [aws_instance.backup_instance.arn]
}

# Add tag to EC2 instance so the selection picks it up
resource "aws_backup_selection" "example" {
  depends_on = [aws_instance.backup_instance]

  iam_role_arn = aws_iam_role.backup_role.arn
  name         = "ec2-instance-backup-selection"
  plan_id      = aws_backup_plan.daily_backup_plan.id

  resources = [aws_instance.backup_instance.arn]
}

