  name = "daily-midnight-backup-plan"

  rule {
    rule_name         = "daily-midnight-backup"
    target_vault_name = aws_backup_vault.backup_vault.name
    schedule          = "cron(0 0 * * ? *)" # Every day at midnight UTC
    start_window_minutes = 60
    completion_window_minutes = 120

    lifecycle {
      delete_after = 35 # Retain backups for 35 days
    }
  }
}

# Step 5 & 6: Create IAM role for AWS Backup service
resource "aws_iam_role" "backup_role" {
  name = "aws-backup-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "backup.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "backup_policy" {
  role       = aws_iam_role.backup_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForBackup"
}

resource "aws_iam_role_policy_attachment" "backup_s3_policy" {
  role       = aws_iam_role.backup_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3FullAccess" # Required if backing up to S3, though Backup vault handles this
}

# Associate the EC2 instance with the Backup Plan using a selection
resource "aws_backup_selection" "instance_selection" {
  iam_role_arn = aws_iam_role.backup_role.arn
  name         = "backup-instance-selection"
  plan_id      = aws_backup_plan.daily_backup_plan.id

  selection_tag {
    type  = "STRINGEQUALS"
    key   = "Backup"
    value = "true"
  }

  # Alternatively, specify resources directly (but tags are more scalable)
  # resources = [aws_instance.backup_instance.arn]
}

# Add tag to EC2 instance so the selection picks it up
resource "aws_backup_selection" "example" {
  depends_on = [aws_instance.backup_instance]

  iam_role_arn = aws_iam_role.backup_role.arn
  name         = "ec2-instance-backup-selection"
  plan_id      = aws_backup_plan.daily_backup_plan.id

  resources = [aws_instance.backup_instance.arn]
}
