extracted_code:
# We are creating a solution that runs code every day at 7 UTC using AWS EventBridge and AWS Lambda.
# Steps:
# 1. Create a Lambda function that contains the code to be executed.
# 2. Create an EventBridge rule that triggers daily at 7 UTC.
# 3. Grant EventBridge permission to invoke the Lambda function.
# 4. Set up the target to link the EventBridge rule to the Lambda function.

# We'll also include a simple Python script inline for the Lambda function.

resource "aws_iam_role" "lambda_role" {
  name = "lambda-eventbridge-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

resource "aws_iam_role_policy" "lambda_allow_eventbridge" {
  name = "lambda_allow_eventbridge"
  role = aws_iam_role.lambda_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = "events:PutTargets"
        Resource = "arn:aws:events:*:*:rule/*"
      },
      {
        Effect = "Allow"
        Action = "events:PutRule"
        Resource = "arn:aws:events:*:*:rule/*"
      }
    ]
  })
}

resource "aws_lambda_function" "daily_task" {
  filename      = "lambda_function_payload.zip" # We'll use a pre-packaged zip or inline equivalent via base64
  function_name = "daily-task-lambda"
  role          = aws_iam_role.lambda_role.arn
  handler       = "index.lambda_handler"
  runtime       = "python3.9"

  # Using a simple inline script for demonstration
  source_code_hash = filebase64sha256("lambda_function_payload.zip")

  # Alternatively, use source_code for small functions (not recommended for production)
  # But since we need a file, we assume the ZIP is created separately.
  # For demo, we can use a local file or use base64inline.

  # We'll create a local file using null_resource or assume it's present.
  # Here we assume the ZIP file is generated or exists.
}

# Create a zip file with the Lambda code using data archive provider (if not external)
data "archive_file" "lambda_zip" {
  type        = "zip"
  source_dir  = "${path.module}/lambda"
  output_path = "${path.module}/lambda_function_payload.zip"
}

# Create directory and file via local-exec if not exists (but we'll just rely on data.archive_file expecting the dir)
# Instead, create a file in the lambda directory

# We'll output the source code hash via archive_file
# Update the lambda function to use this archive
resource "aws_lambda_function" "daily_task" {
  filename      = data.archive_file.lambda_zip.output_path
  function_name = "daily-task-lambda"
  role          = aws_iam_role.lambda_role.arn
  handler       = "index.lambda_handler"
  runtime       = "python3.9"

  source_code_hash = data.archive_file.lambda_zip.output_base64sha256

  provisioner "local-exec" {
    command = "mkdir -p ${path.module}/lambda && echo 'def lambda_handler(event, context):
    print("Daily task executed at " + str(context.get("get_remaining_time_in_millis")))
    return {"status": "success"}' > ${path.module}/lambda/index.py"
    when      = create
  }

  provisioner "local-exec" {
    command = "rm -rf ${path.module}/lambda"
    when    = destroy
  }
}

# Create EventBridge rule to trigger daily at 7 UTC
resource "aws_cloudwatch_event_rule" "daily_7_utc" {
  name                = "daily-7-utc-trigger"
  description         = "Triggers daily at 7 UTC"
  schedule_expression = "cron(0 7 * * ? *)"  # Every day at 7:00 UTC
}

# Allow EventBridge to invoke the Lambda function
resource "aws_lambda_permission" "allow_eventbridge" {
  statement_id  = "AllowExecutionFromEventBridge"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.daily_task.function_name
  principal     = "events.amazonaws.com"
  source_arn    = aws_cloudwatch_event_rule.daily_7_utc.arn
}

# Set the Lambda function as the target of the EventBridge rule
resource "aws_cloudwatch_event_target" "lambda_target" {
  rule      = aws_cloudwatch_event_rule.daily_7_utc.name
  target_id = "DailyLambdaTask"
  arn       = aws_lambda_function.daily_task.arn
}

# Output the Lambda function name and EventBridge rule
output "lambda_function_name" {
  value = aws_lambda_function.daily_task.function_name
}

output "eventbridge_rule_name" {
  value = aws_cloudwatch_event_rule.daily_7_utc.name
}

