# We are implementing a daily cron job that runs at 7 UTC using AWS EventBridge and Lambda.
# Steps:
# 1. Create a Lambda function (using a simple dummy handler for illustration).
# 2. Grant EventBridge permission to invoke the Lambda function via a lambda permission resource.
# 3. Create an EventBridge rule with a cron expression to trigger daily at 7 UTC.
# 4. Define a target to connect the rule to the Lambda function.
# 5. Add necessary IAM role and policy for Lambda execution (basic execution role).

resource "aws_iam_role" "lambda_role" {
  name = "lambda-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_policy" "lambda_logging" {
  name = "lambda-logging"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Effect = "Allow"
        Resource = "arn:aws:logs:*:*:*"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_logging" {
  role       = aws_iam_role.lambda_role.name
  policy_arn = aws_iam_policy.lambda_logging.arn
}

resource "aws_lambda_function" "daily_job_function" {
  filename      = "lambda_function.zip" # Dummy file; in practice, this should be a valid deployment package
  function_name = "daily-job-function"
  role          = aws_iam_role.lambda_role.arn
  handler       = "index.handler"
  runtime       = "python3.9"

  # Example inline source code (very basic)
  source_code_hash = filebase64sha256("lambda_function.zip")

  # To allow updating the function code
  publish = true
}

resource "aws_lambda_permission" "allow_eventbridge" {
  statement_id  = "AllowExecutionFromEventBridge"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.daily_job_function.function_name
  principal     = "events.amazonaws.com"
  source_arn    = aws_cloudwatch_event_rule.daily_cron.arn
}

resource "aws_cloudwatch_event_rule" "daily_cron" {
  name                = "daily-trigger"
  description         = "Daily trigger at 7 UTC"
  schedule_expression = "cron(0 7 * * ? *)"  # Runs every day at 7:00 UTC
}

resource "aws_cloudwatch_event_target" "lambda_target" {
  rule      = aws_cloudwatch_event_rule.daily_cron.name
  target_id = "lambda-daily-job"
  arn       = aws_lambda_function.daily_job_function.arn
}

