# Step 1: Define the Lambda function resource
# We need to create a Lambda function that uses the provided deployment package.
# The source code is in a local zip file located at "./supplement/lambda_func.zip".

resource "aws_lambda_function" "target_function" {
  filename         = "./supplement/lambda_func.zip"
  function_name    = "eventbridge-target-function"
  role             = aws_iam_role.lambda_execution_role.arn
  handler          = "index.handler" # Assuming default handler; can be adjusted
  runtime          = "python3.9"     # Default runtime; should be set based on actual code
  source_code_hash = filebase64sha256("./supplement/lambda_func.zip")
}

# Step 2: Create an IAM role for the Lambda function to execute with necessary permissions
resource "aws_iam_role" "lambda_execution_role" {
  name = "lambda-execution-role-eventbridge"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# Step 3: Attach a basic execution policy to the IAM role
resource "aws_iam_role_policy_attachment" "lambda_basic_exec" {
  role       = aws_iam_role.lambda_execution_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# Step 4: Create an EventBridge rule that triggers daily at 7 UTC
# Use a cron expression: cron(0 7 * * ? *) means "at 0 minutes past hour 7 every day"
resource "aws_cloudwatch_event_rule" "cron_rule" {
  name        = "cron"
  description = "Triggers daily at 7 UTC"
  schedule_expression = "cron(0 7 * * ? *)"
}

# Step 5: Set up permission for EventBridge to invoke the Lambda function
resource "aws_lambda_permission" "eventbridge_to_lambda" {
  statement_id  = "AllowExecutionFromEventBridge"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.target_function.function_name
  principal     = "events.amazonaws.com"
  source_arn    = aws_cloudwatch_event_rule.cron_rule.arn
}

# Step 6: Create the target that links the EventBridge rule to the Lambda function
resource "aws_cloudwatch_event_target" "lambda_target" {
  rule      = aws_cloudwatch_event_rule.cron_rule.name
  target_id = "lambda-target"
  arn       = aws_lambda_function.target_function.arn
}

