```hcl
# Step 1: Create an AWS EventBridge event rule with a cron schedule for every day at 7 UTC
resource "aws_cloudwatch_event_rule" "cron" {
  name                = "cron"
  schedule_expression = "cron(0 7 * * ? *)"
}

# Step 2: Create a Lambda function with the specified configuration
resource "aws_lambda_function" "cron" {
  function_name = "cron-lambda-function"
  filename      = "./supplement/lambda_func.zip"
  handler       = "lambda_func.lambda_handler"
  runtime       = "python3.12"

  # Assuming a role is needed for the Lambda function (typical requirement)
  # This assumes a basic execution role exists or is created separately
  role = aws_iam_role.lambda_exec.arn
}

# Step 3: Create an EventBridge event target to link the rule to the Lambda function
resource "aws_cloudwatch_event_target" "cron_target" {
  rule      = aws_cloudwatch_event_rule.cron.name
  target_id = "cron-lambda-target"
  arn       = aws_lambda_function.cron.arn
}

# Step 4: Grant EventBridge permission to invoke the Lambda function
resource "aws_lambda_permission" "allow_eventbridge" {
  function_name = aws_lambda_function.cron.function_name
  action        = "lambda:InvokeFunction"
  principal     = "events.amazonaws.com"
  source_arn    = aws_cloudwatch_event_rule.cron.arn
}

# Step 5: Create an IAM role for the Lambda function (required for execution)
resource "aws_iam_role" "lambda_exec" {
  name = "lambda-execution-role-cron"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# Step 6: Attach a basic execution policy to the role for logging (required for Lambda)
resource "aws_iam_role_policy_attachment" "lambda_exec_policy" {
  role       = aws_iam_role.lambda_exec.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}
```

