# Step-by-step breakdown:
# 1. We need an S3 bucket to store the video content (source of truth).
# 2. The S3 bucket should be configured for static website hosting or just act as an origin for CloudFront.
# 3. Block public access initially and use CloudFront as the secure distributor.
# 4. Create a CloudFront distribution with the S3 bucket as the origin.
# 5. Configure CloudFront for low-latency global video delivery (e.g., enabled for all edge locations).
# 6. Set up cache behaviors suitable for video streaming (e.g., support for range requests, proper TTLs).
# 7. Optionally enable logging and SSL via ACM certificate on CloudFront (using default domain for simplicity).

resource "aws_s3_bucket" "video_content_bucket" {
  bucket = "my-video-streaming-site-content"

  # Enable static website hosting if needed; otherwise, just act as origin
  # Not required if accessed only via CloudFront
  website {
    index_document = "index.html"
    error_document = "error.html"
  }

  # Block all public access by default - access via CloudFront OAI
  block_public_acls        = true
  block_public_policy      = true
  ignore_public_acls       = true
  restrict_public_buckets  = true

  versioning {
    enabled = true
  }

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }

  tags = {
    Name        = "Video Content Bucket"
    Environment = "production"
  }
}

# S3 bucket policy to allow CloudFront to access the content
data "aws_iam_policy_document" "s3_bucket_policy" {
  statement {
    effect = "Allow"
    principals {
      type        = "AWS"
      identifiers = [aws_cloudfront_origin_access_identity.oai.iam_arn]
    }

    actions = [
      "s3:GetObject"
    ]

    resources = [
      "${aws_s3_bucket.video_content_bucket.arn}/*"
    ]
  }
}

resource "aws_s3_bucket_policy" "allow_cloudfront_access" {
  bucket = aws_s3_bucket.video_content_bucket.id
  policy = data.aws_iam_policy_document.s3_bucket_policy.json
}

# CloudFront Origin Access Identity
resource "aws_cloudfront_origin_access_identity" "oai" {
  comment = "OAI for accessing S3 video content"
}

# CloudFront distribution
resource "aws_cloudfront_distribution" "video_distribution" {
  origin {
    domain_name = aws_s3_bucket.video_content_bucket.bucket_regional_domain_name
    origin_id   = "S3-${aws_s3_bucket.video_content_bucket.id}"

    s3_origin_config {
      origin_access_identity = aws_cloudfront_origin_access_identity.oai.cloudfront_access_identity_path
    }
  }

  enabled             = true
  is_ipv6_enabled     = true
  comment             = "CloudFront distribution for global video streaming"
  default_root_object = "index.html"
  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD", "OPTIONS"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "S3-${aws_s3_bucket.video_content_bucket.id}"

    forward_cookies {
      forward = "none"
    }

    query_string = false

    # Viewer protocol policy - allow HTTPS only for secure streaming
    viewer_protocol_policy = "redirect-to-https"

    # Minimum TTL for video chunks (can be adjusted based on CDN strategy)
    min_ttl     = 0
    default_ttl = 86400  # 24 hours
    max_ttl     = 31536000  # 1 year

    # Enable support for range requests (important for video seeking)
    compress = true

    # Set cache policy for media content (customizable via AWS managed policies)
    cache_policy_id    = "658327ea-f89d-4fab-a63d-7e88639e58f6" # Managed-CachingOptimizedForStreaming
    origin_request_policy_id = "b68967e7-5c5b-4aab-9d28-3b7a6d592a08" # Managed-CORS-S3Origin
  }

  # Optional: custom SSL certificate (if using custom domain)
  # viewer_certificate {
  #   acm_certificate_arn = aws_acm_certificate.cert.arn
  #   ssl_support_method  = "sni-only"
  # }

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  price_class = "PriceClass_100" # Most cost-effective for predictable traffic

  # Logging
  logging_config {
    include_cookies = false
    bucket          = "${aws_s3_bucket.video_content_bucket.bucket_regional_domain_name}"
    prefix          = "cloudfront-logs/"
  }

  tags = {
    Environment = "production"
    Application = "video-streaming"
  }
}

