```hcl
# Step 1: Define required providers
provider "aws" {
  region = "us-east-1" # Default region, can be changed as needed
  default_tags {
    tags = {
      Environment = "production"
      Project     = "video-streaming-site"
    }
  }
}

# Step 2: Create an S3 bucket to store video content
# The bucket will be configured for static website hosting and public read access (videos should be publicly accessible)
resource "aws_s3_bucket" "video_content" {
  bucket = "video-streaming-site-content-${random_string.suffix.result}"

  tags = {
    Name        = "video-content-bucket"
    Environment = "production"
  }
}

resource "aws_s3_bucket_ownership_controls" "video_content_ownership" {
  bucket = aws_s3_bucket.video_content.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "video_content_acl" {
  depends_on = [aws_s3_bucket_ownership_controls.video_content_ownership]
  bucket     = aws_s3_bucket.video_content.id
  acl        = "public-read"
}

# Enable static website hosting if needed (optional for CloudFront + S3 origin)
resource "aws_s3_bucket_website_configuration" "video_content_website" {
  bucket = aws_s3_bucket.video_content.id

  index_document {
    suffix = "index.html"
  }

  error_document {
    key = "error.html"
  }
}

# Bucket policy to allow public read access for CloudFront and direct access
resource "aws_s3_bucket_policy" "video_content_policy" {
  bucket = aws_s3_bucket.video_content.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "PublicReadGetObject"
        Effect    = "Allow"
        Principal = "*"
        Action    = "s3:GetObject"
        Resource  = "${aws_s3_bucket.video_content.arn}/*"
      }
    ]
  })
}

# Step 3: Create a CloudFront distribution to cache and serve content globally
resource "aws_cloudfront_distribution" "video_distribution" {
  enabled             = true
  comment             = "CloudFront distribution for video streaming site"
  default_root_object = "index.html"

  # Use S3 bucket as origin
  origin {
    domain_name = aws_s3_bucket.video_content.bucket_regional_domain_name
    origin_id   = "S3-${aws_s3_bucket.video_content.id}"

    s3_origin_config {
      origin_access_identity = aws_cloudfront_origin_access_identity.oai.cloudfront_access_identity_path
    }
  }

  # Default cache behavior
  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD", "OPTIONS"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "S3-${aws_s3_bucket.video_content.id}"

    forwarded_values {
      query_string = false
      cookies {
        forward = "none"
      }
    }

    viewer_protocol_policy = "redirect-to-https"
    min_ttl                = 0
    default_ttl            = 86400
    max_ttl                = 31536000

    # For video streaming, real-time cache invalidation and field-level encryption are not required
  }

  # Cache policy for video content (longer TTLs)
  cache_policy_id      = aws_cloudfront_cache_policy.video_cache.id
  http_version         = "http2"
  is_ipv6_enabled      = true

  # Use AWS-managed SSL certificate via ACM (requires Route53 domain)
  viewer_certificate {
    acm_certificate_arn = aws_acm_certificate.certificate.arn
    ssl_support_method  = "sni-only"
    minimum_protocol_version = "TLSv1.2_2021"
  }

  # Logging
  logging_config {
    include_cookies = false
    bucket          = "${aws_s3_bucket.logs.bucket}.s3.amazonaws.com"
    prefix          = "cloudfront-logs/"
  }
}

# Step 4: Create a cache policy optimized for video content
resource "aws_cloudfront_cache_policy" "video_cache" {
  name        = "video-streaming-cache-policy"
  comment     = "Cache policy for video streaming content"
  default_ttl = 86400     # 24 hours
  max_ttl     = 31536000  # 1 year
  min_ttl     = 0

  parameters_in_cache_key_and_forwarded_to_origin {
    cookies_config {
      cookie_behavior = "none"
    }

    headers_config {
      header_behavior = "none"
    }

    query_strings_config {
      query_string_behavior = "none"
    }

    enable_accept_encoding_gzip = true
    enable_accept_encoding_brotli = true
  }
}

# Step 5: Create CloudFront Origin Access Identity to securely access S3
resource "aws_cloudfront_origin_access_identity" "oai" {
  comment = "OAI for video content S3 bucket"
}

# Step 6: Update S3 bucket policy to allow CloudFront OAI access instead of public
# Replace the earlier public S3 policy with one that restricts to CloudFront OAI
resource "aws_s3_bucket_policy" "video_content_oai_policy" {
  bucket = aws_s3_bucket.video_content.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid = "AllowCloudFrontServicePrincipalReadOnly"
        Effect = "Allow"
        Principal = {
          Service = "cloudfront.amazonaws.com"
        }
        Action = "s3:GetObject"
        Resource = "${aws_s3_bucket.video_content.arn}/*"
        Condition = {
          StringEquals = {
            "AWS:SourceArn" = aws_cloudfront_distribution.video_distribution.arn
          }
        }
      }
    ]
  })
}

# Step 7: Create a domain in Route53 (assumes domain is registered)
# Note: You need to own the domain or register it via Route53
resource "aws_route53_zone" "main" {
  name = "videostreaming.example.com"

  tags = {
    Environment = "production"
    Project     = "video-streaming-site"
  }
}

# Step 8: Request and validate SSL certificate via ACM for the domain
resource "aws_acm_certificate" "certificate" {
  domain_name       = "videostreaming.example.com"
  validation_method   = "DNS"
  subject_alternative_names = ["www.videostreaming.example.com"]

  validation_option {
    domain_name = "videostreaming.example.com"
    validation_domain = aws_route53_zone.main.name
  }

  lifecycle {
    create_before_destroy = true
  }
}

# Step 9: Validate the certificate using DNS
resource "aws_acm_certificate_validation" "cert_validation" {
  certificate_arn         = aws_acm_certificate.certificate.arn
  validation_record_fqdns = [for record in aws_route53_record.cert_validation : record.fqdn]
}

resource "aws_route53_record" "cert_validation" {
  for_each = {
    for dvo in aws_acm_certificate.certificate.domain_validation_options : dvo.domain_name => {
      name   = dvo.resource_record_name
      record = dvo.resource_record_value
      type   = dvo.resource_record_type
    } if dvo.domain_name == "videostreaming.example.com" || dvo.domain_name == "www.videostreaming.example.com"
  }

  zone_id = aws_route53_zone.main.zone_id
  name    = each.value.name
  type    = each.value.type
  records = [each.value.record]
  ttl     = 600
}

# Step 10: Create DNS record to route domain to CloudFront
resource "aws_route53_record" "cdn" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "videostreaming.example.com"
  type    = "A"

  alias {
    name                   = aws_cloudfront_distribution.video_distribution.domain_name
    zone_id                = aws_cloudfront_distribution.video_distribution.hosted_zone_id
    evaluate_target_health = false
  }
}

resource "aws_route53_record" "www_cdn" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "www.videostreaming.example.com"
  type    = "A"

  alias {
    name                   = aws_cloudfront_distribution.video_distribution.domain_name
    zone_id                = aws_cloudfront_distribution.video_distribution.hosted_zone_id
    evaluate_target_health = false
  }
}

# Step 11: Optional - S3 bucket for logging
resource "aws_s3_bucket" "logs" {
  bucket = "video-streaming-site-logs-${random_string.suffix.result}"

  tags = {
    Name = "access-logs-bucket"
  }
}

resource "aws_s3_bucket_ownership_controls" "logs_ownership" {
  bucket = aws_s3_bucket.logs.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "logs_acl" {
  depends_on = [aws_s3_bucket_ownership_controls.logs_ownership]
  bucket     = aws_s3_bucket.logs.id
  acl        = "log-delivery-write"
}

# Prevent public access to logs
resource "aws_s3_bucket_public_access_block" "logs_block" {
  bucket = aws_s3_bucket.logs.id

  block_public_acls       = false
  block_public_policy     = true
  ignore_public_acls      = false
  restrict_public_buckets = true
}

# Step 12: Generate random suffix for unique bucket names
resource "random_string" "suffix" {
  length  = 8
  special = false
  upper   = false
  number  = true
}

# Outputs
output "cloudfront_domain" {
  description = "CloudFront distribution domain name"
  value       = aws_cloudfront_distribution.video_distribution.domain_name
}

output "s3_bucket_name" {
  description = "S3 bucket name for video content"
  value       = aws_s3_bucket.video_content.bucket
}

output "website_domain" {
  description = "Website domain via Route53"
  value       = "videostreaming.example.com"
}
```

