# 3. CloudFront distribution to cache and serve content globally
# 4. Route53 hosted zone for domain management
# 5. Route53 record to alias the CloudFront distribution to a domain/subdomain

# We assume a domain is registered (e.g., example.com) and will create a subdomain like cdn.example.com

resource "aws_s3_bucket" "video_content" {
  bucket = "video-streaming-content-bucket"

  # Enable static website hosting if needed (optional for CloudFront)
  website {
    index_document = "index.html"
  }

  # Block public access since CloudFront will access via OAC
  block_public_acls        = true
  block_public_policy      = true
  ignore_public_acls       = true
  restrict_public_buckets  = true

  versioning {
    enabled = true
  }

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }
}

