# Create Route53 public zone for netflix.com
resource "aws_route53_zone" "primary" {
  name = "netflix.com"
}

# Create Route53 record alias pointing to CloudFront distribution
resource "aws_route53_record" "cdn_alias" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "cdn.netflix.com"
  type    = "A"

  alias {
    name                   = aws_cloudfront_distribution.video_distribution.domain_name
    zone_id                = aws_cloudfront_distribution.video_distribution.hosted_zone_id
    evaluate_target_health = false
  }
}

# Create another Route53 record (e.g., www) pointing to the same CloudFront distribution
resource "aws_route53_record" "www_alias" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "www.netflix.com"
  type    = "A"

  alias {
    name                   = aws_cloudfront_distribution.video_distribution.domain_name
    zone_id                = aws_cloudfront_distribution.video_distribution.hosted_zone_id
    evaluate_target_health = false
  }
}

