    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Should be restricted in production
  }

  # Allow all outbound
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "ec2-sg"
  }
}

# Launch Template for EC2 Instances
resource "aws_launch_template" "streaming_template" {
  name          = "streaming-launch-template"
  image_id      = "ami-0abcdef1234567890" # Replace with actual AMI (e.g., Amazon Linux 2)
  instance_type = "t3.medium" # Suitable for video streaming
  key_name      = "my-key-pair" # Should exist in AWS

  # IAM Role for EC2 (minimal permissions)
  iam_instance_profile {
    name = aws_iam_instance_profile.ec2_profile.name
  }

  # User data to install and run web server (example: Nginx with video content)
  user_data = base64encode(<<-EOF
              #!/bin/bash
              yum update -y
              yum install -y httpd
              systemctl start httpd
              systemctl enable httpd
              echo "<h1>Video Streaming Server</h1>" > /var/www/html/index.html
              # In practice, stream from RTMP or S3-backed CDN
              EOF
  )

  tags = {
    Name = "streaming-launch-template"
  }
}

# IAM Role for EC2 Instance Profile
resource "aws_iam_role" "ec2_role" {
  name = "ec2-streaming-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

# Attach minimal policies (e.g., CloudWatch Logs)
resource "aws_iam_role_policy_attachment" "ec2_policy" {
  role       = aws_iam_role.ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/CloudWatchAgentServerPolicy"
}

# Instance Profile
resource "aws_iam_instance_profile" "ec2_profile" {
  name = "ec2-streaming-instance-profile"
  role = aws_iam_role.ec2_role.name
}

# Application Load Balancer
resource "aws_lb" "alb" {
  name               = "streaming-alb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb_sg.id]
  subnets            = aws_subnet.public[*].id

  tags = {
    Name = "streaming-alb"
  }
}

# Target Group
resource "aws_lb_target_group" "tg" {
  name     = "streaming-tg"
  port     = 80
  protocol = "HTTP"
  vpc_id   = aws_vpc.streaming_vpc.id

  health_check {
    path                = "/"
    protocol            = "HTTP"
    timeout             = 5
    healthy_threshold   = 2
    unhealthy_threshold = 3
    interval            = 30
  }

  tags = {
    Name = "streaming-tg"
  }
}

# Listener for HTTP (80) -> redirect to HTTPS or forward to target group
resource "aws_lb_listener" "http" {
  load_balancer_arn = aws_lb.alb.arn
  port              = 80
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.tg.arn
  }
}

# Auto Scaling Group
resource "aws_autoscaling_group" "asg" {
  name                = "streaming-asg"
  vpc_zone_identifier = aws_subnet.private[*].id
  target_group_arns   = [aws_lb_target_group.tg.arn]
  launch_template {
    id      = aws_launch_template.streaming_template.id
    version = "$Latest"
  }

  min_size         = 2
  max_size         = 10
  desired_capacity = 3

  tag {
    key                 = "Name"
    value               = "streaming-server"
    propagate_at_launch = true
  }
}

# Route 53 Setup
# We assume a domain is already registered, e.g., "example.com"
resource "aws_route53_zone" "primary" {
  name = "example.com"
  tags = {
    Environment = "production"
  }
}

# DNS record pointing to ALB
resource "aws_route53_record" "www" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "streaming.example.com"
  type    = "A"

  alias {
    name                   = aws_lb.alb.dns_name
    zone_id                = aws_lb.alb.zone_id
    evaluate_target_health = true
  }
}

# Output the ALB DNS name and Route 53 domain
output "alb_dns_name" {
  value = aws_lb.alb.dns_name
}

output "streaming_domain" {
  value = "streaming.example.com"
}
```

