resource "aws_security_group" "lb_sg" {
  vpc_id = aws_vpc.main.id

  # Ingress rule: Allow TCP 80 from VPC CIDR
  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  # Egress rule: Allow TCP 80 to any
  egress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
