# We need to create an AWS RDS instance with a randomly generated identifier and password.
# Steps:
# 1. Use the `random` provider to generate a random string for the DB identifier and master password.
# 2. Create the random resources for the identifier and password.
# 3. Create the AWS RDS instance (e.g., MySQL or PostgreSQL) using those random values.
# 4. Ensure the random provider is required.

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

# Generate a random string for database identifier (alphanumeric, 10 characters)
resource "random_string" "db_identifier" {
  length  = 10
  special = false
  upper   = false
  number  = true
}

# Generate a random password for the master user (alphanumeric + special, 16 characters)
resource "random_string" "db_password" {
  length  = 16
  special = true
  upper   = true
  lower   = true
  number  = true
}

# AWS DB instance
resource "aws_db_instance" "default" {
  identifier           = "db-${random_string.db_identifier.result}"
  engine               = "mysql"
  engine_version       = "8.0"
  instance_class       = "db.t3.micro"
  allocated_storage    = 20
  storage_type         = "gp2"
  username             = "admin"
  password             = random_string.db_password.result
  publicly_accessible  = false
  skip_final_snapshot  = true
  db_subnet_group_name = aws_db_subnet_group.example.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]

  # Add this block if you want automatic backups
  backup_retention_period = 7
  backup_window           = "03:00-04:00"
  maintenance_window      = "sun:05:00-sun:06:00"

  # Enable deletion protection in production (set to true), but false here for easy cleanup
  deletion_protection = false
}

# Create a DB subnet group
resource "aws_db_subnet_group" "example" {
  name       = "main"
  subnet_ids = aws_subnet.example[*].id
  tags = {
    Name = "DB Subnet Group"
  }
}

# Create a security group for RDS
resource "aws_security_group" "rds_sg" {
  name        = "rds_security_group"
  description = "Allow MySQL inbound traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "RDS Security Group"
  }
}

# Example VPC and Subnets (minimal setup)
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "Main VPC"
  }
}

resource "aws_subnet" "example" {
  count                   = 2
  vpc_id                  = aws_vpc.main.id
  cidr_block              = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone       = element(data.aws_availability_zones.available.names, count.index)
  map_public_ip_on_launch = false

  tags = {
    Name = "Subnet-${count.index}"
  }
}

# Data source to get availability zones
data "aws_availability_zones" "available" {
  state = "available"
}

