# Step-by-step breakdown:
# 1. Create a VPC with a defined CIDR block
# 2. Create public subnets within the VPC (at least one for availability)
# 3. Create a security group to allow PostgreSQL access (port 5432) from specific sources (here, we allow from the VPC itself for internal access)
# 4. Create a PostgreSQL RDS instance within the VPC, using the security group for access control

provider "aws" {
  region = "us-west-2" # Can be changed as needed
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "main-vpc"
  }
}

resource "aws_subnet" "public" {
  count             = 2
  cidr_block        = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone = data.aws_availability_zones.available.names[count.index]
  vpc_id            = aws_vpc.main.id

  tags = {
    Name = "public-subnet-${count.index}"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_security_group" "db_sg" {
  name        = "postgresql-access-sg"
  description = "Allow PostgreSQL access from within VPC"
  vpc_id      = aws_vpc.main.id

  # Allow inbound PostgreSQL traffic (port 5432) from within the VPC
  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  # Allow outbound traffic
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "db-security-group"
  }
}

resource "aws_db_subnet_group" "db_subnet_group" {
  name       = "main-db-subnet-group"
  subnet_ids = aws_subnet.public[*].id

  tags = {
    Name = "main-db-subnet-group"
  }
}

resource "aws_db_instance" "postgres" {
  identifier           = "postgres-db-instance"
  engine               = "postgres"
  engine_version       = "15"
  instance_class       = "db.t3.micro"
  allocated_storage    = 20
  storage_type         = "gp2"
  username             = "postgresadmin"
  password             = "securepassword123" # In practice, use AWS Secrets Manager or Terraform variables with sensitive flag
  db_subnet_group_name = aws_db_subnet_group.db_subnet_group.name
  vpc_security_group_ids = [aws_security_group.db_sg.id]
  publicly_accessible  = false  # Ensure DB is not publicly accessible
  skip_final_snapshot  = true   # Not recommended for production

  tags = {
    Name = "postgres-db"
  }
}

