extracted_code:
# We are setting up a VPC with public subnets and a PostgreSQL RDS instance.
# Steps:
# 1. Create a VPC.
# 2. Create public subnets (at least one, but typically in multiple AZs for HA; we'll use two).
# 3. Create a subnet group for the RDS instance using the subnets.
# 4. Create a security group for the RDS instance (PostgreSQL on port 5432) that allows database access (likely from app servers or specific IPs).
# 5. Create the RDS PostgreSQL instance with:
#   - Engine: postgres
#   - Engine version: 17.1
#   - Allocated storage: 5 GB
#   - DB instance identifier: "dolphinscheduler"
#   - Skip final snapshot: true
#   - Associate with the VPC and subnet group.
#   - Use the security group created for the database.

resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "dolphinscheduler-vpc"
  }
}

resource "aws_subnet" "public" {
  count = 2

  vpc_id                  = aws_vpc.main.id
  cidr_block              = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone       = element(data.aws_availability_zones.available.names, count.index)
  map_public_ip_on_launch = true

  tags = {
    Name = "dolphinscheduler-public-subnet-${count.index}"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_db_subnet_group" "rds" {
  name       = "dolphinscheduler-subnet-group"
  subnet_ids = aws_subnet.public[*].id

  tags = {
    Name = "dolphinscheduler-db-subnet-group"
  }
}

resource "aws_security_group" "rds" {
  name        = "dolphinscheduler-rds-sg"
  description = "Security group for PostgreSQL RDS instance"
  vpc_id      = aws_vpc.main.id

  # Allow PostgreSQL access on port 5432 from anywhere (this could be restricted to specific IPs or SGs in production)
  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Modify as needed for security best practices
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "dolphinscheduler-rds-security-group"
  }
}

resource "aws_db_instance" "dolphinscheduler" {
  identifier              = "dolphinscheduler"
  engine                  = "postgres"
  engine_version          = "17.1"
  allocated_storage       = 5
  storage_type            = "gp2"
  instance_class          = "db.t3.micro" # Default instance class, can be changed
  username                = "postgres"
  password                = random_password.db_password.result
  publicly_accessible     = false
  db_subnet_group_name    = aws_db_subnet_group.rds.name
  vpc_security_group_ids  = [aws_security_group.rds.id]
  skip_final_snapshot     = true

  # Enhanced monitoring, backup, etc. can be added as needed

  tags = {
    Name = "dolphinscheduler-db"
  }
}

# Generate a random password for the RDS instance
resource "random_password" "db_password" {
  length           = 16
  special          = true
  override_special = "!#%"
}

