# VPC with public subnets and MySQL RDS instance with security group

provider "aws" {
  region = "us-west-2" # Default region; can be changed as needed
}

# Create a VPC
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "main-vpc"
  }
}

# Create public subnets (example in two availability zones)
resource "aws_subnet" "public_subnet_1" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-west-2a"
  map_public_ip_on_launch = true

  tags = {
    Name = "public-subnet-1"
  }
}

resource "aws_subnet" "public_subnet_2" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-west-2b"
  map_public_ip_on_launch = true

  tags = {
    Name = "public-subnet-2"
  }
}

# Create an internet gateway for public access
resource "aws_internet_gateway" "gw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "main-gateway"
  }
}

# Create a route table for public subnets
resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.gw.id
  }

  tags = {
    Name = "public-route-table"
  }
}

# Associate public subnets with the route table
resource "aws_route_table_association" "public_assoc_1" {
  subnet_id      = aws_subnet.public_subnet_1.id
  route_table_id = aws_route_table.public_rt.id
}

resource "aws_route_table_association" "public_assoc_2" {
  subnet_id      = aws_subnet.public_subnet_2.id
  route_table_id = aws_route_table.public_rt.id
}

# Security group for the MySQL database
resource "aws_security_group" "db_sg" {
  name        = "mysql-security-group"
  description = "Security group for MySQL RDS instance"
  vpc_id      = aws_vpc.main.id

  # Allow inbound MySQL traffic (port 3306) from a specific IP or another security group
  # Adjust the cidr_blocks as needed (e.g., from app servers or specific IPs)
  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Change to specific IPs in production
  }

  # Allow outbound traffic
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "mysql-db-sg"
  }
}

# Subnet group for RDS to place DB in the public subnets
resource "aws_db_subnet_group" "db_subnet_group" {
  name       = "db-subnet-group"
  subnet_ids = [aws_subnet.public_subnet_1.id, aws_subnet.public_subnet_2.id]

  tags = {
    Name = "db-subnet-group"
  }
}

# MySQL RDS instance
resource "aws_db_instance" "mysql" {
  identifier           = "mysql-db-instance"
  engine               = "mysql"
  engine_version       = "8.0.35" # Note: 8.4.3 is not a valid MySQL version; using latest 8.0.x
  instance_class       = "db.t3.micro"
  allocated_storage    = 5 # 5 GB
  storage_type         = "gp2"
  username             = "admin"
  password             = "SecurePassword123!" # Should be loaded from a secure variable
  db_subnet_group_name = aws_db_subnet_group.db_subnet_group.name
  vpc_security_group_ids = [aws_security_group.db_sg.id]
  publicly_accessible  = true # Since placed in public subnets
  skip_final_snapshot  = true # For testing; set to false in production

  # Optional: add tags
  tags = {
    Name        = "MySQL-Database"
    Environment = "dev"
  }
}

# Output the RDS endpoint for reference
output "db_endpoint" {
  value = aws_db_instance.mysql.endpoint
}

output "db_name" {
  value = aws_db_instance.mysql.identifier
}

