# Secure PostgreSQL RDS Instance with VPC, Subnet Group, Security Group, KMS Encryption, and Parameter Group

resource "aws_db_parameter_group" "postgresql" {
  name        = "secure-postgresql-params"
  family      = "postgres14"
  description = "Custom parameter group for PostgreSQL with enhanced security settings"

  parameter {
    name  = "log_connections"
    value = "1"
  }

  parameter {
    name  = "log_disconnections"
    value = "1"
  }

  parameter {
    name  = "rds.log_statement"
    value = "all"
  }

  parameter {
    name  = "log_min_duration_statement"
    value = "5000"
  }
}

resource "aws_kms_key" "db_encryption" {
  description             = "KMS key for encrypting the PostgreSQL RDS instance"
  deletion_window_in_days = 30
  enable_key_rotation     = true
}

resource "aws_kms_alias" "db_encryption" {
  name          = "alias/postgresql-rds-kms-key"
  target_key_id = aws_kms_key.db_encryption.key_id
}

resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "rds-vpc"
  }
}

resource "aws_subnet" "rds_subnet_az1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-west-2a"

  tags = {
    Name = "rds-subnet-az1"
  }
}

resource "aws_subnet" "rds_subnet_az2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-west-2b"

  tags = {
    Name = "rds-subnet-az2"
  }
}

resource "aws_db_subnet_group" "rds_subnet_group" {
  name       = "postgres-subnet-group"
  subnet_ids = [aws_subnet.rds_subnet_az1.id, aws_subnet.rds_subnet_az2.id]

  tags = {
    Name = "postgres-subnet-group"
  }
}

resource "aws_security_group" "rds_sg" {
  name        = "postgresql-rds-sg"
  description = "Security group for PostgreSQL RDS instance"
  vpc_id      = aws_vpc.main.id

  # Allow PostgreSQL access from application servers (example: port 5432 from trusted CIDRs or other SGs)
  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]  # Adjust according to your application's subnet or use source_security_group_id
  }

  # Allow traffic within the same security group (useful for multi-AZ failover or read replicas)
  ingress {
    from_port       = 5432
    to_port         = 5432
    protocol        = "tcp"
    self            = true
  }

  # Allow outbound internet access for logs or patches (if needed)
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "postgresql-rds-sg"
  }
}

resource "aws_db_instance" "postgresql" {
  identifier                          = "secure-postgresql-db"
  engine                              = "postgres"
  engine_version                      = "14.10"
  instance_class                      = "db.t3.micro"
  allocated_storage                   = 20
  storage_type                        = "gp2"
  db_name                             = "mydb"
  username                            = "dbadmin"
  password                            = random_password.db_password.result
  parameter_group_name                = aws_db_parameter_group.postgresql.name
  db_subnet_group_name                = aws_db_subnet_group.rds_subnet_group.name
  vpc_security_group_ids              = [aws_security_group.rds_sg.id]
  multi_az                              = true
  publicly_accessible                 = false
  skip_final_snapshot                 = true
  deletion_protection                 = false  # Set to true for production
  apply_immediately                   = false
  backup_retention_period             = 7
  backup_window                       = "03:00-04:00"
  maintenance_window                  = "sun:05:00-sun:06:00"
  enabled_cloudwatch_logs_exports     = ["postgresql", "upgrade"]
  performance_insights_enabled        = true
  performance_insights_retention_period = 7

  # Enable encryption at rest using KMS
  storage_encrypted = true
  kms_key_id        = aws_kms_key.db_encryption.arn

  tags = {
    Name        = "Secure PostgreSQL RDS Instance"
    Environment = "production"
  }
}

# Generate a secure random password for the DB
resource "random_password" "db_password" {
  length           = 16
  special          = true
  override_special = "!@#$%&*"
}

