# Define required providers
provider "aws" {
  region = "us-west-2" # Default region; can be changed as needed
}

# Variables to make configuration reusable
variable "vpc_id" {
  description = "The VPC ID in which the database will be launched"
  type        = string
}

variable "subnet_ids" {
  description = "List of subnet IDs for the DB subnet group (at least two subnets in different AZs recommended)"
  type        = list(string)
}

variable "db_username" {
  description = "Username for the PostgreSQL database"
  type        = string
  sensitive   = true
}

variable "db_password" {
  description = "Password for the PostgreSQL database"
  type        = string
  sensitive   = true
}

# Create a KMS key for encrypting the RDS instance
resource "aws_kms_key" "rds_kms_key" {
  description             = "KMS key for encrypting PostgreSQL RDS instance"
  enable_key_rotation     = true
  deletion_window_in_days = 30
}

# Create a KMS alias for easier identification
resource "aws_kms_alias" "rds_kms_alias" {
  name          = "alias/postgresql-rds-key"
  target_key_id = aws_kms_key.rds_kms_key.key_id
}

# Create a DB subnet group using the provided subnets
resource "aws_db_subnet_group" "postgres_subnet_group" {
  name       = "postgres-subnet-group"
  subnet_ids = var.subnet_ids

  tags = {
    Name = "PostgreSQL Subnet Group"
  }
}

# Create a security group for the RDS instance
resource "aws_security_group" "postgres_sg" {
  name        = "postgres-db-sg"
  description = "Security group for PostgreSQL RDS instance"
  vpc_id      = var.vpc_id

  # Allow PostgreSQL traffic (port 5432) from specific CIDR or other resources
  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Adjust as needed for allowed sources
  }

  # Outbound: Allow all traffic
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "PostgreSQL Security Group"
  }
}

# Create a custom parameter group for PostgreSQL
resource "aws_db_parameter_group" "postgres_parameter_group" {
  name   = "custom-postgres-param-group"
  family = "postgres15" # Change version if needed (e.g., postgres14, postgres16)
  description = "Custom parameter group for PostgreSQL RDS"

  parameter {
    name  = "log_statement"
    value = "all"
  }

  parameter {
    name  = "timeout"
    value = "60"
  }

  tags = {
    Name = "Custom PostgreSQL Parameter Group"
  }
}

# Provision the RDS PostgreSQL instance
resource "aws_db_instance" "postgres_instance" {
  identifier           = "secure-postgresql-db"
  engine               = "postgres"
  engine_version       = "15.4"
  instance_class       = "db.t3.micro"
  allocated_storage    = 20 # GB; minimum for general purpose storage
  storage_type         = "gp2"
  username             = var.db_username
  password             = var.db_password
  db_subnet_group_name = aws_db_subnet_group.postgres_subnet_group.name
  vpc_security_group_ids = [aws_security_group.postgres_sg.id]
  parameter_group_name = aws_db_parameter_group.postgres_parameter_group.name

  # Enable encryption using KMS
  storage_encrypted      = true
  kms_key_id             = aws_kms_key.rds_kms_key.arn

  # Multi-AZ for high availability
  multi_az               = true

  # Backup configuration
  backup_retention_period = 7
  backup_window           = "03:00-04:00"
  maintenance_window      = "sun:04:00-sun:05:00"

  # Prevent accidental deletion
  deletion_protection = true

  # Enable enhanced monitoring, minor version upgrades
  auto_minor_version_upgrade = true
  monitoring_interval          = 60
  apply_immediately            = true

  # Enable CloudWatch logs export
  enabled_cloudwatch_logs_exports = [
    "postgresql",
    "upgrade"
  ]

  tags = {
    Name        = "Secure PostgreSQL RDS Instance"
    Environment = "production"
  }
}

