# Create a KMS key for encrypting the RDS instance
resource "aws_kms_key" "db_encryption_key" {
  description             = "KMS key for encrypting PostgreSQL RDS instance"
  enable_key_rotation     = true
  deletion_window_in_days = 30
}

# Create a customer managed key alias for easier reference
resource "aws_kms_alias" "db_key_alias" {
  name          = "alias/postgresql-rds-key"
  target_key_id = aws_kms_key.db_encryption_key.key_id
}

# Create a DB subnet group using existing subnets in the VPC
resource "aws_db_subnet_group" "postgresql_subnet_group" {
  name       = "postgresql-subnet-group"
  subnet_ids = var.subnet_ids
  tags = {
    Name = "PostgreSQL Subnet Group"
  }
}

# Create a custom parameter group for PostgreSQL
resource "aws_db_parameter_group" "postgresql_parameter_group" {
  name   = "postgresql-param-group"
  family = "postgres15" # Specify the appropriate PostgreSQL family version
  description = "Custom parameter group for PostgreSQL"

  parameter {
    name  = "log_min_duration_statement"
    value = "5000"
  }

  parameter {
    name  = "rds.force_ssl"
    value = "1"
  }
}

# Create a security group for the RDS instance
resource "aws_security_group" "postgresql_sg" {
  name        = "postgresql-security-group"
  description = "Security group for PostgreSQL RDS instance"
  vpc_id      = var.vpc_id

  # Allow inbound PostgreSQL traffic from specific CIDR or security group
  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = var.allowed_cidr_blocks # e.g., ["10.0.0.0/16"]
  }

  # Allow inbound PostgreSQL traffic from another security group (e.g., ECS or EC2)
  dynamic "ingress" {
    for_each = var.allowed_security_groups
    content {
      from_port       = 5432
      to_port         = 5432
      protocol        = "tcp"
      security_groups = ingress.value
    }
  }

  # Allow all outbound traffic
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "PostgreSQL RDS Security Group"
  }
}

# Provision the RDS PostgreSQL instance
resource "aws_rds_cluster_instance" "postgresql_instance" {
  identifier                  = "secure-postgresql-instance"
  db_subnet_group_name        = aws_db_subnet_group.postgresql_subnet_group.name
  db_parameter_group_name     = aws_db_parameter_group.postgresql_parameter_group.name
  engine                      = "postgres"
  engine_version              = "15.4"
  instance_class              = "db.t3.medium"
  storage_encrypted           = true
  kms_key_id                  = aws_kms_key.db_encryption_key.arn
  allocated_storage           = 100
  max_allocated_storage       = 200
  storage_type                = "gp3"
  multi_az                    = true
  publicly_accessible         = false
  vpc_security_group_ids      = [aws_security_group.postgresql_sg.id]
  skip_final_snapshot         = false
  final_snapshot_identifier   = "pgsnapshot"
  apply_immediately           = false
  backup_retention_period     = 7
  backup_window               = "03:00-04:00"
  maintenance_window          = "sun:05:00-sun:06:00"
  monitoring_interval         = 60
  monitoring_role_arn         = aws_iam_role.rds_monitoring_role.arn
  enabled_cloudwatch_logs_exports = ["postgresql"]

  # Ensure the DB instance is re-created if the KMS key is deleted and re-created
  depends_on = [
