# We need to set up a PostgreSQL 15 instance on AWS RDS in specific public subnets
# for Airbyte connector test cases with managed settings for low maintenance.

# Steps:
# 1. Define the AWS provider
# 2. Specify publicly accessible subnets (we'll assume they're part of a DB subnet group)
# 3. Use a standard PostgreSQL 15 engine version
# 4. Choose a small, cost-effective instance for testing (e.g., db.t4g.small or db.t3.medium)
# 5. Enable auto-minor version upgrade and automated backups for low maintenance
# 6. Set deletion protection to false (since it's for test cases, may be temporary)
# 7. Use enhanced monitoring and CloudWatch logs if needed, but keep it simple
# 8. Set publicly accessible since it's for connector testing
# 9. Define a parameter group for PostgreSQL 15 if customization is needed (optional, using default)

resource "aws_db_subnet_group" "airbyte_test_subnet_group" {
  name       = "airbyte-test-subnet-group"
  subnet_ids = var.public_subnet_ids  # User should provide specific public subnet IDs
  description = "Subnet group for Airbyte PostgreSQL test instance in public subnets"
}

resource "aws_db_instance" "airbyte_postgresql" {
  identifier                   = "airbyte-test-postgresql"
  allocated_storage            = 20
  storage_type                 = "gp2"
  engine                       = "postgres"
  engine_version               = "15.4"
  instance_class               = "db.t4g.small"
  name                         = "airbyte"
  username                     = var.db_username
  password                     = var.db_password
  db_subnet_group_name         = aws_db_subnet_group.airbyte_test_subnet_group.name
  publicly_accessible          = true
  skip_final_snapshot          = true
  deletion_protection          = false
  auto_minor_version_upgrade   = true
  backup_retention_period      = 7
  backup_window                = "03:00-04:00"
  maintenance_window           = "sun:04:00-sun:05:00"
  enabled_cloudwatch_logs_exports = ["postgresql"]

  # Enhanced monitoring (optional, can be disabled if not needed)
  monitoring_interval = 60
  monitoring_role_arn = aws_iam_role.rds_monitoring_role.arn
}

# IAM role for RDS enhanced monitoring
resource "aws_iam_role" "rds_monitoring_role" {
  name = "rds-monitoring-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "monitoring.rds.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "rds_monitoring_role_attachment" {
  role       = aws_iam_role.rds_monitoring_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonRDSEnhancedMonitoringRole"
}

# Variables to be provided by the user
variable "public_subnet_ids" {
  type    = list(string)
  description = "List of public subnet IDs where the RDS instance will be deployed"
}

variable "db_username" {
  type    = string
  description = "Master username for PostgreSQL instance"
  default = "airbyte"
}

variable "db_password" {
  type    = string
  description = "Master password for PostgreSQL instance"
  sensitive = true
}

output "db_endpoint" {
  value = aws_db_instance.airbyte_postgresql.endpoint
}

output "db_name" {
  value = aws_db_instance.airbyte_postgresql.name
}

