extracted_code:
# Step 1: Define the main VPC with a CIDR block
# We'll use a standard 10.0.0.0/16 private CIDR for the VPC

# Step 2: Create two subnets in different availability zones
# We'll create one public subnet in us-west-2a and another in us-west-2b
# Using /24 CIDR blocks within the VPC range

# Step 3: Create a security group to allow MySQL database access
# MySQL uses port 3306, so we'll allow inbound access on this port
# We'll also allow outbound traffic

# Step 4: Configure a MySQL RDS instance
# The instance will be publicly accessible, placed in the defined subnets
# We'll use a db.t3.micro instance for cost efficiency
# The RDS will be associated with the security group and subnets

# Step 5: Output the database endpoint for connectivity

provider "aws" {
  region = "us-west-2"
}

resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "main-vpc"
  }
}

resource "aws_subnet" "subnet_az1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-west-2a"

  tags = {
    Name = "subnet-az1"
  }
}

resource "aws_subnet" "subnet_az2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-west-2b"

  tags = {
    Name = "subnet-az2"
  }
}

resource "aws_security_group" "db_security_group" {
  name        = "allow_mysql_access"
  description = "Allow MySQL access"
  vpc_id      = aws_vpc.main.id

  # Inbound rule for MySQL (port 3306)
  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]  # Allow from anywhere - adjust for production!
  }

  # Outbound rule - allow all outbound traffic
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "db-security-group"
  }
}

resource "aws_db_subnet_group" "db_subnet_group" {
  name       = "main-db-subnet-group"
  subnet_ids = [aws_subnet.subnet_az1.id, aws_subnet.subnet_az2.id]

  tags = {
    Name = "main-db-subnet-group"
  }
}

resource "aws_db_instance" "mysql_instance" {
  identifier              = "main-mysql-instance"
  engine                  = "mysql"
  engine_version          = "8.0"
  instance_class          = "db.t3.micro"
  allocated_storage       = 20
  storage_type            = "gp2"
  publicly_accessible     = true
  db_subnet_group_name    = aws_db_subnet_group.db_subnet_group.name
  vpc_security_group_ids  = [aws_security_group.db_security_group.id]
  username                = "admin"
  password                = "password123"  # Use AWS Secrets Manager in production!
  skip_final_snapshot     = true

  # Apply maintenance and backup windows
  maintenance_window      = "sun:05:00-sun:07:00"
  backup_retention_period = 7
  backup_window           = "03:00-05:00"
}

output "database_endpoint" {
  description = "The connection endpoint for the MySQL database"
  value       = aws_db_instance.mysql_instance.endpoint
}

