# Define required providers
provider "aws" {
  region = "us-west-2" # Default region, can be changed as needed
}

# Create a VPC
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "main-vpc"
  }
}

# Create two subnets in different availability zones
resource "aws_subnet" "subnet_az1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-west-2a"

  tags = {
    Name = "subnet-az1"
  }
}

resource "aws_subnet" "subnet_az2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-west-2b"

  tags = {
    Name = "subnet-az2"
  }
}

# Create a subnet group for RDS
resource "aws_db_subnet_group" "db_subnet_group" {
  name       = "main-db-subnet-group"
  subnet_ids = [aws_subnet.subnet_az1.id, aws_subnet.subnet_az2.id]

  tags = {
    Name = "main-db-subnet-group"
  }
}

# Create a security group to allow database access
resource "aws_security_group" "db_security_group" {
  name        = "db-security-group"
  description = "Allow PostgreSQL access"
  vpc_id      = aws_vpc.main.id

  # Allow inbound PostgreSQL traffic (port 5432) from anywhere
  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow all outbound traffic
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "db-security-group"
  }
}

# Create a PostgreSQL RDS instance
resource "aws_db_instance" "postgres_instance" {
  identifier           = "main-postgres-instance"
  engine               = "postgres"
  engine_version       = "15.3"
  instance_class       = "db.t4g.micro"
  allocated_storage    = 200
  storage_type         = "gp2"
  publicly_accessible  = true
  db_subnet_group_name = aws_db_subnet_group.db_subnet_group.name
  vpc_security_group_ids = [aws_security_group.db_security_group.id]
  username             = "postgres"
  password             = "password123" # In practice, use AWS Secrets Manager or a secure input
  skip_final_snapshot  = true

  tags = {
    Name = "main-postgres-db"
  }
}

# Output the database endpoint for connectivity
output "db_endpoint" {
  value = aws_db_instance.postgres_instance.endpoint
}

output "db_address" {
  value = aws_db_instance.postgres_instance.address
}

output "db_port" {
  value = aws_db_instance.postgres_instance.port
}
