# We need to create an AWS RDS MySQL instance with public access and a random password.
# Steps:
# 1. Create a random password using the random provider.
# 2. Set up a security group to allow public access to the MySQL port (3306).
# 3. Create the RDS MySQL instance with publicly accessible settings and assign the security group.
# 4. Ensure required providers are declared.

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

# Generate a random password for the MySQL instance
resource "random_password" "db_password" {
  length           = 16
  special          = true
  override_special = "!@#$%&*()-_=+[]{}|:;<>.,?"
}

# Create a security group to allow inbound MySQL access from the internet
resource "aws_security_group" "rds_public_sg" {
  name        = "public-rds-mysql-sg"
  description = "Allow public access to MySQL RDS instance"
  vpc_id      = var.vpc_id # Assuming VPC ID is passed as a variable

  # Ingress rule: Allow MySQL (port 3306) from the internet
  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Egress rule: Allow all outbound traffic
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "public-access-mysql-sg"
  }
}

# Create the RDS MySQL instance
resource "aws_db_instance" "mysql" {
  identifier           = "public-mysql-instance"
  db_name              = var.db_name
  engine               = "mysql"
  engine_version       = "8.0"
  instance_class       = "db.t3.micro"
  allocated_storage    = 20
  storage_type         = "gp2"
  publicly_accessible  = true
  skip_final_snapshot  = true
  vpc_security_group_ids = [aws_security_group.rds_public_sg.id]
  username             = var.username
  password             = random_password.db_password.result

  # Enable storage autoscaling
  max_allocated_storage = 100

  tags = {
    Name = "Public-MySQL-Instance"
  }
}

# Variables to make configuration flexible
variable "vpc_id" {
  description = "The VPC ID where the RDS instance and security group will be created."
  type        = string
}

variable "db_name" {
  description = "Name for the MySQL database."
  type        = string
  default     = "mydb"
}

variable "username" {
  description = "Master username for the MySQL instance."
  type        = string
  default     = "admin"
}

# Output the DB instance endpoint and generated password
output "db_endpoint" {
  description = "The connection endpoint of the RDS instance"
  value       = aws_db_instance.mysql.endpoint
}

output "db_password" {
  description = "The generated random password"
  value       = random_password.db_password.result
  sensitive   = true
}

