# Define required providers
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 4.0"
    }
  }
}

# Create a custom VPC
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "pg-vpc"
  }
}

# Create a public subnet within the VPC
resource "aws_subnet" "public" {
  vpc_id                  = aws_vpc.main.id
  cidr_block             = "10.0.1.0/24"
  availability_zone       = data.aws_availability_zones.available.names[0]
  map_public_ip_on_launch = true

  tags = {
    Name = "pg-public-subnet"
  }
}

# Create an internet gateway for the VPC
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "pg-igw"
  }
}

# Create a route table to enable public access
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "pg-public-route-table"
  }
}

# Associate the subnet with the route table
resource "aws_route_table_association" "public" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public.id
}

# Create a security group to allow PostgreSQL access
resource "aws_security_group" "postgres_sg" {
  vpc_id = aws_vpc.main.id

  # Allow inbound PostgreSQL traffic (port 5432) from any IP (adjust as needed for production)
  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow all outbound traffic
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "postgres-security-group"
  }
}

# Use available AZs for high availability
data "aws_availability_zones" "available" {
  state = "available"
}

# Create a DB subnet group
resource "aws_db_subnet_group" "postgres_subnet_group" {
  name       = "postgres-subnet-group"
  subnet_ids = [aws_subnet.public.id]

  tags = {
    Name = "postgres-subnet-group"
  }
}

# Create the PostgreSQL RDS instance
resource "aws_db_instance" "postgres_instance" {
  identifier                  = "postgres-db-instance"
  engine                      = "postgres"
  engine_version              = "15.4"
  instance_class              = "db.t3.micro"  # Cost-effective for small workloads
  allocated_storage           = 5             # Initial storage: 5 GB
  max_allocated_storage       = 50            # Max storage auto-scaling up to 50 GB
  storage_type                = "gp2"
  username                    = "dbadmin"
  password                    = "securepass123!"  # In practice, use AWS Secrets Manager or Terraform variable
  db_name                     = "mydb"
  publicly_accessible         = true
  vpc_security_group_ids      = [aws_security_group.postgres_sg.id]
  db_subnet_group_name        = aws_db_subnet_group.postgres_subnet_group.name
  backup_retention_period     = 7
  maintenance_window          = "mon:00:00-mon:03:00"  # Monday 00:00 to 03:00 UTC
  auto_minor_version_upgrade  = true
  multi_az                    = false  # Set to true for production
  apply_immediately           = true   # For testing; set to false in production to control timing

  # Enable deletion protection in production
  deletion_protection = false

  tags = {
    Name = "PostgreSQL-Instance"
  }
}

# Output the database endpoint
output "db_endpoint" {
  value = aws_db_instance.postgres_instance.endpoint
}

output "db_address" {
  value = aws_db_instance.postgres_instance.address
}

