provider "aws" {
  region = "us-west-2"
}

# Create a VPC for the Aurora cluster
resource "aws_vpc" "aurora_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "aurora-vpc"
  }
}

# Create subnets for the Aurora cluster (at least two in different AZs)
resource "aws_subnet" "aurora_subnet_az1" {
  vpc_id                  = aws_vpc.aurora_vpc.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-west-2a"
  map_public_ip_on_launch = false

  tags = {
    Name = "aurora-subnet-az1"
  }
}

resource "aws_subnet" "aurora_subnet_az2" {
  vpc_id                  = aws_vpc.aurora_vpc.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-west-2b"
  map_public_ip_on_launch = false

  tags = {
    Name = "aurora-subnet-az2"
  }
}

# Create a subnet group for the Aurora cluster
resource "aws_db_subnet_group" "aurora_subnet_group" {
  name       = "aurora-subnet-group"
  subnet_ids = [aws_subnet.aurora_subnet_az1.id, aws_subnet.aurora_subnet_az2.id]

  tags = {
    Name = "aurora-subnet-group"
  }
}

# Create a security group for the Aurora cluster
resource "aws_security_group" "aurora_sg" {
  name        = "aurora-cluster-sg"
  description = "Security group for Aurora MySQL cluster"
  vpc_id      = aws_vpc.aurora_vpc.id

  # Allow MySQL/MariaDB traffic from the proxy security group
  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    source_security_group_id = aws_security_group.aurora_proxy_sg.id
  }

  # Allow outbound all traffic
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "aurora-cluster-sg"
  }
}

# Create a security group for the RDS Proxy
resource "aws_security_group" "aurora_proxy_sg" {
  name        = "aurora-proxy-sg"
  description = "Security group for Aurora Proxy"
  vpc_id      = aws_vpc.aurora_vpc.id

  # Allow MySQL traffic from applications (restrict to your app's source range)
  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]  # Adjust as needed
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "aurora-proxy-sg"
  }
}

# Create an IAM role for RDS Proxy
resource "aws_iam_role" "rds_proxy_role" {
  name = "rds-proxy-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

# Attach required IAM policy to the RDS Proxy role
resource "aws_iam_role_policy_attachment" "rds_proxy_policy" {
  role       = aws_iam_role.rds_proxy_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSRDSProxyServiceRolePolicy"
}

# Store database credentials in Secrets Manager
resource "aws_secretsmanager_secret" "aurora_secret" {
  name = "aurora-cluster-credentials"
  description = "Credentials for Aurora MySQL cluster"
}

resource "aws_secretsmanager_secret_version" "aurora_secret_version" {
  secret_id     = aws_secretsmanager_secret.aurora_secret.id
  secret_string = jsonencode({
    username = "admin"
    password = random_password.db_password.result
  })
}

# Generate random password for the database
resource "random_password" "db_password" {
  length  = 16
  special = true
  override_special = "_%@"
}

# Create the Aurora MySQL cluster (serverless v2 or provisioned)
resource "aws_rds_cluster" "aurora_cluster" {
  cluster_identifier              = "aurora-mysql-cluster"
  engine                          = "aurora-mysql"
  engine_version                  = "8.0.mysql_aurora.3.04.0"
  master_username                 = "admin"
  master_password                 = random_password.db_password.result
  db_subnet_group_name            = aws_db_subnet_group.aurora_subnet_group.name
  vpc_security_group_ids          = [aws_security_group.aurora_sg.id]
  backup_retention_period         = 7
  preferred_backup_window         = "01:00-02:00"
  preferred_maintenance_window    = "sun:05:00-sun:06:00"
  storage_encrypted               = true
  deletion_protection             = true

  # Enable autoscaling for Aurora Serverless v2 (min = max = 1 for testing, adjust for production)
  serverlessv2_scaling_configuration {
    min_capacity = 0.5
    max_capacity = 1.0
  }

  depends_on = [
    aws_db_subnet_group.aurora_subnet_group,
    aws_security_group.aurora_sg,
    aws_secretsmanager_secret_version.aurora_secret_version
  ]
}

# Create an instance as part of the cluster
resource "aws_rds_cluster_instance" "cluster_instances" {
  for_each = toset(["1", "2"])

  identifier           = "aurora-instance-${each.key}"
  cluster_identifier   = aws_rds_cluster.aurora_cluster.id
  instance_class       = "db.r6g.large"
  engine               = "aurora-mysql"
  engine_version       = "8.0.mysql_aurora.3.04.0"
  db_subnet_group_name = aws_db_subnet_group.aurora_subnet_group.name

  apply_immediately               = true
  auto_minor_version_upgrade      = true
  copy_tags_to_snapshot           = true
  monitoring_interval             = 60
  performance_insights_enabled    = true
  publicly_accessible             = false
}

# Create an RDS Proxy
resource "aws_db_proxy" "aurora_proxy" {
  name                   = "aurora-proxy"
  engine_family          = "MYSQL"
  vpc_subnet_ids         = [aws_subnet.aurora_subnet_az1.id, aws_subnet.aurora_subnet_az2.id]
  vpc_security_group_ids = [aws_security_group.aurora_proxy_sg.id]
  auth {
    description              = "Authenticate with Secrets Manager"
    auth_scheme              = "SECRETS"
    iam_auth                 = "DISABLED"
    secret_arn               = aws_secretsmanager_secret.aurora_secret.arn
  }
  role_arn             = aws_iam_role.rds_proxy_role.arn
  idle_client_timeout  = 1800
  require_tls          = true
  debug_logging        = false
  max_connections_percent = 100
  max_idle_connections_percent = 50

  depends_on = [
    aws_rds_cluster.aurora_cluster,
    aws_iam_role_policy_attachment.rds_proxy_policy
  ]
}

# Associate the RDS Proxy with the Aurora cluster
resource "aws_db_proxy_default_target_group" "proxy_target_group" {
  db_proxy_name = aws_db_proxy.aurora_proxy.name
  connection_pool_config {
    max_connections_percent        = 100
    max_idle_connections_percent   = 50
    connection_borrow_timeout      = 120
    session_pinning_filters        = []
    init_query                     = "SET x=1"
  }
}

resource "aws_db_proxy_target_group" "proxy_attach_cluster" {
  db_proxy_name = aws_db_proxy.aurora_proxy.name
  name          = "default"
  target_type   = "RDS_INSTANCE"
  db_instance_identifiers = aws_rds_cluster_instance.cluster_instances[*].identifier
}

# Output the proxy endpoint for applications to use
output "rds_proxy_endpoint" {
  description = "Endpoint for the RDS Proxy"
  value       = aws_db_proxy.aurora_proxy.endpoint
}

output "aurora_cluster_endpoint" {
  description = "Writer endpoint of the Aurora cluster"
  value       = aws_rds_cluster.aurora_cluster.endpoint
}

output "aurora_reader_endpoint" {
  description = "Reader endpoint of the Aurora cluster"
  value       = aws_rds_cluster.aurora_cluster.reader_endpoint
}

