}

# Create a VPC for the Aurora cluster
resource "aws_vpc" "aurora_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "aurora-vpc"
  }
}

# Create subnets for the Aurora cluster (at least two in different AZs)
resource "aws_subnet" "aurora_subnet_az1" {
  vpc_id                  = aws_vpc.aurora_vpc.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-west-2a"
  map_public_ip_on_launch = false

  tags = {
    Name = "aurora-subnet-az1"
  }
}

resource "aws_subnet" "aurora_subnet_az2" {
  vpc_id                  = aws_vpc.aurora_vpc.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-west-2b"
  map_public_ip_on_launch = false

  tags = {
    Name = "aurora-subnet-az2"
  }
}

# Create a subnet group for the Aurora cluster
resource "aws_db_subnet_group" "aurora_subnet_group" {
  name       = "aurora-subnet-group"
  subnet_ids = [aws_subnet.aurora_subnet_az1.id, aws_subnet.aurora_subnet_az2.id]

  tags = {
    Name = "aurora-subnet-group"
  }
}

# Create a security group for the Aurora cluster
resource "aws_security_group" "aurora_sg" {
  name        = "aurora-cluster-sg"
  description = "Security group for Aurora MySQL cluster"
  vpc_id      = aws_vpc.aurora_vpc.id

  # Allow MySQL/MariaDB traffic from the proxy security group
  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    source_security_group_id = aws_security_group.aurora_proxy_sg.id
  }

  # Allow outbound all traffic
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "aurora-cluster-sg"
  }
}

# Create a security group for the RDS Proxy
resource "aws_security_group" "aurora_proxy_sg" {
  name        = "aurora-proxy-sg"
  description = "Security group for Aurora Proxy"
  vpc_id      = aws_vpc.aurora_vpc.id

  # Allow MySQL traffic from applications (restrict to your app's source range)
  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]  # Adjust as needed
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "aurora-proxy-sg"
  }
}

# Create an IAM role for RDS Proxy
resource "aws_iam_role" "rds_proxy_role" {
  name = "rds-proxy-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

# Attach required IAM policy to the RDS Proxy role
resource "aws_iam_role_policy_attachment" "rds_proxy_policy" {
  role       = aws_iam_role.rds_proxy_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSRDSProxyServiceRolePolicy"
}

# Store database credentials in Secrets Manager
resource "aws_secretsmanager_secret" "aurora_secret" {
  name = "aurora-cluster-credentials"
  description = "Credentials for Aurora MySQL cluster"
}

resource "aws_secretsmanager_secret_version" "aurora_secret_version" {
  secret_id     = aws_secretsmanager_secret.aurora_secret.id
  secret_string = jsonencode({
    username = "admin"
    password = random_password.db_password.result
  })
}

# Generate random password for the database
resource "random_password" "db_password" {
