  name                   = "aurora-mysql-proxy"
  engine_family          = "MYSQL"
  vpc_subnet_ids         = [aws_subnet.aurora_subnet_1.id, aws_subnet.aurora_subnet_2.id]
  vpc_security_group_ids = [aws_security_group.rds_proxy_sg.id]
  auth {
    description = "Authenticate using Secrets Manager"
    auth_scheme = "SECRETS"
    secret_arn  = aws_secretsmanager_secret.db_secret.arn
    iam_auth    = "DISABLED"
  }
  role_arn                 = aws_iam_role.rds_proxy_role.arn
  db_proxy_target_group_name = aws_db_proxy_default_target_group.default.target_group_name
  require_tls              = false
  idle_client_timeout      = 1800
  debug_logging            = false  # As requested, debug logging disabled
  tags = {
    Name = "aurora-mysql-proxy"
  }
}

# RDS Proxy default target group (required for DB Proxy)
resource "aws_db_proxy_default_target_group" "default" {
  db_proxy_name = aws_db_proxy.rds_proxy.name
  db_instance_identifier = aws_rds_cluster_instance.cluster_instance[0].identifier
  connection_pool_config {
    max_connections_percent          = 100
    max_idle_connections_percent     = 50
    connection_borrow_timeout        = 120
    session_pinning_filters          = []
    init_query                       = null
  }
}

# Register cluster as target for proxy
resource "aws_db_proxy_target" "proxy_target" {
  db_proxy_name               = aws_db_proxy.rds_proxy.name
  target_group_name           = aws_db_proxy_default_target_group.default.target_group_name
  db_cluster_identifier       = aws_rds_cluster.aurora_mysql.id
}

