# Set up VPC, subnets, security groups, IAM roles, RDS Aurora MySQL cluster, proxy, and Secrets Manager integration
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "rds-aurora-vpc"
  }
}

# Create subnets for Aurora (at least two subnets in different AZs)
resource "aws_subnet" "aurora_subnet_1" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = data.aws_availability_zones.available.names[0]
  map_public_ip_on_launch = false

  tags = {
    Name = "aurora-subnet-1"
  }
}

resource "aws_subnet" "aurora_subnet_2" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = data.aws_availability_zones.available.names[1]
  map_public_ip_on_launch = false

  tags = {
    Name = "aurora-subnet-2"
  }
}

# Subnet group for Aurora cluster
resource "aws_db_subnet_group" "aurora_subnet_group" {
  name       = "aurora-subnet-group"
  subnet_ids = [aws_subnet.aurora_subnet_1.id, aws_subnet.aurora_subnet_2.id]

  tags = {
    Name = "aurora-subnet-group"
  }
}

# Security group for RDS Aurora cluster
resource "aws_security_group" "rds_aurora_sg" {
  name        = "rds-aurora-sg"
  description = "Security group for Aurora MySQL cluster"
  vpc_id      = aws_vpc.main.id

  # Allow MySQL traffic from proxy or application
  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]  # Adjust to your app's CIDR if needed
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-aurora-sg"
  }
}

# Security group for RDS Proxy (optional, if you want to separate)
resource "aws_security_group" "rds_proxy_sg" {
  name        = "rds-proxy-sg"
  description = "Security group for RDS Proxy"
  vpc_id      = aws_vpc.main.id

  # Allow MySQL from application
  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-proxy-sg"
  }
}

# IAM role for RDS Proxy to access Secrets Manager
resource "aws_iam_role" "rds_proxy_role" {
  name = "rds-proxy-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for accessing Secrets Manager
resource "aws_iam_policy" "rds_proxy_secrets_policy" {
  name = "rds-proxy-secrets-policy"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "secretsmanager:GetSecretValue",
          "secretsmanager:DescribeSecret"
        ]
        Resource = aws_secretsmanager_secret.db_secret.arn
      }
    ]
  })
}

# Attach policy to role
resource "aws_iam_role_policy_attachment" "rds_proxy_policy_attach" {
  role       = aws_iam_role.rds_proxy_role.name
  policy_arn = aws_iam_policy.rds_proxy_secrets_policy.arn
}

# Store DB credentials in Secrets Manager
resource "aws_secretsmanager_secret" "db_secret" {
  name = "aurora-mysql-credentials"
  description = "Credentials for Aurora MySQL cluster"
}

resource "aws_secretsmanager_secret_version" "db_secret_version" {
  secret_id = aws_secretsmanager_secret.db_secret.id
  # You might generate random password via random_password, for demo:
  secret_string = jsonencode({
    username = "admin"
    password = "supersecurepassword123"  # Use random_password in production
  })
}

# Aurora MySQL cluster
resource "aws_rds_cluster" "aurora_mysql" {
  cluster_identifier              = "aurora-mysql-cluster"
  engine                          = "aurora-mysql"
  engine_version                  = "5.7.mysql_aurora.2.10.1"
  database_name                   = "mydb"
  master_username                 = jsondecode(aws_secretsmanager_secret_version.db_secret_version.secret_string).username
  master_password                 = jsondecode(aws_secretsmanager_secret_version.db_secret_version.secret_string).password
  db_subnet_group_name            = aws_db_subnet_group.aurora_subnet_group.name
  vpc_security_group_ids          = [aws_security_group.rds_aurora_sg.id]
  backup_retention_period         = 7
  preferred_backup_window         = "03:00-04:00"
  skip_final_snapshot             = true
  apply_immediately               = true
  enable_http_endpoint            = true
  storage_encrypted               = true

  depends_on = [
    aws_secretsmanager_secret_version.db_secret_version
  ]
}

# Aurora instance
resource "aws_rds_cluster_instance" "cluster_instance" {
  count              = 1
  identifier         = "aurora-instance-${count.index}"
  cluster_identifier = aws_rds_cluster.aurora_mysql.id
  instance_class     = "db.r5.large"
  engine             = "aurora-mysql"
  engine_version     = "5.7.mysql_aurora.2.10.1"
  db_subnet_group_name = aws_db_subnet_group.aurora_subnet_group.name
  publicly_accessible = false
  availability_zone   = data.aws_availability_zones.available.names[count.index % length(data.aws_availability_zones.available.names)]
}

# RDS Proxy
resource "aws_db_proxy" "rds_proxy" {
  name                   = "aurora-mysql-proxy"
  engine_family          = "MYSQL"
  vpc_subnet_ids         = [aws_subnet.aurora_subnet_1.id, aws_subnet.aurora_subnet_2.id]
