}

# Create a VPC for the Aurora cluster
resource "aws_vpc" "aurora_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "aurora-vpc"
  }
}

# Create public and private subnets across multiple AZs
resource "aws_subnet" "private_subnet_az1" {
  vpc_id                  = aws_vpc.aurora_vpc.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = false

  tags = {
    Name = "private-subnet-az1"
  }
}

resource "aws_subnet" "private_subnet_az2" {
  vpc_id                  = aws_vpc.aurora_vpc.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-east-1b"
  map_public_ip_on_launch = false

  tags = {
    Name = "private-subnet-az2"
  }
}

resource "aws_subnet" "public_subnet_az1" {
  vpc_id                  = aws_vpc.aurora_vpc.id
  cidr_block              = "10.0.101.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = true

  tags = {
    Name = "public-subnet-az1"
  }
}

# Create a DB subnet group for RDS
resource "aws_db_subnet_group" "aurora_subnet_group" {
  name       = "aurora-subnet-group"
  subnet_ids = [
    aws_subnet.private_subnet_az1.id,
    aws_subnet.private_subnet_az2.id
  ]

  tags = {
    Name = "aurora-db-subnet-group"
  }
}

# Security Group for Aurora cluster
resource "aws_security_group" "aurora_sg" {
  name        = "aurora-cluster-sg"
  description = "Security group for Aurora MySQL cluster"
  vpc_id      = aws_vpc.aurora_vpc.id

  # Allow inbound MySQL traffic from within the SG (for cluster internal comms)
  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    self        = true
  }

  # Allow inbound from the proxy (will be set dynamically)
  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    security_groups = [aws_security_group.rds_proxy_sg.id]
  }

  # Allow all outbound
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "aurora-cluster-sg"
  }
}

# Security Group for RDS Proxy
resource "aws_security_group" "rds_proxy_sg" {
  name        = "rds-proxy-sg"
  description = "Security group for RDS Proxy"
  vpc_id      = aws_vpc.aurora_vpc.id

  # Allow inbound MySQL from anywhere (adjust as needed for specific app SG)
  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]  # Restrict this in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-proxy-sg"
  }
}

# IAM role for RDS Proxy
resource "aws_iam_role" "rds_proxy_role" {
  name = "rds-proxy-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

# Attach required policy to allow RDS to manage secrets
resource "aws_iam_role_policy_attachment" "rds_proxy_service_role" {
  role       = aws_iam_role.rds_proxy_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonRDSServiceRolePolicy"
}

# Store database credentials in Secrets Manager
resource "aws_secretsmanager_secret" "db_credentials" {
  name = "aurora-mysql-credentials"
  description = "Credentials for Aurora MySQL cluster"
}

resource "aws_secretsmanager_secret_version" "db_credentials_version" {
  secret_id = aws_secretsmanager_secret.db_credentials.id
  # Using random password; in real use, this might be sourced externally
  secret_string = jsonencode({
    username = "admin"
    password = random_password.db_password.result
  })
}

# Generate random password
resource "random_password" "db_password" {
  length  = 16
  special = true
  override_special = "!#%"
}

# Define RDS Aurora MySQL cluster
resource "aws_rds_cluster" "aurora_cluster" {
  cluster_identifier           = "aurora-mysql-cluster"
  engine                       = "aurora-mysql"
  engine_version               = "5.7.mysql_aurora.2.10.1"
  database_name                = "mydb"
  master_username              = "admin"
  master_password              = random_password.db_password.result
  backup_retention_period      = 5
  preferred_backup_window      = "07:00-09:00"
  db_subnet_group_name         = aws_db_subnet_group.aurora_subnet_group.name
  vpc_security_group_ids       = [aws_security_group.aurora_sg.id]
  skip_final_snapshot          = true  # For testing; set to false in prod with proper snapshot name
  apply_immediately            = true
  enable_http_endpoint         = true  # Enables Data API

  # Enable deletion protection in production
  deletion_protection = false
}

# Aurora cluster instance
resource "aws_rds_cluster_instance" "cluster_instances" {
  count               = 2
  identifier          = "aurora-instance-${count.index}"
  cluster_identifier  = aws_rds_cluster.aurora_cluster.id
  instance_class      = "db.r5.large"
  engine              = "aurora-mysql"
  db_subnet_group_name = aws_db_subnet_group.aurora_subnet_group.name
  publicly_accessible  = false
}

# RDS Proxy for connection management
resource "aws_db_proxy" "rds_proxy" {
  name                   = "my-rds-proxy"
  engine_family          = "MYSQL"
  auth {
    description            = "Authentication using Secrets Manager"
    auth_type              = "SECRETS"
    secret_arn             = aws_secretsmanager_secret.db_credentials.arn
    iam_auth               = "DISABLED"
    client_password_auth_type = "MYSQL_NATIVE_PASSWORD"
  }
  role_arn               = aws_iam_role.rds_proxy_role.arn
  vpc_security_group_ids = [aws_security_group.rds_proxy_sg.id]
  vpc_subnet_ids         = [
    aws_subnet.private_subnet_az1.id,
    aws_subnet.private_subnet_az2.id
  ]
  require_tls            = false  # Enable in production
  idle_client_timeout    = 1800
  max_connections_percent = 100
  debug_logging          = false
}

# Associate RDS Proxy with the Aurora cluster
resource "aws_db_proxy_default_target_group" "rds_proxy_target_group" {
  db_proxy_name = aws_db_proxy.rds_proxy.name
  connection_pool_config {
    max_connections_percent = 100
    max_idle_connections_percent = 50
    connection_borrow_timeout = 120
    session_pinning_filters = []
    init_query = "SET xact_stmt_level = ON"
  }
}

resource "aws_db_proxy_target" "rds_proxy_target" {
  db_proxy_name = aws_db_proxy.rds_proxy.name
  target_group_name = aws_db_proxy_default_target_group.rds_proxy_target_group.name
  db_cluster_identifier = aws_rds_cluster.aurora_cluster.id
}

# Output the RDS Proxy endpoint for applications to connect
output "rds_proxy_endpoint" {
  description = "RDS Proxy endpoint to use for database connections"
  value       = aws_db_proxy.rds_proxy.endpoint
}

output "aurora_cluster_endpoint" {
  description = "Aurora cluster endpoint"
  value       = aws_rds_cluster.aurora_cluster.endpoint
}

