# Set up infrastructure for an AWS RDS Aurora MySQL cluster with Proxy, VPC, Subnets, Security Groups, IAM Roles, and Secrets Manager

provider "aws" {
  region = "us-east-1"
}

# Create a VPC for the Aurora cluster
resource "aws_vpc" "aurora_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "aurora-vpc"
  }
}

# Create subnets for the Aurora cluster (at least 2 AZs required for high availability)
resource "aws_subnet" "aurora_subnets" {
  count                   = 3
  vpc_id                  = aws_vpc.aurora_vpc.id
  cidr_block              = cidrsubnet(aws_vpc.aurora_vpc.cidr_block, 8, count.index)
  availability_zone       = element(data.aws_availability_zones.available.names, count.index)
  map_public_ip_on_launch = false

  tags = {
    Name = "aurora-subnet-${count.index + 1}"
  }
}

# Data source to get availability zones
data "aws_availability_zones" "available" {
  state = "available"
}

# Create a DB subnet group for the Aurora cluster
resource "aws_db_subnet_group" "aurora_subnet_group" {
  name       = "aurora-subnet-group"
  subnet_ids = aws_subnet.aurora_subnets[*].id

  tags = {
    Name = "aurora-subnet-group"
  }
}

# Security Group for Aurora cluster
resource "aws_security_group" "aurora_sg" {
  name        = "aurora-cluster-sg"
  description = "Security group for Aurora MySQL cluster"
  vpc_id      = aws_vpc.aurora_vpc.id

  # Allow inbound MySQL/Aurora traffic from the proxy or application
  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  # Allow outbound all traffic
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "aurora-cluster-sg"
  }
}

# Security Group for RDS Proxy
resource "aws_security_group" "rds_proxy_sg" {
  name        = "rds-proxy-sg"
  description = "Security group for RDS Proxy"
  vpc_id      = aws_vpc.aurora_vpc.id

  # Allow inbound MySQL traffic from applications
  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-proxy-sg"
  }
}

# IAM Role for RDS Proxy
resource "aws_iam_role" "rds_proxy_role" {
  name = "rds-proxy-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

# Attach IAM policy for Secrets Manager access
resource "aws_iam_role_policy_attachment" "rds_proxy_policy" {
  role       = aws_iam_role.rds_proxy_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonRDSServiceRolePolicy"
}

# Generate database credentials and store in Secrets Manager
resource "aws_secretsmanager_secret" "db_credentials" {
  name = "aurora-mysql-credentials"
}

resource "aws_secretsmanager_secret_version" "db_credentials_version" {
  secret_id     = aws_secretsmanager_secret.db_credentials.id
  secret_string = jsonencode({
    username = "admin"
    password = random_password.db_password.result
  })
}

# Random password for the database user
resource "random_password" "db_password" {
  length  = 16
  special = true
  override_special = "_%@"
}

# Create the Aurora MySQL cluster (Serverless is optional, here we use provisioned)
resource "aws_rds_cluster" "aurora_cluster" {
  cluster_identifier              = "aurora-mysql-cluster"
  engine                          = "aurora-mysql"
  engine_version                  = "8.0.mysql_aurora.3.08.0"
  master_username                 = aws_secretsmanager_secret_version.db_credentials_version.json.username
  master_password                 = aws_secretsmanager_secret_version.db_credentials_version.json.password
