  }
  role_arn                 = aws_iam_role.rds_proxy_role.arn
}

# Associate RDS Proxy with the Aurora cluster
resource "aws_rds_proxy_default_target_group" "rds_proxy_target" {
  db_proxy_name = aws_rds_proxy.rds_proxy.name
  connection_pool_configuration {
    max_connections_percent        = 100
    max_idle_connections_percent   = 50
    connection_borrow_timeout      = 120
    init_query                     = "SET time_zone = 'UTC'"
    session_pinning_filters        = []
    sql_pruning_enabled            = true
  }
}

resource "aws_rds_global_cluster" "this" {
  global_cluster_identifier = "aurora-mysql-global"
  database_name             = "mydb"
