  apply_immediately               = true
  availability_zones              = ["us-west-2a", "us-west-2b"]
}

# Create RDS Proxy
resource "aws_rds_proxy" "aurora_proxy" {
  name                   = "aurora-proxy"
  engine_family          = "MYSQL"
  vpc_subnet_ids         = [aws_subnet.aurora_subnet_1.id, aws_subnet.aurora_subnet_2.id]
  vpc_security_group_ids = [aws_security_group.aurora_sg.id]
  db_proxy_endpoint_name = "aurora-proxy-endpoint"

  auth {
    description      = "Database auth"
    auth_scheme      = "SECRETS"
    secret_arn       = aws_secretsmanager_secret.aurora_secret.arn
    iam_auth         = "REQUIRED"
  }

  require_tls                = true
  idle_client_timeout        = 1800
  debug_logging              = false
  max_connections_percent    = 100
  max_idle_connections_percent = 50
  tags = {
    Name = "Aurora-RDS-Proxy"
  }
}

# Associate RDS Proxy with the Aurora cluster
resource "aws_rds_proxy_default_target_group" "proxy_target_group" {
  db_proxy_name = aws_rds_proxy.aurora_proxy.name

  connection_pool_configuration_info {
    max_connections_percent        = 100
    max_idle_connections_percent   = 50
    connection_borrow_timeout      = 120
    session_pinning_filters        = []
    init_query                     = "SET x=1"
  }
}

resource "aws_db_proxy_target" "proxy_target" {
  db_proxy_name                   = aws_rds_proxy.aurora_proxy.name
  target_group_name               = "default"
  db_instance_identifier          = aws_rds_cluster_instance.instance1.db_instance_identifier
}

# Add cluster instance
resource "aws_rds_cluster_instance" "instance1" {
  identifier                   = "aurora-instance-1"
  cluster_identifier           = aws_rds_cluster.aurora_cluster.id
  instance_class               = "db.r5.large"
  engine                       = "aurora-mysql"
  engine_version               = "5.7.mysql_aurora.2.10.2"
  db_subnet_group_name         = aws_db_subnet_group.aurora_subnet_group.name
  promotion_tier               = 1
  publicly_accessible          = false
}

# Output critical info
output "aurora_cluster_endpoint" {
  value = aws_rds_cluster.aurora_cluster.endpoint
}

output "aurora_cluster_reader_endpoint" {
  value = aws_rds_cluster.aurora_cluster.reader_endpoint
}

output "rds_proxy_endpoint" {
  value = aws_rds_proxy.aurora_proxy.endpoint
}

output "secret_arn" {
  value = aws_secretsmanager_secret.aurora_secret.arn
}
```

