# Note: Amazon Lightsail does not support IPv6 addresses.
# Therefore, dualstack (IPv4 + IPv6) is not available.
# This configuration creates a Lightsail instance with a static IPv4 address only.

resource "aws_lightsail_instance" "example" {
  name              = "dualstack-lightsail" # Logical name for the instance
  availability_zone = "us-west-2a"          # Specify your desired AZ
  blueprint_id      = "amazon_linux_2"     # OS image (e.g., Amazon Linux 2)
  bundle_id         = "nano_2_0"           # Instance size (nano, micro, etc.)
}

# Optional: Assign a static public IPv4 address to the instance
resource "aws_lightsail_static_ip" "static_ip" {
  name           = "static-ip-for-lightsail"
  instance_name  = aws_lightsail_instance.example.id
}

# Output the public IPv4 address
output "public_ip" {
  description = "The public IPv4 address of the Lightsail instance"
  value       = aws_lightsail_static_ip.static_ip.ip_address
}

output "instance_arn" {
  description = "The ARN of the Lightsail instance"
  value       = aws_lightsail_instance.example.arn
}

# Create an AWS Lightsail instance with a separate SSH key
# Step 1: Define the AWS provider (Lightsail is part of AWS)
# Step 2: Create a Lightsail SSH key pair for authentication
# Step 3: Launch a Lightsail instance using the created key

provider "aws" {
  region = "us-east-1"  # Lightsail is available in multiple regions; us-east-1 is commonly used
}

# Step 2: Create a standalone SSH key pair in Lightsail
resource "aws_lightsail_key_pair" "lightsail_ssh_key" {
  name = "lightsail-key-pair"
  # Optional: You can import a public key, or let AWS generate a key pair
  # If you don't specify public_key, Terraform will generate one and save private_key to state
}

# Step 3: Create a Lightsail instance using the created key
resource "aws_lightsail_instance" "web_server" {
  name              = "my-lightsail-instance"
  availability_zone = "us-east-1a"  # Must be in a supported AZ for Lightsail
  blueprint_id      = "amazon_linux_2"  # OS image; e.g., Amazon Linux 2
  bundle_id         = "nano_2_0"    # Instance size; nano with 512MB RAM, 20GB SSD

  # Attach the generated key pair
  key_name = aws_lightsail_key_pair.lightsail_ssh_key.name

  # Optional: Add tags
  tags = {
    Name = "MyLightsailInstance"
  }
}

# Output the public IP and private key for access
output "public_ip" {
  value = aws_lightsail_instance.web_server.public_ip_address
}

output "private_key" {
  value     = aws_lightsail_key_pair.lightsail_ssh_key.private_key
  sensitive = true  # Prevents output from being shown in logs
}

output "ssh_command" {
  value = "ssh -i ./lightsail-key.pem ec2-user@${aws_lightsail_instance.web_server.public_ip_address}"
}

