# Creating a Lightsail instance with multiple attached disks requires:
# 1. A Lightsail instance (using aws_lightsail_instance)
# 2. One or more disks (using aws_lightsail_disk)
# 3. Attaching each disk to the instance using aws_lightsail_instance_disk_attachment

# Step 1: Create the Lightsail instance
resource "aws_lightsail_instance" "example_instance" {
  name              = "example-instance"
  availability_zone = "us-east-1a"  # Must be in a valid Lightsail AZ
  blueprint_id      = "amazon-linux-2"  # OS image
  bundle_id         = "micro_1_0"       # Instance size
}

# Step 2: Create the first disk and attach it
resource "aws_lightsail_disk" "disk1" {
  name              = "disk1"
  availability_zone = "us-east-1a"
  size_in_gb        = 32

  # Optional: tags
  tags = {
    Name = "First disk"
  }
}

resource "aws_lightsail_instance_disk_attachment" "attachment1" {
  disk_name     = aws_lightsail_disk.disk1.name
  instance_name = aws_lightsail_instance.example_instance.name
  disk_path     = "/dev/xvdf"  # Device name visible to the instance
}

# Step 3: Create a second disk and attach it
resource "aws_lightsail_disk" "disk2" {
  name              = "disk2"
  availability_zone = "us-east-1a"
  size_in_gb        = 64

  tags = {
    Name = "Second disk"
  }
}

resource "aws_lightsail_instance_disk_attachment" "attachment2" {
  disk_name     = aws_lightsail_disk.disk2.name
  instance_name = aws_lightsail_instance.example_instance.name
  disk_path     = "/dev/xvdg"  # Another unique device path
}

# This configuration creates one Lightsail instance with two separate disks attached.
# Each disk is created in the same AZ and attached using a unique device path.
```

