# Step-by-step breakdown:
# 1. We need an AWS S3 bucket to serve as the origin for the Lightsail distribution
# 2. We need to create a Lightsail distribution (Content Delivery Network)
# 3. The distribution should reference the S3 bucket as its origin
# 4. We must configure the distribution's default cache behavior and optional settings

# Note: AWS Lightsail distributions support S3 buckets as origins, but require the bucket to be in the same AWS region
# and may require proper permissions for Lightsail to access the bucket.

resource "aws_s3_bucket" "origin_bucket" {
  bucket = "my-lightsail-distribution-origin"
  # Note: S3 bucket names must be globally unique, so consider using a randomized suffix in practice
  force_destroy = true # Useful for testing; disable in production

  # Enable static website hosting if serving web content
  # website {
  #   index_document = "index.html"
  # }
}

resource "aws_lightsail_distribution" "cdn_distribution" {
  name   = "my-lightsail-cdn"
  bundle_id = "small_2.0" # Example bundle; choose based on your needs (e.g., small_2.0, medium_2.0)

  # Origin configuration pointing to S3 bucket
  origin {
    name = aws_s3_bucket.origin_bucket.id
    region_name = var.aws_region # Must match region of the S3 bucket
  }

  # Default cache behavior
  default_cache_behavior {
    behavior = "cache" # Options: cache, dont-cache, or use-headers
  }

  # Cache behavior settings
  cache_behavior_settings {
    default_ttl_seconds = 86400
    minimum_ttl_seconds = 0
    maximum_ttl_seconds = 31536000

    # Headers to forward to origin (none unless needed)
    allowed_http_methods = "GET,HEAD,OPTIONS"
    cached_http_methods  = "GET,HEAD"

    # Logging and compression
    viewer_protocol_policy = "http-and-https"
    compress               = true

    # Cookies to forward
    forwarded_cookies {
      option = "none"
    }

    # Headers to forward
    forwarded_headers {
      option = "none"
    }

    # Query strings to forward
    forwarded_query_strings {
      option = false
    }
  }

  # Add index and error pages if serving static site
  # and ensure your bucket has the appropriate public access if needed
  # Also, consider adding a certificate and domain if using custom domain
}

# Optional: If you want to allow Lightsail to read from the S3 bucket
# resource "aws_s3_bucket_policy" "bucket_policy" {
#   bucket = aws_s3_bucket.origin_bucket.id
#   policy = jsonencode({
#     Version = "2012-10-17"
#     Statement = [
#       {
#         Effect = "Allow"
#         Principal = {
#           Service = "lightsail.amazonaws.com"
#         }
#         Action = [
#           "s3:GetObject"
#         ]
#         Resource = "${aws_s3_bucket.origin_bucket.arn}/*"
#       }
#     ]
#   })
# }

# Note: You may need to manually enable S3 bucket access for Lightsail via AWS Console
# or via AWS CLI as Terraform might not fully manage this yet.
# Also ensure the region supports Lightsail distributions.

variable "aws_region" {
  description = "AWS region for resources"
  default     = "us-east-1"
}

