# Step 1: Create an S3 Glacier Vault
# AWS Glacier vaults are created using the aws_glacier_vault resource.
# We'll define a vault with a name and optional access policy.

# Step 2: Use AWS Data Lifecycle Manager (DLM)
# AWS DLM manages lifecycle policies for EBS snapshots and EBS-backed AMIs.
# However, note: AWS Data Lifecycle Manager does **not** directly manage Glacier vaults.
# Instead, DLM is used to automate EBS snapshot creation and retention, and optionally archive snapshots to S3 Glacier.
# So we interpret the request as:
# - Create a Glacier vault (for potential archive access)
# - Set up a DLM lifecycle policy to back up EBS volumes and archive snapshots to Glacier

# Thus, we will:
# 1. Create an S3 Glacier vault.
# 2. Create an IAM role used by DLM to manage snapshots and archive to Glacier.
# 3. Create a DLM lifecycle policy that:
#    - Creates EBS snapshots on a schedule
#    - Archives snapshots to S3 Glacier after a certain period

resource "aws_glacier_vault" "backup_vault" {
  name = "dlm-glacier-archive-vault"

  tags = {
    Name        = "DLM Glacier Archive Vault"
    Environment = "production"
  }
}

# IAM Role for Data Lifecycle Manager
resource "aws_iam_role" "dlm_lifecycle_role" {
  name = "dlm-lifecycle-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "dlm.amazonaws.com"
        }
        Condition = {}
      }
    ]
  })
}

# Attach required policies to the role
resource "aws_iam_role_policy_attachment" "dlm_service_policy" {
  role       = aws_iam_role.dlm_lifecycle_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSDataLifecycleManagerServiceRole"
}

# Optionally: Allow Glacier archive (though the above managed policy includes required permissions)
# Including explicit Glacier permissions just in case (though not typically needed)

# Define Lifecycle Policy to backup EBS volumes and archive to Glacier
resource "aws_dlm_lifecycle_policy" "ebs_snapshot_glacier" {
  description        = "Backup EBS volumes and archive to Glacier"
  execution_role_arn = aws_iam_role.dlm_lifecycle_role.arn
  state              = "ENABLED"

  policy_details {
    resource_types = ["VOLUME"]

    schedule {
      name = "daily-snapshots-to-glacier"

      create_rule {
        interval      = 24
        interval_unit = "HOURS"
        times         = ["03:00"]
      }

      retain_rule {
        count = 14
      }

      # Archive rule: after 60 days, move snapshot to Glacier
      archive_rule {
        retain_rule {
          # Days after creation to archive (minimum is 90, but depends on policy)
          # AWS requires at least 90 days for archiving
          based_on_time {
            count         = 90
            interval      = 365
            interval_unit = "DAYS"
            # Note: Only one of count or interval should be used
            count         = 90
            unit          = "DAYS"
          }
        }
      }
    }

    # Optional: Target tags to apply policy to volumes with specific tags
    # For example, only volumes with Backup=true
    # target_tags = {
    #   Backup = "true"
    # }

    # Optionally define a tag to identify created snapshots
    tags_to_add = {
      BackupPolicy = "DLM-Glacier-Archive"
    }

    copy_tags = true
  }
}

