  policy     = data.aws_iam_policy_document.vault_access_policy.json
}

# Lock the Glacier vault policy to prevent changes
resource "aws_glacier_vault_lock" "example_lock" {
  vault_name        = aws_glacier_vault.example.name
  policy            = data.aws_iam_policy_document.vault_access_policy.json
  complete_lock     = true # Ensures the policy cannot be changed after locking

  # Optional: Define compliance deadline (e.g., 1 day from now)
  # compliance_control = "incomplete-lock" # Use if you want to allow future lock completion

  # Ensure the vault policy is applied before locking
  depends_on = [aws_glacier_vault_policy.example_policy]
}
