extracted_code:
# This Terraform configuration creates:
# - A VPC
# - A subnet
# - A security group allowing traffic to EC2 and NLB
# - A t2.micro EC2 instance
# - A Network Load Balancer (NLB) with a target group and listener
# The NLB is internet-facing and forwards traffic to the EC2 instance.

provider "aws" {
  region = "us-west-2"  # You can change this to your preferred region
}

# Create a VPC
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "nlb-ec2-vpc"
  }
}

# Create a public subnet
resource "aws_subnet" "public" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-west-2a"
  map_public_ip_on_launch = true

  tags = {
    Name = "public-subnet"
  }
}

# Internet Gateway for public access
resource "aws_internet_gateway" "gw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "internet-gateway"
  }
}

# Route table to enable internet access
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.gw.id
  }

  tags = {
    Name = "public-route-table"
  }
}

# Associate route table with subnet
resource "aws_route_table_association" "public" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public.id
}

# Security group for EC2 instance and NLB
resource "aws_security_group" "nlb_sg" {
  name        = "nlb-sg"
  description = "Allow traffic for NLB and EC2"
  vpc_id      = aws_vpc.main.id

  # Allow inbound HTTP traffic (port 80) from anywhere
  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow inbound SSH traffic (port 22) for EC2
  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow all outbound traffic
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "nlb-security-group"
  }
}

# EC2 instance (t2.micro)
resource "aws_instance" "web" {
  ami           = "ami-0c02fb55956c7d316"  # Amazon Linux 2 in us-west-2
  instance_type = "t2.micro"
  subnet_id              = aws_subnet.public.id
  vpc_security_group_ids = [aws_security_group.nlb_sg.id]
  associate_public_ip_address = true

  user_data = <<-EOF
              #!/bin/bash
              echo "Hello from $(hostname)" > /var/www/html/index.html
              nohup busybox httpd -f -p 80 &
              EOF

  tags = {
    Name = "nlb-target-instance"
  }
}

# Network Load Balancer
resource "aws_lb" "nlb" {
  name               = "demo-network-lb"
  internal           = false
  load_balancer_type = "network"
  subnets            = [aws_subnet.public.id]

  tags = {
    Name = "network-lb"
  }
}

# Target group for NLB
resource "aws_lb_target_group" "tg" {
  name     = "nlb-target-group"
  port     = 80
  protocol = "TCP"
  target_type = "instance"
  vpc_id   = aws_vpc.main.id

  health_check {
    port            = "80"
    protocol        = "TCP"
    interval        = 10
    timeout         = 10
    healthy_threshold   = 3
    unhealthy_threshold = 3
  }
}

# Register EC2 instance with target group
resource "aws_lb_target_group_attachment" "attachment" {
  target_group_arn = aws_lb_target_group.tg.arn
  target_id        = aws_instance.web.id
  port             = 80
}

# Listener to route traffic from NLB to target group
resource "aws_lb_listener" "listener" {
  load_balancer_arn = aws_lb.nlb.arn
  port              = "80"
  protocol          = "TCP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.tg.arn
  }
}

# Output the NLB DNS name for access
output "nlb_dns_name" {
  value = aws_lb.nlb.dns_name
}

