# Variables to make the configuration reusable
variable "subnet_ids" {
  description = "List of subnet IDs for the NLB"
  type        = list(string)
}

variable "vpc_id" {
  description = "VPC ID where the NLB will be created"
  type        = string
}

variable "target_port" {
  description = "Port on which targets receive traffic"
  type        = number
  default     = 80
}

variable "listener_port" {
  description = "Port on which the NLB listens for traffic"
  type        = number
  default     = 80
}

variable "health_check_port" {
  description = "Port used for health checks"
  type        = number
  default     = 80
}

