To create an internal-facing load balancer with a specified private IP address using Terraform, we need to consider the following steps:

1. **Choose the Provider**: We'll assume AWS for this example, as it's commonly used and supports this feature.
2. **VPC and Subnets**: The load balancer must be deployed in a VPC with at least one subnet. For internal load balancers, subnets should be private.
3. **Internal Load Balancer**: We'll use an AWS Application Load Balancer (ALB) or Network Load Balancer (NLB). For assigning a specific private IP, NLB is more suitable.
4. **Specify Private IP**: For internal NLBs, we can assign a specific private IP address in each subnet using the `private_ip_address` attribute within the `subnet_mapping` block.
5. **Security Groups and Target Groups**: Required for routing traffic to backend instances.

We’ll create:
- A Network Load Balancer (NLB), internal-facing.
- Subnet mappings with specified private IP addresses.
- A target group and listener for routing.

Here is the complete Terraform configuration:

```hcl
provider "aws" {
  region = "us-west-2"
}

# Existing VPC and Subnets (assumed to exist; you can create them if needed)
# Replace with actual subnet IDs and CIDR as needed
variable "subnet_ids" {
  description = "List of private subnet IDs"
  type        = list(string)
  default     = ["subnet-12345678", "subnet-87654321"]
}

variable "private_ips" {
  description = "List of private IP addresses to assign in each subnet"
  type        = list(string)
  default     = ["10.0.1.100", "10.0.2.100"]
}

# Target group for backend instances
resource "aws_lb_target_group" "app" {
  name     = "internal-app-tg"
  port     = 80
  protocol = "TCP"
  vpc_id   = "vpc-12345678"  # Replace with your VPC ID
  target_type = "instance"

  health_check {
    healthy_threshold   = 3
    interval            = 30
    protocol            = "TCP"
    timeout             = 6
    unhealthy_threshold = 3
  }
}

# Internal Network Load Balancer with specified private IPs
resource "aws_lb" "internal" {
  name               = "internal-nlb"
  internal           = true
  load_balancer_type = "network"
  security_groups    = [aws_security_group.lb.id]
  subnets            = var.subnet_ids

  # Map subnets with specific private IP addresses
  dynamic "subnet_mapping" {
    for_each = zipmap(var.subnet_ids, var.private_ips)
    content {
      subnet_id        = subnet_mapping.key
      private_ipv4_address = subnet_mapping.value
    }
  }

  tags = {
    Name = "InternalNLB"
  }
}

# Security group for the load balancer
resource "aws_security_group" "lb" {
  name        = "nlb-sg"
  vpc_id      = "vpc-12345678"  # Replace with your VPC ID
  description = "Security group for internal NLB"

  # Allow inbound traffic on port 80
  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]  # Adjust as needed
  }

  # Allow all outbound traffic
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Listener to route traffic to target group
resource "aws_lb_listener" "front_end" {
  load_balancer_arn = aws_lb.internal.arn
  port              = 80
  protocol          = "TCP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.app.arn
  }
}
