# Step-by-step reasoning:

# 1. We need an AWS Application Load Balancer (ALB) because it supports Lambda functions as a target.
# 2. An ALB requires a VPC and subnets (public) to be attached.
# 3. We need a listener on the ALB (typically port 80 or 443) to route requests.
# 4. A target group is required to associate the Lambda function as a target.
# 5. The target group must be configured with `target_type = "lambda"`.
# 6. Listener rules will forward requests to the Lambda-backed target group.
# 7. Permissions are needed for the ALB to invoke the Lambda function.

# Note: This example assumes you have a Lambda function already defined or will provide the ARN.
# We'll define the ALB, target group, listener, and necessary permissions for Lambda invocation.

resource "aws_lb" "alb" {
  name               = "lambda-alb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb_sg.id]
  subnets            = aws_subnet.public[*].id
}

resource "aws_lb_target_group" "lambda_tg" {
  name     = "lambda-target-group"
  port     = 80
  protocol = "HTTP"
  target_type = "lambda"

  # Health check is optional for Lambda targets
  health_check {
    enabled             = false
  }
}

resource "aws_lb_listener" "http_listener" {
  load_balancer_arn = aws_lb.alb.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.lambda_tg.arn
  }
}

# Allow the ALB to invoke the Lambda function
resource "aws_lambda_permission" "allow_alb" {
  statement_id  = "AllowExecutionFromALB"
  action        = "lambda:InvokeFunction"
  function_name = var.lambda_function_arn
  principal     = "elasticloadbalancing.amazonaws.com"
  source_arn    = aws_lb_listener.http_listener.arn
}

# Optional: Security group for ALB
resource "aws_security_group" "alb_sg" {
  name        = "alb-security-group"
  description = "Allow HTTP access from the internet"

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Optional: Public subnets and VPC (assuming minimal infrastructure)
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "main-vpc"
  }
}

resource "aws_subnet" "public" {
  count = 2

  vpc_id                  = aws_vpc.main.id
  cidr_block              = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone       = element(data.aws_availability_zones.available.names, count.index)
  map_public_ip_on_launch = true

  tags = {
    Name = "public-subnet-${count.index}"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

# Variables to input the Lambda function ARN
variable "lambda_function_arn" {
  description = "ARN of the Lambda function to be used as target"
  type        = string
}

