response:
To generate a Terraform configuration for an Application Load Balancer (ALB) with a Target Group, we need to consider the following components:

1. **VPC**: The ALB and target instances (like EC2) must be in a VPC.
2. **Subnets**: ALB needs at least two subnets in different Availability Zones.
3. **Security Groups**: Control traffic to the ALB and the target instances.
4. **ALB (Load Balancer)**: The main load balancer resource.
5. **Target Group**: Defines where the ALB routes requests.
6. **Listener**: Listens for traffic (e.g., HTTP on port 80) and forwards to the target group.

We'll assume:
- We're using AWS.
- The VPC and subnets already exist or will be created (here, we’ll reference existing ones for simplicity).
- We’re creating a basic HTTP listener.
- The target group will route to EC2 instances on port 80.

We’ll use variables for flexibility (like VPC ID and subnets), but in this example, we’ll use placeholders.

```hcl
# Providers
provider "aws" {
  region = "us-west-2"
}

# Variables (can be overridden via tfvars or CLI)
variable "vpc_id" {
  description = "The VPC ID where ALB will be created"
  type        = string
}

variable "subnet_ids" {
  description = "List of subnet IDs (at least 2) for ALB across AZs"
  type        = list(string)
}

# Security Group for ALB
resource "aws_security_group" "alb_sg" {
  name        = "alb-security-group"
  description = "Security group for ALB"
  vpc_id      = var.vpc_id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Application Load Balancer
resource "aws_lb" "app_lb" {
  name            = "sample-application-lb"
  internal        = false
  load_balancer_type = "application"
  security_groups = [aws_security_group.alb_sg.id]
  subnets         = var.subnet_ids

  tags = {
    Name = "SampleALB"
  }
}

# ALB Target Group
resource "aws_lb_target_group" "target_group" {
  name     = "sample-target-group"
  port     = 80
  protocol = "HTTP"
  vpc_id   = var.vpc_id

  health_check {
    path                = "/health"
    protocol            = "HTTP"
    port                = "traffic-port"
    healthy_threshold   = 5
    unhealthy_threshold = 2
    timeout             = 3
    interval            = 30
    matcher             = "200"
  }

  tags = {
    Name = "SampleTargetGroup"
  }
}

# Listener for Load Balancer
resource "aws_lb_listener" "listener_http" {
  load_balancer_arn = aws_lb.app_lb.arn
  port              = 80
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.target_group.arn
  }
}

# Output the DNS name of the ALB
output "alb_dns_name" {
  value = aws_lb.app_lb.dns_name
}

output "target_group_arn" {
  value = aws_lb_target_group.target_group.arn
}
```

