# Step 1: Define required providers (we'll use AWS as the most common use case)
# Step 2: Create a target group that defines where traffic should be routed (e.g., EC2 instances on a port)
# Step 3: Create a load balancer (Application Load Balancer in this case) which listens for incoming traffic
# Step 4: Create a listener to associate the load balancer with the target group
# We assume default VPC and subnets exist; otherwise, they'd need to be created or referenced.

provider "aws" {
  region = "us-west-2"  # Example region; change as needed
}

# Create a Target Group
resource "aws_lb_target_group" "example_target_group" {
  name     = "example-target-group"
  port     = 80
  protocol = "HTTP"
  vpc_id   = aws_vpc.example_vpc.id  # This VPC needs to exist or be created

  # Health check settings
  health_check {
    path                = "/health"
    interval            = 30
    timeout             = 5
    healthy_threshold   = 2
    unhealthy_threshold = 2
    matcher             = "200"
  }

  # Ensure Terraform doesn't wait for deregistration
  deregistration_delay = 10
}

# Create a Load Balancer (Application Load Balancer)
resource "aws_lb" "example_load_balancer" {
  name               = "example-load-balancer"
  internal           = false  # Internet-facing
  load_balancer_type = "application"
  security_groups    = [aws_security_group.lb_sg.id]
  subnets            = aws_subnet.example_subnets[*].id

  # Enable deletion protection
  enable_deletion_protection = true

  # Access logs can be enabled if needed (optional)
  # access_logs {
  #   bucket = aws_s3_bucket.lb_logs.bucket
  #   prefix = "lb-access-logs"
  # }
}

# Create a Listener to route requests from the LB to the Target Group
resource "aws_lb_listener" "example_listener" {
  load_balancer_arn = aws_lb.example_load_balancer.arn
  port              = "80"
  protocol          = "HTTP"

  # Forward traffic to the target group
  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.example_target_group.arn
  }
}

# Supporting resources (minimal setup assumed; adjust as needed)

# VPC
resource "aws_vpc" "example_vpc" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "example-vpc"
  }
}

# Subnets (public subnets for ALB)
resource "aws_subnet" "example_subnets" {
  count = 2

  vpc_id                  = aws_vpc.example_vpc.id
  cidr_block              = cidrsubnet(aws_vpc.example_vpc.cidr_block, 8, count.index)
  availability_zone       = element(data.aws_availability_zones.available.names, count.index)
  map_public_ip_on_launch = true

  tags = {
    Name = "example-subnet-${count.index}"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

# Security Group for Load Balancer
resource "aws_security_group" "lb_sg" {
  name        = "lb-security-group"
  description = "Allow HTTP traffic"
  vpc_id      = aws_vpc.example_vpc.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "lb-sg"
  }
}

