# providers.tf
provider "aws" {
  region = "us-west-2"
}

# We need to create an IAM role for RDS to access S3
resource "aws_iam_role" "rds_s3_access_role" {
  name = "rds-s3-access-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "rds_s3_access_policy" {
  name = "rds-s3-access-policy"
  role = aws_iam_role.rds_s3_access_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = [
          "arn:aws:s3:::your-backup-bucket-name",
          "arn:aws:s3:::your-backup-bucket-name/*"
        ]
      }
    ]
  })
}

# Optional: If the bucket doesn't exist, create it (but likely it exists)
# resource "aws_s3_bucket" "backup_bucket" {
#   bucket = "your-backup-bucket-name"
# }

# Now, create a DB subnet group
resource "aws_db_subnet_group" "main" {
  name       = "main-db-subnet-group"
  subnet_ids = [aws_subnet.subnet1.id, aws_subnet.subnet2.id]
  tags = {
    Name = "Main DB Subnet Group"
  }
}

# Create VPC and subnets (minimal setup for RDS)
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "main-vpc"
  }
}

resource "aws_subnet" "subnet1" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-west-2a"
  map_public_ip_on_launch = false
  tags = {
    Name = "subnet-1"
  }
}

resource "aws_subnet" "subnet2" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-west-2b"
  map_public_ip_on_launch = false
  tags = {
    Name = "subnet-2"
  }
}

# Security group for RDS
resource "aws_security_group" "rds_sg" {
  name        = "rds-security-group"
  description = "Allow PostgreSQL inbound"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 1433  # SQL Server default
    to_port     = 1433
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Now, create the RDS instance restored from S3
resource "aws_db_instance" "restored_db" {
  identifier_prefix           = "restored-from-s3-"
  instance_class              = "db.t3.micro"
  engine                      = "sqlserver-ee"
  allocated_storage           = 100
  max_allocated_storage       = 200
  engine_version              = "15.00.4249.2.v1"
  storage_type                = "gp2"
  license_model               = "license-included"
  storage_encrypted           = false
  backup_retention_period     = 7
  multi_az                    = false
  auto_minor_version_upgrade  = true
  final_snapshot_identifier   = "final-snapshot-before-deletion"
  skip_final_snapshot         = false
  db_subnet_group_name        = aws_db_subnet_group.main.name
  vpc_security_group_ids      = [aws_security_group.rds_sg.id]
  publicly_accessible         = false

  # RDS will restore from S3
  # Additional parameters required for S3 import
  s3_import {
    source_engine         = "sqlserver-ee"
    source_engine_version = "15.00.4249.2.v1"
    bucket_name           = "your-backup-bucket-name"
    bucket_prefix         = "backups/"
    ingestion_role        = aws_iam_role.rds_s3_access_role.arn
    data_format           = "native"
  }

  # Must be set when restoring from S3
  # RDS will ignore username/password during restore, but required in HCL
  # Real credentials come from the backup
  username = "ignored_admin"  # will be ignored during S3 restore
  password = "ignored_password"
}

# Note: The aws_db_instance resource does not natively support `s3_import` in current Terraform AWS provider (yet).
# As of v5.x, direct S3 import during DB creation is not supported via `aws_db_instance`.
# This requires using an AWS CLI call or a null_resource with local-exec.

# Workaround: Create the DB instance and use null_resource with AWS CLI
# Since Terraform doesn't support the `--s3-bucket-name` and related flags directly in the resource,
# we can create the DB instance via CLI.

resource "null_resource" "restore_rds_from_s3" {
  provisioner "local-exec" {
    command = <<EOT
      aws rds restore-db-instance-from-s3 \n        --db-instance-identifier ${aws_db_instance.restored_db.identifier} \n        --db-instance-class ${aws_db_instance.restored_db.instance_class} \n        --engine sqlserver-ee \n        --engine-version ${aws_db_instance.restored_db.engine_version} \n        --master-username ignored_admin \n        --master-user-password ignored_password \n        --allocated-storage ${aws_db_instance.restored_db.allocated_storage} \n        --s3-bucket-name your-backup-bucket-name \n        --s3-prefix backups/ \n        --s3-ingestion-role-arn ${aws_iam_role.rds_s3_access_role.arn} \n        --backup-retention-period ${aws_db_instance.restored_db.backup_retention_period} \n        --db-subnet-group-name ${aws_db_subnet_group.main.name} \n        --vpc-security-group-ids ${join(",", aws_db_instance.restored_db.vpc_security_group_ids)} \n        --no-multi-az
    EOT
  }

  # Ensure DB instance and IAM role are ready
  depends_on = [
    aws_iam_role.rds_s3_access_role,
    aws_db_subnet_group.main,
    aws_security_group.rds_sg
  ]

  # Run only once
  triggers = {
    s3_bucket = "your-backup-bucket-name"
    backup_key = "latest.bak"
  }
}

# Output the DB instance endpoint
output "db_instance_endpoint" {
  value = aws_db_instance.restored_db.endpoint
}

