# Step 1: Create an AWS EFS file system
resource "aws_efs_file_system" "example" {
  creation_token = "example-efs"
  encrypted      = true
  throughput_mode = "elastic"

  # Enable lifecycle management policy (optional)
  lifecycle_policy {
    transition_to_ia = "AFTER_30_DAYS"
  }
}

# Step 2: Create a mount target for the EFS in a specific subnet
# Note: You need at least one subnet to mount the EFS. Assuming one subnet for demonstration.
resource "aws_efs_mount_target" "example_mount_target" {
  file_system_id  = aws_efs_file_system.example.id
  subnet_id       = aws_subnet.example.id  # This should be a valid subnet ID
  security_groups = [aws_security_group.efs-sg.id]  # Attach a security group
}

# Step 3: Define a security group for EFS mount targets
resource "aws_security_group" "efs-sg" {
  name        = "efs-security-group"
  description = "Security group for EFS mount targets"
  vpc_id      = aws_vpc.example.id  # This should be a valid VPC ID

  # Allow NFS traffic from your instances (adjust CIDR as needed)
  ingress {
    from_port   = 2049
    to_port     = 2049
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]  # Adjust to your VPC or subnet range
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Step 4: Attach a file system policy (system policy) to the EFS
# This policy allows EFS access from specific IAM principals or services
resource "aws_efs_file_system_policy" "example_policy" {
  file_system_id = aws_efs_file_system.example.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "AllowRootAccess"
        Effect = "Allow"
        Principal = {
          AWS = "*"
        }
        Action = [
          "elasticfilesystem:ClientMount",
          "elasticfilesystem:ClientWrite",
          "elasticfilesystem:ClientRootAccess"
        ]
        Condition = {
          Bool = {
            "aws:SecureTransport" = "true"
          }
        }
      }
    ]
  })
}

# Note: In production, avoid using "*" in Principal and further restrict with conditions.
# Also, ensure that aws_subnet.example and aws_vpc.example exist or be defined.

