# Step 1: Create an AWS EFS file system
# We'll define an AWS EFS (Elastic File System) resource with default settings.
# This creates the actual file system in AWS.

# Step 2: Create a mount target for the EFS
# A mount target is required to allow EC2 instances or other resources to mount the EFS.
# We need to specify a subnet ID where the mount target will be created.
# Optionally, we can specify security groups to control access.

# Assumptions:
# - We assume there is at least one subnet available in the desired VPC.
# - We'll create a security group specifically for EFS to allow NFS access (port 2049).
# - For production use, you should specify your own VPC and subnets. Here we simplify.

resource "aws_efs_file_system" "efs" {
  creation_token = "my-efs-file-system"
  performance_mode = "generalPurpose"
  throughput_mode = "bursting"

  tags = {
    Name = "my-efs"
  }
}

resource "aws_security_group" "efs_sg" {
  description = "Security group for EFS"
  vpc_id      = var.vpc_id # This should be passed as a variable

  # Allow inbound NFS traffic from specific sources (e.g., EC2 instances)
  ingress {
    from_port   = 2049
    to_port     = 2049
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Adjust this to your VPC or subnet range
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "efs-security-group"
  }
}

resource "aws_efs_mount_target" "efs_mount_target" {
  file_system_id  = aws_efs_file_system.efs.id
  subnet_id       = var.subnet_id # This should be passed as a variable
  security_groups = [aws_security_group.efs_sg.id]
}

# Note: To use this configuration, you must define variables for vpc_id and subnet_id
# or replace them with actual values.

variable "vpc_id" {
  description = "The VPC ID where EFS will be mounted"
  type        = string
}

variable "subnet_id" {
  description = "The subnet ID in which to create the mount target"
  type        = string
}

