extracted_code:
# Define provider and region
provider "aws" {
  region = "us-west-2" # Default region, can be changed as needed
}

# Create a VPC
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "main-vpc"
  }
}

# Create two subnets in different availability zones
resource "aws_subnet" "subnet_az1" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-west-2a"
  map_public_ip_on_launch = true

  tags = {
    Name = "subnet-az1"
  }
}

resource "aws_subnet" "subnet_az2" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-west-2b"
  map_public_ip_on_launch = true

  tags = {
    Name = "subnet-az2"
  }
}

# Create an Internet Gateway
resource "aws_internet_gateway" "gw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "main-igw"
  }
}

# Create a Route Table and add a default route to the Internet Gateway
resource "aws_route_table" "public_route_table" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.gw.id
  }

  tags = {
    Name = "public-route-table"
  }
}

# Associate both subnets with the route table
resource "aws_route_table_association" "rta_subnet_az1" {
  subnet_id      = aws_subnet.subnet_az1.id
  route_table_id = aws_route_table.public_route_table.id
}

resource "aws_route_table_association" "rta_subnet_az2" {
  subnet_id      = aws_subnet.subnet_az2.id
  route_table_id = aws_route_table.public_route_table.id
}

# Create a security group to allow MySQL and PostgreSQL access
resource "aws_security_group" "db_security_group" {
  name        = "db-security-group"
  description = "Allow MySQL and PostgreSQL inbound traffic"
  vpc_id      = aws_vpc.main.id

  # Allow MySQL (port 3306) from any IP
  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow PostgreSQL (port 5432) from any IP
  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow all outbound traffic
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "db-security-group"
  }
}

# Create a database subnet group with both subnets
resource "aws_db_subnet_group" "db_subnet_group" {
  name       = "main-db-subnet-group"
  description = "DB subnet group with subnets in two AZs"
  subnet_ids = [
    aws_subnet.subnet_az1.id,
    aws_subnet.subnet_az2.id
  ]

  tags = {
    Name = "main-db-subnet-group"
  }
}

