# Step 1: Create a DHCP Options resource with Google's DNS servers (8.8.8.8 and 8.8.4.4)
# and name it "pike" using tags. The DHCP options will be configured for a specific VPC.

# Step 2: Associate the created DHCP options with a specified VPC using the dhcp_options_id
# and vpc_id. This ensures the VPC uses the custom DHCP settings.

# Step 3: Tag both the DHCP options and the association with "permissions" as per request.
# Note: AWS does not allow tagging of the DHCP association resource directly.
# Instead, we tag the DHCP options resource, and the association will inherit logically.

resource "aws_vpc_dhcp_options" "pike_dhcp" {
  domain_name_servers = ["8.8.8.8", "8.8.4.4"]

  tags = {
    Name        = "pike"
    permissions = "true"
  }
}

resource "aws_vpc_dhcp_options_association" "pike_association" {
  vpc_id          = var.vpc_id
  dhcp_options_id = aws_vpc_dhcp_options.pike_dhcp.id

  # Note: aws_vpc_dhcp_options_association does not support tags
}

