extracted_code:
# Step 1: Define the NAT Gateway resource
# - The NAT Gateway requires an associated subnet (specified by subnet_id)
# - It needs a public IP address, which is provided via allocation_id from an Elastic IP
# - It should have tags to indicate ownership or purpose

resource "aws_nat_gateway" "example" {
  allocation_id = var.eip_allocation_id
  subnet_id     = var.subnet_id

  # Ensure proper cleanup by deleting the EIP when the NAT Gateway is destroyed
  depends_on = [aws_internet_gateway.main]

  tags = {
    pike = "permissions"
  }
}

# Step 2: Define input variables to accept subnet_id and allocation_id
variable "subnet_id" {
  description = "The ID of the public subnet in which to place the NAT Gateway"
  type        = string
}

variable "eip_allocation_id" {
  description = "The allocation ID of the Elastic IP to associate with the NAT Gateway"
  type        = string
}

# Step 3: Note that AWS requires a route table entry directing traffic through the NAT Gateway.
# This configuration does not include the route table association, assuming it's managed separately.
# However, best practice would include a route in a private route table.

