# Step 1: Create the first VPC named "peer" with CIDR block 10.0.0.0/24
resource "aws_vpc" "peer" {
  cidr_block = "10.0.0.0/24"
  tags = {
    Name = "peer"
  }
}

# Step 2: Create the second VPC named "base" with CIDR block 10.1.0.0/24
resource "aws_vpc" "base" {
  cidr_block = "10.1.0.0/24"
  tags = {
    Name = "base"
  }
}

# Step 3: Establish a VPC peering connection named "pike" between the two VPCs
resource "aws_vpc_peering_connection" "pike" {
  vpc_id      = aws_vpc.peer.id
  peer_vpc_id = aws_vpc.base.id

  tags = {
    Name       = "pike"
    pike       = "permissions"
  }
}

# Step 4: Update the route tables to allow traffic between the VPCs
# Create or reference route tables for both VPCs and add routes

resource "aws_default_route_table" "peer_route_table" {
  default_route_table_id = aws_vpc.peer.default_route_table_id

  route {
    cidr_block = aws_vpc.base.cidr_block
    vpc_peering_connection_id = aws_vpc_peering_connection.pike.id
  }

  tags = {
    Name = "peer-route-table"
  }
}

resource "aws_default_route_table" "base_route_table" {
  default_route_table_id = aws_vpc.base.default_route_table_id

