resource "aws_vpc_peering_connection" "pike" {
  vpc_id      = aws_vpc.peer.id
  peer_vpc_id = aws_vpc.base.id
  auto_accept = false

  tags = {
    Name = "pike"
  }
}

# Accept the peering connection from the requester side (assuming same account)
resource "aws_vpc_peering_connection_accepter" "pike_accepter" {
  vpc_peering_connection_id = aws_vpc_peering_connection.pike.id
  auto_accept               = true

  tags = {
    Name = "pike-accepter"
  }
}

# Update route tables to enable communication between VPCs

# Route in the "base" VPC's main route table to reach the "peer" VPC
